#!/usr/bin/env python3
"""Validate foundational math example-pack structure.

Usage:
  python3 scripts/validate-foundational-example-pack.py
  python3 scripts/validate-foundational-example-pack.py artifacts/examples/math/template-v0
"""

from __future__ import annotations

import json
import re
import sys
from collections import deque
from fractions import Fraction
from itertools import combinations, product
from math import comb, gcd
from pathlib import Path
from typing import Any, Callable


ROOT = Path(__file__).resolve().parents[1]
SCHEMA = ROOT / "artifacts" / "ontology" / "foundational-example-pack.schema.json"
CONCEPTS = ROOT / "artifacts" / "ontology" / "foundational-concepts.json"
DEFAULT_ROOT = ROOT / "artifacts" / "examples" / "math"
REQUIRED_FILES = {"README.md", "metadata.json", "model.md", "checks.md", "expected.json"}

CLAIM_STATUS = {"template", "planned", "witnessed", "checked", "proof-gap"}
TRUST_STATUS = {"template", "planned", "replay-only", "checked-evidence", "proof-gap", "numerical"}
EXPECTED_RESULT = {"sat", "unsat", "unknown", "not-run"}
PROOF_STATUS = {"template", "checked", "replay-only", "proof-gap", "lean-horizon", "not-required"}
SOLVER_REUSE_STATUS = {"candidate", "promoted", "non-benchmark-horizon"}
METADATA_REQUIRED = {
    "schema_version",
    "id",
    "title",
    "domain",
    "claim_status",
    "trust_status",
    "concept_ids",
    "field_ids",
    "curriculum_nodes",
    "axeyum_fragments",
    "validator_command",
    "source_refs",
    "expected_results",
    "graduation_criteria",
}
METADATA_OPTIONAL = {"solver_reuse"}


class ValidationError(Exception):
    pass


def fail(message: str) -> None:
    raise ValidationError(message)


def load_json(path: Path) -> Any:
    try:
        with path.open("r", encoding="utf-8") as handle:
            return json.load(handle)
    except json.JSONDecodeError as error:
        fail(f"{path.relative_to(ROOT)} is invalid JSON: {error}")


def require_keys(context: str, value: dict[str, Any], keys: set[str]) -> None:
    missing = sorted(keys - set(value))
    if missing:
        fail(f"{context} missing required keys: {', '.join(missing)}")


def require_string(context: str, value: Any) -> None:
    if not isinstance(value, str) or not value:
        fail(f"{context} must be a non-empty string")


def require_string_list(context: str, value: Any, *, nonempty: bool = True) -> list[str]:
    if not isinstance(value, list):
        fail(f"{context} must be a list")
    if nonempty and not value:
        fail(f"{context} must not be empty")
    seen: set[str] = set()
    for index, item in enumerate(value):
        if not isinstance(item, str) or not item:
            fail(f"{context}[{index}] must be a non-empty string")
        if item in seen:
            fail(f"{context} repeats {item!r}")
        seen.add(item)
    return value


def check_source(context: str, source: str) -> None:
    if source.startswith(("http://", "https://")):
        return
    path_part = source.split("#", 1)[0]
    if not path_part:
        return
    if not (ROOT / path_part).exists():
        fail(f"{context} references missing local source: {source}")


def concept_indexes() -> tuple[set[str], set[str], set[str]]:
    data = load_json(CONCEPTS)
    rows = data["rows"]
    concept_ids = {row["id"] for row in rows}
    field_ids = {field_id for row in rows for field_id in row["field_ids"]}
    curriculum_nodes = {
        row["curriculum_node"]
        for row in rows
        if row["kind"] == "curriculum-node" and row["curriculum_node"]
    }
    return concept_ids, field_ids, curriculum_nodes


def validate_metadata(
    pack_dir: Path,
    metadata: dict[str, Any],
    concept_ids: set[str],
    field_ids: set[str],
    curriculum_nodes: set[str],
) -> None:
    require_keys("metadata", metadata, METADATA_REQUIRED)
    extra_keys = sorted(set(metadata) - METADATA_REQUIRED - METADATA_OPTIONAL)
    if extra_keys:
        fail(f"metadata has unknown keys: {', '.join(extra_keys)}")
    if metadata["schema_version"] != 1:
        fail("metadata.schema_version must be 1")
    if metadata["id"] != pack_dir.name:
        fail(f"metadata.id must match directory name {pack_dir.name!r}")
    if not re.fullmatch(r"[a-z0-9][a-z0-9-]*", metadata["id"]):
        fail("metadata.id must be lowercase kebab case")
    require_string("metadata.title", metadata["title"])
    if metadata["domain"] not in {"mathematics", "computer-science", "logic", "statistics"}:
        fail(f"metadata.domain invalid: {metadata['domain']!r}")
    if metadata["claim_status"] not in CLAIM_STATUS:
        fail(f"metadata.claim_status invalid: {metadata['claim_status']!r}")
    if metadata["trust_status"] not in TRUST_STATUS:
        fail(f"metadata.trust_status invalid: {metadata['trust_status']!r}")
    pack_concepts = set(require_string_list("metadata.concept_ids", metadata["concept_ids"]))
    missing_concepts = sorted(pack_concepts - concept_ids)
    if missing_concepts:
        fail(f"metadata.concept_ids references unknown concepts: {', '.join(missing_concepts)}")
    pack_fields = set(require_string_list("metadata.field_ids", metadata["field_ids"]))
    missing_fields = sorted(pack_fields - field_ids)
    if missing_fields:
        fail(f"metadata.field_ids references unknown fields: {', '.join(missing_fields)}")
    nodes = set(require_string_list("metadata.curriculum_nodes", metadata["curriculum_nodes"], nonempty=False))
    missing_nodes = sorted(nodes - curriculum_nodes)
    if missing_nodes:
        fail(f"metadata.curriculum_nodes references unknown nodes: {', '.join(missing_nodes)}")
    require_string_list("metadata.axeyum_fragments", metadata["axeyum_fragments"])
    require_string("metadata.validator_command", metadata["validator_command"])
    sources = require_string_list("metadata.source_refs", metadata["source_refs"])
    for source in sources:
        check_source("metadata.source_refs", source)
    expected_ids = require_string_list(
        "metadata.expected_results",
        metadata["expected_results"],
        nonempty=metadata["claim_status"] != "template",
    )
    validate_solver_reuse(metadata, expected_ids)
    if metadata["claim_status"] == "template" and metadata["trust_status"] != "template":
        fail("template claim_status requires template trust_status")
    criteria = require_string_list("metadata.graduation_criteria", metadata["graduation_criteria"])
    if metadata["claim_status"] != "template" and not criteria:
        fail("non-template packs require graduation criteria")
    return expected_ids


def validate_solver_reuse(metadata: dict[str, Any], expected_ids: list[str]) -> None:
    if "solver_reuse" not in metadata:
        return
    if metadata["claim_status"] == "template":
        fail("template packs must not set metadata.solver_reuse")
    solver_reuse = metadata["solver_reuse"]
    if not isinstance(solver_reuse, dict):
        fail("metadata.solver_reuse must be an object")
    required = {"status", "target", "pressure", "evidence", "next_step"}
    require_keys("metadata.solver_reuse", solver_reuse, required)
    extra_keys = sorted(set(solver_reuse) - required)
    if extra_keys:
        fail(f"metadata.solver_reuse has unknown keys: {', '.join(extra_keys)}")
    if solver_reuse["status"] not in SOLVER_REUSE_STATUS:
        fail(f"metadata.solver_reuse.status invalid: {solver_reuse['status']!r}")
    require_string("metadata.solver_reuse.target", solver_reuse["target"])
    require_string("metadata.solver_reuse.pressure", solver_reuse["pressure"])
    evidence = require_string_list("metadata.solver_reuse.evidence", solver_reuse["evidence"])
    missing = sorted(set(evidence) - set(expected_ids))
    if missing:
        fail(
            "metadata.solver_reuse.evidence references unknown expected results: "
            + ", ".join(missing)
        )
    require_string("metadata.solver_reuse.next_step", solver_reuse["next_step"])


def validate_expected(metadata: dict[str, Any], expected: dict[str, Any], expected_ids: list[str]) -> None:
    require_keys("expected", expected, {"schema_version", "pack_id", "witnesses", "checks"})
    if expected["schema_version"] != 1:
        fail("expected.schema_version must be 1")
    if expected["pack_id"] != metadata["id"]:
        fail("expected.pack_id must match metadata.id")

    witness_ids: set[str] = set()
    for index, witness in enumerate(expected["witnesses"]):
        require_keys(f"witnesses[{index}]", witness, {"id", "description", "values"})
        witness_id = witness["id"]
        if witness_id in witness_ids:
            fail(f"duplicate witness id {witness_id}")
        witness_ids.add(witness_id)
        require_string(f"witnesses[{index}].description", witness["description"])
        if not isinstance(witness["values"], dict):
            fail(f"witnesses[{index}].values must be an object")

    check_ids: set[str] = set()
    for index, check in enumerate(expected["checks"]):
        require_keys(
            f"checks[{index}]",
            check,
            {"id", "claim", "expected_result", "validation", "proof_status", "notes"},
        )
        check_id = check["id"]
        if check_id in check_ids:
            fail(f"duplicate check id {check_id}")
        check_ids.add(check_id)
        require_string(f"checks[{index}].claim", check["claim"])
        if check["expected_result"] not in EXPECTED_RESULT:
            fail(f"{check_id}.expected_result invalid: {check['expected_result']!r}")
        require_string(f"checks[{index}].validation", check["validation"])
        if check["proof_status"] not in PROOF_STATUS:
            fail(f"{check_id}.proof_status invalid: {check['proof_status']!r}")
        for witness_id in check.get("witnesses", []):
            if witness_id not in witness_ids:
                fail(f"{check_id} references unknown witness {witness_id}")
        if "data" in check and not isinstance(check["data"], dict):
            fail(f"{check_id}.data must be an object when present")
        require_string(f"checks[{index}].notes", check["notes"])

    if set(expected_ids) != check_ids:
        fail(
            "metadata.expected_results must match expected.checks ids: "
            f"metadata={sorted(expected_ids)} expected={sorted(check_ids)}"
        )
    if "solver_reuse" in metadata:
        checks_by_id = {check["id"]: check for check in expected["checks"]}
        for check_id in metadata["solver_reuse"]["evidence"]:
            check = checks_by_id[check_id]
            if check["expected_result"] == "not-run":
                fail(f"metadata.solver_reuse.evidence uses not-run row {check_id}")
            if check["proof_status"] not in {"checked", "replay-only", "not-required"}:
                fail(
                    "metadata.solver_reuse.evidence must reference deterministic "
                    f"checked/replay rows, got {check_id} with {check['proof_status']!r}"
                )
    validate_pack_semantics(metadata, expected)


def require_int(context: str, value: Any) -> int:
    if not isinstance(value, int):
        fail(f"{context} must be an integer")
    return value


def witness_by_id(expected: dict[str, Any]) -> dict[str, dict[str, Any]]:
    return {witness["id"]: witness for witness in expected["witnesses"]}


def single_witness_values(check: dict[str, Any], witnesses: dict[str, dict[str, Any]]) -> dict[str, Any]:
    ids = check.get("witnesses", [])
    if len(ids) != 1:
        fail(f"{check['id']} must reference exactly one witness")
    values = witnesses[ids[0]]["values"]
    if not isinstance(values, dict):
        fail(f"{check['id']} witness values must be an object")
    return values


def require_set_values(context: str, values: dict[str, Any]) -> tuple[set[str], set[str], set[str], set[str]]:
    universe = require_string_list(f"{context}.universe", values.get("universe"))
    universe_set = set(universe)

    def read_subset(name: str) -> set[str]:
        items = require_string_list(f"{context}.{name}", values.get(name), nonempty=False)
        extra = sorted(set(items) - universe_set)
        if extra:
            fail(f"{context}.{name} contains elements outside universe: {extra}")
        return set(items)

    return universe_set, read_subset("A"), read_subset("B"), read_subset("C")


def validate_finite_sets(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    identity = checks["union-intersection-identity"]
    if identity["expected_result"] != "sat":
        fail("union-intersection-identity must expect sat")
    values = single_witness_values(identity, witnesses)
    _, a_set, b_set, c_set = require_set_values("union-intersection identity", values)
    left = a_set | (b_set & c_set)
    right = (a_set | b_set) & (a_set | c_set)
    if left != right:
        fail("union-intersection identity witness does not satisfy distributivity")

    transitivity = checks["subset-transitivity-witness"]
    if transitivity["expected_result"] != "sat":
        fail("subset-transitivity-witness must expect sat")
    values = single_witness_values(transitivity, witnesses)
    _, a_set, b_set, c_set = require_set_values("subset transitivity", values)
    if not (a_set <= b_set and b_set <= c_set and a_set <= c_set):
        fail("subset transitivity witness does not satisfy A <= B <= C")

    bad_identity = checks["distributive-law-counterexample-rejected"]
    if bad_identity["expected_result"] != "unsat":
        fail("distributive-law-counterexample-rejected must expect unsat")
    values = single_witness_values(bad_identity, witnesses)
    _, a_set, b_set, c_set = require_set_values("bad distributive identity", values)
    left = a_set & (b_set | c_set)
    right = (a_set & b_set) | c_set
    if left == right:
        fail("bad distributive identity unexpectedly holds for the fixed witness")


def require_pair_set(
    context: str,
    value: Any,
    left_values: set[str],
    right_values: set[str],
) -> set[tuple[str, str]]:
    if not isinstance(value, list):
        fail(f"{context} must be a list")
    pairs: set[tuple[str, str]] = set()
    for index, pair in enumerate(value):
        if not isinstance(pair, list) or len(pair) != 2:
            fail(f"{context}[{index}] must be a two-element list")
        left, right = pair
        require_string(f"{context}[{index}][0]", left)
        require_string(f"{context}[{index}][1]", right)
        if left not in left_values:
            fail(f"{context}[{index}][0] references missing left element {left!r}")
        if right not in right_values:
            fail(f"{context}[{index}][1] references missing right element {right!r}")
        normalized = (left, right)
        if normalized in pairs:
            fail(f"{context} repeats pair {normalized}")
        pairs.add(normalized)
    return pairs


def require_relation_data(context: str, values: dict[str, Any]) -> tuple[list[str], set[tuple[str, str]]]:
    elements = require_string_list(f"{context}.elements", values.get("elements"))
    element_set = set(elements)
    pairs = require_pair_set(f"{context}.pairs", values.get("pairs"), element_set, element_set)
    return elements, pairs


def is_reflexive(elements: list[str], pairs: set[tuple[str, str]]) -> bool:
    return all((element, element) in pairs for element in elements)


def is_antisymmetric(pairs: set[tuple[str, str]]) -> bool:
    return all(left == right or (right, left) not in pairs for left, right in pairs)


def is_symmetric(pairs: set[tuple[str, str]]) -> bool:
    return all((right, left) in pairs for left, right in pairs)


def is_transitive(pairs: set[tuple[str, str]]) -> bool:
    return all(
        (left, right_2) in pairs
        for left, right_1 in pairs
        for left_2, right_2 in pairs
        if right_1 == left_2
    )


def require_function_graph_data(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], list[str], set[tuple[str, str]]]:
    domain = require_string_list(f"{context}.domain", values.get("domain"))
    codomain = require_string_list(f"{context}.codomain", values.get("codomain"))
    pairs = require_pair_set(f"{context}.pairs", values.get("pairs"), set(domain), set(codomain))
    return domain, codomain, pairs


def outputs_by_input(domain: list[str], pairs: set[tuple[str, str]]) -> dict[str, set[str]]:
    return {
        item: {output for input_item, output in pairs if input_item == item}
        for item in domain
    }


def is_total_function(domain: list[str], pairs: set[tuple[str, str]]) -> bool:
    outputs = outputs_by_input(domain, pairs)
    return all(outputs[item] for item in domain)


def is_single_valued(domain: list[str], pairs: set[tuple[str, str]]) -> bool:
    outputs = outputs_by_input(domain, pairs)
    return all(len(outputs[item]) <= 1 for item in domain)


def function_mapping(domain: list[str], pairs: set[tuple[str, str]]) -> dict[str, str]:
    outputs = outputs_by_input(domain, pairs)
    if not all(len(outputs[item]) == 1 for item in domain):
        fail("function graph must be total and single-valued before extracting a mapping")
    return {item: next(iter(outputs[item])) for item in domain}


def validate_relations_functions(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    order = checks["partial-order-witness"]
    if order["expected_result"] != "sat":
        fail("partial-order-witness must expect sat")
    values = single_witness_values(order, witnesses)
    elements, pairs = require_relation_data("partial order", values)
    if not is_reflexive(elements, pairs):
        fail("partial-order-witness relation is not reflexive")
    if not is_antisymmetric(pairs):
        fail("partial-order-witness relation is not antisymmetric")
    if not is_transitive(pairs):
        fail("partial-order-witness relation is not transitive")

    bijection = checks["bijection-table-witness"]
    if bijection["expected_result"] != "sat":
        fail("bijection-table-witness must expect sat")
    values = single_witness_values(bijection, witnesses)
    domain, codomain, pairs = require_function_graph_data("bijection table", values)
    if not is_total_function(domain, pairs):
        fail("bijection-table-witness graph is not total")
    if not is_single_valued(domain, pairs):
        fail("bijection-table-witness graph is not single-valued")
    mapping = function_mapping(domain, pairs)
    images = list(mapping.values())
    if len(set(images)) != len(images):
        fail("bijection-table-witness graph is not injective")
    if set(images) != set(codomain):
        fail("bijection-table-witness graph is not surjective")

    bad_function = checks["non-function-rejected"]
    if bad_function["expected_result"] != "unsat":
        fail("non-function-rejected must expect unsat")
    values = single_witness_values(bad_function, witnesses)
    domain, _, pairs = require_function_graph_data("non-function graph", values)
    if is_single_valued(domain, pairs):
        fail("non-function-rejected graph unexpectedly is single-valued")
    if is_total_function(domain, pairs) and is_single_valued(domain, pairs):
        fail("non-function-rejected graph unexpectedly is a function")

    qf_uf = checks["qf-uf-function-single-valued-alethe"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-function-single-valued-alethe must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-function-single-valued-alethe must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-function-single-valued-alethe must use qf_uf_congruence_alethe validation")
    data = qf_uf.get("data", {})
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf function single-valued smt2_artifact", smt2_artifact)
    check_source("qf-uf function single-valued smt2_artifact", smt2_artifact)
    require_string("qf-uf function single-valued proof_regression", data.get("proof_regression"))
    certificate = data.get("certificate")
    require_string("qf-uf function single-valued certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf function single-valued certificate must document zero-trust Alethe evidence")


def is_partial_order(elements: list[str], pairs: set[tuple[str, str]]) -> bool:
    return is_reflexive(elements, pairs) and is_antisymmetric(pairs) and is_transitive(pairs)


def leq(pairs: set[tuple[str, str]], left: str, right: str) -> bool:
    return (left, right) in pairs


def greatest_lower_bound(
    elements: list[str],
    pairs: set[tuple[str, str]],
    left: str,
    right: str,
) -> str:
    lower_bounds = [candidate for candidate in elements if leq(pairs, candidate, left) and leq(pairs, candidate, right)]
    greatest = [candidate for candidate in lower_bounds if all(leq(pairs, other, candidate) for other in lower_bounds)]
    if len(greatest) != 1:
        fail(f"expected a unique greatest lower bound for {(left, right)}, got {greatest}")
    return greatest[0]


def least_upper_bound(
    elements: list[str],
    pairs: set[tuple[str, str]],
    left: str,
    right: str,
) -> str:
    upper_bounds = [candidate for candidate in elements if leq(pairs, left, candidate) and leq(pairs, right, candidate)]
    least = [candidate for candidate in upper_bounds if all(leq(pairs, candidate, other) for other in upper_bounds)]
    if len(least) != 1:
        fail(f"expected a unique least upper bound for {(left, right)}, got {least}")
    return least[0]


def require_lattice_data(
    context: str,
    values: Any,
) -> tuple[list[str], set[tuple[str, str]], str, str, dict[tuple[str, str], str], dict[tuple[str, str], str]]:
    if not isinstance(values, dict):
        fail(f"{context} must be an object")
    elements, pairs = require_relation_data(context, values)
    element_set = set(elements)
    bottom = values.get("bottom")
    top = values.get("top")
    require_string(f"{context}.bottom", bottom)
    require_string(f"{context}.top", top)
    if bottom not in element_set:
        fail(f"{context}.bottom must be in the carrier")
    if top not in element_set:
        fail(f"{context}.top must be in the carrier")
    meet = require_binary_table(f"{context}.meet", elements, values.get("meet"))
    join = require_binary_table(f"{context}.join", elements, values.get("join"))
    return elements, pairs, bottom, top, meet, join


def check_bottom_top(context: str, elements: list[str], pairs: set[tuple[str, str]], bottom: str, top: str) -> None:
    for element in elements:
        if not leq(pairs, bottom, element):
            fail(f"{context} bottom is not below {element}")
        if not leq(pairs, element, top):
            fail(f"{context} top is not above {element}")


def check_lattice_tables(
    context: str,
    elements: list[str],
    pairs: set[tuple[str, str]],
    meet: dict[tuple[str, str], str],
    join: dict[tuple[str, str], str],
) -> None:
    for left in elements:
        for right in elements:
            if table_op(meet, left, right) != greatest_lower_bound(elements, pairs, left, right):
                fail(f"{context} meet table is incorrect for {(left, right)}")
            if table_op(join, left, right) != least_upper_bound(elements, pairs, left, right):
                fail(f"{context} join table is incorrect for {(left, right)}")


def check_distributive_lattice(
    context: str,
    elements: list[str],
    meet: dict[tuple[str, str], str],
    join: dict[tuple[str, str], str],
) -> None:
    for x_value in elements:
        for y_value in elements:
            for z_value in elements:
                lhs = table_op(meet, x_value, table_op(join, y_value, z_value))
                rhs = table_op(join, table_op(meet, x_value, y_value), table_op(meet, x_value, z_value))
                if lhs != rhs:
                    fail(f"{context} meet-over-join distributivity fails for {(x_value, y_value, z_value)}")
                dual_lhs = table_op(join, x_value, table_op(meet, y_value, z_value))
                dual_rhs = table_op(meet, table_op(join, x_value, y_value), table_op(join, x_value, z_value))
                if dual_lhs != dual_rhs:
                    fail(f"{context} join-over-meet distributivity fails for {(x_value, y_value, z_value)}")


def validate_finite_order_lattices(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    poset = checks["boolean-lattice-poset"]
    if poset["expected_result"] != "sat":
        fail("boolean-lattice-poset must expect sat")
    values = single_witness_values(poset, witnesses)
    elements, pairs, bottom, top, meet, join = require_lattice_data("boolean lattice", values)
    if not is_partial_order(elements, pairs):
        fail("boolean-lattice-poset relation is not a partial order")
    check_bottom_top("boolean-lattice-poset", elements, pairs, bottom, top)

    lattice = checks["meet-join-table-replay"]
    if lattice["expected_result"] != "sat":
        fail("meet-join-table-replay must expect sat")
    values = single_witness_values(lattice, witnesses)
    elements, pairs, bottom, top, meet, join = require_lattice_data("meet join lattice", values)
    if not is_partial_order(elements, pairs):
        fail("meet-join-table-replay relation is not a partial order")
    check_bottom_top("meet-join-table-replay", elements, pairs, bottom, top)
    check_lattice_tables("meet-join-table-replay", elements, pairs, meet, join)

    distributive = checks["distributive-lattice-replay"]
    if distributive["expected_result"] != "sat":
        fail("distributive-lattice-replay must expect sat")
    values = single_witness_values(distributive, witnesses)
    elements, pairs, bottom, top, meet, join = require_lattice_data("distributive lattice", values)
    if not is_partial_order(elements, pairs):
        fail("distributive-lattice-replay relation is not a partial order")
    check_bottom_top("distributive-lattice-replay", elements, pairs, bottom, top)
    check_lattice_tables("distributive-lattice-replay", elements, pairs, meet, join)
    check_distributive_lattice("distributive-lattice-replay", elements, meet, join)

    monotone = checks["monotone-map-fixed-points"]
    if monotone["expected_result"] != "sat":
        fail("monotone-map-fixed-points must expect sat")
    values = single_witness_values(monotone, witnesses)
    elements, pairs = require_relation_data("monotone map order", values)
    if not is_partial_order(elements, pairs):
        fail("monotone-map-fixed-points relation is not a partial order")
    mapping = require_mapping_object("monotone map", values.get("map"), elements, elements)
    for left in elements:
        for right in elements:
            if leq(pairs, left, right) and not leq(pairs, mapping[left], mapping[right]):
                fail(f"monotone-map-fixed-points map is not monotone for {(left, right)}")
    computed_fixed = {element for element in elements if mapping[element] == element}
    fixed_points = set(require_string_list("monotone fixed_points", values.get("fixed_points"), nonempty=True))
    extra = sorted(fixed_points - set(elements))
    if extra:
        fail(f"monotone-map-fixed-points fixed_points contain elements outside the carrier: {extra}")
    if fixed_points != computed_fixed:
        fail("monotone-map-fixed-points fixed point set is incorrect")
    least_fixed_point = values.get("least_fixed_point")
    require_string("monotone least_fixed_point", least_fixed_point)
    if least_fixed_point not in fixed_points:
        fail("monotone-map-fixed-points least_fixed_point is not fixed")
    if not all(leq(pairs, least_fixed_point, fixed_point) for fixed_point in fixed_points):
        fail("monotone-map-fixed-points least_fixed_point is not below every fixed point")

    bad = checks["bad-partial-order-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-partial-order-rejected must be a checked unsat row")
    data = bad.get("data", {})
    elements, pairs = require_relation_data("bad partial order", data)
    if not is_reflexive(elements, pairs):
        fail("bad-partial-order-rejected should document a reflexive relation")
    if not is_transitive(pairs):
        fail("bad-partial-order-rejected should document a transitive relation")
    if is_antisymmetric(pairs):
        fail("bad-partial-order-rejected relation unexpectedly is antisymmetric")
    failing_pair = data.get("failing_pair")
    if not isinstance(failing_pair, list) or len(failing_pair) != 2:
        fail("bad-partial-order-rejected failing_pair must be a two-element list")
    left, right = failing_pair
    require_string("bad partial order failing_pair[0]", left)
    require_string("bad partial order failing_pair[1]", right)
    if left == right:
        fail("bad-partial-order-rejected failing_pair must contain distinct elements")
    if (left, right) not in pairs or (right, left) not in pairs:
        fail("bad-partial-order-rejected failing_pair must witness antisymmetry failure")
    qf_uf = checks["qf-uf-bad-partial-order-antisymmetry"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-bad-partial-order-antisymmetry must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-bad-partial-order-antisymmetry must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-partial-order-antisymmetry must use qf_uf_congruence_alethe validation")
    qf_data = qf_uf.get("data", {})
    qf_elements = require_string_list("qf-uf bad partial order elements", qf_data.get("elements"), nonempty=True)
    if set(qf_elements) != set(elements):
        fail("qf-uf-bad-partial-order-antisymmetry elements must match bad-partial-order-rejected")
    qf_pairs = qf_data.get("relation_pairs")
    if not isinstance(qf_pairs, list):
        fail("qf-uf-bad-partial-order-antisymmetry relation_pairs must be a list")
    parsed_qf_pairs: set[tuple[str, str]] = set()
    for i, pair in enumerate(qf_pairs):
        if not isinstance(pair, list) or len(pair) != 2:
            fail(f"qf-uf-bad-partial-order-antisymmetry relation_pairs[{i}] must be a pair")
        qf_left, qf_right = pair
        require_string(f"qf-uf bad partial order relation_pairs[{i}][0]", qf_left)
        require_string(f"qf-uf bad partial order relation_pairs[{i}][1]", qf_right)
        parsed_qf_pairs.add((qf_left, qf_right))
    if parsed_qf_pairs != {(left, right), (right, left)}:
        fail("qf-uf-bad-partial-order-antisymmetry relation_pairs must match the replayed antisymmetry failure")
    qf_failing_pair = qf_data.get("failing_pair")
    if qf_failing_pair != [left, right]:
        fail("qf-uf-bad-partial-order-antisymmetry failing_pair must match bad-partial-order-rejected")
    distinctness_claim = qf_data.get("distinctness_claim")
    require_string("qf-uf bad partial order distinctness_claim", distinctness_claim)
    if distinctness_claim != f"{left} != {right}":
        fail("qf-uf-bad-partial-order-antisymmetry must document the distinctness claim")
    alethe_claim = qf_data.get("alethe_antisymmetry_claim")
    require_string("qf-uf bad partial order alethe_antisymmetry_claim", alethe_claim)
    if alethe_claim != f"{left} = {right}":
        fail("qf-uf-bad-partial-order-antisymmetry must document the Alethe antisymmetry equality claim")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("qf-uf bad partial order smt2_artifact", smt2_artifact)
    expected_smt2 = (
        "artifacts/examples/math/finite-order-lattices-v0/smt2/"
        "bad-partial-order-antisymmetry-conflict.smt2"
    )
    if smt2_artifact != expected_smt2:
        fail("qf-uf-bad-partial-order-antisymmetry smt2_artifact must name the checked source artifact")
    check_source("qf-uf bad partial order smt2_artifact", smt2_artifact)
    proof_regression = qf_data.get("proof_regression")
    require_string("qf-uf bad partial order proof_regression", proof_regression)
    if "finite_order_lattices_bad_partial_order_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-partial-order-antisymmetry must link the Alethe regression")
    certificate = qf_data.get("certificate")
    require_string("qf-uf bad partial order certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-partial-order-antisymmetry certificate must document zero-trust Alethe evidence")

    bad_top = checks["bad-top-element-rejected"]
    if bad_top["expected_result"] != "unsat" or bad_top.get("proof_status") != "checked":
        fail("bad-top-element-rejected must be a checked unsat row")
    if bad_top["validation"] != "finite_bad_top_element_refutation":
        fail("bad-top-element-rejected must use finite_bad_top_element_refutation validation")
    data = bad_top.get("data", {})
    elements, pairs = require_relation_data("bad top element relation", data)
    if not is_partial_order(elements, pairs):
        fail("bad-top-element-rejected relation should be a valid partial order")
    claimed_top = data.get("claimed_top")
    missing_below = data.get("missing_below")
    require_string("bad top claimed_top", claimed_top)
    require_string("bad top missing_below", missing_below)
    if claimed_top not in set(elements):
        fail("bad-top-element-rejected claimed_top must be in the carrier")
    if missing_below not in set(elements):
        fail("bad-top-element-rejected missing_below must be in the carrier")
    if leq(pairs, missing_below, claimed_top):
        fail("bad-top-element-rejected missing_below is unexpectedly below the claimed top")
    if all(leq(pairs, element, claimed_top) for element in elements):
        fail("bad-top-element-rejected claimed_top unexpectedly is a top element")
    cnf_variable = data.get("cnf_variable")
    require_string("bad top cnf_variable", cnf_variable)
    if cnf_variable != f"{missing_below}_le_{claimed_top}":
        fail("bad-top-element-rejected cnf_variable must name the missing comparison")
    require_dimacs_artifact(
        "bad-top-element-rejected",
        data.get("cnf_artifact"),
        "p cnf 1 2",
        [["-1"], ["1"]],
    )
    cnf_artifact = data.get("cnf_artifact")
    if cnf_artifact != "artifacts/examples/math/finite-order-lattices-v0/cnf/bad-top-element-rejected.cnf":
        fail("bad-top-element-rejected cnf_artifact must name the checked DIMACS artifact")
    regression = data.get("boolean_regression")
    require_string("bad top boolean_regression", regression)
    if "finite_order_lattices_bad_top_element_emits_checked_drat_and_lrat" not in regression:
        fail("bad-top-element-rejected must link the Boolean proof-route regression")
    certificate = data.get("certificate")
    require_string("bad top certificate", certificate)
    if not all(token in certificate for token in ("DRAT", "LRAT", "check_drat", "check_lrat")):
        fail("bad-top-element-rejected certificate must document checked DRAT/LRAT evidence")

    horizon = checks["general-order-lattice-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-order-lattice-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-order-lattice-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general order target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general order future_checker", data.get("future_checker"))


def require_total_mapping(
    context: str,
    domain: list[str],
    codomain: list[str],
    pairs: set[tuple[str, str]],
) -> dict[str, str]:
    if not is_total_function(domain, pairs):
        fail(f"{context} graph is not total")
    if not is_single_valued(domain, pairs):
        fail(f"{context} graph is not single-valued")
    mapping = function_mapping(domain, pairs)
    extra_outputs = sorted(set(mapping.values()) - set(codomain))
    if extra_outputs:
        fail(f"{context} maps outside codomain: {extra_outputs}")
    return mapping


def graph_from_mapping(domain: list[str], mapping: dict[str, str]) -> set[tuple[str, str]]:
    return {(item, mapping[item]) for item in domain}


def compose_mapping(
    context: str,
    domain: list[str],
    left: dict[str, str],
    right: dict[str, str],
) -> dict[str, str]:
    composed: dict[str, str] = {}
    for item in domain:
        middle = left[item]
        if middle not in right:
            fail(f"{context} composition is undefined at {item!r} through {middle!r}")
        composed[item] = right[middle]
    return composed


def require_subset_labels(context: str, value: Any, universe: list[str]) -> set[str]:
    items = require_string_list(context, value, nonempty=False)
    universe_set = set(universe)
    extra = sorted(set(items) - universe_set)
    if extra:
        fail(f"{context} contains labels outside the universe: {extra}")
    return set(items)


def is_bijection_mapping(mapping: dict[str, str], codomain: list[str]) -> bool:
    return len(set(mapping.values())) == len(mapping) and set(mapping.values()) == set(codomain)


def inverse_mapping(mapping: dict[str, str]) -> dict[str, str]:
    inverse: dict[str, str] = {}
    for left, right in mapping.items():
        if right in inverse:
            fail("cannot invert a non-injective mapping")
        inverse[right] = left
    return inverse


def identity_graph(elements: list[str]) -> set[tuple[str, str]]:
    return {(item, item) for item in elements}


def validate_function_composition(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    composition = checks["composition-table-replay"]
    if composition["expected_result"] != "sat" or composition.get("proof_status") != "checked":
        fail("composition-table-replay must be a checked sat row")
    values = single_witness_values(composition, witnesses)
    domain = require_string_list("composition domain", values.get("domain"))
    middle = require_string_list("composition middle", values.get("middle"))
    codomain = require_string_list("composition codomain", values.get("codomain"))
    f_pairs = require_pair_set("composition f_pairs", values.get("f_pairs"), set(domain), set(middle))
    g_pairs = require_pair_set("composition g_pairs", values.get("g_pairs"), set(middle), set(codomain))
    composite_pairs = require_pair_set("composition composite_pairs", values.get("composite_pairs"), set(domain), set(codomain))
    f_map = require_total_mapping("composition f", domain, middle, f_pairs)
    g_map = require_total_mapping("composition g", middle, codomain, g_pairs)
    composite = compose_mapping("composition", domain, f_map, g_map)
    if composite_pairs != graph_from_mapping(domain, composite):
        fail("composition-table-replay composite table is wrong")

    image = checks["image-preimage-replay"]
    if image["expected_result"] != "sat" or image.get("proof_status") != "checked":
        fail("image-preimage-replay must be a checked sat row")
    values = single_witness_values(image, witnesses)
    domain = require_string_list("image domain", values.get("domain"))
    codomain = require_string_list("image codomain", values.get("codomain"))
    pairs = require_pair_set("image pairs", values.get("pairs"), set(domain), set(codomain))
    mapping = require_total_mapping("image function", domain, codomain, pairs)
    subset_domain = require_subset_labels("image subset_domain", values.get("subset_domain"), domain)
    listed_image = require_subset_labels("image image", values.get("image"), codomain)
    subset_codomain = require_subset_labels("image subset_codomain", values.get("subset_codomain"), codomain)
    listed_preimage = require_subset_labels("image preimage", values.get("preimage"), domain)
    actual_image = {mapping[item] for item in subset_domain}
    actual_preimage = {item for item in domain if mapping[item] in subset_codomain}
    if listed_image != actual_image:
        fail("image-preimage-replay listed image is wrong")
    if listed_preimage != actual_preimage:
        fail("image-preimage-replay listed preimage is wrong")

    inverse = checks["bijection-inverse-table"]
    if inverse["expected_result"] != "sat" or inverse.get("proof_status") != "checked":
        fail("bijection-inverse-table must be a checked sat row")
    values = single_witness_values(inverse, witnesses)
    domain = require_string_list("inverse domain", values.get("domain"))
    codomain = require_string_list("inverse codomain", values.get("codomain"))
    pairs = require_pair_set("inverse pairs", values.get("pairs"), set(domain), set(codomain))
    inverse_pairs = require_pair_set("inverse inverse_pairs", values.get("inverse_pairs"), set(codomain), set(domain))
    left_identity = require_pair_set("inverse left_identity", values.get("left_identity"), set(domain), set(domain))
    right_identity = require_pair_set("inverse right_identity", values.get("right_identity"), set(codomain), set(codomain))
    mapping = require_total_mapping("inverse function", domain, codomain, pairs)
    if not is_bijection_mapping(mapping, codomain):
        fail("bijection-inverse-table function is not bijective")
    actual_inverse = inverse_mapping(mapping)
    if inverse_pairs != graph_from_mapping(codomain, actual_inverse):
        fail("bijection-inverse-table inverse table is wrong")
    if left_identity != identity_graph(domain):
        fail("bijection-inverse-table left identity table is wrong")
    if right_identity != identity_graph(codomain):
        fail("bijection-inverse-table right identity table is wrong")
    inverse_then_function = compose_mapping("inverse left identity", domain, mapping, actual_inverse)
    function_then_inverse = compose_mapping("inverse right identity", codomain, actual_inverse, mapping)
    if graph_from_mapping(domain, inverse_then_function) != left_identity:
        fail("bijection-inverse-table inverse-after-function is not identity")
    if graph_from_mapping(codomain, function_then_inverse) != right_identity:
        fail("bijection-inverse-table function-after-inverse is not identity")

    assoc = checks["composition-associativity-table"]
    if assoc["expected_result"] != "sat" or assoc.get("proof_status") != "checked":
        fail("composition-associativity-table must be a checked sat row")
    values = single_witness_values(assoc, witnesses)
    set_a = require_string_list("associativity A", values.get("A"))
    set_b = require_string_list("associativity B", values.get("B"))
    set_c = require_string_list("associativity C", values.get("C"))
    set_d = require_string_list("associativity D", values.get("D"))
    f_pairs = require_pair_set("associativity f_pairs", values.get("f_pairs"), set(set_a), set(set_b))
    g_pairs = require_pair_set("associativity g_pairs", values.get("g_pairs"), set(set_b), set(set_c))
    h_pairs = require_pair_set("associativity h_pairs", values.get("h_pairs"), set(set_c), set(set_d))
    g_after_f_pairs = require_pair_set("associativity g_after_f", values.get("g_after_f"), set(set_a), set(set_c))
    h_after_g_pairs = require_pair_set("associativity h_after_g", values.get("h_after_g"), set(set_b), set(set_d))
    left_pairs = require_pair_set("associativity left", values.get("h_after_g_after_f_left"), set(set_a), set(set_d))
    right_pairs = require_pair_set("associativity right", values.get("h_after_g_after_f_right"), set(set_a), set(set_d))
    f_map = require_total_mapping("associativity f", set_a, set_b, f_pairs)
    g_map = require_total_mapping("associativity g", set_b, set_c, g_pairs)
    h_map = require_total_mapping("associativity h", set_c, set_d, h_pairs)
    g_after_f = compose_mapping("associativity g after f", set_a, f_map, g_map)
    h_after_g = compose_mapping("associativity h after g", set_b, g_map, h_map)
    if g_after_f_pairs != graph_from_mapping(set_a, g_after_f):
        fail("composition-associativity-table g_after_f is wrong")
    if h_after_g_pairs != graph_from_mapping(set_b, h_after_g):
        fail("composition-associativity-table h_after_g is wrong")
    left_map = compose_mapping("associativity h after (g after f)", set_a, g_after_f, h_map)
    right_map = compose_mapping("associativity (h after g) after f", set_a, f_map, h_after_g)
    if left_pairs != graph_from_mapping(set_a, left_map):
        fail("composition-associativity-table left table is wrong")
    if right_pairs != graph_from_mapping(set_a, right_map):
        fail("composition-associativity-table right table is wrong")
    if left_pairs != right_pairs:
        fail("composition-associativity-table left and right tables differ")

    noninjective = checks["non-injective-inverse-rejected"]
    if noninjective["expected_result"] != "sat" or noninjective.get("proof_status") != "checked":
        fail("non-injective-inverse-rejected must be a checked sat row")
    values = single_witness_values(noninjective, witnesses)
    domain = require_string_list("noninjective domain", values.get("domain"))
    codomain = require_string_list("noninjective codomain", values.get("codomain"))
    pairs = require_pair_set("noninjective pairs", values.get("pairs"), set(domain), set(codomain))
    mapping = require_total_mapping("noninjective function", domain, codomain, pairs)
    collision_output = values.get("collision_output")
    require_string("noninjective collision_output", collision_output)
    if collision_output not in codomain:
        fail("non-injective-inverse-rejected collision_output is outside codomain")
    collision_inputs = require_subset_labels("noninjective collision_inputs", values.get("collision_inputs"), domain)
    if len(collision_inputs) < 2:
        fail("non-injective-inverse-rejected must list at least two collision inputs")
    if any(mapping[item] != collision_output for item in collision_inputs):
        fail("non-injective-inverse-rejected collision inputs do not map to collision_output")
    if len(set(mapping.values())) == len(mapping):
        fail("non-injective-inverse-rejected function unexpectedly is injective")

    qf_uf = checks["qf-uf-composition-application-alethe"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-composition-application-alethe must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-composition-application-alethe must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-composition-application-alethe must use qf_uf_congruence_alethe validation")
    data = qf_uf.get("data", {})
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf composition application smt2_artifact", smt2_artifact)
    check_source("qf-uf composition application smt2_artifact", smt2_artifact)
    require_string("qf-uf composition application proof_regression", data.get("proof_regression"))
    certificate = data.get("certificate")
    require_string("qf-uf composition application certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf composition application certificate must document zero-trust Alethe evidence")

    horizon = checks["general-function-laws-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-function-laws-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-function-laws-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general function laws target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general function laws future_checker", data.get("future_checker"))


def require_named_blocks(
    context: str,
    value: Any,
    elements: list[str],
    *,
    require_partition: bool,
) -> list[tuple[str, set[str]]]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty block list")
    element_set = set(elements)
    blocks: list[tuple[str, set[str]]] = []
    seen_ids: set[str] = set()
    seen_members: set[str] = set()
    for index, block in enumerate(value):
        if not isinstance(block, dict):
            fail(f"{context}[{index}] must be an object")
        block_id = block.get("id")
        require_string(f"{context}[{index}].id", block_id)
        if block_id in seen_ids:
            fail(f"{context} repeats block id {block_id!r}")
        seen_ids.add(block_id)
        members = set(require_string_list(f"{context}[{index}].members", block.get("members")))
        if not members:
            fail(f"{context}[{index}].members must be non-empty")
        if not members <= element_set:
            fail(f"{context}[{index}].members contains values outside the carrier")
        overlap = seen_members & members
        if overlap:
            fail(f"{context} blocks overlap on {sorted(overlap)}")
        seen_members |= members
        blocks.append((block_id, members))
    if require_partition and seen_members != element_set:
        fail(f"{context} blocks must cover every carrier element")
    return blocks


def equivalence_classes(elements: list[str], pairs: set[tuple[str, str]]) -> set[frozenset[str]]:
    return {
        frozenset(right for left, right in pairs if left == element)
        for element in elements
    }


def induced_relation_from_blocks(blocks: list[tuple[str, set[str]]]) -> set[tuple[str, str]]:
    return {
        (left, right)
        for _, members in blocks
        for left in members
        for right in members
    }


def block_set(blocks: list[tuple[str, set[str]]]) -> set[frozenset[str]]:
    return {frozenset(members) for _, members in blocks}


def validate_equivalence_classes(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    classes_check = checks["equivalence-relation-classes-witness"]
    if classes_check["expected_result"] != "sat":
        fail("equivalence-relation-classes-witness must expect sat")
    values = single_witness_values(classes_check, witnesses)
    elements, pairs = require_relation_data("equivalence relation", values)
    if not is_reflexive(elements, pairs):
        fail("equivalence-relation-classes-witness relation is not reflexive")
    if not is_symmetric(pairs):
        fail("equivalence-relation-classes-witness relation is not symmetric")
    if not is_transitive(pairs):
        fail("equivalence-relation-classes-witness relation is not transitive")
    listed_classes = require_named_blocks(
        "equivalence relation classes",
        values.get("classes"),
        elements,
        require_partition=True,
    )
    if equivalence_classes(elements, pairs) != block_set(listed_classes):
        fail("equivalence-relation-classes-witness classes do not match the relation")

    quotient_check = checks["quotient-map-fiber-witness"]
    if quotient_check["expected_result"] != "sat":
        fail("quotient-map-fiber-witness must expect sat")
    values = single_witness_values(quotient_check, witnesses)
    domain, codomain, graph = require_function_graph_data("quotient map", values)
    if not is_total_function(domain, graph):
        fail("quotient-map-fiber-witness graph is not total")
    if not is_single_valued(domain, graph):
        fail("quotient-map-fiber-witness graph is not single-valued")
    mapping = function_mapping(domain, graph)
    relation_pairs = require_pair_set(
        "quotient map relation_pairs",
        values.get("relation_pairs"),
        set(domain),
        set(domain),
    )
    listed_fibers = require_named_blocks(
        "quotient map fibers",
        values.get("fibers"),
        domain,
        require_partition=True,
    )
    if {fiber_id for fiber_id, _ in listed_fibers} != set(codomain):
        fail("quotient-map-fiber-witness fiber ids must match the codomain")
    actual_fibers = {
        label: {item for item, image in mapping.items() if image == label}
        for label in codomain
    }
    if any(not members for members in actual_fibers.values()):
        fail("quotient-map-fiber-witness quotient map must hit every class label")
    if dict(listed_fibers) != actual_fibers:
        fail("quotient-map-fiber-witness listed fibers are incorrect")
    induced_relation = {
        (left, right)
        for left in domain
        for right in domain
        if mapping[left] == mapping[right]
    }
    if induced_relation != relation_pairs:
        fail("quotient-map-fiber-witness relation does not match quotient equality")
    if not is_reflexive(domain, relation_pairs) or not is_symmetric(relation_pairs) or not is_transitive(relation_pairs):
        fail("quotient-map-fiber-witness relation_pairs must form an equivalence relation")

    partition_check = checks["partition-relation-roundtrip"]
    if partition_check["expected_result"] != "sat":
        fail("partition-relation-roundtrip must expect sat")
    values = single_witness_values(partition_check, witnesses)
    elements = require_string_list("partition roundtrip elements", values.get("elements"))
    blocks = require_named_blocks(
        "partition roundtrip blocks",
        values.get("blocks"),
        elements,
        require_partition=True,
    )
    pairs = require_pair_set(
        "partition roundtrip pairs",
        values.get("pairs"),
        set(elements),
        set(elements),
    )
    if induced_relation_from_blocks(blocks) != pairs:
        fail("partition-relation-roundtrip pairs do not match the induced relation")
    if not is_reflexive(elements, pairs) or not is_symmetric(pairs) or not is_transitive(pairs):
        fail("partition-relation-roundtrip induced relation is not an equivalence relation")
    representative_rows = values.get("representatives")
    if not isinstance(representative_rows, list):
        fail("partition roundtrip representatives must be a list")
    block_by_id = dict(blocks)
    seen_representatives: set[str] = set()
    for index, row in enumerate(representative_rows):
        if not isinstance(row, list) or len(row) != 2:
            fail(f"partition roundtrip representatives[{index}] must be a two-element list")
        block_id = row[0]
        representative = row[1]
        require_string(f"partition roundtrip representatives[{index}][0]", block_id)
        require_string(f"partition roundtrip representatives[{index}][1]", representative)
        if block_id in seen_representatives:
            fail(f"partition roundtrip representatives repeats block {block_id!r}")
        seen_representatives.add(block_id)
        if block_id not in block_by_id:
            fail(f"partition roundtrip representatives references missing block {block_id!r}")
        if representative not in block_by_id[block_id]:
            fail("partition-relation-roundtrip representative is outside its block")
    if seen_representatives != set(block_by_id):
        fail("partition-relation-roundtrip must list one representative per block")

    bad_check = checks["bad-equivalence-rejected"]
    if bad_check["expected_result"] != "unsat" or bad_check.get("proof_status") != "checked":
        fail("bad-equivalence-rejected must be a checked unsat row")
    data = bad_check.get("data", {})
    elements, pairs = require_relation_data("bad equivalence relation", data)
    if not is_reflexive(elements, pairs):
        fail("bad-equivalence-rejected should document a reflexive relation")
    if not is_symmetric(pairs):
        fail("bad-equivalence-rejected should document a symmetric relation")
    if is_transitive(pairs):
        fail("bad-equivalence-rejected relation unexpectedly is transitive")
    counterexample = require_string_list(
        "bad equivalence transitivity_counterexample",
        data.get("transitivity_counterexample"),
    )
    if len(counterexample) != 3:
        fail("bad-equivalence-rejected transitivity_counterexample must have three elements")
    left, middle, right = counterexample
    missing_pair_value = data.get("missing_pair")
    if not isinstance(missing_pair_value, list) or len(missing_pair_value) != 2:
        fail("bad-equivalence-rejected missing_pair must be a two-element list")
    require_string("bad equivalence missing_pair[0]", missing_pair_value[0])
    require_string("bad equivalence missing_pair[1]", missing_pair_value[1])
    missing_pair = (missing_pair_value[0], missing_pair_value[1])
    if (left, middle) not in pairs or (middle, right) not in pairs:
        fail("bad-equivalence-rejected transitivity premise is not present")
    if missing_pair != (left, right):
        fail("bad-equivalence-rejected missing_pair does not match the transitivity conclusion")
    if missing_pair in pairs:
        fail("bad-equivalence-rejected missing transitivity pair is present")

    congruence = checks["qf-uf-quotient-congruence-alethe"]
    if congruence["expected_result"] != "unsat":
        fail("qf-uf-quotient-congruence-alethe must expect unsat")
    if congruence["proof_status"] != "checked":
        fail("qf-uf-quotient-congruence-alethe must be checked")
    if congruence["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-quotient-congruence-alethe must use qf_uf_congruence_alethe validation")
    data = congruence.get("data", {})
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf quotient congruence smt2_artifact", smt2_artifact)
    check_source("qf-uf quotient congruence smt2_artifact", smt2_artifact)
    require_string("qf-uf quotient congruence proof_regression", data.get("proof_regression"))
    certificate = data.get("certificate")
    require_string("qf-uf quotient congruence certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf quotient congruence certificate must document zero-trust Alethe evidence")


def require_graph_data(context: str, values: dict[str, Any]) -> tuple[list[str], list[tuple[str, str]], list[str]]:
    vertices = require_string_list(f"{context}.vertices", values.get("vertices"))
    colors = require_string_list(f"{context}.colors", values.get("colors"))
    edge_values = values.get("edges")
    if not isinstance(edge_values, list):
        fail(f"{context}.edges must be a list")
    vertex_set = set(vertices)
    edges: list[tuple[str, str]] = []
    seen_edges: set[tuple[str, str]] = set()
    for index, edge in enumerate(edge_values):
        if not isinstance(edge, list) or len(edge) != 2:
            fail(f"{context}.edges[{index}] must be a two-element list")
        left, right = edge
        require_string(f"{context}.edges[{index}][0]", left)
        require_string(f"{context}.edges[{index}][1]", right)
        if left == right:
            fail(f"{context}.edges[{index}] must not be a self-loop")
        if left not in vertex_set or right not in vertex_set:
            fail(f"{context}.edges[{index}] references a missing vertex")
        normalized = tuple(sorted((left, right)))
        if normalized in seen_edges:
            fail(f"{context}.edges repeats undirected edge {normalized}")
        seen_edges.add(normalized)
        edges.append((left, right))
    return vertices, edges, colors


def require_coloring_assignment(
    context: str,
    values: dict[str, Any],
    vertices: list[str],
    colors: list[str],
) -> dict[str, str]:
    assignment = values.get("assignment")
    if not isinstance(assignment, dict):
        fail(f"{context}.assignment must be an object")
    vertex_set = set(vertices)
    color_set = set(colors)
    if set(assignment) != vertex_set:
        missing = sorted(vertex_set - set(assignment))
        extra = sorted(set(assignment) - vertex_set)
        fail(f"{context}.assignment must cover exactly the graph vertices; missing={missing} extra={extra}")
    for vertex, color in assignment.items():
        require_string(f"{context}.assignment key", vertex)
        require_string(f"{context}.assignment[{vertex}]", color)
        if color not in color_set:
            fail(f"{context}.assignment[{vertex}] uses unknown color {color!r}")
    return assignment


def is_proper_coloring(edges: list[tuple[str, str]], assignment: dict[str, str]) -> bool:
    return all(assignment[left] != assignment[right] for left, right in edges)


def has_proper_coloring(vertices: list[str], edges: list[tuple[str, str]], colors: list[str]) -> bool:
    for color_tuple in product(colors, repeat=len(vertices)):
        assignment = dict(zip(vertices, color_tuple))
        if is_proper_coloring(edges, assignment):
            return True
    return False


def validate_graph_coloring(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    triangle = checks["triangle-3-coloring-witness"]
    if triangle["expected_result"] != "sat":
        fail("triangle-3-coloring-witness must expect sat")
    values = single_witness_values(triangle, witnesses)
    vertices, edges, colors = require_graph_data("triangle coloring", values)
    if len(colors) != 3:
        fail("triangle-3-coloring-witness must use three colors")
    assignment = require_coloring_assignment("triangle coloring", values, vertices, colors)
    if not is_proper_coloring(edges, assignment):
        fail("triangle-3-coloring witness is not a proper coloring")

    bad_edge = checks["bad-edge-coloring-rejected"]
    if bad_edge["expected_result"] != "unsat":
        fail("bad-edge-coloring-rejected must expect unsat")
    values = single_witness_values(bad_edge, witnesses)
    vertices, edges, colors = require_graph_data("bad edge coloring", values)
    assignment = require_coloring_assignment("bad edge coloring", values, vertices, colors)
    if is_proper_coloring(edges, assignment):
        fail("bad-edge-coloring-rejected witness unexpectedly is a proper coloring")

    noncolorable = checks["triangle-not-2-colorable"]
    if noncolorable["expected_result"] != "unsat":
        fail("triangle-not-2-colorable must expect unsat")
    data = noncolorable.get("data", {})
    vertices, edges, colors = require_graph_data("triangle-not-2-colorable data", data)
    if len(vertices) != 3 or len(edges) != 3 or len(colors) != 2:
        fail("triangle-not-2-colorable must use K3 with exactly two colors")
    if has_proper_coloring(vertices, edges, colors):
        fail("triangle-not-2-colorable found a proper 2-coloring unexpectedly")

    qf_bv = checks["triangle-not-2-colorable-qf-bv-drat"]
    if qf_bv["expected_result"] != "unsat":
        fail("triangle-not-2-colorable-qf-bv-drat must expect unsat")
    if qf_bv["proof_status"] != "checked":
        fail("triangle-not-2-colorable-qf-bv-drat must be checked")
    if qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("triangle-not-2-colorable-qf-bv-drat must use qf_bv_bitblast_drat validation")
    data = qf_bv.get("data", {})
    vertices, edges, colors = require_graph_data("triangle-not-2-colorable QF_BV data", data)
    if len(vertices) != 3 or len(edges) != 3 or len(colors) != 2:
        fail("triangle-not-2-colorable-qf-bv-drat must use K3 with exactly two colors")
    if has_proper_coloring(vertices, edges, colors):
        fail("triangle-not-2-colorable-qf-bv-drat found a proper 2-coloring unexpectedly")
    color_width = require_int("triangle-not-2-colorable QF_BV color_width", data.get("color_width"))
    if color_width != 1:
        fail("triangle-not-2-colorable-qf-bv-drat must use one-bit colors")
    smt2_artifact = data.get("smt2_artifact")
    require_string("triangle-not-2-colorable-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("triangle-not-2-colorable-qf-bv-drat smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("triangle-not-2-colorable-qf-bv-drat proof_regression", proof_regression)
    if "graph_coloring_triangle_not_2_colorable_emits_checked_bv_drat" not in proof_regression:
        fail("triangle-not-2-colorable-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("triangle-not-2-colorable-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("triangle-not-2-colorable-qf-bv-drat certificate must document DRAT and lowering trust")


def require_finite_graph(context: str, values: dict[str, Any]) -> tuple[list[str], list[tuple[str, str]]]:
    vertices = require_string_list(f"{context}.vertices", values.get("vertices"))
    edge_values = values.get("edges")
    if not isinstance(edge_values, list):
        fail(f"{context}.edges must be a list")
    vertex_set = set(vertices)
    edges: list[tuple[str, str]] = []
    seen_edges: set[tuple[str, str]] = set()
    for index, edge in enumerate(edge_values):
        if not isinstance(edge, list) or len(edge) != 2:
            fail(f"{context}.edges[{index}] must be a two-element list")
        left, right = edge
        require_string(f"{context}.edges[{index}][0]", left)
        require_string(f"{context}.edges[{index}][1]", right)
        if left == right:
            fail(f"{context}.edges[{index}] must not be a self-loop")
        if left not in vertex_set or right not in vertex_set:
            fail(f"{context}.edges[{index}] references a missing vertex")
        normalized = tuple(sorted((left, right)))
        if normalized in seen_edges:
            fail(f"{context}.edges repeats undirected edge {normalized}")
        seen_edges.add(normalized)
        edges.append((left, right))
    return vertices, edges


def require_graph_vertex(context: str, value: Any, vertices: list[str]) -> str:
    require_string(context, value)
    if value not in set(vertices):
        fail(f"{context} references a missing vertex")
    return value


def require_graph_path(context: str, value: Any, vertices: list[str]) -> list[str]:
    path = require_string_list(context, value)
    vertex_set = set(vertices)
    for vertex in path:
        if vertex not in vertex_set:
            fail(f"{context} references missing vertex {vertex!r}")
    return path


def graph_edge_set(edges: list[tuple[str, str]]) -> set[tuple[str, str]]:
    return {tuple(sorted(edge)) for edge in edges}


def graph_adjacency(vertices: list[str], edges: list[tuple[str, str]]) -> dict[str, list[str]]:
    order = {vertex: index for index, vertex in enumerate(vertices)}
    adjacency = {vertex: [] for vertex in vertices}
    for left, right in edges:
        adjacency[left].append(right)
        adjacency[right].append(left)
    for vertex in vertices:
        adjacency[vertex].sort(key=lambda item: order[item])
    return adjacency


def shortest_distances(
    vertices: list[str],
    edges: list[tuple[str, str]],
    source: str,
) -> dict[str, int]:
    adjacency = graph_adjacency(vertices, edges)
    distances = {source: 0}
    queue: deque[str] = deque([source])
    while queue:
        vertex = queue.popleft()
        for neighbor in adjacency[vertex]:
            if neighbor not in distances:
                distances[neighbor] = distances[vertex] + 1
                queue.append(neighbor)
    return distances


def expected_bounded_reachability_dimacs(
    vertices: list[str],
    edges: list[tuple[str, str]],
    source: str,
    target: str,
    depth_bound: int,
    final_reachable: bool,
) -> list[list[str]]:
    adjacency = graph_adjacency(vertices, edges)
    expected_dimacs: list[list[str]] = []
    vertex_count = len(vertices)
    for vertex_index, vertex in enumerate(vertices):
        variable = vertex_index + 1
        expected_dimacs.append([str(variable if vertex == source else -variable)])
    for depth in range(1, depth_bound + 1):
        for vertex_index, vertex in enumerate(vertices):
            current = depth * vertex_count + vertex_index + 1
            previous_sources = [
                (depth - 1) * vertex_count + vertices.index(previous_vertex) + 1
                for previous_vertex in [vertex, *adjacency[vertex]]
            ]
            for previous_source in previous_sources:
                expected_dimacs.append([f"-{previous_source}", str(current)])
            expected_dimacs.append(
                [
                    f"-{current}",
                    *[str(previous_source) for previous_source in previous_sources],
                ]
            )
    target_variable = depth_bound * vertex_count + vertices.index(target) + 1
    expected_dimacs.append([str(target_variable if final_reachable else -target_variable)])
    return expected_dimacs


def deterministic_dfs_order(vertices: list[str], edges: list[tuple[str, str]], start: str) -> list[str]:
    adjacency = graph_adjacency(vertices, edges)
    seen: set[str] = set()
    order: list[str] = []

    def visit(vertex: str) -> None:
        seen.add(vertex)
        order.append(vertex)
        for neighbor in adjacency[vertex]:
            if neighbor not in seen:
                visit(neighbor)

    visit(start)
    return order


def bfs_pop_order_until_target(
    vertices: list[str],
    edges: list[tuple[str, str]],
    source: str,
    target: str,
) -> list[str]:
    adjacency = graph_adjacency(vertices, edges)
    seen = {source}
    queue: deque[str] = deque([source])
    order: list[str] = []
    while queue:
        vertex = queue.popleft()
        order.append(vertex)
        if vertex == target:
            return order
        for neighbor in adjacency[vertex]:
            if neighbor not in seen:
                seen.add(neighbor)
                queue.append(neighbor)
    return order


def dfs_order_until_target(
    vertices: list[str],
    edges: list[tuple[str, str]],
    source: str,
    target: str,
) -> list[str]:
    order = deterministic_dfs_order(vertices, edges, source)
    if target not in order:
        return order
    return order[: order.index(target) + 1]


def shortcut_tail_graph(tail_length: int) -> tuple[list[str], list[tuple[str, str]]]:
    if tail_length <= 0:
        fail("shortcut-tail graph tail_length must be positive")
    vertices = ["s"] + [f"a{index}" for index in range(1, tail_length + 1)] + ["t"]
    edges = [("s", "a1"), ("s", "t")]
    edges.extend((f"a{index}", f"a{index + 1}") for index in range(1, tail_length))
    return vertices, edges


def path_is_valid(path: list[str], edges: list[tuple[str, str]]) -> bool:
    edge_set = graph_edge_set(edges)
    return all(tuple(sorted((left, right))) in edge_set for left, right in zip(path, path[1:]))


def require_distance_map(context: str, value: Any, vertices: list[str]) -> dict[str, int]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    vertex_set = set(vertices)
    if set(value) != vertex_set:
        missing = sorted(vertex_set - set(value))
        extra = sorted(set(value) - vertex_set)
        fail(f"{context} must cover exactly the graph vertices; missing={missing} extra={extra}")
    distances: dict[str, int] = {}
    for vertex in vertices:
        distance = require_int(f"{context}.{vertex}", value[vertex])
        if distance < 0:
            fail(f"{context}.{vertex} must be nonnegative")
        distances[vertex] = distance
    return distances


def require_cut_edges(
    context: str,
    value: Any,
    vertices: list[str],
    graph_edges: list[tuple[str, str]],
) -> list[tuple[str, str]]:
    cut_edges = require_finite_graph(context, {"vertices": vertices, "edges": value})[1]
    graph_edge_set_value = graph_edge_set(graph_edges)
    for edge in cut_edges:
        if tuple(sorted(edge)) not in graph_edge_set_value:
            fail(f"{context} contains an edge that is not in the graph")
    return cut_edges


def remove_edges(
    edges: list[tuple[str, str]],
    removed: list[tuple[str, str]],
) -> list[tuple[str, str]]:
    removed_set = graph_edge_set(removed)
    return [edge for edge in edges if tuple(sorted(edge)) not in removed_set]


def validate_graph_reachability(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    bfs = checks["bfs-shortest-distance-witness"]
    if bfs["expected_result"] != "sat" or bfs.get("proof_status") != "checked":
        fail("bfs-shortest-distance-witness must be a checked sat row")
    values = single_witness_values(bfs, witnesses)
    vertices, edges = require_finite_graph("bfs shortest path", values)
    source = require_graph_vertex("bfs shortest path source", values.get("source"), vertices)
    target = require_graph_vertex("bfs shortest path target", values.get("target"), vertices)
    path = require_graph_path("bfs shortest path path", values.get("path"), vertices)
    if path[0] != source or path[-1] != target:
        fail("bfs-shortest-distance-witness path endpoints do not match source/target")
    if not path_is_valid(path, edges):
        fail("bfs-shortest-distance-witness path contains a non-edge")
    claimed_distance = require_int("bfs shortest path distance", values.get("distance"))
    if claimed_distance < 0:
        fail("bfs shortest path distance must be nonnegative")
    if len(path) - 1 != claimed_distance:
        fail("bfs-shortest-distance-witness distance does not match path length")
    computed_distances = shortest_distances(vertices, edges, source)
    if computed_distances.get(target) != claimed_distance:
        fail("bfs-shortest-distance-witness distance is not shortest")
    listed_distances = require_distance_map("bfs shortest path distances", values.get("distances"), vertices)
    if listed_distances != computed_distances:
        fail("bfs-shortest-distance-witness distance map does not match BFS")

    dfs = checks["dfs-long-tail-order-replay"]
    if dfs["expected_result"] != "sat" or dfs.get("proof_status") != "checked":
        fail("dfs-long-tail-order-replay must be a checked sat row")
    values = single_witness_values(dfs, witnesses)
    vertices, edges = require_finite_graph("dfs long-tail order", values)
    start = require_graph_vertex("dfs long-tail start", values.get("start"), vertices)
    target = require_graph_vertex("dfs long-tail target", values.get("target"), vertices)
    order = require_string_list("dfs long-tail order", values.get("order"))
    expected_order = deterministic_dfs_order(vertices, edges, start)
    if order != expected_order:
        fail("dfs-long-tail-order-replay order does not match deterministic DFS")
    if target not in order:
        fail("dfs-long-tail-order-replay target is not reached")
    target_index = require_int("dfs target_discovery_index", values.get("target_discovery_index"))
    if target_index != order.index(target):
        fail("dfs-long-tail-order-replay target discovery index is wrong")
    distances = shortest_distances(vertices, edges, start)
    if target not in distances:
        fail("dfs-long-tail-order-replay target must be BFS-reachable")
    if target_index <= distances[target]:
        fail("dfs-long-tail-order-replay must witness DFS doing more work than BFS distance")

    unreachable = checks["disconnected-no-path"]
    if unreachable["expected_result"] != "unsat" or unreachable.get("proof_status") != "checked":
        fail("disconnected-no-path must be a checked unsat row")
    data = unreachable.get("data", {})
    vertices, edges = require_finite_graph("disconnected no path", data)
    source = require_graph_vertex("disconnected source", data.get("source"), vertices)
    target = require_graph_vertex("disconnected target", data.get("target"), vertices)
    if target in shortest_distances(vertices, edges, source):
        fail("disconnected-no-path unexpectedly has a source-to-target path")
    depth_bound = require_int("disconnected-no-path depth_bound", data.get("depth_bound"))
    if vertices != ["s", "a", "b", "t"] or edges != [("s", "a"), ("b", "t")]:
        fail("disconnected-no-path DIMACS artifact is fixed to the two-component s-a/b-t graph")
    if source != "s" or target != "t" or depth_bound != len(vertices) - 1:
        fail("disconnected-no-path DIMACS artifact is fixed to s, t, and depth bound 3")
    require_dimacs_artifact(
        "disconnected-no-path",
        data.get("cnf_artifact"),
        "p cnf 16 41",
        expected_bounded_reachability_dimacs(
            vertices,
            edges,
            source,
            target,
            depth_bound,
            final_reachable=True,
        ),
    )
    proof_regression = data.get("proof_regression")
    require_string("disconnected-no-path proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::graph_reachability_disconnected_no_path" not in proof_regression:
        fail("disconnected-no-path proof_regression must name the Boolean resource test")
    certificate = data.get("certificate")
    require_string("disconnected-no-path certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("disconnected-no-path certificate must document DRAT/LRAT independent checking")

    cut = checks["edge-cut-separates"]
    if cut["expected_result"] != "sat" or cut.get("proof_status") != "checked":
        fail("edge-cut-separates must be a checked sat row")
    data = cut.get("data", {})
    vertices, edges = require_finite_graph("edge cut", data)
    source = require_graph_vertex("edge cut source", data.get("source"), vertices)
    target = require_graph_vertex("edge cut target", data.get("target"), vertices)
    cut_edges = require_cut_edges("edge cut cut_edges", data.get("cut_edges"), vertices, edges)
    if target not in shortest_distances(vertices, edges, source):
        fail("edge-cut-separates original graph must have an s-t path")
    if target in shortest_distances(vertices, remove_edges(edges, cut_edges), source):
        fail("edge-cut-separates cut edges do not separate source and target")


def require_positive_runtime_int(context: str, value: Any) -> int:
    integer = require_int(context, value)
    if integer <= 0:
        fail(f"{context} must be positive")
    return integer


def validate_graph_search_runtime(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    bfs = checks["bfs-nearest-target-witness"]
    if bfs["expected_result"] != "sat" or bfs.get("proof_status") != "checked":
        fail("bfs-nearest-target-witness must be a checked sat row")
    values = single_witness_values(bfs, witnesses)
    vertices, edges = require_finite_graph("BFS runtime graph", values)
    source = require_graph_vertex("BFS runtime source", values.get("source"), vertices)
    target = require_graph_vertex("BFS runtime target", values.get("target"), vertices)
    shortest_distance = require_int("BFS runtime shortest_distance", values.get("shortest_distance"))
    if shortest_distance < 0:
        fail("BFS runtime shortest_distance must be nonnegative")
    distances = shortest_distances(vertices, edges, source)
    if distances.get(target) != shortest_distance:
        fail("bfs-nearest-target-witness shortest_distance is incorrect")
    listed_bfs_order = require_string_list("BFS order until target", values.get("bfs_order_until_target"))
    computed_bfs_order = bfs_pop_order_until_target(vertices, edges, source, target)
    if computed_bfs_order != listed_bfs_order:
        fail("bfs-nearest-target-witness BFS order is incorrect")
    bfs_visits = require_positive_runtime_int(
        "BFS visited_until_target",
        values.get("bfs_visited_until_target"),
    )
    if len(computed_bfs_order) != bfs_visits:
        fail("bfs-nearest-target-witness visited count does not match BFS order")
    if not computed_bfs_order or computed_bfs_order[-1] != target:
        fail("bfs-nearest-target-witness BFS order must end at the target")

    dfs = checks["dfs-long-tail-target-witness"]
    if dfs["expected_result"] != "sat" or dfs.get("proof_status") != "checked":
        fail("dfs-long-tail-target-witness must be a checked sat row")
    values = single_witness_values(dfs, witnesses)
    vertices, edges = require_finite_graph("DFS runtime graph", values)
    source = require_graph_vertex("DFS runtime source", values.get("source"), vertices)
    target = require_graph_vertex("DFS runtime target", values.get("target"), vertices)
    listed_dfs_order = require_string_list("DFS order until target", values.get("dfs_order_until_target"))
    computed_dfs_order = dfs_order_until_target(vertices, edges, source, target)
    if computed_dfs_order != listed_dfs_order:
        fail("dfs-long-tail-target-witness DFS order is incorrect")
    dfs_visits = require_positive_runtime_int(
        "DFS visited_until_target",
        values.get("dfs_visited_until_target"),
    )
    if len(computed_dfs_order) != dfs_visits:
        fail("dfs-long-tail-target-witness visited count does not match DFS order")
    bfs_visits = require_positive_runtime_int(
        "DFS row BFS visited_until_target",
        values.get("bfs_visited_until_target"),
    )
    computed_bfs_order = bfs_pop_order_until_target(vertices, edges, source, target)
    if len(computed_bfs_order) != bfs_visits:
        fail("dfs-long-tail-target-witness BFS comparison count is incorrect")
    if dfs_visits <= bfs_visits:
        fail("dfs-long-tail-target-witness must witness DFS visiting more vertices than BFS")
    if not computed_dfs_order or computed_dfs_order[-1] != target:
        fail("dfs-long-tail-target-witness DFS order must end at the target")

    family = checks["shortcut-tail-family-costs"]
    if family["expected_result"] != "sat" or family.get("proof_status") != "checked":
        fail("shortcut-tail-family-costs must be a checked sat row")
    values = single_witness_values(family, witnesses)
    rows = values.get("rows")
    if not isinstance(rows, list) or not rows:
        fail("shortcut-tail-family-costs rows must be a non-empty list")
    seen_lengths: set[int] = set()
    for index, row in enumerate(rows):
        if not isinstance(row, dict):
            fail(f"shortcut-tail-family-costs rows[{index}] must be an object")
        tail_length = require_positive_runtime_int(
            f"shortcut-tail-family-costs rows[{index}].tail_length",
            row.get("tail_length"),
        )
        if tail_length in seen_lengths:
            fail("shortcut-tail-family-costs repeats a tail_length")
        seen_lengths.add(tail_length)
        vertices, edges = shortcut_tail_graph(tail_length)
        vertex_count = require_positive_runtime_int(
            f"shortcut-tail-family-costs rows[{index}].vertex_count",
            row.get("vertex_count"),
        )
        shortest_distance = require_int(
            f"shortcut-tail-family-costs rows[{index}].shortest_distance",
            row.get("shortest_distance"),
        )
        bfs_visits = require_positive_runtime_int(
            f"shortcut-tail-family-costs rows[{index}].bfs_visited_until_target",
            row.get("bfs_visited_until_target"),
        )
        dfs_visits = require_positive_runtime_int(
            f"shortcut-tail-family-costs rows[{index}].dfs_visited_until_target",
            row.get("dfs_visited_until_target"),
        )
        if len(vertices) != vertex_count:
            fail("shortcut-tail-family-costs vertex_count is incorrect")
        distances = shortest_distances(vertices, edges, "s")
        if distances.get("t") != shortest_distance:
            fail("shortcut-tail-family-costs shortest_distance is incorrect")
        if len(bfs_pop_order_until_target(vertices, edges, "s", "t")) != bfs_visits:
            fail("shortcut-tail-family-costs BFS visit count is incorrect")
        if len(dfs_order_until_target(vertices, edges, "s", "t")) != dfs_visits:
            fail("shortcut-tail-family-costs DFS visit count is incorrect")
        if dfs_visits != tail_length + 2:
            fail("shortcut-tail-family-costs DFS visit count must equal tail_length + 2")

    bad = checks["bad-dfs-cost-bound-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-dfs-cost-bound-rejected must be a checked unsat row")
    data = bad.get("data", {})
    tail_length = require_positive_runtime_int("bad DFS tail_length", data.get("tail_length"))
    vertices, edges = shortcut_tail_graph(tail_length)
    source = require_graph_vertex("bad DFS source", data.get("source"), vertices)
    target = require_graph_vertex("bad DFS target", data.get("target"), vertices)
    claimed_upper_bound = require_positive_runtime_int(
        "bad DFS claimed_upper_bound",
        data.get("claimed_upper_bound"),
    )
    actual_dfs = require_positive_runtime_int(
        "bad DFS actual_dfs_visited_until_target",
        data.get("actual_dfs_visited_until_target"),
    )
    actual_bfs = require_positive_runtime_int(
        "bad DFS actual_bfs_visited_until_target",
        data.get("actual_bfs_visited_until_target"),
    )
    if len(dfs_order_until_target(vertices, edges, source, target)) != actual_dfs:
        fail("bad-dfs-cost-bound-rejected actual DFS count is incorrect")
    if len(bfs_pop_order_until_target(vertices, edges, source, target)) != actual_bfs:
        fail("bad-dfs-cost-bound-rejected actual BFS count is incorrect")
    if actual_dfs <= claimed_upper_bound:
        fail("bad-dfs-cost-bound-rejected claimed upper bound unexpectedly holds")
    if (
        tail_length != 4
        or source != "s"
        or target != "t"
        or claimed_upper_bound != 3
        or actual_dfs != 6
        or actual_bfs != 3
    ):
        fail("bad-dfs-cost-bound-rejected SMT-LIB promotion is fixed to the length-four shortcut-tail graph")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad DFS smt2_artifact", smt2_artifact)
    check_source("bad DFS smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/graph-search-runtime-v0/smt2/bad-dfs-cost-bound-lia-conflict.smt2":
        fail("bad-dfs-cost-bound-rejected smt2_artifact must name the checked LIA conflict artifact")
    proof_regression = data.get("proof_regression")
    require_string("bad DFS proof_regression", proof_regression)
    if "math_resource_lia_routes.rs::graph_search_bad_dfs_cost_bound_emits_checked_lia_evidence" not in proof_regression:
        fail("bad-dfs-cost-bound-rejected proof_regression must name the LIA resource test")
    certificate = data.get("certificate")
    require_string("bad DFS certificate", certificate)
    if "QF_LIA arithmetic evidence" not in certificate or "independently" not in certificate:
        fail("bad-dfs-cost-bound-rejected certificate must document independent checked LIA arithmetic evidence")

    horizon = checks["asymptotic-search-runtime-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("asymptotic-search-runtime-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("asymptotic-search-runtime-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("asymptotic search target_theorem_shape", data.get("target_theorem_shape"))
    require_string("asymptotic search future_checker", data.get("future_checker"))


def require_graph_edge_list(
    context: str,
    value: Any,
    vertices: list[str],
    graph_edges: list[tuple[str, str]],
) -> list[tuple[str, str]]:
    if not isinstance(value, list):
        fail(f"{context} must be a list")
    vertex_set = set(vertices)
    available_edges = graph_edge_set(graph_edges)
    parsed_edges: list[tuple[str, str]] = []
    seen_edges: set[tuple[str, str]] = set()
    for index, edge in enumerate(value):
        if not isinstance(edge, list) or len(edge) != 2:
            fail(f"{context}[{index}] must be a two-element list")
        left, right = edge
        require_string(f"{context}[{index}][0]", left)
        require_string(f"{context}[{index}][1]", right)
        if left == right:
            fail(f"{context}[{index}] must not be a self-loop")
        if left not in vertex_set or right not in vertex_set:
            fail(f"{context}[{index}] references a missing vertex")
        normalized = tuple(sorted((left, right)))
        if normalized not in available_edges:
            fail(f"{context}[{index}] is not an edge of the graph")
        if normalized in seen_edges:
            fail(f"{context} repeats edge {normalized}")
        seen_edges.add(normalized)
        parsed_edges.append((left, right))
    return parsed_edges


def is_matching(edge_list: list[tuple[str, str]]) -> bool:
    used: set[str] = set()
    for left, right in edge_list:
        if left in used or right in used:
            return False
        used.add(left)
        used.add(right)
    return True


def covered_vertices(edge_list: list[tuple[str, str]]) -> set[str]:
    covered: set[str] = set()
    for left, right in edge_list:
        covered.add(left)
        covered.add(right)
    return covered


def enumerate_matchings(edges: list[tuple[str, str]]) -> list[list[tuple[str, str]]]:
    matchings: list[list[tuple[str, str]]] = []

    def visit(index: int, current: list[tuple[str, str]], used: set[str]) -> None:
        if index == len(edges):
            matchings.append(list(current))
            return
        visit(index + 1, current, used)
        left, right = edges[index]
        if left not in used and right not in used:
            current.append((left, right))
            visit(index + 1, current, used | {left, right})
            current.pop()

    visit(0, [], set())
    return matchings


def maximum_matching_size(edges: list[tuple[str, str]]) -> int:
    return max(len(matching) for matching in enumerate_matchings(edges))


def has_perfect_matching(vertices: list[str], edges: list[tuple[str, str]]) -> bool:
    vertex_set = set(vertices)
    return any(covered_vertices(matching) == vertex_set for matching in enumerate_matchings(edges))


def normalized_edge_set(edges: list[tuple[str, str]]) -> set[tuple[str, str]]:
    return {tuple(sorted(edge)) for edge in edges}


def validate_augmenting_path(
    context: str,
    graph_edges: list[tuple[str, str]],
    current_matching: list[tuple[str, str]],
    path: list[str],
    improved_matching: list[tuple[str, str]],
) -> None:
    if not is_matching(current_matching):
        fail(f"{context} current matching is not a matching")
    if not is_matching(improved_matching):
        fail(f"{context} improved matching is not a matching")
    if len(path) < 2:
        fail(f"{context} augmenting path must contain at least two vertices")
    if len(set(path)) != len(path):
        fail(f"{context} augmenting path must be simple")
    if not path_is_valid(path, graph_edges):
        fail(f"{context} augmenting path contains a non-edge")

    current_set = normalized_edge_set(current_matching)
    path_edges = [
        tuple(sorted((left, right)))
        for left, right in zip(path, path[1:])
    ]
    if len(path_edges) % 2 == 0:
        fail(f"{context} augmenting path must have odd edge length")
    current_covered = covered_vertices(current_matching)
    if path[0] in current_covered or path[-1] in current_covered:
        fail(f"{context} augmenting path endpoints must be unmatched")
    for index, edge in enumerate(path_edges):
        edge_is_matched = edge in current_set
        if index % 2 == 0 and edge_is_matched:
            fail(f"{context} even path edge {index} must be unmatched")
        if index % 2 == 1 and not edge_is_matched:
            fail(f"{context} odd path edge {index} must be matched")
    flipped = current_set ^ set(path_edges)
    if flipped != normalized_edge_set(improved_matching):
        fail(f"{context} improved matching is not the path flip")
    if len(improved_matching) != len(current_matching) + 1:
        fail(f"{context} improved matching must increase size by one")
    if not normalized_edge_set(improved_matching).issubset(graph_edge_set(graph_edges)):
        fail(f"{context} improved matching contains an edge outside the graph")


def validate_graph_matching(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    size_two = checks["matching-size-two-witness"]
    if size_two["expected_result"] != "sat" or size_two.get("proof_status") != "checked":
        fail("matching-size-two-witness must be a checked sat row")
    values = single_witness_values(size_two, witnesses)
    vertices, edges = require_finite_graph("matching-size-two", values)
    matching = require_graph_edge_list("matching-size-two.matching", values.get("matching"), vertices, edges)
    if not is_matching(matching):
        fail("matching-size-two-witness listed edges are not a matching")
    size = require_int("matching-size-two.size", values.get("size"))
    if len(matching) != size:
        fail("matching-size-two-witness size does not match listed matching")
    if size != maximum_matching_size(edges):
        fail("matching-size-two-witness is not maximum for the graph")
    if covered_vertices(matching) != set(vertices):
        fail("matching-size-two-witness should cover every vertex in the path graph")

    overlapping = checks["overlapping-matching-rejected"]
    if overlapping["expected_result"] != "unsat" or overlapping.get("proof_status") != "checked":
        fail("overlapping-matching-rejected must be a checked unsat row")
    values = single_witness_values(overlapping, witnesses)
    vertices, edges = require_finite_graph("overlapping matching", values)
    matching = require_graph_edge_list("overlapping matching.matching", values.get("matching"), vertices, edges)
    if is_matching(matching):
        fail("overlapping-matching-rejected unexpectedly is a valid matching")

    augmenting = checks["augmenting-path-improves"]
    if augmenting["expected_result"] != "sat" or augmenting.get("proof_status") != "checked":
        fail("augmenting-path-improves must be a checked sat row")
    values = single_witness_values(augmenting, witnesses)
    vertices, edges = require_finite_graph("augmenting path", values)
    current_matching = require_graph_edge_list(
        "augmenting path.current_matching",
        values.get("current_matching"),
        vertices,
        edges,
    )
    improved_matching = require_graph_edge_list(
        "augmenting path.improved_matching",
        values.get("improved_matching"),
        vertices,
        edges,
    )
    path = require_graph_path("augmenting path.path", values.get("augmenting_path"), vertices)
    validate_augmenting_path("augmenting-path-improves", edges, current_matching, path, improved_matching)

    no_perfect = checks["triangle-no-perfect-matching"]
    if no_perfect["expected_result"] != "unsat" or no_perfect.get("proof_status") != "checked":
        fail("triangle-no-perfect-matching must be a checked unsat row")
    data = no_perfect.get("data", {})
    vertices, edges = require_finite_graph("triangle no perfect matching", data)
    maximum_size = require_int("triangle no perfect matching maximum_size", data.get("maximum_size"))
    if maximum_size != maximum_matching_size(edges):
        fail("triangle-no-perfect-matching maximum_size does not match enumeration")
    if has_perfect_matching(vertices, edges):
        fail("triangle-no-perfect-matching unexpectedly has a perfect matching")
    if vertices != ["a", "b", "c"] or edges != [("a", "b"), ("b", "c"), ("a", "c")]:
        fail("triangle-no-perfect-matching DIMACS artifact is fixed to K3")
    require_dimacs_artifact(
        "triangle-no-perfect-matching",
        data.get("cnf_artifact"),
        "p cnf 3 6",
        [["1", "3"], ["1", "2"], ["2", "3"], ["-1", "-3"], ["-1", "-2"], ["-2", "-3"]],
    )
    proof_regression = data.get("proof_regression")
    require_string("triangle-no-perfect-matching proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::graph_matching_triangle_no_perfect_matching" not in proof_regression:
        fail("triangle-no-perfect-matching proof_regression must name the Boolean resource test")
    certificate = data.get("certificate")
    require_string("triangle-no-perfect-matching certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("triangle-no-perfect-matching certificate must document DRAT/LRAT independent checking")


def require_directed_graph(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], list[tuple[str, str]]]:
    vertices = require_string_list(f"{context}.vertices", values.get("vertices"))
    edge_values = values.get("directed_edges")
    if not isinstance(edge_values, list):
        fail(f"{context}.directed_edges must be a list")
    vertex_set = set(vertices)
    directed_edges: list[tuple[str, str]] = []
    seen_edges: set[tuple[str, str]] = set()
    for index, edge in enumerate(edge_values):
        if not isinstance(edge, list) or len(edge) != 2:
            fail(f"{context}.directed_edges[{index}] must be a two-element list")
        parent, child = edge
        require_string(f"{context}.directed_edges[{index}][0]", parent)
        require_string(f"{context}.directed_edges[{index}][1]", child)
        if parent == child:
            fail(f"{context}.directed_edges[{index}] must not be a self-loop")
        if parent not in vertex_set or child not in vertex_set:
            fail(f"{context}.directed_edges[{index}] references a missing vertex")
        directed_edge = (parent, child)
        if directed_edge in seen_edges:
            fail(f"{context}.directed_edges repeats edge {directed_edge}")
        seen_edges.add(directed_edge)
        directed_edges.append(directed_edge)
    return vertices, directed_edges


def require_directed_acyclic_graph(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], list[tuple[str, str]]]:
    vertices, directed_edges = require_directed_graph(context, values)
    if not is_dag(vertices, directed_edges):
        fail(f"{context} must be acyclic")
    return vertices, directed_edges


def is_dag(vertices: list[str], directed_edges: list[tuple[str, str]]) -> bool:
    indegree = {vertex: 0 for vertex in vertices}
    children = {vertex: [] for vertex in vertices}
    for parent, child in directed_edges:
        children[parent].append(child)
        indegree[child] += 1
    queue = deque([vertex for vertex in vertices if indegree[vertex] == 0])
    visited = 0
    while queue:
        vertex = queue.popleft()
        visited += 1
        for child in children[vertex]:
            indegree[child] -= 1
            if indegree[child] == 0:
                queue.append(child)
    return visited == len(vertices)


def require_topological_order(context: str, value: Any, vertices: list[str]) -> list[str]:
    order = require_string_list(context, value)
    vertex_set = set(vertices)
    if set(order) != vertex_set or len(order) != len(vertices):
        missing = sorted(vertex_set - set(order))
        extra = sorted(set(order) - vertex_set)
        fail(f"{context} must list every vertex exactly once; missing={missing} extra={extra}")
    return order


def topological_order_violations(
    order: list[str],
    directed_edges: list[tuple[str, str]],
) -> list[tuple[str, str]]:
    positions = {vertex: index for index, vertex in enumerate(order)}
    return [
        (parent, child)
        for parent, child in directed_edges
        if positions[parent] >= positions[child]
    ]


def require_directed_cycle(
    context: str,
    value: Any,
    vertices: list[str],
    directed_edges: list[tuple[str, str]],
) -> list[str]:
    if not isinstance(value, list):
        fail(f"{context} must be a list")
    cycle: list[str] = []
    for index, item in enumerate(value):
        require_string(f"{context}[{index}]", item)
        cycle.append(item)
    if len(cycle) < 4:
        fail(f"{context} must contain at least three edges and repeat the start vertex")
    if cycle[0] != cycle[-1]:
        fail(f"{context} must repeat its start vertex at the end")
    internal = cycle[:-1]
    if len(set(internal)) != len(internal):
        fail(f"{context} must be simple before the repeated start vertex")
    vertex_set = set(vertices)
    for vertex in internal:
        if vertex not in vertex_set:
            fail(f"{context} references missing vertex {vertex!r}")
    edge_set = directed_edge_set(directed_edges)
    for parent, child in zip(cycle, cycle[1:]):
        if (parent, child) not in edge_set:
            fail(f"{context} uses missing directed edge {(parent, child)}")
    return cycle


def validate_finite_dag_topological_order(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    topo = checks["topological-order-witness"]
    if topo["expected_result"] != "sat" or topo.get("proof_status") != "checked":
        fail("topological-order-witness must be a checked sat row")
    values = single_witness_values(topo, witnesses)
    vertices, directed_edges = require_directed_acyclic_graph("topological-order-witness", values)
    order = require_topological_order("topological-order-witness.order", values.get("order"), vertices)
    if topological_order_violations(order, directed_edges):
        fail("topological-order-witness order violates a directed edge")

    swap = checks["independent-swap-order-witness"]
    if swap["expected_result"] != "sat" or swap.get("proof_status") != "checked":
        fail("independent-swap-order-witness must be a checked sat row")
    values = single_witness_values(swap, witnesses)
    vertices, directed_edges = require_directed_acyclic_graph("independent-swap-order-witness", values)
    order = require_topological_order("independent-swap-order-witness.order", values.get("order"), vertices)
    if topological_order_violations(order, directed_edges):
        fail("independent-swap-order-witness order violates a directed edge")

    bad_order = checks["bad-order-rejected"]
    if bad_order["expected_result"] != "unsat" or bad_order.get("proof_status") != "checked":
        fail("bad-order-rejected must be a checked unsat row")
    data = bad_order.get("data", {})
    vertices, directed_edges = require_directed_acyclic_graph("bad-order-rejected", data)
    order = require_topological_order("bad-order-rejected.order", data.get("order"), vertices)
    violations = topological_order_violations(order, directed_edges)
    if not violations:
        fail("bad-order-rejected must list an order that violates an edge")
    listed_violation = data.get("violating_edge")
    if not isinstance(listed_violation, list) or len(listed_violation) != 2:
        fail("bad-order-rejected.violating_edge must be a two-element list")
    parent, child = listed_violation
    require_string("bad-order-rejected.violating_edge[0]", parent)
    require_string("bad-order-rejected.violating_edge[1]", child)
    if (parent, child) not in violations:
        fail("bad-order-rejected.violating_edge is not violated by the listed order")

    cycle = checks["cycle-obstruction-rejected"]
    if cycle["expected_result"] != "unsat" or cycle.get("proof_status") != "checked":
        fail("cycle-obstruction-rejected must be a checked unsat row")
    data = cycle.get("data", {})
    vertices, directed_edges = require_directed_graph("cycle-obstruction-rejected", data)
    if is_dag(vertices, directed_edges):
        fail("cycle-obstruction-rejected graph must contain a directed cycle")
    order = require_topological_order("cycle-obstruction-rejected.order", data.get("order"), vertices)
    if not topological_order_violations(order, directed_edges):
        fail("cycle-obstruction-rejected must violate at least one directed edge")
    require_directed_cycle(
        "cycle-obstruction-rejected.cycle",
        data.get("cycle"),
        vertices,
        directed_edges,
    )

    horizon = checks["topological-sort-theorem-lean-horizon"]
    if horizon["expected_result"] != "not-run" or horizon.get("proof_status") != "lean-horizon":
        fail("topological-sort-theorem-lean-horizon must be a Lean-horizon not-run row")


def require_vertex_set(context: str, value: Any, vertices: list[str], *, nonempty: bool = False) -> set[str]:
    items = require_string_list(context, value, nonempty=nonempty)
    vertex_set = set(vertices)
    for item in items:
        if item not in vertex_set:
            fail(f"{context} references missing vertex {item!r}")
    return set(items)


def directed_edge_set(directed_edges: list[tuple[str, str]]) -> set[tuple[str, str]]:
    return set(directed_edges)


def dag_skeleton_edges(directed_edges: list[tuple[str, str]]) -> list[tuple[str, str]]:
    skeleton: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for parent, child in directed_edges:
        edge = tuple(sorted((parent, child)))
        if edge not in seen:
            seen.add(edge)
            skeleton.append((parent, child))
    return skeleton


def dag_descendants(vertices: list[str], directed_edges: list[tuple[str, str]]) -> dict[str, set[str]]:
    children = {vertex: [] for vertex in vertices}
    for parent, child in directed_edges:
        children[parent].append(child)
    descendants: dict[str, set[str]] = {}
    for root in vertices:
        seen: set[str] = set()
        stack = list(children[root])
        while stack:
            vertex = stack.pop()
            if vertex in seen:
                continue
            seen.add(vertex)
            stack.extend(children[vertex])
        descendants[root] = seen
    return descendants


def is_collider(prev_vertex: str, middle: str, next_vertex: str, edge_set: set[tuple[str, str]]) -> bool:
    return (prev_vertex, middle) in edge_set and (next_vertex, middle) in edge_set


def dag_path_is_valid(path: list[str], directed_edges: list[tuple[str, str]]) -> bool:
    skeleton = graph_edge_set(dag_skeleton_edges(directed_edges))
    return all(tuple(sorted((left, right))) in skeleton for left, right in zip(path, path[1:]))


def active_dag_path(
    vertices: list[str],
    directed_edges: list[tuple[str, str]],
    path: list[str],
    conditioned: set[str],
) -> bool:
    if len(path) < 2:
        fail("d-separation path must contain at least two vertices")
    if len(set(path)) != len(path):
        fail("d-separation path must be simple")
    if not all(vertex in set(vertices) for vertex in path):
        fail("d-separation path references a missing vertex")
    if not dag_path_is_valid(path, directed_edges):
        fail("d-separation path contains a non-edge")
    edge_set = directed_edge_set(directed_edges)
    descendants = dag_descendants(vertices, directed_edges)
    for prev_vertex, middle, next_vertex in zip(path, path[1:], path[2:]):
        if is_collider(prev_vertex, middle, next_vertex, edge_set):
            if middle not in conditioned and descendants[middle].isdisjoint(conditioned):
                return False
        elif middle in conditioned:
            return False
    return True


def enumerate_simple_skeleton_paths(
    vertices: list[str],
    directed_edges: list[tuple[str, str]],
    source: str,
    target: str,
) -> list[list[str]]:
    adjacency = graph_adjacency(vertices, dag_skeleton_edges(directed_edges))
    paths: list[list[str]] = []

    def visit(vertex: str, path: list[str], seen: set[str]) -> None:
        if vertex == target:
            paths.append(list(path))
            return
        for neighbor in adjacency[vertex]:
            if neighbor in seen:
                continue
            path.append(neighbor)
            visit(neighbor, path, seen | {neighbor})
            path.pop()

    visit(source, [source], {source})
    return paths


def d_connected(
    vertices: list[str],
    directed_edges: list[tuple[str, str]],
    source: str,
    target: str,
    conditioned: set[str],
) -> bool:
    return any(
        active_dag_path(vertices, directed_edges, path, conditioned)
        for path in enumerate_simple_skeleton_paths(vertices, directed_edges, source, target)
    )


def validate_active_path_witness(context: str, values: dict[str, Any]) -> None:
    vertices, directed_edges = require_directed_acyclic_graph(context, values)
    source = require_graph_vertex(f"{context}.source", values.get("source"), vertices)
    target = require_graph_vertex(f"{context}.target", values.get("target"), vertices)
    conditioned = require_vertex_set(
        f"{context}.conditioning_set",
        values.get("conditioning_set", []),
        vertices,
        nonempty=False,
    )
    path = require_graph_path(f"{context}.path", values.get("path"), vertices)
    if path[0] != source or path[-1] != target:
        fail(f"{context} path endpoints must match source and target")
    if not active_dag_path(vertices, directed_edges, path, conditioned):
        fail(f"{context} path is not active under the conditioning set")
    if not d_connected(vertices, directed_edges, source, target, conditioned):
        fail(f"{context} source and target should be d-connected")


def validate_blocked_dag_query(context: str, data: dict[str, Any]) -> None:
    vertices, directed_edges = require_directed_acyclic_graph(context, data)
    source = require_graph_vertex(f"{context}.source", data.get("source"), vertices)
    target = require_graph_vertex(f"{context}.target", data.get("target"), vertices)
    conditioned = require_vertex_set(
        f"{context}.conditioning_set",
        data.get("conditioning_set", []),
        vertices,
        nonempty=False,
    )
    expected_paths = data.get("all_simple_paths")
    if expected_paths is not None:
        if not isinstance(expected_paths, list):
            fail(f"{context}.all_simple_paths must be a list")
        listed_paths = [
            require_graph_path(f"{context}.all_simple_paths[{index}]", path, vertices)
            for index, path in enumerate(expected_paths)
        ]
        computed_paths = enumerate_simple_skeleton_paths(vertices, directed_edges, source, target)
        if listed_paths != computed_paths:
            fail(f"{context}.all_simple_paths does not match skeleton-path enumeration")
    if d_connected(vertices, directed_edges, source, target, conditioned):
        fail(f"{context} unexpectedly has an active path")


def validate_graph_d_separation(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    chain_active = checks["chain-active-without-conditioning"]
    if chain_active["expected_result"] != "sat" or chain_active.get("proof_status") != "checked":
        fail("chain-active-without-conditioning must be a checked sat row")
    validate_active_path_witness("chain-active-without-conditioning", single_witness_values(chain_active, witnesses))

    chain_blocked = checks["chain-conditioned-blocks"]
    if chain_blocked["expected_result"] != "unsat" or chain_blocked.get("proof_status") != "checked":
        fail("chain-conditioned-blocks must be a checked unsat row")
    chain_blocked_data = chain_blocked.get("data", {})
    validate_blocked_dag_query("chain-conditioned-blocks", chain_blocked_data)
    chain_vertices, chain_edges = require_directed_acyclic_graph("chain-conditioned-blocks", chain_blocked_data)
    chain_source = require_graph_vertex("chain-conditioned-blocks.source", chain_blocked_data.get("source"), chain_vertices)
    chain_target = require_graph_vertex("chain-conditioned-blocks.target", chain_blocked_data.get("target"), chain_vertices)
    chain_conditioned = require_vertex_set(
        "chain-conditioned-blocks.conditioning_set",
        chain_blocked_data.get("conditioning_set", []),
        chain_vertices,
        nonempty=False,
    )
    chain_paths = chain_blocked_data.get("all_simple_paths")
    if (
        chain_vertices != ["a", "b", "c"]
        or chain_edges != [("a", "b"), ("b", "c")]
        or chain_source != "a"
        or chain_target != "c"
        or chain_conditioned != {"b"}
        or chain_paths != [["a", "b", "c"]]
    ):
        fail("chain-conditioned-blocks DIMACS artifact is fixed to a -> b -> c conditioned on b")
    require_dimacs_artifact(
        "chain-conditioned-blocks",
        chain_blocked_data.get("cnf_artifact"),
        "p cnf 4 6",
        [["1"], ["2"], ["3"], ["4"], ["-4", "1"], ["-4", "-2", "-3"]],
    )
    proof_regression = chain_blocked_data.get("proof_regression")
    require_string("chain-conditioned-blocks proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::graph_d_separation_chain_conditioned_blocks" not in proof_regression:
        fail("chain-conditioned-blocks proof_regression must name the Boolean resource test")
    certificate = chain_blocked_data.get("certificate")
    require_string("chain-conditioned-blocks certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("chain-conditioned-blocks certificate must document DRAT/LRAT independent checking")

    fork_blocked = checks["fork-conditioned-blocks"]
    if fork_blocked["expected_result"] != "unsat" or fork_blocked.get("proof_status") != "checked":
        fail("fork-conditioned-blocks must be a checked unsat row")
    validate_blocked_dag_query("fork-conditioned-blocks", fork_blocked.get("data", {}))

    collider_blocked = checks["collider-unconditioned-blocks"]
    if collider_blocked["expected_result"] != "unsat" or collider_blocked.get("proof_status") != "checked":
        fail("collider-unconditioned-blocks must be a checked unsat row")
    collider_blocked_data = collider_blocked.get("data", {})
    validate_blocked_dag_query("collider-unconditioned-blocks", collider_blocked_data)
    collider_vertices, collider_edges = require_directed_acyclic_graph(
        "collider-unconditioned-blocks",
        collider_blocked_data,
    )
    collider_source = require_graph_vertex(
        "collider-unconditioned-blocks.source",
        collider_blocked_data.get("source"),
        collider_vertices,
    )
    collider_target = require_graph_vertex(
        "collider-unconditioned-blocks.target",
        collider_blocked_data.get("target"),
        collider_vertices,
    )
    collider_conditioned = require_vertex_set(
        "collider-unconditioned-blocks.conditioning_set",
        collider_blocked_data.get("conditioning_set", []),
        collider_vertices,
        nonempty=False,
    )
    collider_paths = collider_blocked_data.get("all_simple_paths")
    if (
        collider_vertices != ["a", "b", "c"]
        or collider_edges != [("a", "b"), ("c", "b")]
        or collider_source != "a"
        or collider_target != "c"
        or collider_conditioned
        or collider_paths != [["a", "b", "c"]]
    ):
        fail("collider-unconditioned-blocks DIMACS artifact is fixed to a -> b <- c with no conditioning")
    require_dimacs_artifact(
        "collider-unconditioned-blocks",
        collider_blocked_data.get("cnf_artifact"),
        "p cnf 4 6",
        [["1"], ["2"], ["-3"], ["4"], ["-4", "1"], ["-4", "-2", "3"]],
    )
    proof_regression = collider_blocked_data.get("proof_regression")
    require_string("collider-unconditioned-blocks proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::graph_d_separation_collider_unconditioned_blocks" not in proof_regression:
        fail("collider-unconditioned-blocks proof_regression must name the Boolean resource test")
    certificate = collider_blocked_data.get("certificate")
    require_string("collider-unconditioned-blocks certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("collider-unconditioned-blocks certificate must document DRAT/LRAT independent checking")

    collider_open = checks["collider-descendant-opens"]
    if collider_open["expected_result"] != "sat" or collider_open.get("proof_status") != "checked":
        fail("collider-descendant-opens must be a checked sat row")
    validate_active_path_witness("collider-descendant-opens", single_witness_values(collider_open, witnesses))


def graph_separates(
    vertices: list[str],
    edges: list[tuple[str, str]],
    source: str,
    target: str,
) -> bool:
    return target not in shortest_distances(vertices, edges, source)


def minimum_edge_cut_size(
    vertices: list[str],
    edges: list[tuple[str, str]],
    source: str,
    target: str,
) -> int:
    if graph_separates(vertices, edges, source, target):
        return 0
    for size in range(1, len(edges) + 1):
        for removed in combinations(edges, size):
            if graph_separates(vertices, remove_edges(edges, list(removed)), source, target):
                return size
    fail("minimum edge cut search failed to separate a finite connected graph")


def remove_vertices(edges: list[tuple[str, str]], removed_vertices: set[str]) -> list[tuple[str, str]]:
    return [
        edge
        for edge in edges
        if edge[0] not in removed_vertices and edge[1] not in removed_vertices
    ]


def minimum_vertex_cut_size(
    vertices: list[str],
    edges: list[tuple[str, str]],
    source: str,
    target: str,
) -> int:
    if graph_separates(vertices, edges, source, target):
        return 0
    candidates = [vertex for vertex in vertices if vertex not in {source, target}]
    for size in range(1, len(candidates) + 1):
        for removed in combinations(candidates, size):
            if graph_separates(vertices, remove_vertices(edges, set(removed)), source, target):
                return size
    return len(candidates) + 1


def require_graph_cut_partition(
    context: str,
    data: dict[str, Any],
    vertices: list[str],
    source: str,
    target: str,
) -> tuple[set[str], set[str]]:
    source_side = require_vertex_set(
        f"{context}.source_side",
        data.get("source_side"),
        vertices,
        nonempty=True,
    )
    target_side = require_vertex_set(
        f"{context}.target_side",
        data.get("target_side"),
        vertices,
        nonempty=True,
    )
    if source_side & target_side:
        fail(f"{context} partition sides must be disjoint")
    if source_side | target_side != set(vertices):
        fail(f"{context} partition sides must cover every vertex")
    if source not in source_side:
        fail(f"{context} source must be in source_side")
    if target not in target_side:
        fail(f"{context} target must be in target_side")
    return source_side, target_side


def crossing_edges(edges: list[tuple[str, str]], source_side: set[str], target_side: set[str]) -> list[tuple[str, str]]:
    return [
        edge
        for edge in edges
        if (edge[0] in source_side and edge[1] in target_side)
        or (edge[1] in source_side and edge[0] in target_side)
    ]


def require_cut_vertices(
    context: str,
    value: Any,
    vertices: list[str],
    source: str,
    target: str,
) -> set[str]:
    cut_vertices = require_vertex_set(context, value, vertices, nonempty=True)
    if source in cut_vertices or target in cut_vertices:
        fail(f"{context} must not remove source or target")
    return cut_vertices


def validate_graph_cut(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    edge_cut = checks["min-edge-cut-partition-witness"]
    if edge_cut["expected_result"] != "sat" or edge_cut.get("proof_status") != "checked":
        fail("min-edge-cut-partition-witness must be a checked sat row")
    values = single_witness_values(edge_cut, witnesses)
    vertices, edges = require_finite_graph("min edge cut", values)
    source = require_graph_vertex("min edge cut source", values.get("source"), vertices)
    target = require_graph_vertex("min edge cut target", values.get("target"), vertices)
    cut_edges = require_graph_edge_list("min edge cut.cut_edges", values.get("cut_edges"), vertices, edges)
    source_side, target_side = require_graph_cut_partition("min edge cut", values, vertices, source, target)
    if normalized_edge_set(cut_edges) != normalized_edge_set(crossing_edges(edges, source_side, target_side)):
        fail("min-edge-cut-partition-witness cut_edges do not match the partition crossing edges")
    if not graph_separates(vertices, remove_edges(edges, cut_edges), source, target):
        fail("min-edge-cut-partition-witness cut does not separate source and target")
    min_size = require_int("min edge cut min_cut_size", values.get("min_cut_size"))
    if min_size != len(cut_edges) or min_size != minimum_edge_cut_size(vertices, edges, source, target):
        fail("min-edge-cut-partition-witness minimum edge cut size is wrong")

    bad_edge_cut = checks["one-edge-cut-rejected"]
    if bad_edge_cut["expected_result"] != "unsat" or bad_edge_cut.get("proof_status") != "checked":
        fail("one-edge-cut-rejected must be a checked unsat row")
    values = single_witness_values(bad_edge_cut, witnesses)
    vertices, edges = require_finite_graph("bad edge cut", values)
    source = require_graph_vertex("bad edge cut source", values.get("source"), vertices)
    target = require_graph_vertex("bad edge cut target", values.get("target"), vertices)
    cut_edges = require_graph_edge_list("bad edge cut.cut_edges", values.get("cut_edges"), vertices, edges)
    if graph_separates(vertices, remove_edges(edges, cut_edges), source, target):
        fail("one-edge-cut-rejected unexpectedly separates source and target")
    data = bad_edge_cut.get("data", {})
    depth_bound = require_int("one-edge-cut-rejected depth_bound", data.get("depth_bound"))
    if vertices != ["s", "a", "b", "t"] or edges != [
        ("s", "a"),
        ("a", "t"),
        ("s", "b"),
        ("b", "t"),
    ]:
        fail("one-edge-cut-rejected DIMACS artifact is fixed to the diamond graph")
    if source != "s" or target != "t" or graph_edge_set(cut_edges) != {tuple(sorted(("s", "a")))}:
        fail("one-edge-cut-rejected DIMACS artifact is fixed to removing edge (s,a)")
    if depth_bound != len(vertices) - 1:
        fail("one-edge-cut-rejected DIMACS artifact is fixed to depth bound 3")
    remaining_edges = remove_edges(edges, cut_edges)
    require_dimacs_artifact(
        "one-edge-cut-rejected",
        data.get("cnf_artifact"),
        "p cnf 16 47",
        expected_bounded_reachability_dimacs(
            vertices,
            remaining_edges,
            source,
            target,
            depth_bound,
            final_reachable=False,
        ),
    )
    proof_regression = data.get("proof_regression")
    require_string("one-edge-cut-rejected proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::graph_cut_one_edge_rejected" not in proof_regression:
        fail("one-edge-cut-rejected proof_regression must name the Boolean resource test")
    certificate = data.get("certificate")
    require_string("one-edge-cut-rejected certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("one-edge-cut-rejected certificate must document DRAT/LRAT independent checking")

    vertex_cut = checks["min-vertex-cut-witness"]
    if vertex_cut["expected_result"] != "sat" or vertex_cut.get("proof_status") != "checked":
        fail("min-vertex-cut-witness must be a checked sat row")
    values = single_witness_values(vertex_cut, witnesses)
    vertices, edges = require_finite_graph("min vertex cut", values)
    source = require_graph_vertex("min vertex cut source", values.get("source"), vertices)
    target = require_graph_vertex("min vertex cut target", values.get("target"), vertices)
    cut_vertices = require_cut_vertices("min vertex cut.cut_vertices", values.get("cut_vertices"), vertices, source, target)
    if not graph_separates(vertices, remove_vertices(edges, cut_vertices), source, target):
        fail("min-vertex-cut-witness cut does not separate source and target")
    min_size = require_int("min vertex cut min_cut_size", values.get("min_cut_size"))
    if min_size != len(cut_vertices) or min_size != minimum_vertex_cut_size(vertices, edges, source, target):
        fail("min-vertex-cut-witness minimum vertex cut size is wrong")

    bad_vertex_cut = checks["one-vertex-cut-rejected"]
    if bad_vertex_cut["expected_result"] != "unsat" or bad_vertex_cut.get("proof_status") != "checked":
        fail("one-vertex-cut-rejected must be a checked unsat row")
    values = single_witness_values(bad_vertex_cut, witnesses)
    vertices, edges = require_finite_graph("bad vertex cut", values)
    source = require_graph_vertex("bad vertex cut source", values.get("source"), vertices)
    target = require_graph_vertex("bad vertex cut target", values.get("target"), vertices)
    cut_vertices = require_cut_vertices("bad vertex cut.cut_vertices", values.get("cut_vertices"), vertices, source, target)
    if graph_separates(vertices, remove_vertices(edges, cut_vertices), source, target):
        fail("one-vertex-cut-rejected unexpectedly separates source and target")


FlowEdge = tuple[str, str, Fraction, Fraction]


def require_directed_flow_network(
    context: str,
    values: dict[str, Any],
    *,
    enforce_capacity: bool = True,
) -> tuple[list[str], list[FlowEdge], str, str, Fraction]:
    vertices = require_string_list(f"{context}.vertices", values.get("vertices"))
    edge_values = values.get("directed_edges")
    if not isinstance(edge_values, list) or not edge_values:
        fail(f"{context}.directed_edges must be a non-empty list")
    vertex_set = set(vertices)
    edges: list[FlowEdge] = []
    seen_edges: set[tuple[str, str]] = set()
    for index, edge in enumerate(edge_values):
        if not isinstance(edge, dict):
            fail(f"{context}.directed_edges[{index}] must be an object")
        tail = edge.get("from")
        head = edge.get("to")
        require_string(f"{context}.directed_edges[{index}].from", tail)
        require_string(f"{context}.directed_edges[{index}].to", head)
        if tail == head:
            fail(f"{context}.directed_edges[{index}] must not be a self-loop")
        if tail not in vertex_set or head not in vertex_set:
            fail(f"{context}.directed_edges[{index}] references a missing vertex")
        directed_edge = (tail, head)
        if directed_edge in seen_edges:
            fail(f"{context}.directed_edges repeats directed edge {directed_edge}")
        seen_edges.add(directed_edge)
        capacity = require_fraction(f"{context}.directed_edges[{index}].capacity", edge.get("capacity"))
        flow = require_fraction(f"{context}.directed_edges[{index}].flow", edge.get("flow"))
        if capacity < 0:
            fail(f"{context}.directed_edges[{index}].capacity must be nonnegative")
        if flow < 0:
            fail(f"{context}.directed_edges[{index}].flow must be nonnegative")
        if enforce_capacity and flow > capacity:
            fail(f"{context}.directed_edges[{index}].flow exceeds capacity")
        edges.append((tail, head, capacity, flow))
    source = require_graph_vertex(f"{context}.source", values.get("source"), vertices)
    sink = require_graph_vertex(f"{context}.sink", values.get("sink"), vertices)
    if source == sink:
        fail(f"{context}.source and sink must be distinct")
    flow_value = require_fraction(f"{context}.flow_value", values.get("flow_value"))
    if flow_value < 0:
        fail(f"{context}.flow_value must be nonnegative")
    return vertices, edges, source, sink, flow_value


def require_directed_edge_ref(
    context: str,
    value: Any,
    edges: list[FlowEdge],
) -> tuple[str, str, Fraction, Fraction]:
    if not isinstance(value, list) or len(value) != 2:
        fail(f"{context} must be a two-element list")
    tail, head = value
    require_string(f"{context}[0]", tail)
    require_string(f"{context}[1]", head)
    for edge_tail, edge_head, capacity, flow in edges:
        if edge_tail == tail and edge_head == head:
            return edge_tail, edge_head, capacity, flow
    fail(f"{context} references a missing directed edge")


def validate_flow_conservation(
    context: str,
    vertices: list[str],
    edges: list[FlowEdge],
    source: str,
    sink: str,
    flow_value: Fraction,
) -> None:
    net_out = {vertex: Fraction(0) for vertex in vertices}
    for tail, head, _capacity, flow in edges:
        net_out[tail] += flow
        net_out[head] -= flow
    if net_out[source] != flow_value:
        fail(f"{context} source net outflow does not match flow_value")
    if net_out[sink] != -flow_value:
        fail(f"{context} sink net inflow does not match flow_value")
    for vertex in vertices:
        if vertex not in {source, sink} and net_out[vertex] != 0:
            fail(f"{context} violates conservation at {vertex}")


def require_flow_cut_partition(
    context: str,
    values: dict[str, Any],
    vertices: list[str],
    source: str,
    sink: str,
) -> tuple[set[str], set[str]]:
    source_side = require_vertex_set(
        f"{context}.source_side",
        values.get("source_side"),
        vertices,
        nonempty=True,
    )
    target_side_value = values.get("target_side")
    if target_side_value is None:
        target_side = set(vertices) - source_side
    else:
        target_side = require_vertex_set(
            f"{context}.target_side",
            target_side_value,
            vertices,
            nonempty=True,
        )
    if source_side & target_side:
        fail(f"{context} cut partition sides must be disjoint")
    if source_side | target_side != set(vertices):
        fail(f"{context} cut partition sides must cover every vertex")
    if source not in source_side:
        fail(f"{context} source must be in source_side")
    if sink not in target_side:
        fail(f"{context} sink must be in target_side")
    return source_side, target_side


def directed_cut_capacity(edges: list[FlowEdge], source_side: set[str], target_side: set[str]) -> Fraction:
    return sum(
        (
            capacity
            for tail, head, capacity, _flow in edges
            if tail in source_side and head in target_side
        ),
        Fraction(0),
    )


def directed_cut_net_flow(edges: list[FlowEdge], source_side: set[str], target_side: set[str]) -> Fraction:
    forward = sum(
        (
            flow
            for tail, head, _capacity, flow in edges
            if tail in source_side and head in target_side
        ),
        Fraction(0),
    )
    backward = sum(
        (
            flow
            for tail, head, _capacity, flow in edges
            if tail in target_side and head in source_side
        ),
        Fraction(0),
    )
    return forward - backward


def validate_finite_flow_cut(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    feasible = checks["feasible-flow-witness"]
    if feasible["expected_result"] != "sat" or feasible.get("proof_status") != "checked":
        fail("feasible-flow-witness must be a checked sat row")
    values = single_witness_values(feasible, witnesses)
    vertices, edges, source, sink, flow_value = require_directed_flow_network("feasible flow", values)
    validate_flow_conservation("feasible-flow-witness", vertices, edges, source, sink, flow_value)

    optimal = checks["flow-cut-optimality-witness"]
    if optimal["expected_result"] != "sat" or optimal.get("proof_status") != "checked":
        fail("flow-cut-optimality-witness must be a checked sat row")
    values = single_witness_values(optimal, witnesses)
    vertices, edges, source, sink, flow_value = require_directed_flow_network("flow cut optimality", values)
    validate_flow_conservation("flow-cut-optimality-witness", vertices, edges, source, sink, flow_value)
    source_side, target_side = require_flow_cut_partition("flow-cut-optimality-witness", values, vertices, source, sink)
    cut_capacity = directed_cut_capacity(edges, source_side, target_side)
    listed_cut_capacity = require_fraction("flow-cut-optimality-witness.cut_capacity", values.get("cut_capacity"))
    if listed_cut_capacity != cut_capacity:
        fail("flow-cut-optimality-witness cut_capacity does not match the directed cut")
    if directed_cut_net_flow(edges, source_side, target_side) != flow_value:
        fail("flow-cut-optimality-witness net flow across the cut does not match flow_value")
    if flow_value != cut_capacity:
        fail("flow-cut-optimality-witness must saturate the listed cut")

    bad_capacity = checks["bad-capacity-bound-rejected"]
    if bad_capacity["expected_result"] != "unsat" or bad_capacity.get("proof_status") != "checked":
        fail("bad-capacity-bound-rejected must be a checked unsat row")
    values = single_witness_values(bad_capacity, witnesses)
    _vertices, edges, _source, _sink, _flow_value = require_directed_flow_network(
        "bad capacity flow",
        values,
        enforce_capacity=False,
    )
    tail, head, capacity, flow = require_directed_edge_ref(
        "bad-capacity-bound-rejected.violating_edge",
        values.get("violating_edge"),
        edges,
    )
    if flow <= capacity:
        fail(f"bad-capacity-bound-rejected edge {(tail, head)} does not violate capacity")
    listed_capacity = require_fraction("bad-capacity-bound-rejected.capacity", values.get("capacity"))
    listed_claimed_flow = require_fraction("bad-capacity-bound-rejected.claimed_flow", values.get("claimed_flow"))
    if listed_capacity != capacity or listed_claimed_flow != flow:
        fail("bad-capacity-bound-rejected listed capacity/claimed_flow do not match the violating edge")

    bad_value = checks["bad-flow-value-rejected"]
    if bad_value["expected_result"] != "unsat" or bad_value.get("proof_status") != "checked":
        fail("bad-flow-value-rejected must be a checked unsat row")
    data = bad_value.get("data", {})
    vertices, edges, source, sink, flow_value = require_directed_flow_network("bad flow value", data)
    validate_flow_conservation("bad-flow-value-rejected", vertices, edges, source, sink, flow_value)
    source_side, target_side = require_flow_cut_partition("bad-flow-value-rejected", data, vertices, source, sink)
    cut_capacity = directed_cut_capacity(edges, source_side, target_side)
    listed_cut_capacity = require_fraction("bad-flow-value-rejected.cut_capacity", data.get("cut_capacity"))
    claimed_flow_value = require_fraction("bad-flow-value-rejected.claimed_flow_value", data.get("claimed_flow_value"))
    if listed_cut_capacity != cut_capacity:
        fail("bad-flow-value-rejected cut_capacity does not match the directed cut")
    if claimed_flow_value <= cut_capacity:
        fail("bad-flow-value-rejected claimed flow must exceed the listed cut capacity")

    horizon = checks["max-flow-min-cut-theorem-lean-horizon"]
    if horizon["expected_result"] != "not-run" or horizon.get("proof_status") != "lean-horizon":
        fail("max-flow-min-cut-theorem-lean-horizon must be a Lean-horizon not-run row")


WeightedEdge = tuple[str, str, Fraction]


def require_directed_weighted_graph(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], list[WeightedEdge], str, str]:
    vertices = require_string_list(f"{context}.vertices", values.get("vertices"))
    edge_values = values.get("directed_edges")
    if not isinstance(edge_values, list) or not edge_values:
        fail(f"{context}.directed_edges must be a non-empty list")
    vertex_set = set(vertices)
    edges: list[WeightedEdge] = []
    seen_edges: set[tuple[str, str]] = set()
    for index, edge in enumerate(edge_values):
        if not isinstance(edge, dict):
            fail(f"{context}.directed_edges[{index}] must be an object")
        tail = edge.get("from")
        head = edge.get("to")
        require_string(f"{context}.directed_edges[{index}].from", tail)
        require_string(f"{context}.directed_edges[{index}].to", head)
        if tail == head:
            fail(f"{context}.directed_edges[{index}] must not be a self-loop")
        if tail not in vertex_set or head not in vertex_set:
            fail(f"{context}.directed_edges[{index}] references a missing vertex")
        directed_edge = (tail, head)
        if directed_edge in seen_edges:
            fail(f"{context}.directed_edges repeats directed edge {directed_edge}")
        seen_edges.add(directed_edge)
        weight = require_fraction(f"{context}.directed_edges[{index}].weight", edge.get("weight"))
        if weight < 0:
            fail(f"{context}.directed_edges[{index}].weight must be nonnegative")
        edges.append((tail, head, weight))
    source = require_graph_vertex(f"{context}.source", values.get("source"), vertices)
    target = require_graph_vertex(f"{context}.target", values.get("target"), vertices)
    if source == target:
        fail(f"{context}.source and target must be distinct")
    return vertices, edges, source, target


def weighted_edge_map(edges: list[WeightedEdge]) -> dict[tuple[str, str], Fraction]:
    return {(tail, head): weight for tail, head, weight in edges}


def require_directed_path(
    context: str,
    values: dict[str, Any],
    vertices: list[str],
    source: str,
    target: str,
) -> list[str]:
    path = require_string_list(f"{context}.path", values.get("path"))
    if len(path) < 2:
        fail(f"{context}.path must have at least two vertices")
    vertex_set = set(vertices)
    for index, vertex in enumerate(path):
        if vertex not in vertex_set:
            fail(f"{context}.path[{index}] references a missing vertex")
    if path[0] != source:
        fail(f"{context}.path must start at source")
    if path[-1] != target:
        fail(f"{context}.path must end at target")
    return path


def directed_path_length(context: str, path: list[str], edges: list[WeightedEdge]) -> Fraction:
    by_edge = weighted_edge_map(edges)
    total = Fraction(0)
    for tail, head in zip(path, path[1:]):
        weight = by_edge.get((tail, head))
        if weight is None:
            fail(f"{context}.path uses missing directed edge {(tail, head)}")
        total += weight
    return total


def require_potentials(context: str, values: dict[str, Any], vertices: list[str]) -> dict[str, Fraction]:
    potential_values = values.get("potentials")
    if not isinstance(potential_values, dict) or not potential_values:
        fail(f"{context}.potentials must be a non-empty object")
    vertex_set = set(vertices)
    potential_vertices = set(potential_values)
    if potential_vertices != vertex_set:
        missing = sorted(vertex_set - potential_vertices)
        extra = sorted(potential_vertices - vertex_set)
        detail = []
        if missing:
            detail.append("missing " + ", ".join(missing))
        if extra:
            detail.append("extra " + ", ".join(extra))
        fail(f"{context}.potentials must cover exactly the vertices ({'; '.join(detail)})")
    return {
        vertex: require_fraction(f"{context}.potentials.{vertex}", potential_values[vertex])
        for vertex in vertices
    }


def validate_shortest_path_potentials(
    context: str,
    edges: list[WeightedEdge],
    potentials: dict[str, Fraction],
) -> None:
    for tail, head, weight in edges:
        if potentials[head] > potentials[tail] + weight:
            fail(f"{context} violates edge relaxation on {(tail, head)}")


def validate_finite_shortest_path(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    path_check = checks["path-distance-witness"]
    if path_check["expected_result"] != "sat" or path_check.get("proof_status") != "checked":
        fail("path-distance-witness must be a checked sat row")
    values = single_witness_values(path_check, witnesses)
    vertices, edges, source, target = require_directed_weighted_graph("path-distance-witness", values)
    path = require_directed_path("path-distance-witness", values, vertices, source, target)
    path_length = directed_path_length("path-distance-witness", path, edges)
    listed_path_length = require_fraction("path-distance-witness.path_length", values.get("path_length"))
    if listed_path_length != path_length:
        fail("path-distance-witness path_length does not match the path")

    optimal = checks["potential-optimality-witness"]
    if optimal["expected_result"] != "sat" or optimal.get("proof_status") != "checked":
        fail("potential-optimality-witness must be a checked sat row")
    values = single_witness_values(optimal, witnesses)
    vertices, edges, source, target = require_directed_weighted_graph("potential-optimality-witness", values)
    path = require_directed_path("potential-optimality-witness", values, vertices, source, target)
    path_length = directed_path_length("potential-optimality-witness", path, edges)
    listed_path_length = require_fraction("potential-optimality-witness.path_length", values.get("path_length"))
    if listed_path_length != path_length:
        fail("potential-optimality-witness path_length does not match the path")
    potentials = require_potentials("potential-optimality-witness", values, vertices)
    if potentials[source] != 0:
        fail("potential-optimality-witness source potential must be 0")
    validate_shortest_path_potentials("potential-optimality-witness", edges, potentials)
    target_distance = require_fraction("potential-optimality-witness.target_distance", values.get("target_distance"))
    if potentials[target] != target_distance:
        fail("potential-optimality-witness target_distance must equal target potential")
    if path_length != target_distance:
        fail("potential-optimality-witness path must meet the potential lower bound")

    bad_path = checks["bad-path-distance-rejected"]
    if bad_path["expected_result"] != "unsat" or bad_path.get("proof_status") != "checked":
        fail("bad-path-distance-rejected must be a checked unsat row")
    values = single_witness_values(bad_path, witnesses)
    vertices, edges, source, target = require_directed_weighted_graph("bad-path-distance-rejected", values)
    path = require_directed_path("bad-path-distance-rejected", values, vertices, source, target)
    path_length = directed_path_length("bad-path-distance-rejected", path, edges)
    claimed_path_length = require_fraction("bad-path-distance-rejected.path_length", values.get("path_length"))
    actual_path_length = require_fraction("bad-path-distance-rejected.actual_path_length", values.get("actual_path_length"))
    if actual_path_length != path_length:
        fail("bad-path-distance-rejected actual_path_length does not match the path")
    if claimed_path_length == path_length:
        fail("bad-path-distance-rejected must disagree with the recomputed path length")

    bad_bound = checks["bad-shorter-distance-rejected"]
    if bad_bound["expected_result"] != "unsat" or bad_bound.get("proof_status") != "checked":
        fail("bad-shorter-distance-rejected must be a checked unsat row")
    data = bad_bound.get("data", {})
    vertices, edges, source, target = require_directed_weighted_graph("bad-shorter-distance-rejected", data)
    potentials = require_potentials("bad-shorter-distance-rejected", data, vertices)
    if potentials[source] != 0:
        fail("bad-shorter-distance-rejected source potential must be 0")
    validate_shortest_path_potentials("bad-shorter-distance-rejected", edges, potentials)
    target_distance = require_fraction("bad-shorter-distance-rejected.target_distance", data.get("target_distance"))
    claimed_upper_bound = require_fraction(
        "bad-shorter-distance-rejected.claimed_upper_bound",
        data.get("claimed_upper_bound"),
    )
    if potentials[target] != target_distance:
        fail("bad-shorter-distance-rejected target_distance must equal target potential")
    if claimed_upper_bound >= target_distance:
        fail("bad-shorter-distance-rejected claimed upper bound must be below the potential lower bound")

    horizon = checks["shortest-path-theorem-lean-horizon"]
    if horizon["expected_result"] != "not-run" or horizon.get("proof_status") != "lean-horizon":
        fail("shortest-path-theorem-lean-horizon must be a Lean-horizon not-run row")


def has_mod_inverse(a: int, modulus: int) -> bool:
    return any((a * candidate) % modulus == 1 for candidate in range(modulus))


def is_prime(value: int) -> bool:
    if value < 2:
        return False
    for candidate in range(2, int(value**0.5) + 1):
        if value % candidate == 0:
            return False
    return True


def require_modulus(context: str, value: Any) -> int:
    modulus = require_int(context, value)
    if modulus <= 1:
        fail(f"{context} must be > 1")
    return modulus


def validate_finite_fields(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    inverse_table = checks["prime-field-inverse-table"]
    if inverse_table["expected_result"] != "sat":
        fail("prime-field-inverse-table must expect sat")
    values = single_witness_values(inverse_table, witnesses)
    modulus = require_modulus("finite field inverse modulus", values.get("modulus"))
    if not is_prime(modulus):
        fail("finite field inverse modulus must be prime")
    inverses = values.get("inverses")
    if not isinstance(inverses, dict):
        fail("finite field inverses must be an object")
    expected_keys = {str(residue) for residue in range(1, modulus)}
    if set(inverses) != expected_keys:
        fail(
            "finite field inverse table must cover exactly nonzero residues: "
            f"expected={sorted(expected_keys, key=int)} actual={sorted(inverses, key=int)}"
        )
    for residue_text in sorted(inverses, key=int):
        residue = int(residue_text)
        inverse = require_int(f"inverse table {residue_text}", inverses[residue_text])
        if inverse <= 0 or inverse >= modulus:
            fail(f"inverse for {residue} must be a nonzero residue modulo {modulus}")
        if (residue * inverse) % modulus != 1:
            fail(f"inverse table entry {residue}->{inverse} does not multiply to 1 modulo {modulus}")

    distributivity = checks["prime-field-distributivity-no-counterexample"]
    if distributivity["expected_result"] != "unsat":
        fail("prime-field-distributivity-no-counterexample must expect unsat")
    data = distributivity.get("data", {})
    modulus = require_modulus("finite field distributivity modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("finite field distributivity modulus must be prime")
    for a, b, c in product(range(modulus), repeat=3):
        left = (a * ((b + c) % modulus)) % modulus
        right = ((a * b) + (a * c)) % modulus
        if left != right:
            fail(f"distributivity counterexample found modulo {modulus}: {(a, b, c)}")

    composite = checks["composite-modulus-nonfield"]
    if composite["expected_result"] != "unsat":
        fail("composite-modulus-nonfield must expect unsat")
    data = composite.get("data", {})
    modulus = require_modulus("composite modulus", data.get("modulus"))
    if is_prime(modulus):
        fail("composite-modulus-nonfield must use a composite modulus")
    element = require_int("composite modulus element", data.get("element"))
    if element <= 0 or element >= modulus:
        fail("composite modulus element must be a nonzero residue")
    if has_mod_inverse(element, modulus):
        fail(f"element {element} unexpectedly has an inverse modulo {modulus}")

    bad_inverse = checks["bad-prime-field-inverse-candidate-rejected"]
    if bad_inverse["expected_result"] != "unsat":
        fail("bad-prime-field-inverse-candidate-rejected must expect unsat")
    if bad_inverse["proof_status"] != "checked":
        fail("bad-prime-field-inverse-candidate-rejected must be checked")
    if bad_inverse["validation"] != "finite_field_inverse_candidate_replay":
        fail("bad-prime-field-inverse-candidate-rejected must use finite_field_inverse_candidate_replay validation")
    data = bad_inverse.get("data", {})
    modulus = require_modulus("bad inverse candidate modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("bad-prime-field-inverse-candidate-rejected must use a prime modulus")
    element = require_int("bad inverse candidate element", data.get("element"))
    candidate_inverse = require_int(
        "bad inverse candidate candidate_inverse", data.get("candidate_inverse")
    )
    product_value = require_int("bad inverse candidate product", data.get("product"))
    required_value = require_int("bad inverse candidate required", data.get("required"))
    for label, value in (("element", element), ("candidate_inverse", candidate_inverse)):
        if value <= 0 or value >= modulus:
            fail(f"bad-prime-field-inverse-candidate-rejected {label} must be a nonzero residue")
    if required_value != 1:
        fail("bad-prime-field-inverse-candidate-rejected required value must be 1")
    computed_product = (element * candidate_inverse) % modulus
    if computed_product != product_value:
        fail("bad-prime-field-inverse-candidate-rejected product does not match modular replay")
    if product_value == required_value:
        fail("bad-prime-field-inverse-candidate-rejected candidate unexpectedly is an inverse")

    qf_bv = checks["composite-modulus-nonfield-qf-bv-drat"]
    if qf_bv["expected_result"] != "unsat":
        fail("composite-modulus-nonfield-qf-bv-drat must expect unsat")
    if qf_bv["proof_status"] != "checked":
        fail("composite-modulus-nonfield-qf-bv-drat must be checked")
    if qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("composite-modulus-nonfield-qf-bv-drat must use qf_bv_bitblast_drat validation")
    data = qf_bv.get("data", {})
    modulus = require_modulus("composite QF_BV modulus", data.get("modulus"))
    if is_prime(modulus):
        fail("composite-modulus-nonfield-qf-bv-drat must use a composite modulus")
    element = require_int("composite QF_BV element", data.get("element"))
    if element <= 0 or element >= modulus:
        fail("composite QF_BV element must be a nonzero residue")
    if has_mod_inverse(element, modulus):
        fail(f"QF_BV element {element} unexpectedly has an inverse modulo {modulus}")
    residue_width = require_int("composite QF_BV residue_width", data.get("residue_width"))
    product_width = require_int("composite QF_BV product_width", data.get("product_width"))
    if 2**residue_width <= modulus:
        fail("composite QF_BV residue_width must encode every residue and the modulus guard")
    if 2**product_width <= element * (modulus - 1):
        fail("composite QF_BV product_width must encode the maximum listed product exactly")
    smt2_artifact = data.get("smt2_artifact")
    require_string("composite-modulus-nonfield-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("composite-modulus-nonfield-qf-bv-drat smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("composite-modulus-nonfield-qf-bv-drat proof_regression", proof_regression)
    if "finite_fields_composite_nonfield_emits_checked_drat" not in proof_regression:
        fail("composite-modulus-nonfield-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("composite-modulus-nonfield-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("composite-modulus-nonfield-qf-bv-drat certificate must document DRAT and lowering trust")

    inverse_qf_bv = checks["bad-prime-field-inverse-candidate-qf-bv-drat"]
    if inverse_qf_bv["expected_result"] != "unsat":
        fail("bad-prime-field-inverse-candidate-qf-bv-drat must expect unsat")
    if inverse_qf_bv["proof_status"] != "checked":
        fail("bad-prime-field-inverse-candidate-qf-bv-drat must be checked")
    if inverse_qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("bad-prime-field-inverse-candidate-qf-bv-drat must use qf_bv_bitblast_drat validation")
    data = inverse_qf_bv.get("data", {})
    modulus = require_modulus("bad inverse candidate QF_BV modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("bad-prime-field-inverse-candidate-qf-bv-drat must use a prime modulus")
    element = require_int("bad inverse candidate QF_BV element", data.get("element"))
    candidate_inverse = require_int(
        "bad inverse candidate QF_BV candidate_inverse", data.get("candidate_inverse")
    )
    product_value = require_int("bad inverse candidate QF_BV product", data.get("product"))
    required_value = require_int("bad inverse candidate QF_BV required", data.get("required"))
    for label, value in (("element", element), ("candidate_inverse", candidate_inverse)):
        if value <= 0 or value >= modulus:
            fail(f"bad-prime-field-inverse-candidate-qf-bv-drat {label} must be a nonzero residue")
    if required_value != 1:
        fail("bad-prime-field-inverse-candidate-qf-bv-drat required value must be 1")
    computed_product = (element * candidate_inverse) % modulus
    if computed_product != product_value:
        fail("bad-prime-field-inverse-candidate-qf-bv-drat product does not match modular replay")
    if product_value == required_value:
        fail("bad-prime-field-inverse-candidate-qf-bv-drat candidate unexpectedly is an inverse")
    residue_width = require_int("bad inverse candidate QF_BV residue_width", data.get("residue_width"))
    product_width = require_int("bad inverse candidate QF_BV product_width", data.get("product_width"))
    if 2**residue_width <= modulus:
        fail("bad-prime-field-inverse-candidate-qf-bv-drat residue_width must encode every residue")
    if 2**product_width <= element * candidate_inverse:
        fail("bad-prime-field-inverse-candidate-qf-bv-drat product_width must encode the product exactly")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad-prime-field-inverse-candidate-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("bad-prime-field-inverse-candidate-qf-bv-drat smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("bad-prime-field-inverse-candidate-qf-bv-drat proof_regression", proof_regression)
    if "finite_fields_bad_inverse_candidate_emits_checked_drat" not in proof_regression:
        fail("bad-prime-field-inverse-candidate-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("bad-prime-field-inverse-candidate-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("bad-prime-field-inverse-candidate-qf-bv-drat certificate must document DRAT and lowering trust")


def require_cayley_table(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], str, dict[tuple[str, str], str]]:
    carrier = require_string_list(f"{context}.carrier", values.get("carrier"))
    carrier_set = set(carrier)
    identity = values.get("identity")
    require_string(f"{context}.identity", identity)
    if identity not in carrier_set:
        fail(f"{context}.identity must be in the carrier")
    raw_table = values.get("table")
    if not isinstance(raw_table, list) or len(raw_table) != len(carrier):
        fail(f"{context}.table must have one row per carrier element")
    operation: dict[tuple[str, str], str] = {}
    for row_index, row in enumerate(raw_table):
        if not isinstance(row, list) or len(row) != len(carrier):
            fail(f"{context}.table[{row_index}] must have one entry per carrier element")
        left = carrier[row_index]
        for col_index, result in enumerate(row):
            require_string(f"{context}.table[{row_index}][{col_index}]", result)
            if result not in carrier_set:
                fail(f"{context}.table[{row_index}][{col_index}] is outside the carrier")
            operation[(left, carrier[col_index])] = result
    return carrier, identity, operation


def table_op(operation: dict[tuple[str, str], str], left: str, right: str) -> str:
    return operation[(left, right)]


def group_axiom_failures(
    carrier: list[str],
    identity: str,
    operation: dict[tuple[str, str], str],
) -> list[str]:
    failures: list[str] = []
    for item in carrier:
        if table_op(operation, identity, item) != item:
            failures.append(f"left identity fails for {item}")
        if table_op(operation, item, identity) != item:
            failures.append(f"right identity fails for {item}")
    for item in carrier:
        if not any(
            table_op(operation, item, candidate) == identity
            and table_op(operation, candidate, item) == identity
            for candidate in carrier
        ):
            failures.append(f"inverse fails for {item}")
    for left in carrier:
        for middle in carrier:
            for right in carrier:
                lhs = table_op(operation, table_op(operation, left, middle), right)
                rhs = table_op(operation, left, table_op(operation, middle, right))
                if lhs != rhs:
                    failures.append(f"associativity fails for {(left, middle, right)}")
                    return failures
    return failures


def require_group_structure(
    context: str,
    value: Any,
) -> tuple[list[str], str, dict[tuple[str, str], str]]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    carrier, identity, operation = require_cayley_table(context, value)
    failures = group_axiom_failures(carrier, identity, operation)
    if failures:
        fail(f"{context} is not a group: {failures[0]}")
    return carrier, identity, operation


def require_inverse_table(
    context: str,
    value: Any,
    carrier: list[str],
) -> dict[str, str]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    carrier_set = set(carrier)
    if set(value) != carrier_set:
        fail(f"{context} must cover exactly the carrier")
    inverses: dict[str, str] = {}
    for item, inverse in value.items():
        require_string(f"{context}.{item}", inverse)
        if inverse not in carrier_set:
            fail(f"{context}.{item} must be in the carrier")
        inverses[item] = inverse
    return inverses


def require_mapping_object(
    context: str,
    value: Any,
    domain: list[str],
    codomain: list[str],
) -> dict[str, str]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    domain_set = set(domain)
    codomain_set = set(codomain)
    if set(value) != domain_set:
        missing = sorted(domain_set - set(value))
        extra = sorted(set(value) - domain_set)
        fail(f"{context} must cover exactly the domain; missing={missing} extra={extra}")
    mapping: dict[str, str] = {}
    for source in domain:
        target = value[source]
        require_string(f"{context}.{source}", target)
        if target not in codomain_set:
            fail(f"{context}.{source} maps outside codomain")
        mapping[source] = target
    return mapping


def group_homomorphism_failures(
    domain_carrier: list[str],
    domain_op: dict[tuple[str, str], str],
    codomain_op: dict[tuple[str, str], str],
    mapping: dict[str, str],
) -> list[tuple[str, str, str, str]]:
    failures: list[tuple[str, str, str, str]] = []
    for left in domain_carrier:
        for right in domain_carrier:
            source_product = table_op(domain_op, left, right)
            mapped_product = mapping[source_product]
            product_of_images = table_op(codomain_op, mapping[left], mapping[right])
            if mapped_product != product_of_images:
                failures.append((left, right, mapped_product, product_of_images))
    return failures


def require_subset_exact(
    context: str,
    value: Any,
    universe: list[str],
    expected: set[str],
) -> set[str]:
    subset = set(require_string_list(context, value, nonempty=False))
    universe_set = set(universe)
    extra = sorted(subset - universe_set)
    if extra:
        fail(f"{context} contains elements outside universe: {extra}")
    if subset != expected:
        fail(f"{context} is incorrect: expected={sorted(expected)} actual={sorted(subset)}")
    return subset


def group_kernel(mapping: dict[str, str], codomain_identity: str) -> set[str]:
    return {source for source, target in mapping.items() if target == codomain_identity}


def group_image(mapping: dict[str, str]) -> set[str]:
    return set(mapping.values())


def require_cosets(
    context: str,
    value: Any,
    carrier: list[str],
) -> tuple[list[str], dict[str, str], dict[str, set[str]]]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty coset list")
    carrier_set = set(carrier)
    ids: list[str] = []
    representatives: dict[str, str] = {}
    members: dict[str, set[str]] = {}
    seen_members: set[str] = set()
    for index, item in enumerate(value):
        if not isinstance(item, dict):
            fail(f"{context}[{index}] must be an object")
        require_keys(f"{context}[{index}]", item, {"id", "representative", "members"})
        coset_id = item.get("id")
        representative = item.get("representative")
        require_string(f"{context}[{index}].id", coset_id)
        require_string(f"{context}[{index}].representative", representative)
        if coset_id in members:
            fail(f"{context} repeats coset id {coset_id!r}")
        if representative not in carrier_set:
            fail(f"{context}[{index}].representative is outside the carrier")
        member_set = set(require_string_list(f"{context}[{index}].members", item.get("members")))
        extra = sorted(member_set - carrier_set)
        if extra:
            fail(f"{context}[{index}].members contains elements outside carrier: {extra}")
        overlap = sorted(member_set & seen_members)
        if overlap:
            fail(f"{context}[{index}].members overlaps earlier cosets: {overlap}")
        seen_members.update(member_set)
        ids.append(coset_id)
        representatives[coset_id] = representative
        members[coset_id] = member_set
    if seen_members != carrier_set:
        missing = sorted(carrier_set - seen_members)
        extra = sorted(seen_members - carrier_set)
        fail(f"{context} must partition the carrier; missing={missing} extra={extra}")
    return ids, representatives, members


def require_quotient_table(
    context: str,
    value: Any,
    coset_ids: list[str],
) -> dict[tuple[str, str], str]:
    coset_set = set(coset_ids)
    if not isinstance(value, list) or len(value) != len(coset_ids):
        fail(f"{context} must have one row per coset")
    operation: dict[tuple[str, str], str] = {}
    for row_index, row in enumerate(value):
        if not isinstance(row, list) or len(row) != len(coset_ids):
            fail(f"{context}[{row_index}] must have one entry per coset")
        left = coset_ids[row_index]
        for col_index, result in enumerate(row):
            require_string(f"{context}[{row_index}][{col_index}]", result)
            if result not in coset_set:
                fail(f"{context}[{row_index}][{col_index}] is outside the quotient carrier")
            operation[(left, coset_ids[col_index])] = result
    return operation


def coset_id_for_member(context: str, member: str, coset_members: dict[str, set[str]]) -> str:
    hits = [coset_id for coset_id, members in coset_members.items() if member in members]
    if len(hits) != 1:
        fail(f"{context} member {member!r} is not in exactly one coset")
    return hits[0]


def validate_finite_algebra_homomorphisms(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    hom = checks["z4-to-z2-group-homomorphism"]
    if hom["expected_result"] != "sat":
        fail("z4-to-z2-group-homomorphism must expect sat")
    values = single_witness_values(hom, witnesses)
    domain_carrier, _, domain_op = require_group_structure("group hom domain", values.get("domain"))
    codomain_carrier, _, codomain_op = require_group_structure("group hom codomain", values.get("codomain"))
    mapping = require_mapping_object("group hom map", values.get("map"), domain_carrier, codomain_carrier)
    if group_homomorphism_failures(domain_carrier, domain_op, codomain_op, mapping):
        fail("z4-to-z2-group-homomorphism does not preserve the group operation")

    kernel_image = checks["kernel-image-replay"]
    if kernel_image["expected_result"] != "sat":
        fail("kernel-image-replay must expect sat")
    values = single_witness_values(kernel_image, witnesses)
    domain_carrier, _, domain_op = require_group_structure("kernel image domain", values.get("domain"))
    codomain_carrier, codomain_identity, codomain_op = require_group_structure(
        "kernel image codomain",
        values.get("codomain"),
    )
    mapping = require_mapping_object("kernel image map", values.get("map"), domain_carrier, codomain_carrier)
    if group_homomorphism_failures(domain_carrier, domain_op, codomain_op, mapping):
        fail("kernel-image-replay map does not preserve the group operation")
    require_subset_exact("kernel-image-replay kernel", values.get("kernel"), domain_carrier, group_kernel(mapping, codomain_identity))
    require_subset_exact("kernel-image-replay image", values.get("image"), codomain_carrier, group_image(mapping))

    quotient = checks["quotient-first-isomorphism-replay"]
    if quotient["expected_result"] != "sat":
        fail("quotient-first-isomorphism-replay must expect sat")
    values = single_witness_values(quotient, witnesses)
    domain_carrier, _, domain_op = require_group_structure("quotient domain", values.get("domain"))
    codomain_carrier, codomain_identity, codomain_op = require_group_structure("quotient codomain", values.get("codomain"))
    mapping = require_mapping_object("quotient map", values.get("map"), domain_carrier, codomain_carrier)
    if group_homomorphism_failures(domain_carrier, domain_op, codomain_op, mapping):
        fail("quotient-first-isomorphism-replay map does not preserve the group operation")
    kernel = require_subset_exact("quotient kernel", values.get("kernel"), domain_carrier, group_kernel(mapping, codomain_identity))
    image = require_subset_exact("quotient image", values.get("image"), codomain_carrier, group_image(mapping))
    coset_ids, representatives, coset_members = require_cosets("quotient cosets", values.get("cosets"), domain_carrier)
    quotient_identity = values.get("quotient_identity")
    require_string("quotient identity", quotient_identity)
    if quotient_identity not in set(coset_ids):
        fail("quotient identity must be one of the listed cosets")
    if coset_members[quotient_identity] != kernel:
        fail("quotient identity coset must equal the kernel")
    for coset_id in coset_ids:
        representative = representatives[coset_id]
        computed_coset = {table_op(domain_op, representative, kernel_member) for kernel_member in kernel}
        if computed_coset != coset_members[coset_id]:
            fail(f"quotient coset {coset_id} does not match representative times kernel")
        image_values = {mapping[member] for member in coset_members[coset_id]}
        if len(image_values) != 1:
            fail(f"quotient coset {coset_id} does not have a well-defined induced image")
    quotient_op = require_quotient_table("quotient quotient_table", values.get("quotient_table"), coset_ids)
    for left in coset_ids:
        for right in coset_ids:
            representative_product = table_op(domain_op, representatives[left], representatives[right])
            expected_coset = coset_id_for_member("quotient operation", representative_product, coset_members)
            if quotient_op[(left, right)] != expected_coset:
                fail("quotient-first-isomorphism-replay quotient operation is incorrect")
    induced_map = require_mapping_object("quotient induced_map", values.get("induced_map"), coset_ids, codomain_carrier)
    if set(induced_map.values()) != image:
        fail("quotient-first-isomorphism-replay induced map image does not match listed image")
    if len(set(induced_map.values())) != len(induced_map):
        fail("quotient-first-isomorphism-replay induced map is not injective")
    for coset_id in coset_ids:
        expected_image = mapping[representatives[coset_id]]
        if induced_map[coset_id] != expected_image:
            fail(f"quotient induced map for {coset_id} is not the representative image")
    if group_homomorphism_failures(coset_ids, quotient_op, codomain_op, induced_map):
        fail("quotient-first-isomorphism-replay induced map is not a homomorphism")

    ring_hom = checks["z4-to-z2-ring-homomorphism"]
    if ring_hom["expected_result"] != "sat":
        fail("z4-to-z2-ring-homomorphism must expect sat")
    values = single_witness_values(ring_hom, witnesses)
    domain_carrier, domain_zero, domain_one, domain_add, domain_mul = require_ring_tables("ring hom domain", values.get("domain"))
    codomain_carrier, codomain_zero, codomain_one, codomain_add, codomain_mul = require_ring_tables(
        "ring hom codomain",
        values.get("codomain"),
    )
    failures = ring_axiom_failures(domain_carrier, domain_zero, domain_one, domain_add, domain_mul)
    if failures:
        fail(f"z4-to-z2-ring-homomorphism domain is not a ring: {failures[0]}")
    failures = ring_axiom_failures(codomain_carrier, codomain_zero, codomain_one, codomain_add, codomain_mul)
    if failures:
        fail(f"z4-to-z2-ring-homomorphism codomain is not a ring: {failures[0]}")
    mapping = require_mapping_object("ring hom map", values.get("map"), domain_carrier, codomain_carrier)
    if mapping[domain_zero] != codomain_zero:
        fail("z4-to-z2-ring-homomorphism does not preserve zero")
    if domain_one is not None and codomain_one is not None and mapping[domain_one] != codomain_one:
        fail("z4-to-z2-ring-homomorphism does not preserve one")
    for left in domain_carrier:
        for right in domain_carrier:
            if mapping[table_op(domain_add, left, right)] != table_op(codomain_add, mapping[left], mapping[right]):
                fail("z4-to-z2-ring-homomorphism does not preserve addition")
            if mapping[table_op(domain_mul, left, right)] != table_op(codomain_mul, mapping[left], mapping[right]):
                fail("z4-to-z2-ring-homomorphism does not preserve multiplication")

    qf_uf = checks["qf-uf-homomorphism-preservation-alethe"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-homomorphism-preservation-alethe must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-homomorphism-preservation-alethe must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-homomorphism-preservation-alethe must use qf_uf_congruence_alethe validation")
    data = qf_uf.get("data", {})
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf homomorphism preservation smt2_artifact", smt2_artifact)
    check_source("qf-uf homomorphism preservation smt2_artifact", smt2_artifact)
    require_string("qf-uf homomorphism preservation proof_regression", data.get("proof_regression"))
    certificate = data.get("certificate")
    require_string("qf-uf homomorphism preservation certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf homomorphism preservation certificate must document zero-trust Alethe evidence")

    bad = checks["bad-group-homomorphism-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-group-homomorphism-rejected must be a checked unsat row")
    data = bad.get("data", {})
    domain_carrier, _, domain_op = require_group_structure("bad hom domain", data.get("domain"))
    codomain_carrier, _, codomain_op = require_group_structure("bad hom codomain", data.get("codomain"))
    mapping = require_mapping_object("bad hom map", data.get("map"), domain_carrier, codomain_carrier)
    failures = group_homomorphism_failures(domain_carrier, domain_op, codomain_op, mapping)
    if not failures:
        fail("bad-group-homomorphism-rejected map unexpectedly preserves the group operation")
    failing_pair = data.get("failing_pair")
    if not isinstance(failing_pair, list) or len(failing_pair) != 2:
        fail("bad-group-homomorphism-rejected failing_pair must be a two-element list")
    left, right = failing_pair
    require_string("bad hom failing_pair[0]", left)
    require_string("bad hom failing_pair[1]", right)
    if left not in set(domain_carrier) or right not in set(domain_carrier):
        fail("bad-group-homomorphism-rejected failing_pair references a source outside the domain")
    claimed_image = data.get("claimed_image")
    actual_homomorphic_image = data.get("actual_homomorphic_image")
    require_string("bad hom claimed_image", claimed_image)
    require_string("bad hom actual_homomorphic_image", actual_homomorphic_image)
    source_product = table_op(domain_op, left, right)
    if mapping[source_product] != claimed_image:
        fail("bad-group-homomorphism-rejected claimed_image does not match f(left * right)")
    computed_homomorphic_image = table_op(codomain_op, mapping[left], mapping[right])
    if computed_homomorphic_image != actual_homomorphic_image:
        fail("bad-group-homomorphism-rejected actual_homomorphic_image is incorrect")
    if claimed_image == actual_homomorphic_image:
        fail("bad-group-homomorphism-rejected malformed map unexpectedly agrees on failing_pair")

    horizon = checks["general-isomorphism-theorems-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-isomorphism-theorems-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-isomorphism-theorems-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general isomorphism target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general isomorphism future_checker", data.get("future_checker"))


def finite_field_axiom_failures(
    carrier: list[str],
    zero: str,
    one: str | None,
    add_op: dict[tuple[str, str], str],
    mul_op: dict[tuple[str, str], str],
) -> list[str]:
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        return failures
    if one is None:
        return ["field requires a multiplicative identity"]
    if not is_commutative(carrier, mul_op):
        return ["multiplication is not commutative"]
    for item in carrier:
        if item == zero:
            continue
        if not any(table_op(mul_op, item, candidate) == one for candidate in carrier):
            return [f"nonzero element {item} has no multiplicative inverse"]
    return []


def require_finite_field_tables(
    context: str,
    value: Any,
) -> tuple[list[str], str, str, dict[tuple[str, str], str], dict[tuple[str, str], str]]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    carrier, zero, one, add_op, mul_op = require_ring_tables(context, value)
    if one is None:
        fail(f"{context}.one is required for a finite field")
    failures = finite_field_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        fail(f"{context} is not a finite field: {failures[0]}")
    return carrier, zero, one, add_op, mul_op


def require_scalar_mul_table(
    context: str,
    value: Any,
    scalars: list[str],
    vectors: list[str],
) -> dict[tuple[str, str], str]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    scalar_set = set(scalars)
    vector_set = set(vectors)
    if set(value) != scalar_set:
        missing = sorted(scalar_set - set(value))
        extra = sorted(set(value) - scalar_set)
        fail(f"{context} must cover exactly the scalars; missing={missing} extra={extra}")
    scalar_mul: dict[tuple[str, str], str] = {}
    for scalar in scalars:
        row = value[scalar]
        if not isinstance(row, dict):
            fail(f"{context}.{scalar} must be an object")
        if set(row) != vector_set:
            missing = sorted(vector_set - set(row))
            extra = sorted(set(row) - vector_set)
            fail(f"{context}.{scalar} must cover vectors; missing={missing} extra={extra}")
        for vector in vectors:
            product = row[vector]
            require_string(f"{context}.{scalar}.{vector}", product)
            if product not in vector_set:
                fail(f"{context}.{scalar}.{vector} is outside the vector carrier")
            scalar_mul[(scalar, vector)] = product
    return scalar_mul


def require_vector_space_tables(
    context: str,
    value: Any,
    scalars: list[str],
) -> tuple[list[str], str, dict[tuple[str, str], str], dict[tuple[str, str], str], int]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    vectors = require_string_list(f"{context}.vectors", value.get("vectors"))
    vector_set = set(vectors)
    zero = value.get("zero")
    require_string(f"{context}.zero", zero)
    if zero not in vector_set:
        fail(f"{context}.zero must be in the vector carrier")
    add_op = require_binary_table(f"{context}.add", vectors, value.get("add"))
    scalar_mul = require_scalar_mul_table(f"{context}.scalar_mul", value.get("scalar_mul"), scalars, vectors)
    dimension = require_nonnegative_int(f"{context}.dimension", value.get("dimension"))
    return vectors, zero, add_op, scalar_mul, dimension


def vector_space_axiom_failures(
    field_carrier: list[str],
    field_zero: str,
    field_one: str,
    field_add: dict[tuple[str, str], str],
    field_mul: dict[tuple[str, str], str],
    vectors: list[str],
    vector_zero: str,
    vector_add: dict[tuple[str, str], str],
    scalar_mul: dict[tuple[str, str], str],
) -> list[str]:
    failures = group_axiom_failures(vectors, vector_zero, vector_add)
    if failures:
        return [f"vector addition {failures[0]}"]
    if not is_commutative(vectors, vector_add):
        return ["vector addition is not commutative"]
    for vector in vectors:
        if table_op(scalar_mul, field_one, vector) != vector:
            return [f"one scalar action fails for {vector}"]
        if table_op(scalar_mul, field_zero, vector) != vector_zero:
            return [f"zero scalar action fails for {vector}"]
    for scalar in field_carrier:
        if table_op(scalar_mul, scalar, vector_zero) != vector_zero:
            return [f"scalar action on zero vector fails for {scalar}"]
        for left in vectors:
            for right in vectors:
                left_sum = table_op(vector_add, left, right)
                lhs = table_op(scalar_mul, scalar, left_sum)
                rhs = table_op(vector_add, table_op(scalar_mul, scalar, left), table_op(scalar_mul, scalar, right))
                if lhs != rhs:
                    return [f"scalar distributivity over vector addition fails for {(scalar, left, right)}"]
    for left_scalar in field_carrier:
        for right_scalar in field_carrier:
            scalar_sum = table_op(field_add, left_scalar, right_scalar)
            scalar_product = table_op(field_mul, left_scalar, right_scalar)
            for vector in vectors:
                add_lhs = table_op(scalar_mul, scalar_sum, vector)
                add_rhs = table_op(
                    vector_add,
                    table_op(scalar_mul, left_scalar, vector),
                    table_op(scalar_mul, right_scalar, vector),
                )
                if add_lhs != add_rhs:
                    return [f"scalar addition distributivity fails for {(left_scalar, right_scalar, vector)}"]
                mul_lhs = table_op(scalar_mul, scalar_product, vector)
                mul_rhs = table_op(scalar_mul, left_scalar, table_op(scalar_mul, right_scalar, vector))
                if mul_lhs != mul_rhs:
                    return [f"scalar multiplication associativity fails for {(left_scalar, right_scalar, vector)}"]
    return []


def finite_dimension_from_size(context: str, field_size: int, size: int) -> int:
    if field_size <= 1:
        fail(f"{context} field size must be > 1")
    dimension = 0
    current = 1
    while current < size:
        current *= field_size
        dimension += 1
    if current != size:
        fail(f"{context} size {size} is not a power of field size {field_size}")
    return dimension


def require_vector_subset(context: str, value: Any, vectors: list[str], *, nonempty: bool = False) -> set[str]:
    items = require_string_list(context, value, nonempty=nonempty)
    vector_set = set(vectors)
    subset = set(items)
    extra = sorted(subset - vector_set)
    if extra:
        fail(f"{context} contains vectors outside the carrier: {extra}")
    return subset


def is_vector_subspace(
    subset: set[str],
    field_carrier: list[str],
    vector_zero: str,
    vector_add: dict[tuple[str, str], str],
    scalar_mul: dict[tuple[str, str], str],
) -> bool:
    if vector_zero not in subset:
        return False
    for left in subset:
        for right in subset:
            if table_op(vector_add, left, right) not in subset:
                return False
    for scalar in field_carrier:
        for vector in subset:
            if table_op(scalar_mul, scalar, vector) not in subset:
                return False
    return True


def span_vectors(
    basis: set[str],
    field_carrier: list[str],
    vector_zero: str,
    vector_add: dict[tuple[str, str], str],
    scalar_mul: dict[tuple[str, str], str],
) -> set[str]:
    span = {vector_zero}
    for basis_vector in sorted(basis):
        next_span: set[str] = set()
        for existing in span:
            for scalar in field_carrier:
                scaled = table_op(scalar_mul, scalar, basis_vector)
                next_span.add(table_op(vector_add, existing, scaled))
        span = next_span
    return span


def linear_map_failures(
    field_carrier: list[str],
    domain_vectors: list[str],
    domain_add: dict[tuple[str, str], str],
    domain_scalar_mul: dict[tuple[str, str], str],
    codomain_add: dict[tuple[str, str], str],
    codomain_scalar_mul: dict[tuple[str, str], str],
    mapping: dict[str, str],
) -> list[str]:
    for left in domain_vectors:
        for right in domain_vectors:
            lhs = mapping[table_op(domain_add, left, right)]
            rhs = table_op(codomain_add, mapping[left], mapping[right])
            if lhs != rhs:
                return [f"additivity fails for {(left, right)}"]
    for scalar in field_carrier:
        for vector in domain_vectors:
            lhs = mapping[table_op(domain_scalar_mul, scalar, vector)]
            rhs = table_op(codomain_scalar_mul, scalar, mapping[vector])
            if lhs != rhs:
                return [f"scalar preservation fails for {(scalar, vector)}"]
    return []


def require_checked_vector_space(
    context: str,
    value: Any,
    field_carrier: list[str],
    field_zero: str,
    field_one: str,
    field_add: dict[tuple[str, str], str],
    field_mul: dict[tuple[str, str], str],
) -> tuple[list[str], str, dict[tuple[str, str], str], dict[tuple[str, str], str], int]:
    vectors, zero, add_op, scalar_mul, dimension = require_vector_space_tables(context, value, field_carrier)
    failures = vector_space_axiom_failures(
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
        vectors,
        zero,
        add_op,
        scalar_mul,
    )
    if failures:
        fail(f"{context} failed vector-space axioms: {failures[0]}")
    computed_dimension = finite_dimension_from_size(context, len(field_carrier), len(vectors))
    if computed_dimension != dimension:
        fail(f"{context} listed dimension is incorrect")
    return vectors, zero, add_op, scalar_mul, dimension


def require_bilinear_map_table(
    context: str,
    value: Any,
    left_vectors: list[str],
    right_vectors: list[str],
    target_vectors: list[str],
) -> dict[tuple[str, str], str]:
    if not isinstance(value, list):
        fail(f"{context} must be a list")
    left_set = set(left_vectors)
    right_set = set(right_vectors)
    target_set = set(target_vectors)
    table: dict[tuple[str, str], str] = {}
    for index, row in enumerate(value):
        if not isinstance(row, dict):
            fail(f"{context}[{index}] must be an object")
        require_keys(f"{context}[{index}]", row, {"left", "right", "value"})
        left = row["left"]
        right = row["right"]
        output = row["value"]
        require_string(f"{context}[{index}].left", left)
        require_string(f"{context}[{index}].right", right)
        require_string(f"{context}[{index}].value", output)
        if left not in left_set:
            fail(f"{context}[{index}].left references a missing left vector")
        if right not in right_set:
            fail(f"{context}[{index}].right references a missing right vector")
        if output not in target_set:
            fail(f"{context}[{index}].value references a missing target vector")
        key = (left, right)
        if key in table:
            fail(f"{context} repeats pair {key}")
        table[key] = output
    expected = {(left, right) for left in left_vectors for right in right_vectors}
    if set(table) != expected:
        missing = sorted(expected - set(table))
        extra = sorted(set(table) - expected)
        fail(f"{context} must cover every pair; missing={missing} extra={extra}")
    return table


def bilinear_map_failures(
    field_carrier: list[str],
    left_vectors: list[str],
    left_add: dict[tuple[str, str], str],
    left_scalar_mul: dict[tuple[str, str], str],
    right_vectors: list[str],
    right_add: dict[tuple[str, str], str],
    right_scalar_mul: dict[tuple[str, str], str],
    target_add: dict[tuple[str, str], str],
    target_scalar_mul: dict[tuple[str, str], str],
    mapping: dict[tuple[str, str], str],
) -> list[str]:
    for left_a in left_vectors:
        for left_b in left_vectors:
            left_sum = table_op(left_add, left_a, left_b)
            for right in right_vectors:
                lhs = mapping[(left_sum, right)]
                rhs = table_op(target_add, mapping[(left_a, right)], mapping[(left_b, right)])
                if lhs != rhs:
                    return [f"left additivity fails for {(left_a, left_b, right)}"]
    for right_a in right_vectors:
        for right_b in right_vectors:
            right_sum = table_op(right_add, right_a, right_b)
            for left in left_vectors:
                lhs = mapping[(left, right_sum)]
                rhs = table_op(target_add, mapping[(left, right_a)], mapping[(left, right_b)])
                if lhs != rhs:
                    return [f"right additivity fails for {(left, right_a, right_b)}"]
    for scalar in field_carrier:
        for left in left_vectors:
            scaled_left = table_op(left_scalar_mul, scalar, left)
            for right in right_vectors:
                lhs = mapping[(scaled_left, right)]
                rhs = table_op(target_scalar_mul, scalar, mapping[(left, right)])
                if lhs != rhs:
                    return [f"left scalar preservation fails for {(scalar, left, right)}"]
        for right in right_vectors:
            scaled_right = table_op(right_scalar_mul, scalar, right)
            for left in left_vectors:
                lhs = mapping[(left, scaled_right)]
                rhs = table_op(target_scalar_mul, scalar, mapping[(left, right)])
                if lhs != rhs:
                    return [f"right scalar preservation fails for {(scalar, left, right)}"]
    return []


def require_tensor_basis_rows(
    context: str,
    value: Any,
    left_basis: set[str],
    right_basis: set[str],
    tensor_vectors: list[str],
) -> dict[tuple[str, str], str]:
    if not isinstance(value, list):
        fail(f"{context} must be a list")
    tensor_set = set(tensor_vectors)
    rows: dict[tuple[str, str], str] = {}
    for index, row in enumerate(value):
        if not isinstance(row, dict):
            fail(f"{context}[{index}] must be an object")
        require_keys(f"{context}[{index}]", row, {"left", "right", "tensor"})
        left = row["left"]
        right = row["right"]
        tensor = row["tensor"]
        require_string(f"{context}[{index}].left", left)
        require_string(f"{context}[{index}].right", right)
        require_string(f"{context}[{index}].tensor", tensor)
        if left not in left_basis:
            fail(f"{context}[{index}].left is outside the listed left basis")
        if right not in right_basis:
            fail(f"{context}[{index}].right is outside the listed right basis")
        if tensor not in tensor_set:
            fail(f"{context}[{index}].tensor is outside the tensor carrier")
        key = (left, right)
        if key in rows:
            fail(f"{context} repeats basis pair {key}")
        rows[key] = tensor
    expected = {(left, right) for left in left_basis for right in right_basis}
    if set(rows) != expected:
        fail(f"{context} must list exactly one tensor for each basis pair")
    return rows


def require_field_matrix(context: str, value: Any, field_carrier: list[str]) -> list[list[str]]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty matrix")
    field_set = set(field_carrier)
    matrix: list[list[str]] = []
    width: int | None = None
    for row_index, row in enumerate(value):
        if not isinstance(row, list) or not row:
            fail(f"{context}[{row_index}] must be a non-empty row")
        entries: list[str] = []
        for column_index, item in enumerate(row):
            require_string(f"{context}[{row_index}][{column_index}]", item)
            entries.append(item)
        if width is None:
            width = len(entries)
        elif len(entries) != width:
            fail(f"{context}[{row_index}] must have width {width}")
        extra = sorted(set(entries) - field_set)
        if extra:
            fail(f"{context}[{row_index}] contains values outside the field: {extra}")
        matrix.append(entries)
    return matrix


def kronecker_product(
    left: list[list[str]],
    right: list[list[str]],
    field_mul: dict[tuple[str, str], str],
) -> list[list[str]]:
    result: list[list[str]] = []
    for left_row in left:
        for right_row in right:
            result.append([
                table_op(field_mul, left_entry, right_entry)
                for left_entry in left_row
                for right_entry in right_row
            ])
    return result


def require_evaluation_table(
    context: str,
    value: Any,
    covectors: list[str],
    vectors: list[str],
    field_carrier: list[str],
) -> dict[tuple[str, str], str]:
    if not isinstance(value, list):
        fail(f"{context} must be a list")
    covector_set = set(covectors)
    vector_set = set(vectors)
    field_set = set(field_carrier)
    table: dict[tuple[str, str], str] = {}
    for index, row in enumerate(value):
        if not isinstance(row, dict):
            fail(f"{context}[{index}] must be an object")
        require_keys(f"{context}[{index}]", row, {"covector", "vector", "value"})
        covector = row["covector"]
        vector = row["vector"]
        output = row["value"]
        require_string(f"{context}[{index}].covector", covector)
        require_string(f"{context}[{index}].vector", vector)
        require_string(f"{context}[{index}].value", output)
        if covector not in covector_set:
            fail(f"{context}[{index}].covector references a missing covector")
        if vector not in vector_set:
            fail(f"{context}[{index}].vector references a missing vector")
        if output not in field_set:
            fail(f"{context}[{index}].value is outside the field")
        key = (covector, vector)
        if key in table:
            fail(f"{context} repeats evaluation pair {key}")
        table[key] = output
    expected = {(covector, vector) for covector in covectors for vector in vectors}
    if set(table) != expected:
        missing = sorted(expected - set(table))
        extra = sorted(set(table) - expected)
        fail(f"{context} must cover every covector/vector pair; missing={missing} extra={extra}")
    return table


def require_functional_table(
    context: str,
    value: Any,
    vectors: list[str],
    field_carrier: list[str],
) -> dict[str, str]:
    vector_set = set(vectors)
    field_set = set(field_carrier)
    functional: dict[str, str] = {}
    if isinstance(value, dict):
        if set(value) != vector_set:
            missing = sorted(vector_set - set(value))
            extra = sorted(set(value) - vector_set)
            fail(f"{context} must cover exactly the vectors; missing={missing} extra={extra}")
        for vector in vectors:
            output = value[vector]
            require_string(f"{context}.{vector}", output)
            if output not in field_set:
                fail(f"{context}.{vector} is outside the field")
            functional[vector] = output
        return functional
    if not isinstance(value, list):
        fail(f"{context} must be an object or row list")
    for index, row in enumerate(value):
        if not isinstance(row, dict):
            fail(f"{context}[{index}] must be an object")
        require_keys(f"{context}[{index}]", row, {"vector", "value"})
        vector = row["vector"]
        output = row["value"]
        require_string(f"{context}[{index}].vector", vector)
        require_string(f"{context}[{index}].value", output)
        if vector not in vector_set:
            fail(f"{context}[{index}].vector references a missing vector")
        if output not in field_set:
            fail(f"{context}[{index}].value is outside the field")
        if vector in functional:
            fail(f"{context} repeats vector {vector!r}")
        functional[vector] = output
    if set(functional) != vector_set:
        missing = sorted(vector_set - set(functional))
        extra = sorted(set(functional) - vector_set)
        fail(f"{context} must cover exactly the vectors; missing={missing} extra={extra}")
    return functional


def functional_linearity_failures(
    field_carrier: list[str],
    field_add: dict[tuple[str, str], str],
    field_mul: dict[tuple[str, str], str],
    vectors: list[str],
    vector_add: dict[tuple[str, str], str],
    scalar_mul: dict[tuple[str, str], str],
    functional: dict[str, str],
) -> list[str]:
    for left in vectors:
        for right in vectors:
            vector_sum = table_op(vector_add, left, right)
            lhs = functional[vector_sum]
            rhs = table_op(field_add, functional[left], functional[right])
            if lhs != rhs:
                return [f"additivity fails for {(left, right)}"]
    for scalar in field_carrier:
        for vector in vectors:
            scaled = table_op(scalar_mul, scalar, vector)
            lhs = functional[scaled]
            rhs = table_op(field_mul, scalar, functional[vector])
            if lhs != rhs:
                return [f"scalar preservation fails for {(scalar, vector)}"]
    return []


def dual_operation_failures(
    field_carrier: list[str],
    field_add: dict[tuple[str, str], str],
    field_mul: dict[tuple[str, str], str],
    primal_vectors: list[str],
    dual_vectors: list[str],
    dual_add: dict[tuple[str, str], str],
    dual_scalar_mul: dict[tuple[str, str], str],
    evaluation: dict[tuple[str, str], str],
) -> list[str]:
    for left in dual_vectors:
        for right in dual_vectors:
            dual_sum = table_op(dual_add, left, right)
            for vector in primal_vectors:
                lhs = evaluation[(dual_sum, vector)]
                rhs = table_op(field_add, evaluation[(left, vector)], evaluation[(right, vector)])
                if lhs != rhs:
                    return [f"dual addition is not pointwise for {(left, right, vector)}"]
    for scalar in field_carrier:
        for covector in dual_vectors:
            scaled_covector = table_op(dual_scalar_mul, scalar, covector)
            for vector in primal_vectors:
                lhs = evaluation[(scaled_covector, vector)]
                rhs = table_op(field_mul, scalar, evaluation[(covector, vector)])
                if lhs != rhs:
                    return [f"dual scalar action is not pointwise for {(scalar, covector, vector)}"]
    return []


def validate_finite_dual_spaces(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    table = checks["dual-space-table-replay"]
    if table["expected_result"] != "sat":
        fail("dual-space-table-replay must expect sat")
    values = single_witness_values(table, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("dual table field", values.get("field"))
    primal_vectors, _, primal_add, primal_scalar_mul, _ = require_checked_vector_space(
        "dual table primal_space",
        values.get("primal_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    dual_vectors, _, dual_add, dual_scalar_mul, _ = require_checked_vector_space(
        "dual table dual_space",
        values.get("dual_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    evaluation = require_evaluation_table(
        "dual table evaluation",
        values.get("evaluation"),
        dual_vectors,
        primal_vectors,
        field_carrier,
    )
    for covector in dual_vectors:
        functional = {vector: evaluation[(covector, vector)] for vector in primal_vectors}
        failures = functional_linearity_failures(
            field_carrier,
            field_add,
            field_mul,
            primal_vectors,
            primal_add,
            primal_scalar_mul,
            functional,
        )
        if failures:
            fail(f"dual-space-table-replay covector {covector!r} is not linear: {failures[0]}")
    failures = dual_operation_failures(
        field_carrier,
        field_add,
        field_mul,
        primal_vectors,
        dual_vectors,
        dual_add,
        dual_scalar_mul,
        evaluation,
    )
    if failures:
        fail(f"dual-space-table-replay failed pointwise dual operations: {failures[0]}")

    basis = checks["dual-basis-pairing-replay"]
    if basis["expected_result"] != "sat" or basis.get("proof_status") != "checked":
        fail("dual-basis-pairing-replay must be a checked sat row")
    values = single_witness_values(basis, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("dual basis field", values.get("field"))
    primal_vectors, _, _, _, _ = require_checked_vector_space(
        "dual basis primal_space",
        values.get("primal_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    dual_vectors, _, _, _, _ = require_checked_vector_space(
        "dual basis dual_space",
        values.get("dual_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    evaluation = require_evaluation_table(
        "dual basis evaluation",
        values.get("evaluation"),
        dual_vectors,
        primal_vectors,
        field_carrier,
    )
    basis_vectors = require_string_list("dual basis basis_vectors", values.get("basis_vectors"))
    dual_basis = require_string_list("dual basis dual_basis", values.get("dual_basis"))
    if len(basis_vectors) != len(dual_basis):
        fail("dual-basis-pairing-replay basis and dual_basis must have equal length")
    if set(basis_vectors) - set(primal_vectors):
        fail("dual-basis-pairing-replay basis_vectors contains missing primal vectors")
    if set(dual_basis) - set(dual_vectors):
        fail("dual-basis-pairing-replay dual_basis contains missing covectors")
    pairing_matrix = require_field_matrix("dual basis pairing_matrix", values.get("pairing_matrix"), field_carrier)
    expected_pairing = [
        [evaluation[(covector, vector)] for vector in basis_vectors]
        for covector in dual_basis
    ]
    if pairing_matrix != expected_pairing:
        fail("dual-basis-pairing-replay pairing matrix does not match evaluation")
    identity = [
        [field_one if row == column else field_zero for column in range(len(basis_vectors))]
        for row in range(len(dual_basis))
    ]
    if pairing_matrix != identity:
        fail("dual-basis-pairing-replay pairing matrix is not the identity")

    annihilator = checks["annihilator-replay"]
    if annihilator["expected_result"] != "sat" or annihilator.get("proof_status") != "checked":
        fail("annihilator-replay must be a checked sat row")
    values = single_witness_values(annihilator, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("annihilator field", values.get("field"))
    primal_vectors, primal_zero, primal_add, primal_scalar_mul, _ = require_checked_vector_space(
        "annihilator primal_space",
        values.get("primal_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    dual_vectors, dual_zero, dual_add, dual_scalar_mul, _ = require_checked_vector_space(
        "annihilator dual_space",
        values.get("dual_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    evaluation = require_evaluation_table(
        "annihilator evaluation",
        values.get("evaluation"),
        dual_vectors,
        primal_vectors,
        field_carrier,
    )
    subspace = require_vector_subset("annihilator annihilator_subspace", values.get("annihilator_subspace"), primal_vectors)
    if not is_vector_subspace(subspace, field_carrier, primal_zero, primal_add, primal_scalar_mul):
        fail("annihilator-replay listed primal subspace is not a subspace")
    listed_annihilator = require_vector_subset("annihilator annihilator", values.get("annihilator"), dual_vectors)
    computed_annihilator = {
        covector
        for covector in dual_vectors
        if all(evaluation[(covector, vector)] == field_zero for vector in subspace)
    }
    if listed_annihilator != computed_annihilator:
        fail(
            "annihilator-replay listed annihilator is incorrect: "
            f"expected={sorted(computed_annihilator)} actual={sorted(listed_annihilator)}"
        )
    if not is_vector_subspace(listed_annihilator, field_carrier, dual_zero, dual_add, dual_scalar_mul):
        fail("annihilator-replay listed annihilator is not a dual subspace")
    dimension = require_nonnegative_int("annihilator annihilator_dimension", values.get("annihilator_dimension"))
    if finite_dimension_from_size("annihilator dimension", len(field_carrier), len(listed_annihilator)) != dimension:
        fail("annihilator-replay listed annihilator_dimension is incorrect")

    transpose = checks["transpose-map-replay"]
    if transpose["expected_result"] != "sat" or transpose.get("proof_status") != "checked":
        fail("transpose-map-replay must be a checked sat row")
    values = single_witness_values(transpose, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("transpose field", values.get("field"))
    domain_vectors, _, domain_add, domain_scalar_mul, _ = require_checked_vector_space(
        "transpose domain_space",
        values.get("domain_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    codomain_vectors, _, codomain_add, codomain_scalar_mul, _ = require_checked_vector_space(
        "transpose codomain_space",
        values.get("codomain_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    domain_dual_vectors, _, domain_dual_add, domain_dual_scalar_mul, _ = require_checked_vector_space(
        "transpose domain_dual",
        values.get("domain_dual"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    codomain_dual_vectors, _, codomain_dual_add, codomain_dual_scalar_mul, _ = require_checked_vector_space(
        "transpose codomain_dual",
        values.get("codomain_dual"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    domain_evaluation = require_evaluation_table(
        "transpose domain_evaluation",
        values.get("domain_evaluation"),
        domain_dual_vectors,
        domain_vectors,
        field_carrier,
    )
    codomain_evaluation = require_evaluation_table(
        "transpose codomain_evaluation",
        values.get("codomain_evaluation"),
        codomain_dual_vectors,
        codomain_vectors,
        field_carrier,
    )
    mapping = require_mapping_object("transpose map", values.get("map"), domain_vectors, codomain_vectors)
    failures = linear_map_failures(
        field_carrier,
        domain_vectors,
        domain_add,
        domain_scalar_mul,
        codomain_add,
        codomain_scalar_mul,
        mapping,
    )
    if failures:
        fail(f"transpose-map-replay map is not linear: {failures[0]}")
    transpose_mapping = require_mapping_object(
        "transpose transpose_map",
        values.get("transpose_map"),
        codomain_dual_vectors,
        domain_dual_vectors,
    )
    failures = linear_map_failures(
        field_carrier,
        codomain_dual_vectors,
        codomain_dual_add,
        codomain_dual_scalar_mul,
        domain_dual_add,
        domain_dual_scalar_mul,
        transpose_mapping,
    )
    if failures:
        fail(f"transpose-map-replay transpose_map is not linear: {failures[0]}")
    for covector in codomain_dual_vectors:
        for vector in domain_vectors:
            lhs = domain_evaluation[(transpose_mapping[covector], vector)]
            rhs = codomain_evaluation[(covector, mapping[vector])]
            if lhs != rhs:
                fail(f"transpose-map-replay transpose equation fails for {(covector, vector)}")

    bad = checks["bad-covector-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-covector-rejected must be a checked unsat row")
    data = bad.get("data", {})
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("bad covector field", data.get("field"))
    primal_vectors, _, primal_add, primal_scalar_mul, _ = require_checked_vector_space(
        "bad covector primal_space",
        data.get("primal_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    functional = require_functional_table("bad covector functional", data.get("functional"), primal_vectors, field_carrier)
    failures = functional_linearity_failures(
        field_carrier,
        field_add,
        field_mul,
        primal_vectors,
        primal_add,
        primal_scalar_mul,
        functional,
    )
    if not failures:
        fail("bad-covector-rejected functional unexpectedly is linear")
    failure = data.get("failing_additivity")
    if not isinstance(failure, dict):
        fail("bad-covector-rejected failing_additivity must be an object")
    left = failure.get("left")
    right = failure.get("right")
    claimed = failure.get("claimed")
    actual_sum = failure.get("actual_sum")
    require_string("bad covector failing_additivity.left", left)
    require_string("bad covector failing_additivity.right", right)
    require_string("bad covector failing_additivity.claimed", claimed)
    require_string("bad covector failing_additivity.actual_sum", actual_sum)
    if left not in set(primal_vectors) or right not in set(primal_vectors):
        fail("bad-covector-rejected failing_additivity references a missing vector")
    if claimed not in set(field_carrier) or actual_sum not in set(field_carrier):
        fail("bad-covector-rejected failing_additivity values must be field elements")
    vector_sum = table_op(primal_add, left, right)
    if functional[vector_sum] != claimed:
        fail("bad-covector-rejected claimed value does not match f(left + right)")
    computed_sum = table_op(field_add, functional[left], functional[right])
    if computed_sum != actual_sum:
        fail("bad-covector-rejected actual_sum does not match f(left) + f(right)")
    if claimed == actual_sum:
        fail("bad-covector-rejected failing_additivity unexpectedly agrees")
    qf_uf = checks["qf-uf-bad-covector-additivity"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-bad-covector-additivity must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-bad-covector-additivity must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail(
            "qf-uf-bad-covector-additivity must use qf_uf_congruence_alethe validation"
        )
    qf_data = qf_uf.get("data", {})
    if qf_data.get("field") != "F2":
        fail("qf-uf-bad-covector-additivity field must be F2")
    if qf_data.get("space") != "F2^2":
        fail("qf-uf-bad-covector-additivity space must be F2^2")
    values = qf_data.get("functional_values")
    if not isinstance(values, dict):
        fail("qf-uf-bad-covector-additivity functional_values must be an object")
    for vector in (left, right, vector_sum):
        require_string(
            f"qf-uf bad covector functional_values[{vector}]",
            values.get(vector),
        )
        if values[vector] != functional[vector]:
            fail(
                "qf-uf-bad-covector-additivity functional_values must match bad-covector-rejected"
            )
    qf_failure = qf_data.get("failing_additivity")
    if not isinstance(qf_failure, dict):
        fail("qf-uf-bad-covector-additivity failing_additivity must be an object")
    if qf_failure.get("left") != left:
        fail("qf-uf-bad-covector-additivity left vector must match bad-covector-rejected")
    if qf_failure.get("right") != right:
        fail("qf-uf-bad-covector-additivity right vector must match bad-covector-rejected")
    if qf_failure.get("sum_vector") != vector_sum:
        fail("qf-uf-bad-covector-additivity sum_vector must match bad-covector-rejected")
    if qf_failure.get("claimed") != claimed:
        fail("qf-uf-bad-covector-additivity claimed value must match bad-covector-rejected")
    if qf_failure.get("actual_sum") != actual_sum:
        fail("qf-uf-bad-covector-additivity actual_sum must match bad-covector-rejected")
    qf_alethe_claim = qf_data.get("alethe_additivity_claim")
    require_string("qf-uf bad covector alethe_additivity_claim", qf_alethe_claim)
    if qf_alethe_claim != f"f({left}+{right}) = f({left})+f({right})":
        fail(
            "qf-uf-bad-covector-additivity must document the Alethe additivity claim"
        )
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("qf-uf bad covector smt2_artifact", smt2_artifact)
    expected_smt2 = (
        "artifacts/examples/math/finite-dual-spaces-v0/smt2/"
        "bad-covector-additivity-conflict.smt2"
    )
    if smt2_artifact != expected_smt2:
        fail(
            "qf-uf-bad-covector-additivity smt2_artifact must name the checked source artifact"
        )
    check_source("qf-uf bad covector smt2_artifact", smt2_artifact)
    proof_regression = qf_data.get("proof_regression")
    require_string("qf-uf bad covector proof_regression", proof_regression)
    if "finite_dual_spaces_bad_covector_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-covector-additivity must link the Alethe regression")
    certificate = qf_data.get("certificate")
    require_string("qf-uf bad covector certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail(
            "qf-uf-bad-covector-additivity certificate must document zero-trust Alethe evidence"
        )

    horizon = checks["general-duality-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-duality-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-duality-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general duality target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general duality future_checker", data.get("future_checker"))


def validate_finite_tensor_products(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    basis = checks["tensor-product-basis-replay"]
    if basis["expected_result"] != "sat":
        fail("tensor-product-basis-replay must expect sat")
    values = single_witness_values(basis, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("tensor basis field", values.get("field"))
    left_vectors, _, _, _, left_dimension = require_checked_vector_space(
        "tensor basis left_space",
        values.get("left_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    right_vectors, _, _, _, right_dimension = require_checked_vector_space(
        "tensor basis right_space",
        values.get("right_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    tensor_vectors, tensor_zero, tensor_add, tensor_scalar_mul, tensor_dimension = require_checked_vector_space(
        "tensor basis tensor_space",
        values.get("tensor_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    basis_left = require_vector_subset("tensor basis basis_left", values.get("basis_left"), left_vectors, nonempty=True)
    basis_right = require_vector_subset("tensor basis basis_right", values.get("basis_right"), right_vectors, nonempty=True)
    basis_rows = require_tensor_basis_rows("tensor basis basis_tensors", values.get("basis_tensors"), basis_left, basis_right, tensor_vectors)
    dimension_product = require_nonnegative_int("tensor basis dimension_product", values.get("dimension_product"))
    if dimension_product != left_dimension * right_dimension:
        fail("tensor-product-basis-replay dimension_product is incorrect")
    if tensor_dimension != dimension_product:
        fail("tensor-product-basis-replay tensor-space dimension is not the dimension product")
    tensor_basis_values = set(basis_rows.values())
    if len(tensor_basis_values) != dimension_product:
        fail("tensor-product-basis-replay basis tensor values must be distinct")
    if span_vectors(tensor_basis_values, field_carrier, tensor_zero, tensor_add, tensor_scalar_mul) != set(tensor_vectors):
        fail("tensor-product-basis-replay listed basis tensors do not span the tensor space")

    bilinear = checks["bilinear-map-table-replay"]
    if bilinear["expected_result"] != "sat" or bilinear.get("proof_status") != "checked":
        fail("bilinear-map-table-replay must be a checked sat row")
    values = single_witness_values(bilinear, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("bilinear field", values.get("field"))
    left_vectors, _, left_add, left_scalar_mul, _ = require_checked_vector_space(
        "bilinear left_space",
        values.get("left_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    right_vectors, _, right_add, right_scalar_mul, _ = require_checked_vector_space(
        "bilinear right_space",
        values.get("right_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    target_vectors, _, target_add, target_scalar_mul, _ = require_checked_vector_space(
        "bilinear target_space",
        values.get("target_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    mapping = require_bilinear_map_table("bilinear map", values.get("map"), left_vectors, right_vectors, target_vectors)
    failures = bilinear_map_failures(
        field_carrier,
        left_vectors,
        left_add,
        left_scalar_mul,
        right_vectors,
        right_add,
        right_scalar_mul,
        target_add,
        target_scalar_mul,
        mapping,
    )
    if failures:
        fail(f"bilinear-map-table-replay map is not bilinear: {failures[0]}")

    factor = checks["universal-factorization-replay"]
    if factor["expected_result"] != "sat" or factor.get("proof_status") != "checked":
        fail("universal-factorization-replay must be a checked sat row")
    values = single_witness_values(factor, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("tensor factor field", values.get("field"))
    left_vectors, _, left_add, left_scalar_mul, _ = require_checked_vector_space(
        "tensor factor left_space",
        values.get("left_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    right_vectors, _, right_add, right_scalar_mul, _ = require_checked_vector_space(
        "tensor factor right_space",
        values.get("right_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    tensor_vectors, _, tensor_add, tensor_scalar_mul, _ = require_checked_vector_space(
        "tensor factor tensor_space",
        values.get("tensor_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    codomain_vectors, _, codomain_add, codomain_scalar_mul, _ = require_checked_vector_space(
        "tensor factor codomain_space",
        values.get("codomain_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    tensor_map = require_bilinear_map_table("tensor factor tensor_map", values.get("tensor_map"), left_vectors, right_vectors, tensor_vectors)
    failures = bilinear_map_failures(
        field_carrier,
        left_vectors,
        left_add,
        left_scalar_mul,
        right_vectors,
        right_add,
        right_scalar_mul,
        tensor_add,
        tensor_scalar_mul,
        tensor_map,
    )
    if failures:
        fail(f"universal-factorization-replay tensor_map is not bilinear: {failures[0]}")
    factor_map = require_mapping_object("tensor factor factor_map", values.get("factor_map"), tensor_vectors, codomain_vectors)
    failures = linear_map_failures(
        field_carrier,
        tensor_vectors,
        tensor_add,
        tensor_scalar_mul,
        codomain_add,
        codomain_scalar_mul,
        factor_map,
    )
    if failures:
        fail(f"universal-factorization-replay factor_map is not linear: {failures[0]}")
    factored_map = require_bilinear_map_table("tensor factor factored_map", values.get("factored_map"), left_vectors, right_vectors, codomain_vectors)
    failures = bilinear_map_failures(
        field_carrier,
        left_vectors,
        left_add,
        left_scalar_mul,
        right_vectors,
        right_add,
        right_scalar_mul,
        codomain_add,
        codomain_scalar_mul,
        factored_map,
    )
    if failures:
        fail(f"universal-factorization-replay factored_map is not bilinear: {failures[0]}")
    for left in left_vectors:
        for right in right_vectors:
            if factored_map[(left, right)] != factor_map[tensor_map[(left, right)]]:
                fail(f"universal-factorization-replay does not factor at {(left, right)}")

    kronecker = checks["kronecker-product-replay"]
    if kronecker["expected_result"] != "sat" or kronecker.get("proof_status") != "checked":
        fail("kronecker-product-replay must be a checked sat row")
    values = single_witness_values(kronecker, witnesses)
    field_carrier, _, _, _, field_mul = require_finite_field_tables("kronecker field", values.get("field"))
    left_matrix = require_field_matrix("kronecker left_matrix", values.get("left_matrix"), field_carrier)
    right_matrix = require_field_matrix("kronecker right_matrix", values.get("right_matrix"), field_carrier)
    listed_product = require_field_matrix("kronecker kronecker_product", values.get("kronecker_product"), field_carrier)
    if listed_product != kronecker_product(left_matrix, right_matrix, field_mul):
        fail("kronecker-product-replay listed product is incorrect")

    bad = checks["bad-bilinear-map-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-bilinear-map-rejected must be a checked unsat row")
    data = bad.get("data", {})
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("bad bilinear field", data.get("field"))
    left_vectors, _, left_add, left_scalar_mul, _ = require_checked_vector_space(
        "bad bilinear left_space",
        data.get("left_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    right_vectors, _, right_add, right_scalar_mul, _ = require_checked_vector_space(
        "bad bilinear right_space",
        data.get("right_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    target_vectors, _, target_add, target_scalar_mul, _ = require_checked_vector_space(
        "bad bilinear target_space",
        data.get("target_space"),
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
    )
    mapping = require_bilinear_map_table("bad bilinear map", data.get("map"), left_vectors, right_vectors, target_vectors)
    failures = bilinear_map_failures(
        field_carrier,
        left_vectors,
        left_add,
        left_scalar_mul,
        right_vectors,
        right_add,
        right_scalar_mul,
        target_add,
        target_scalar_mul,
        mapping,
    )
    if not failures:
        fail("bad-bilinear-map-rejected map unexpectedly is bilinear")
    witness = data.get("failing_left_additivity")
    if not isinstance(witness, dict):
        fail("bad-bilinear-map-rejected failing_left_additivity must be an object")
    left_a = witness.get("left_a")
    left_b = witness.get("left_b")
    right = witness.get("right")
    claimed = witness.get("claimed")
    actual_sum = witness.get("actual_sum")
    for name, value in [
        ("left_a", left_a),
        ("left_b", left_b),
        ("right", right),
        ("claimed", claimed),
        ("actual_sum", actual_sum),
    ]:
        require_string(f"bad bilinear failing_left_additivity.{name}", value)
    if left_a not in set(left_vectors) or left_b not in set(left_vectors) or right not in set(right_vectors):
        fail("bad-bilinear-map-rejected failing_left_additivity references a missing vector")
    left_sum = table_op(left_add, left_a, left_b)
    if mapping[(left_sum, right)] != claimed:
        fail("bad-bilinear-map-rejected claimed value does not match beta(left_a + left_b, right)")
    recomputed_sum = table_op(target_add, mapping[(left_a, right)], mapping[(left_b, right)])
    if recomputed_sum != actual_sum:
        fail("bad-bilinear-map-rejected actual_sum is incorrect")
    if claimed == actual_sum:
        fail("bad-bilinear-map-rejected malformed map unexpectedly satisfies the documented additivity row")
    qf_uf = checks["qf-uf-bad-bilinear-left-additivity"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-bad-bilinear-left-additivity must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-bad-bilinear-left-additivity must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-bilinear-left-additivity must use qf_uf_congruence_alethe validation")
    qf_data = qf_uf.get("data", {})
    if qf_data.get("field") != "F2":
        fail("qf-uf-bad-bilinear-left-additivity field must be F2")
    if qf_data.get("left_space") != "F2^2":
        fail("qf-uf-bad-bilinear-left-additivity left_space must be F2^2")
    if qf_data.get("right_space") != "F2":
        fail("qf-uf-bad-bilinear-left-additivity right_space must be F2")
    if qf_data.get("target_space") != "F2^2":
        fail("qf-uf-bad-bilinear-left-additivity target_space must be F2^2")
    table_values = qf_data.get("table_values")
    if not isinstance(table_values, dict):
        fail("qf-uf-bad-bilinear-left-additivity table_values must be an object")
    expected_table_values = {
        f"beta({left_a},{right})": mapping[(left_a, right)],
        f"beta({left_b},{right})": mapping[(left_b, right)],
        f"beta({left_sum},{right})": mapping[(left_sum, right)],
    }
    for key, value in expected_table_values.items():
        require_string(f"qf-uf bad bilinear table_values[{key}]", table_values.get(key))
        if table_values[key] != value:
            fail("qf-uf-bad-bilinear-left-additivity table_values must match bad-bilinear-map-rejected")
    qf_witness = qf_data.get("failing_left_additivity")
    if not isinstance(qf_witness, dict):
        fail("qf-uf-bad-bilinear-left-additivity failing_left_additivity must be an object")
    if qf_witness.get("left_a") != left_a:
        fail("qf-uf-bad-bilinear-left-additivity left_a must match bad-bilinear-map-rejected")
    if qf_witness.get("left_b") != left_b:
        fail("qf-uf-bad-bilinear-left-additivity left_b must match bad-bilinear-map-rejected")
    if qf_witness.get("left_sum") != left_sum:
        fail("qf-uf-bad-bilinear-left-additivity left_sum must match bad-bilinear-map-rejected")
    if qf_witness.get("right") != right:
        fail("qf-uf-bad-bilinear-left-additivity right must match bad-bilinear-map-rejected")
    if qf_witness.get("claimed") != claimed:
        fail("qf-uf-bad-bilinear-left-additivity claimed value must match bad-bilinear-map-rejected")
    if qf_witness.get("actual_sum") != actual_sum:
        fail("qf-uf-bad-bilinear-left-additivity actual_sum must match bad-bilinear-map-rejected")
    alethe_claim = qf_data.get("alethe_left_additivity_claim")
    require_string("qf-uf bad bilinear alethe_left_additivity_claim", alethe_claim)
    if alethe_claim != f"beta({left_a}+{left_b},{right}) = beta({left_a},{right})+beta({left_b},{right})":
        fail("qf-uf-bad-bilinear-left-additivity must document the Alethe left-additivity claim")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("qf-uf bad bilinear smt2_artifact", smt2_artifact)
    expected_smt2 = (
        "artifacts/examples/math/finite-tensor-products-v0/smt2/"
        "bad-bilinear-left-additivity-conflict.smt2"
    )
    if smt2_artifact != expected_smt2:
        fail("qf-uf-bad-bilinear-left-additivity smt2_artifact must name the checked source artifact")
    check_source("qf-uf bad bilinear smt2_artifact", smt2_artifact)
    proof_regression = qf_data.get("proof_regression")
    require_string("qf-uf bad bilinear proof_regression", proof_regression)
    if "finite_tensor_products_bad_bilinear_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-bilinear-left-additivity must link the Alethe regression")
    certificate = qf_data.get("certificate")
    require_string("qf-uf bad bilinear certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-bilinear-left-additivity certificate must document zero-trust Alethe evidence")

    horizon = checks["general-tensor-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-tensor-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-tensor-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general tensor target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general tensor future_checker", data.get("future_checker"))


def validate_finite_vector_spaces(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    vector_space = checks["f2-plane-vector-space"]
    if vector_space["expected_result"] != "sat":
        fail("f2-plane-vector-space must expect sat")
    values = single_witness_values(vector_space, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("vector space field", values.get("field"))
    vectors, vector_zero, vector_add, scalar_mul, listed_dimension = require_vector_space_tables(
        "vector space",
        values.get("space"),
        field_carrier,
    )
    failures = vector_space_axiom_failures(
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
        vectors,
        vector_zero,
        vector_add,
        scalar_mul,
    )
    if failures:
        fail(f"f2-plane-vector-space failed vector-space axioms: {failures[0]}")
    if finite_dimension_from_size("f2-plane-vector-space", len(field_carrier), len(vectors)) != listed_dimension:
        fail("f2-plane-vector-space listed dimension is incorrect")

    subspace = checks["subspace-span-replay"]
    if subspace["expected_result"] != "sat":
        fail("subspace-span-replay must expect sat")
    values = single_witness_values(subspace, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("subspace field", values.get("field"))
    vectors, vector_zero, vector_add, scalar_mul, _ = require_vector_space_tables("subspace space", values.get("space"), field_carrier)
    failures = vector_space_axiom_failures(
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
        vectors,
        vector_zero,
        vector_add,
        scalar_mul,
    )
    if failures:
        fail(f"subspace-span-replay ambient space failed axioms: {failures[0]}")
    subset = require_vector_subset("subspace subset", values.get("subset"), vectors, nonempty=True)
    if not is_vector_subspace(subset, field_carrier, vector_zero, vector_add, scalar_mul):
        fail("subspace-span-replay listed subset is not a subspace")
    basis = require_vector_subset("subspace basis", values.get("basis"), vectors, nonempty=True)
    expected_span = require_vector_subset("subspace span", values.get("span"), vectors, nonempty=True)
    computed_span = span_vectors(basis, field_carrier, vector_zero, vector_add, scalar_mul)
    if computed_span != expected_span:
        fail("subspace-span-replay listed span is incorrect")
    if computed_span != subset:
        fail("subspace-span-replay span does not equal the listed subset")
    listed_subspace_dimension = require_nonnegative_int("subspace subspace_dimension", values.get("subspace_dimension"))
    if finite_dimension_from_size("subspace-span-replay", len(field_carrier), len(subset)) != listed_subspace_dimension:
        fail("subspace-span-replay listed subspace dimension is incorrect")

    linear = checks["linear-map-kernel-image"]
    if linear["expected_result"] != "sat":
        fail("linear-map-kernel-image must expect sat")
    values = single_witness_values(linear, witnesses)
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("linear map field", values.get("field"))
    domain_vectors, domain_zero, domain_add, domain_scalar_mul, domain_dimension = require_vector_space_tables(
        "linear map domain",
        values.get("domain"),
        field_carrier,
    )
    codomain_vectors, codomain_zero, codomain_add, codomain_scalar_mul, _ = require_vector_space_tables(
        "linear map codomain",
        values.get("codomain"),
        field_carrier,
    )
    for context, vectors_, zero_, add_, scalar_mul_ in [
        ("linear map domain", domain_vectors, domain_zero, domain_add, domain_scalar_mul),
        ("linear map codomain", codomain_vectors, codomain_zero, codomain_add, codomain_scalar_mul),
    ]:
        failures = vector_space_axiom_failures(
            field_carrier,
            field_zero,
            field_one,
            field_add,
            field_mul,
            vectors_,
            zero_,
            add_,
            scalar_mul_,
        )
        if failures:
            fail(f"{context} failed vector-space axioms: {failures[0]}")
    mapping = require_mapping_object("linear map", values.get("map"), domain_vectors, codomain_vectors)
    failures = linear_map_failures(
        field_carrier,
        domain_vectors,
        domain_add,
        domain_scalar_mul,
        codomain_add,
        codomain_scalar_mul,
        mapping,
    )
    if failures:
        fail(f"linear-map-kernel-image map is not linear: {failures[0]}")
    computed_kernel = {vector for vector in domain_vectors if mapping[vector] == codomain_zero}
    computed_image = set(mapping.values())
    kernel = require_vector_subset("linear map kernel", values.get("kernel"), domain_vectors)
    image = require_vector_subset("linear map image", values.get("image"), codomain_vectors)
    if kernel != computed_kernel:
        fail("linear-map-kernel-image listed kernel is incorrect")
    if image != computed_image:
        fail("linear-map-kernel-image listed image is incorrect")
    if not is_vector_subspace(kernel, field_carrier, domain_zero, domain_add, domain_scalar_mul):
        fail("linear-map-kernel-image kernel is not a subspace")
    if not is_vector_subspace(image, field_carrier, codomain_zero, codomain_add, codomain_scalar_mul):
        fail("linear-map-kernel-image image is not a subspace")

    rank_nullity = checks["rank-nullity-replay"]
    if rank_nullity["expected_result"] != "sat":
        fail("rank-nullity-replay must expect sat")
    values = single_witness_values(rank_nullity, witnesses)
    listed_domain_dimension = require_nonnegative_int("rank-nullity domain_dimension", values.get("domain_dimension"))
    listed_kernel_dimension = require_nonnegative_int("rank-nullity kernel_dimension", values.get("kernel_dimension"))
    listed_image_dimension = require_nonnegative_int("rank-nullity image_dimension", values.get("image_dimension"))
    if domain_dimension != listed_domain_dimension:
        fail("rank-nullity-replay domain dimension disagrees with the domain table")
    if finite_dimension_from_size("rank-nullity kernel", len(field_carrier), len(kernel)) != listed_kernel_dimension:
        fail("rank-nullity-replay listed kernel dimension is incorrect")
    if finite_dimension_from_size("rank-nullity image", len(field_carrier), len(image)) != listed_image_dimension:
        fail("rank-nullity-replay listed image dimension is incorrect")
    if listed_domain_dimension != listed_kernel_dimension + listed_image_dimension:
        fail("rank-nullity-replay dimension equation does not hold")

    bad = checks["bad-subspace-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-subspace-rejected must be a checked unsat row")
    data = bad.get("data", {})
    field_carrier, field_zero, field_one, field_add, field_mul = require_finite_field_tables("bad subspace field", data.get("field"))
    vectors, vector_zero, vector_add, scalar_mul, _ = require_vector_space_tables("bad subspace space", data.get("space"), field_carrier)
    failures = vector_space_axiom_failures(
        field_carrier,
        field_zero,
        field_one,
        field_add,
        field_mul,
        vectors,
        vector_zero,
        vector_add,
        scalar_mul,
    )
    if failures:
        fail(f"bad-subspace-rejected ambient space failed axioms: {failures[0]}")
    subset = require_vector_subset("bad subspace subset", data.get("subset"), vectors, nonempty=True)
    if is_vector_subspace(subset, field_carrier, vector_zero, vector_add, scalar_mul):
        fail("bad-subspace-rejected subset unexpectedly is a subspace")
    failing_sum = data.get("failing_sum")
    if not isinstance(failing_sum, list) or len(failing_sum) != 2:
        fail("bad-subspace-rejected failing_sum must be a two-element list")
    left, right = failing_sum
    require_string("bad subspace failing_sum[0]", left)
    require_string("bad subspace failing_sum[1]", right)
    if left not in subset or right not in subset:
        fail("bad-subspace-rejected failing_sum entries must be in the claimed subset")
    actual_sum = data.get("actual_sum")
    require_string("bad subspace actual_sum", actual_sum)
    if table_op(vector_add, left, right) != actual_sum:
        fail("bad-subspace-rejected actual_sum is incorrect")
    if actual_sum in subset:
        fail("bad-subspace-rejected actual_sum unexpectedly belongs to the subset")

    alethe = checks["qf-uf-bad-subspace-addition-closure"]
    if alethe["expected_result"] != "unsat" or alethe.get("proof_status") != "checked":
        fail("qf-uf-bad-subspace-addition-closure must be a checked unsat row")
    if alethe.get("validation") != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-subspace-addition-closure must use the QF_UF/Alethe validation route")
    data = alethe.get("data", {})
    if data.get("field") != "F2":
        fail("qf-uf-bad-subspace-addition-closure field must be F2")
    if data.get("space") != "F2^2":
        fail("qf-uf-bad-subspace-addition-closure space must be F2^2")
    alethe_subset = require_vector_subset("qf-uf bad subspace subset", data.get("subset"), vectors, nonempty=True)
    if alethe_subset != subset:
        fail("qf-uf-bad-subspace-addition-closure subset must match the replay row")
    alethe_failing_sum = data.get("failing_sum")
    if not isinstance(alethe_failing_sum, list) or len(alethe_failing_sum) != 2:
        fail("qf-uf-bad-subspace-addition-closure failing_sum must be a two-element list")
    alethe_left, alethe_right = alethe_failing_sum
    require_string("qf-uf bad subspace failing_sum[0]", alethe_left)
    require_string("qf-uf bad subspace failing_sum[1]", alethe_right)
    if [alethe_left, alethe_right] != [left, right]:
        fail("qf-uf-bad-subspace-addition-closure failing_sum must match the replay row")
    alethe_actual_sum = data.get("actual_sum")
    require_string("qf-uf bad subspace actual_sum", alethe_actual_sum)
    if alethe_actual_sum != actual_sum:
        fail("qf-uf-bad-subspace-addition-closure actual_sum must match the replay row")
    actual_membership = data.get("actual_membership")
    require_string("qf-uf bad subspace actual_membership", actual_membership)
    if actual_membership != "absent":
        fail("qf-uf-bad-subspace-addition-closure actual_membership must be absent")
    claimed_membership = data.get("claimed_membership")
    require_string("qf-uf bad subspace claimed_membership", claimed_membership)
    if claimed_membership != "present":
        fail("qf-uf-bad-subspace-addition-closure claimed_membership must be present")
    alethe_claim = data.get("alethe_closure_claim")
    require_string("qf-uf bad subspace alethe_closure_claim", alethe_claim)
    if alethe_claim != f"in_subset(add({left},{right})) = present":
        fail("qf-uf-bad-subspace-addition-closure must document the Alethe additive-closure membership claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf bad subspace smt2_artifact", smt2_artifact)
    check_source("qf-uf bad subspace smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("qf-uf bad subspace proof_regression", proof_regression)
    if "finite_vector_spaces_bad_subspace_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-subspace-addition-closure must link the Alethe regression")
    certificate = data.get("certificate")
    require_string("qf-uf bad subspace certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-subspace-addition-closure certificate must document zero-trust Alethe evidence")

    horizon = checks["general-vector-space-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-vector-space-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-vector-space-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general vector-space target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general vector-space future_checker", data.get("future_checker"))


def require_module_tables(
    context: str,
    value: Any,
    scalars: list[str],
) -> tuple[list[str], str, dict[tuple[str, str], str], dict[tuple[str, str], str]]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    elements = require_string_list(f"{context}.elements", value.get("elements"))
    element_set = set(elements)
    zero = value.get("zero")
    require_string(f"{context}.zero", zero)
    if zero not in element_set:
        fail(f"{context}.zero must be in the module carrier")
    add_op = require_binary_table(f"{context}.add", elements, value.get("add"))
    scalar_mul = require_scalar_mul_table(f"{context}.scalar_mul", value.get("scalar_mul"), scalars, elements)
    return elements, zero, add_op, scalar_mul


def module_axiom_failures(
    ring_carrier: list[str],
    ring_zero: str,
    ring_one: str | None,
    ring_add: dict[tuple[str, str], str],
    ring_mul: dict[tuple[str, str], str],
    module_elements: list[str],
    module_zero: str,
    module_add: dict[tuple[str, str], str],
    scalar_mul: dict[tuple[str, str], str],
) -> list[str]:
    if ring_one is None:
        return ["module requires a unital scalar ring"]
    failures = group_axiom_failures(module_elements, module_zero, module_add)
    if failures:
        return [f"module addition {failures[0]}"]
    if not is_commutative(module_elements, module_add):
        return ["module addition is not commutative"]
    for element in module_elements:
        if table_op(scalar_mul, ring_one, element) != element:
            return [f"one scalar action fails for {element}"]
        if table_op(scalar_mul, ring_zero, element) != module_zero:
            return [f"zero scalar action fails for {element}"]
    for scalar in ring_carrier:
        if table_op(scalar_mul, scalar, module_zero) != module_zero:
            return [f"scalar action on zero module element fails for {scalar}"]
        for left in module_elements:
            for right in module_elements:
                left_sum = table_op(module_add, left, right)
                lhs = table_op(scalar_mul, scalar, left_sum)
                rhs = table_op(
                    module_add,
                    table_op(scalar_mul, scalar, left),
                    table_op(scalar_mul, scalar, right),
                )
                if lhs != rhs:
                    return [f"scalar distributivity over module addition fails for {(scalar, left, right)}"]
    for left_scalar in ring_carrier:
        for right_scalar in ring_carrier:
            scalar_sum = table_op(ring_add, left_scalar, right_scalar)
            scalar_product = table_op(ring_mul, left_scalar, right_scalar)
            for element in module_elements:
                add_lhs = table_op(scalar_mul, scalar_sum, element)
                add_rhs = table_op(
                    module_add,
                    table_op(scalar_mul, left_scalar, element),
                    table_op(scalar_mul, right_scalar, element),
                )
                if add_lhs != add_rhs:
                    return [f"scalar addition distributivity fails for {(left_scalar, right_scalar, element)}"]
                mul_lhs = table_op(scalar_mul, scalar_product, element)
                mul_rhs = table_op(scalar_mul, left_scalar, table_op(scalar_mul, right_scalar, element))
                if mul_lhs != mul_rhs:
                    return [f"scalar multiplication associativity fails for {(left_scalar, right_scalar, element)}"]
    return []


def require_module_subset(context: str, value: Any, elements: list[str], *, nonempty: bool = False) -> set[str]:
    items = require_string_list(context, value, nonempty=nonempty)
    element_set = set(elements)
    subset = set(items)
    extra = sorted(subset - element_set)
    if extra:
        fail(f"{context} contains module elements outside the carrier: {extra}")
    return subset


def is_module_submodule(
    subset: set[str],
    ring_carrier: list[str],
    module_zero: str,
    module_add: dict[tuple[str, str], str],
    scalar_mul: dict[tuple[str, str], str],
) -> bool:
    if module_zero not in subset:
        return False
    for left in subset:
        for right in subset:
            if table_op(module_add, left, right) not in subset:
                return False
    for scalar in ring_carrier:
        for element in subset:
            if table_op(scalar_mul, scalar, element) not in subset:
                return False
    return True


def span_module_elements(
    generators: set[str],
    ring_carrier: list[str],
    module_zero: str,
    module_add: dict[tuple[str, str], str],
    scalar_mul: dict[tuple[str, str], str],
) -> set[str]:
    span = {module_zero}
    for generator in sorted(generators):
        next_span: set[str] = set()
        for existing in span:
            for scalar in ring_carrier:
                scaled = table_op(scalar_mul, scalar, generator)
                next_span.add(table_op(module_add, existing, scaled))
        span = next_span
    return span


def module_homomorphism_failures(
    ring_carrier: list[str],
    domain_elements: list[str],
    domain_add: dict[tuple[str, str], str],
    domain_scalar_mul: dict[tuple[str, str], str],
    codomain_add: dict[tuple[str, str], str],
    codomain_scalar_mul: dict[tuple[str, str], str],
    mapping: dict[str, str],
) -> list[str]:
    for left in domain_elements:
        for right in domain_elements:
            lhs = mapping[table_op(domain_add, left, right)]
            rhs = table_op(codomain_add, mapping[left], mapping[right])
            if lhs != rhs:
                return [f"additivity fails for {(left, right)}"]
    for scalar in ring_carrier:
        for element in domain_elements:
            lhs = mapping[table_op(domain_scalar_mul, scalar, element)]
            rhs = table_op(codomain_scalar_mul, scalar, mapping[element])
            if lhs != rhs:
                return [f"scalar preservation fails for {(scalar, element)}"]
    return []


def require_quotient_scalar_table(
    context: str,
    value: Any,
    scalars: list[str],
    coset_ids: list[str],
) -> dict[tuple[str, str], str]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    scalar_set = set(scalars)
    coset_set = set(coset_ids)
    if set(value) != scalar_set:
        missing = sorted(scalar_set - set(value))
        extra = sorted(set(value) - scalar_set)
        fail(f"{context} must cover exactly the scalars; missing={missing} extra={extra}")
    scalar_mul: dict[tuple[str, str], str] = {}
    for scalar in scalars:
        row = value[scalar]
        if not isinstance(row, dict):
            fail(f"{context}.{scalar} must be an object")
        if set(row) != coset_set:
            missing = sorted(coset_set - set(row))
            extra = sorted(set(row) - coset_set)
            fail(f"{context}.{scalar} must cover quotient cosets; missing={missing} extra={extra}")
        for coset_id in coset_ids:
            result = row[coset_id]
            require_string(f"{context}.{scalar}.{coset_id}", result)
            if result not in coset_set:
                fail(f"{context}.{scalar}.{coset_id} is outside the quotient carrier")
            scalar_mul[(scalar, coset_id)] = result
    return scalar_mul


def validate_finite_modules(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    module_table = checks["z4-regular-module"]
    if module_table["expected_result"] != "sat":
        fail("z4-regular-module must expect sat")
    values = single_witness_values(module_table, witnesses)
    ring_carrier, ring_zero, ring_one, ring_add, ring_mul = require_ring_tables("module scalar ring", values.get("ring"))
    failures = ring_axiom_failures(ring_carrier, ring_zero, ring_one, ring_add, ring_mul)
    if failures:
        fail(f"z4-regular-module scalar ring failed axioms: {failures[0]}")
    module_elements, module_zero, module_add, scalar_mul = require_module_tables(
        "regular module",
        values.get("module"),
        ring_carrier,
    )
    failures = module_axiom_failures(
        ring_carrier,
        ring_zero,
        ring_one,
        ring_add,
        ring_mul,
        module_elements,
        module_zero,
        module_add,
        scalar_mul,
    )
    if failures:
        fail(f"z4-regular-module failed module axioms: {failures[0]}")

    submodule = checks["submodule-span-replay"]
    if submodule["expected_result"] != "sat":
        fail("submodule-span-replay must expect sat")
    values = single_witness_values(submodule, witnesses)
    ring_carrier, ring_zero, ring_one, ring_add, ring_mul = require_ring_tables("submodule scalar ring", values.get("ring"))
    failures = ring_axiom_failures(ring_carrier, ring_zero, ring_one, ring_add, ring_mul)
    if failures:
        fail(f"submodule-span-replay scalar ring failed axioms: {failures[0]}")
    module_elements, module_zero, module_add, scalar_mul = require_module_tables(
        "submodule module",
        values.get("module"),
        ring_carrier,
    )
    failures = module_axiom_failures(
        ring_carrier,
        ring_zero,
        ring_one,
        ring_add,
        ring_mul,
        module_elements,
        module_zero,
        module_add,
        scalar_mul,
    )
    if failures:
        fail(f"submodule-span-replay module failed axioms: {failures[0]}")
    subset = require_module_subset("submodule subset", values.get("subset"), module_elements, nonempty=True)
    if not is_module_submodule(subset, ring_carrier, module_zero, module_add, scalar_mul):
        fail("submodule-span-replay listed subset is not a submodule")
    generators = require_module_subset("submodule generators", values.get("generators"), module_elements, nonempty=True)
    expected_span = require_module_subset("submodule span", values.get("span"), module_elements, nonempty=True)
    computed_span = span_module_elements(generators, ring_carrier, module_zero, module_add, scalar_mul)
    if computed_span != expected_span:
        fail("submodule-span-replay listed span is incorrect")
    if computed_span != subset:
        fail("submodule-span-replay span does not equal the listed subset")

    hom = checks["module-hom-kernel-image"]
    if hom["expected_result"] != "sat":
        fail("module-hom-kernel-image must expect sat")
    values = single_witness_values(hom, witnesses)
    ring_carrier, ring_zero, ring_one, ring_add, ring_mul = require_ring_tables("module hom scalar ring", values.get("ring"))
    failures = ring_axiom_failures(ring_carrier, ring_zero, ring_one, ring_add, ring_mul)
    if failures:
        fail(f"module-hom-kernel-image scalar ring failed axioms: {failures[0]}")
    domain_elements, domain_zero, domain_add, domain_scalar_mul = require_module_tables(
        "module hom domain",
        values.get("domain"),
        ring_carrier,
    )
    codomain_elements, codomain_zero, codomain_add, codomain_scalar_mul = require_module_tables(
        "module hom codomain",
        values.get("codomain"),
        ring_carrier,
    )
    for context, elements, zero, add_op, action in [
        ("module hom domain", domain_elements, domain_zero, domain_add, domain_scalar_mul),
        ("module hom codomain", codomain_elements, codomain_zero, codomain_add, codomain_scalar_mul),
    ]:
        failures = module_axiom_failures(
            ring_carrier,
            ring_zero,
            ring_one,
            ring_add,
            ring_mul,
            elements,
            zero,
            add_op,
            action,
        )
        if failures:
            fail(f"{context} failed module axioms: {failures[0]}")
    mapping = require_mapping_object("module hom map", values.get("map"), domain_elements, codomain_elements)
    failures = module_homomorphism_failures(
        ring_carrier,
        domain_elements,
        domain_add,
        domain_scalar_mul,
        codomain_add,
        codomain_scalar_mul,
        mapping,
    )
    if failures:
        fail(f"module-hom-kernel-image map is not a module homomorphism: {failures[0]}")
    computed_kernel = {element for element in domain_elements if mapping[element] == codomain_zero}
    computed_image = set(mapping.values())
    kernel = require_module_subset("module hom kernel", values.get("kernel"), domain_elements)
    image = require_module_subset("module hom image", values.get("image"), codomain_elements)
    if kernel != computed_kernel:
        fail("module-hom-kernel-image listed kernel is incorrect")
    if image != computed_image:
        fail("module-hom-kernel-image listed image is incorrect")
    if not is_module_submodule(kernel, ring_carrier, domain_zero, domain_add, domain_scalar_mul):
        fail("module-hom-kernel-image kernel is not a submodule")
    if not is_module_submodule(image, ring_carrier, codomain_zero, codomain_add, codomain_scalar_mul):
        fail("module-hom-kernel-image image is not a submodule")

    quotient = checks["quotient-module-replay"]
    if quotient["expected_result"] != "sat":
        fail("quotient-module-replay must expect sat")
    values = single_witness_values(quotient, witnesses)
    ring_carrier, ring_zero, ring_one, ring_add, ring_mul = require_ring_tables("quotient scalar ring", values.get("ring"))
    failures = ring_axiom_failures(ring_carrier, ring_zero, ring_one, ring_add, ring_mul)
    if failures:
        fail(f"quotient-module-replay scalar ring failed axioms: {failures[0]}")
    module_elements, module_zero, module_add, scalar_mul = require_module_tables(
        "quotient module",
        values.get("module"),
        ring_carrier,
    )
    failures = module_axiom_failures(
        ring_carrier,
        ring_zero,
        ring_one,
        ring_add,
        ring_mul,
        module_elements,
        module_zero,
        module_add,
        scalar_mul,
    )
    if failures:
        fail(f"quotient-module-replay module failed axioms: {failures[0]}")
    submodule_set = require_module_subset("quotient submodule", values.get("submodule"), module_elements, nonempty=True)
    if not is_module_submodule(submodule_set, ring_carrier, module_zero, module_add, scalar_mul):
        fail("quotient-module-replay listed submodule is not a submodule")
    coset_ids, representatives, coset_members = require_cosets("quotient cosets", values.get("cosets"), module_elements)
    quotient_zero = values.get("quotient_zero")
    require_string("quotient module zero", quotient_zero)
    if quotient_zero not in set(coset_ids):
        fail("quotient-module-replay quotient_zero must be one of the listed cosets")
    if coset_members[quotient_zero] != submodule_set:
        fail("quotient-module-replay zero coset must equal the listed submodule")
    for coset_id in coset_ids:
        representative = representatives[coset_id]
        expected_coset = {table_op(module_add, representative, member) for member in submodule_set}
        if expected_coset != coset_members[coset_id]:
            fail(f"quotient-module-replay coset {coset_id} does not match representative plus submodule")
    quotient_add = require_quotient_table("quotient module add", values.get("quotient_add"), coset_ids)
    for left in coset_ids:
        for right in coset_ids:
            representative_sum = table_op(module_add, representatives[left], representatives[right])
            expected_coset = coset_id_for_member("quotient module addition", representative_sum, coset_members)
            if quotient_add[(left, right)] != expected_coset:
                fail("quotient-module-replay quotient addition is incorrect")
    quotient_scalar_mul = require_quotient_scalar_table(
        "quotient module scalar_mul",
        values.get("quotient_scalar_mul"),
        ring_carrier,
        coset_ids,
    )
    for scalar in ring_carrier:
        for coset_id in coset_ids:
            representative_product = table_op(scalar_mul, scalar, representatives[coset_id])
            expected_coset = coset_id_for_member("quotient module scalar action", representative_product, coset_members)
            if quotient_scalar_mul[(scalar, coset_id)] != expected_coset:
                fail("quotient-module-replay quotient scalar action is incorrect")
    failures = module_axiom_failures(
        ring_carrier,
        ring_zero,
        ring_one,
        ring_add,
        ring_mul,
        coset_ids,
        quotient_zero,
        quotient_add,
        quotient_scalar_mul,
    )
    if failures:
        fail(f"quotient-module-replay quotient tables failed module axioms: {failures[0]}")

    bad = checks["bad-submodule-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-submodule-rejected must be a checked unsat row")
    data = bad.get("data", {})
    ring_carrier, ring_zero, ring_one, ring_add, ring_mul = require_ring_tables("bad submodule scalar ring", data.get("ring"))
    failures = ring_axiom_failures(ring_carrier, ring_zero, ring_one, ring_add, ring_mul)
    if failures:
        fail(f"bad-submodule-rejected scalar ring failed axioms: {failures[0]}")
    module_elements, module_zero, module_add, scalar_mul = require_module_tables(
        "bad submodule module",
        data.get("module"),
        ring_carrier,
    )
    failures = module_axiom_failures(
        ring_carrier,
        ring_zero,
        ring_one,
        ring_add,
        ring_mul,
        module_elements,
        module_zero,
        module_add,
        scalar_mul,
    )
    if failures:
        fail(f"bad-submodule-rejected module failed axioms: {failures[0]}")
    subset = require_module_subset("bad submodule subset", data.get("subset"), module_elements, nonempty=True)
    if is_module_submodule(subset, ring_carrier, module_zero, module_add, scalar_mul):
        fail("bad-submodule-rejected subset unexpectedly is a submodule")
    failing_scalar = data.get("failing_scalar")
    failing_vector = data.get("failing_vector")
    actual_scalar_product = data.get("actual_scalar_product")
    require_string("bad submodule failing_scalar", failing_scalar)
    require_string("bad submodule failing_vector", failing_vector)
    require_string("bad submodule actual_scalar_product", actual_scalar_product)
    if failing_scalar not in set(ring_carrier):
        fail("bad-submodule-rejected failing_scalar is outside the scalar ring")
    if failing_vector not in subset:
        fail("bad-submodule-rejected failing_vector must be in the claimed subset")
    if table_op(scalar_mul, failing_scalar, failing_vector) != actual_scalar_product:
        fail("bad-submodule-rejected actual_scalar_product is incorrect")
    if actual_scalar_product in subset:
        fail("bad-submodule-rejected actual_scalar_product unexpectedly belongs to the subset")

    qf_uf = checks["qf-uf-bad-submodule-scalar-closure"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-bad-submodule-scalar-closure must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-bad-submodule-scalar-closure must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-submodule-scalar-closure must use qf_uf_congruence_alethe validation")
    qf_data = qf_uf.get("data", {})
    qf_subset = require_module_subset("qf-uf bad submodule subset", qf_data.get("subset"), module_elements, nonempty=True)
    if qf_subset != subset:
        fail("qf-uf-bad-submodule-scalar-closure subset must match bad-submodule-rejected")
    if qf_data.get("failing_scalar") != failing_scalar:
        fail("qf-uf-bad-submodule-scalar-closure failing_scalar must match bad-submodule-rejected")
    if qf_data.get("failing_vector") != failing_vector:
        fail("qf-uf-bad-submodule-scalar-closure failing_vector must match bad-submodule-rejected")
    if qf_data.get("actual_scalar_product") != actual_scalar_product:
        fail("qf-uf-bad-submodule-scalar-closure actual_scalar_product must match bad-submodule-rejected")
    if qf_data.get("actual_membership") != "absent":
        fail("qf-uf-bad-submodule-scalar-closure actual_membership must be absent")
    if qf_data.get("claimed_membership") != "present":
        fail("qf-uf-bad-submodule-scalar-closure claimed_membership must be present")
    qf_alethe_claim = qf_data.get("alethe_scalar_closure_claim")
    require_string("qf-uf bad submodule alethe_scalar_closure_claim", qf_alethe_claim)
    expected_alethe_claim = f"in_subset(smul({failing_scalar},{failing_vector})) = present"
    if qf_alethe_claim != expected_alethe_claim:
        fail("qf-uf-bad-submodule-scalar-closure must document the Alethe scalar-closure claim")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("qf-uf bad submodule smt2_artifact", smt2_artifact)
    expected_smt2 = "artifacts/examples/math/finite-modules-v0/smt2/bad-submodule-scalar-closure-conflict.smt2"
    if smt2_artifact != expected_smt2:
        fail("qf-uf-bad-submodule-scalar-closure smt2_artifact must name the checked source artifact")
    check_source("qf-uf bad submodule smt2_artifact", smt2_artifact)
    proof_regression = qf_data.get("proof_regression")
    require_string("qf-uf bad submodule proof_regression", proof_regression)
    if "finite_modules_bad_submodule_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-submodule-scalar-closure must link the Alethe regression")
    certificate = qf_data.get("certificate")
    require_string("qf-uf bad submodule certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-submodule-scalar-closure certificate must document zero-trust Alethe evidence")

    horizon = checks["general-module-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-module-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-module-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general module target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general module future_checker", data.get("future_checker"))


def require_ring_subset(context: str, value: Any, carrier: list[str], *, nonempty: bool = False) -> set[str]:
    items = require_string_list(context, value, nonempty=nonempty)
    carrier_set = set(carrier)
    subset = set(items)
    extra = sorted(subset - carrier_set)
    if extra:
        fail(f"{context} contains ring elements outside the carrier: {extra}")
    return subset


def is_ring_ideal(
    subset: set[str],
    carrier: list[str],
    zero: str,
    add_op: dict[tuple[str, str], str],
    mul_op: dict[tuple[str, str], str],
) -> bool:
    if zero not in subset:
        return False
    for item in subset:
        if not any(
            table_op(add_op, item, candidate) == zero and table_op(add_op, candidate, item) == zero
            for candidate in subset
        ):
            return False
    for left in subset:
        for right in subset:
            if table_op(add_op, left, right) not in subset:
                return False
    for ring_item in carrier:
        for ideal_item in subset:
            if table_op(mul_op, ring_item, ideal_item) not in subset:
                return False
            if table_op(mul_op, ideal_item, ring_item) not in subset:
                return False
    return True


def generated_two_sided_ideal(
    generators: set[str],
    carrier: list[str],
    zero: str,
    add_op: dict[tuple[str, str], str],
    mul_op: dict[tuple[str, str], str],
) -> set[str]:
    closure = {zero} | set(generators)
    changed = True
    while changed:
        changed = False
        additions: set[str] = set()
        for left in closure:
            for right in closure:
                additions.add(table_op(add_op, left, right))
        for ring_item in carrier:
            for ideal_item in closure:
                additions.add(table_op(mul_op, ring_item, ideal_item))
                additions.add(table_op(mul_op, ideal_item, ring_item))
        for item in additions:
            if item not in closure:
                closure.add(item)
                changed = True
    return closure


def ring_homomorphism_failures(
    domain_carrier: list[str],
    domain_zero: str,
    domain_one: str | None,
    domain_add: dict[tuple[str, str], str],
    domain_mul: dict[tuple[str, str], str],
    codomain_zero: str,
    codomain_one: str | None,
    codomain_add: dict[tuple[str, str], str],
    codomain_mul: dict[tuple[str, str], str],
    mapping: dict[str, str],
) -> list[str]:
    if mapping[domain_zero] != codomain_zero:
        return ["zero preservation fails"]
    if domain_one is not None and codomain_one is not None and mapping[domain_one] != codomain_one:
        return ["one preservation fails"]
    for left in domain_carrier:
        for right in domain_carrier:
            if mapping[table_op(domain_add, left, right)] != table_op(codomain_add, mapping[left], mapping[right]):
                return [f"addition preservation fails for {(left, right)}"]
            if mapping[table_op(domain_mul, left, right)] != table_op(codomain_mul, mapping[left], mapping[right]):
                return [f"multiplication preservation fails for {(left, right)}"]
    return []


def validate_finite_ideals(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    ideal_check = checks["z6-even-ideal"]
    if ideal_check["expected_result"] != "sat":
        fail("z6-even-ideal must expect sat")
    values = single_witness_values(ideal_check, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables("z6 ideal ring", values.get("ring"))
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        fail(f"z6-even-ideal ring failed axioms: {failures[0]}")
    ideal = require_ring_subset("z6 ideal", values.get("ideal"), carrier, nonempty=True)
    if not is_ring_ideal(ideal, carrier, zero, add_op, mul_op):
        fail("z6-even-ideal listed subset is not an ideal")

    span = checks["principal-ideal-span-replay"]
    if span["expected_result"] != "sat":
        fail("principal-ideal-span-replay must expect sat")
    values = single_witness_values(span, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables("principal ideal ring", values.get("ring"))
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        fail(f"principal-ideal-span-replay ring failed axioms: {failures[0]}")
    ideal = require_ring_subset("principal ideal", values.get("ideal"), carrier, nonempty=True)
    if not is_ring_ideal(ideal, carrier, zero, add_op, mul_op):
        fail("principal-ideal-span-replay listed subset is not an ideal")
    generators = require_ring_subset("principal ideal generators", values.get("generators"), carrier, nonempty=True)
    expected_ideal = require_ring_subset("principal generated_ideal", values.get("generated_ideal"), carrier, nonempty=True)
    computed_ideal = generated_two_sided_ideal(generators, carrier, zero, add_op, mul_op)
    if computed_ideal != expected_ideal:
        fail("principal-ideal-span-replay generated ideal is incorrect")
    if computed_ideal != ideal:
        fail("principal-ideal-span-replay generated ideal does not equal the listed ideal")

    hom = checks["mod-two-ring-hom-kernel-image"]
    if hom["expected_result"] != "sat":
        fail("mod-two-ring-hom-kernel-image must expect sat")
    values = single_witness_values(hom, witnesses)
    domain_carrier, domain_zero, domain_one, domain_add, domain_mul = require_ring_tables("ring hom domain", values.get("domain"))
    codomain_carrier, codomain_zero, codomain_one, codomain_add, codomain_mul = require_ring_tables(
        "ring hom codomain",
        values.get("codomain"),
    )
    failures = ring_axiom_failures(domain_carrier, domain_zero, domain_one, domain_add, domain_mul)
    if failures:
        fail(f"mod-two-ring-hom-kernel-image domain failed axioms: {failures[0]}")
    failures = ring_axiom_failures(codomain_carrier, codomain_zero, codomain_one, codomain_add, codomain_mul)
    if failures:
        fail(f"mod-two-ring-hom-kernel-image codomain failed axioms: {failures[0]}")
    mapping = require_mapping_object("ring hom map", values.get("map"), domain_carrier, codomain_carrier)
    failures = ring_homomorphism_failures(
        domain_carrier,
        domain_zero,
        domain_one,
        domain_add,
        domain_mul,
        codomain_zero,
        codomain_one,
        codomain_add,
        codomain_mul,
        mapping,
    )
    if failures:
        fail(f"mod-two-ring-hom-kernel-image map is not a ring homomorphism: {failures[0]}")
    computed_kernel = {source for source, target in mapping.items() if target == codomain_zero}
    computed_image = set(mapping.values())
    kernel = require_ring_subset("ring hom kernel", values.get("kernel"), domain_carrier, nonempty=True)
    image = require_ring_subset("ring hom image", values.get("image"), codomain_carrier, nonempty=True)
    if kernel != computed_kernel:
        fail("mod-two-ring-hom-kernel-image listed kernel is incorrect")
    if image != computed_image:
        fail("mod-two-ring-hom-kernel-image listed image is incorrect")
    if not is_ring_ideal(kernel, domain_carrier, domain_zero, domain_add, domain_mul):
        fail("mod-two-ring-hom-kernel-image kernel is not an ideal")

    quotient = checks["quotient-ring-replay"]
    if quotient["expected_result"] != "sat":
        fail("quotient-ring-replay must expect sat")
    values = single_witness_values(quotient, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables("quotient ring source", values.get("ring"))
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        fail(f"quotient-ring-replay source ring failed axioms: {failures[0]}")
    ideal = require_ring_subset("quotient ideal", values.get("ideal"), carrier, nonempty=True)
    if not is_ring_ideal(ideal, carrier, zero, add_op, mul_op):
        fail("quotient-ring-replay listed ideal is not an ideal")
    coset_ids, representatives, coset_members = require_cosets("quotient ring cosets", values.get("cosets"), carrier)
    quotient_zero = values.get("quotient_zero")
    quotient_one = values.get("quotient_one")
    require_string("quotient ring zero", quotient_zero)
    require_string("quotient ring one", quotient_one)
    if quotient_zero not in set(coset_ids) or quotient_one not in set(coset_ids):
        fail("quotient-ring-replay quotient zero/one must be listed cosets")
    if coset_members[quotient_zero] != ideal:
        fail("quotient-ring-replay zero coset must equal the ideal")
    if one is not None and one not in coset_members[quotient_one]:
        fail("quotient-ring-replay one coset must contain the source ring identity")
    for coset_id in coset_ids:
        representative = representatives[coset_id]
        expected_coset = {table_op(add_op, representative, member) for member in ideal}
        if expected_coset != coset_members[coset_id]:
            fail(f"quotient-ring-replay coset {coset_id} does not match representative plus ideal")
    quotient_add = require_quotient_table("quotient ring add", values.get("quotient_add"), coset_ids)
    quotient_mul = require_quotient_table("quotient ring mul", values.get("quotient_mul"), coset_ids)
    for left in coset_ids:
        for right in coset_ids:
            representative_sum = table_op(add_op, representatives[left], representatives[right])
            expected_sum_coset = coset_id_for_member("quotient ring addition", representative_sum, coset_members)
            if quotient_add[(left, right)] != expected_sum_coset:
                fail("quotient-ring-replay quotient addition is incorrect")
            representative_product = table_op(mul_op, representatives[left], representatives[right])
            expected_product_coset = coset_id_for_member("quotient ring multiplication", representative_product, coset_members)
            if quotient_mul[(left, right)] != expected_product_coset:
                fail("quotient-ring-replay quotient multiplication is incorrect")
    failures = ring_axiom_failures(coset_ids, quotient_zero, quotient_one, quotient_add, quotient_mul)
    if failures:
        fail(f"quotient-ring-replay quotient tables failed ring axioms: {failures[0]}")

    quotient_alethe = checks["qf-uf-quotient-ring-representative-alethe"]
    if quotient_alethe["expected_result"] != "unsat" or quotient_alethe.get("proof_status") != "checked":
        fail("qf-uf-quotient-ring-representative-alethe must be a checked unsat row")
    if quotient_alethe["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-quotient-ring-representative-alethe must use the QF_UF/Alethe route")
    data = quotient_alethe.get("data", {})
    equalities = require_string_list(
        "quotient representative equalities",
        data.get("representative_equalities"),
    )
    if set(equalities) != {"quotient(0) = quotient(2)", "quotient(1) = quotient(3)"}:
        fail("qf-uf-quotient-ring-representative-alethe must document both representative equalities")
    quotient_claim = data.get("quotient_congruence_claim")
    require_string("quotient representative congruence claim", quotient_claim)
    if quotient_claim != "qadd(quotient(0), quotient(1)) = qadd(quotient(2), quotient(3))":
        fail("qf-uf-quotient-ring-representative-alethe must document the quotient addition congruence claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("quotient representative smt2_artifact", smt2_artifact)
    check_source("quotient representative smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("quotient representative proof_regression", proof_regression)
    if "finite_ideals_quotient_representative_congruence_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-quotient-ring-representative-alethe must link the Alethe regression")
    certificate = data.get("certificate")
    require_string("quotient representative certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-quotient-ring-representative-alethe certificate must document zero-trust Alethe evidence")

    bad = checks["bad-ideal-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-ideal-rejected must be a replay-only unsat row")
    data = bad.get("data", {})
    carrier, zero, one, add_op, mul_op = require_ring_tables("bad ideal ring", data.get("ring"))
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        fail(f"bad-ideal-rejected ring failed axioms: {failures[0]}")
    subset = require_ring_subset("bad ideal subset", data.get("subset"), carrier, nonempty=True)
    if is_ring_ideal(subset, carrier, zero, add_op, mul_op):
        fail("bad-ideal-rejected subset unexpectedly is an ideal")
    failing_sum = data.get("failing_sum")
    if not isinstance(failing_sum, list) or len(failing_sum) != 2:
        fail("bad-ideal-rejected failing_sum must be a two-element list")
    left, right = failing_sum
    require_string("bad ideal failing_sum[0]", left)
    require_string("bad ideal failing_sum[1]", right)
    if left not in subset or right not in subset:
        fail("bad-ideal-rejected failing_sum entries must be in the claimed subset")
    actual_sum = data.get("actual_sum")
    require_string("bad ideal actual_sum", actual_sum)
    if table_op(add_op, left, right) != actual_sum:
        fail("bad-ideal-rejected actual_sum is incorrect")
    if actual_sum in subset:
        fail("bad-ideal-rejected actual_sum unexpectedly belongs to the subset")

    bad_alethe = checks["qf-uf-bad-ideal-additive-closure"]
    if bad_alethe["expected_result"] != "unsat" or bad_alethe.get("proof_status") != "checked":
        fail("qf-uf-bad-ideal-additive-closure must be a checked unsat row")
    if bad_alethe["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-ideal-additive-closure must use qf_uf_congruence_alethe validation")
    data = bad_alethe.get("data", {})
    qf_subset = require_ring_subset("qf-uf bad ideal subset", data.get("subset"), carrier, nonempty=True)
    if qf_subset != subset:
        fail("qf-uf-bad-ideal-additive-closure subset must match bad-ideal-rejected")
    qf_failing_sum = data.get("failing_sum")
    if not isinstance(qf_failing_sum, list) or len(qf_failing_sum) != 2:
        fail("qf-uf-bad-ideal-additive-closure failing_sum must be a two-element list")
    qf_left, qf_right = qf_failing_sum
    require_string("qf-uf bad ideal failing_sum[0]", qf_left)
    require_string("qf-uf bad ideal failing_sum[1]", qf_right)
    if [qf_left, qf_right] != [left, right]:
        fail("qf-uf-bad-ideal-additive-closure failing_sum must match bad-ideal-rejected")
    qf_actual_sum = data.get("actual_sum")
    require_string("qf-uf bad ideal actual_sum", qf_actual_sum)
    if qf_actual_sum != actual_sum:
        fail("qf-uf-bad-ideal-additive-closure actual_sum must match bad-ideal-rejected")
    if data.get("actual_membership") != "absent":
        fail("qf-uf-bad-ideal-additive-closure actual_membership must be absent")
    if data.get("claimed_membership") != "present":
        fail("qf-uf-bad-ideal-additive-closure claimed_membership must be present")
    alethe_claim = data.get("alethe_additive_closure_claim")
    require_string("qf-uf bad ideal alethe_additive_closure_claim", alethe_claim)
    if alethe_claim != f"in_subset(add({left},{right})) = present":
        fail("qf-uf-bad-ideal-additive-closure must document the Alethe additive-closure claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf bad ideal smt2_artifact", smt2_artifact)
    check_source("qf-uf bad ideal smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("qf-uf bad ideal proof_regression", proof_regression)
    if "finite_ideals_bad_ideal_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-ideal-additive-closure must link the Alethe regression")
    certificate = data.get("certificate")
    require_string("qf-uf bad ideal certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-ideal-additive-closure certificate must document zero-trust Alethe evidence")

    horizon = checks["general-ideal-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-ideal-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-ideal-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general ideal target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general ideal future_checker", data.get("future_checker"))


def validate_finite_groups(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    group_table = checks["z4-addition-group-table"]
    if group_table["expected_result"] != "sat":
        fail("z4-addition-group-table must expect sat")
    values = single_witness_values(group_table, witnesses)
    carrier, identity, operation = require_cayley_table("z4 addition", values)
    failures = group_axiom_failures(carrier, identity, operation)
    if failures:
        fail(f"z4-addition-group-table failed group axioms: {failures[0]}")

    inverse_check = checks["z4-inverse-table"]
    if inverse_check["expected_result"] != "sat":
        fail("z4-inverse-table must expect sat")
    values = single_witness_values(inverse_check, witnesses)
    carrier, identity, operation = require_cayley_table("z4 inverse table", values)
    inverses = require_inverse_table("z4 inverses", values.get("inverses"), carrier)
    for item, inverse in inverses.items():
        if table_op(operation, item, inverse) != identity:
            fail(f"z4 inverse table has bad right inverse for {item}")
        if table_op(operation, inverse, item) != identity:
            fail(f"z4 inverse table has bad left inverse for {item}")

    bad_group = checks["subtraction-mod3-non-group"]
    if bad_group["expected_result"] != "unsat":
        fail("subtraction-mod3-non-group must expect unsat")
    values = single_witness_values(bad_group, witnesses)
    carrier, identity, operation = require_cayley_table("subtraction mod 3", values)
    if not group_axiom_failures(carrier, identity, operation):
        fail("subtraction-mod3-non-group unexpectedly satisfies the group axioms")

    qf_uf = checks["qf-uf-group-operation-congruence-alethe"]
    if qf_uf["expected_result"] != "unsat":
        fail("qf-uf-group-operation-congruence-alethe must expect unsat")
    if qf_uf["proof_status"] != "checked":
        fail("qf-uf-group-operation-congruence-alethe must be checked")
    if qf_uf["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-group-operation-congruence-alethe must use qf_uf_congruence_alethe validation")
    data = qf_uf.get("data", {})
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf group operation smt2_artifact", smt2_artifact)
    check_source("qf-uf group operation smt2_artifact", smt2_artifact)
    require_string("qf-uf group operation proof_regression", data.get("proof_regression"))
    certificate = data.get("certificate")
    require_string("qf-uf group operation certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf group operation certificate must document zero-trust Alethe evidence")


def monoid_axiom_failures(
    carrier: list[str],
    identity: str,
    operation: dict[tuple[str, str], str],
) -> list[str]:
    failures: list[str] = []
    for item in carrier:
        if table_op(operation, identity, item) != item:
            failures.append(f"left identity fails for {item}")
        if table_op(operation, item, identity) != item:
            failures.append(f"right identity fails for {item}")
    for left in carrier:
        for middle in carrier:
            for right in carrier:
                lhs = table_op(operation, table_op(operation, left, middle), right)
                rhs = table_op(operation, left, table_op(operation, middle, right))
                if lhs != rhs:
                    failures.append(f"associativity fails for {(left, middle, right)}")
                    return failures
    return failures


def require_monoid_table(
    context: str,
    values: Any,
) -> tuple[list[str], str, dict[tuple[str, str], str]]:
    if not isinstance(values, dict):
        fail(f"{context} must be an object")
    carrier, identity, operation = require_cayley_table(context, values)
    failures = monoid_axiom_failures(carrier, identity, operation)
    if failures:
        fail(f"{context} is not a monoid: {failures[0]}")
    return carrier, identity, operation


def require_transformation_monoid_values(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], list[str], str, dict[tuple[str, str], str], dict[str, dict[str, str]]]:
    points = require_string_list(f"{context}.points", values.get("points"))
    carrier, identity, operation = require_monoid_table(context, values)
    raw_functions = values.get("functions")
    if not isinstance(raw_functions, dict) or set(raw_functions) != set(carrier):
        fail(f"{context}.functions must contain exactly one function per carrier element")
    functions = {
        element: require_mapping_object(f"{context}.functions.{element}", raw_functions[element], points, points)
        for element in carrier
    }
    return points, carrier, identity, operation, functions


def compose_endomorphism(
    points: list[str],
    left_after: dict[str, str],
    right_first: dict[str, str],
) -> dict[str, str]:
    return {point: left_after[right_first[point]] for point in points}


def matching_transformation_label(
    context: str,
    functions: dict[str, dict[str, str]],
    mapping: dict[str, str],
) -> str:
    matches = [name for name, candidate in functions.items() if candidate == mapping]
    if len(matches) != 1:
        fail(f"{context} must match exactly one listed transformation")
    return matches[0]


def validate_finite_monoids(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    laws = checks["two-point-transformation-monoid-laws"]
    if laws["expected_result"] != "sat" or laws.get("proof_status") != "checked":
        fail("two-point-transformation-monoid-laws must be a checked sat row")
    values = single_witness_values(laws, witnesses)
    points, carrier, identity, operation, functions = require_transformation_monoid_values(
        "two-point transformation monoid",
        values,
    )
    identity_map = {point: point for point in points}
    if functions[identity] != identity_map:
        fail("two-point-transformation-monoid-laws identity function is incorrect")

    composition = checks["function-composition-table-replay"]
    if composition["expected_result"] != "sat" or composition.get("proof_status") != "checked":
        fail("function-composition-table-replay must be a checked sat row")
    values = single_witness_values(composition, witnesses)
    points, carrier, identity, operation, functions = require_transformation_monoid_values(
        "composition transformation monoid",
        values,
    )
    for left in carrier:
        for right in carrier:
            computed = compose_endomorphism(points, functions[left], functions[right])
            computed_label = matching_transformation_label(
                f"function-composition-table-replay {left} after {right}",
                functions,
                computed,
            )
            if table_op(operation, left, right) != computed_label:
                fail("function-composition-table-replay table entry does not match function composition")

    units = checks["units-and-idempotents-replay"]
    if units["expected_result"] != "sat" or units.get("proof_status") != "checked":
        fail("units-and-idempotents-replay must be a checked sat row")
    values = single_witness_values(units, witnesses)
    points, carrier, identity, operation, functions = require_transformation_monoid_values(
        "units transformation monoid",
        values,
    )
    listed_units = set(require_string_list("monoid units", values.get("units")))
    listed_idempotents = set(require_string_list("monoid idempotents", values.get("idempotents")))
    carrier_set = set(carrier)
    if not listed_units <= carrier_set:
        fail("units-and-idempotents-replay units contain elements outside the carrier")
    if not listed_idempotents <= carrier_set:
        fail("units-and-idempotents-replay idempotents contain elements outside the carrier")
    actual_units = {
        element
        for element in carrier
        if any(
            table_op(operation, element, candidate) == identity
            and table_op(operation, candidate, element) == identity
            for candidate in carrier
        )
    }
    actual_idempotents = {element for element in carrier if table_op(operation, element, element) == element}
    if listed_units != actual_units:
        fail("units-and-idempotents-replay listed units are incorrect")
    if listed_idempotents != actual_idempotents:
        fail("units-and-idempotents-replay listed idempotents are incorrect")

    bad = checks["bad-nonassociative-table-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-nonassociative-table-rejected must be a replay-only unsat row")
    data = bad.get("data", {})
    if not isinstance(data, dict):
        fail("bad-nonassociative-table-rejected data must be an object")
    carrier, identity, operation = require_cayley_table("bad monoid table", data)
    failures = monoid_axiom_failures(carrier, identity, operation)
    if not failures:
        fail("bad-nonassociative-table-rejected unexpectedly satisfies the monoid axioms")
    failing_triple = data.get("failing_triple")
    if not isinstance(failing_triple, list) or len(failing_triple) != 3:
        fail("bad-nonassociative-table-rejected failing_triple must have three elements")
    left, middle, right = failing_triple
    for index, item in enumerate(failing_triple):
        require_string(f"bad monoid failing_triple[{index}]", item)
        if item not in set(carrier):
            fail("bad-nonassociative-table-rejected failing_triple references an element outside the carrier")
    left_associated = table_op(operation, table_op(operation, left, middle), right)
    right_associated = table_op(operation, left, table_op(operation, middle, right))
    expected_left = data.get("left_associated")
    expected_right = data.get("right_associated")
    require_string("bad monoid left_associated", expected_left)
    require_string("bad monoid right_associated", expected_right)
    if left_associated != expected_left:
        fail("bad-nonassociative-table-rejected left_associated is incorrect")
    if right_associated != expected_right:
        fail("bad-nonassociative-table-rejected right_associated is incorrect")
    if left_associated == right_associated:
        fail("bad-nonassociative-table-rejected failing_triple is not an associativity failure")

    bad_alethe = checks["qf-uf-bad-monoid-associativity"]
    if bad_alethe["expected_result"] != "unsat" or bad_alethe.get("proof_status") != "checked":
        fail("qf-uf-bad-monoid-associativity must be a checked unsat row")
    if bad_alethe["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-monoid-associativity must use qf_uf_congruence_alethe validation")
    data = bad_alethe.get("data", {})
    qf_carrier = require_string_list("qf-uf bad monoid carrier", data.get("carrier"))
    if qf_carrier != carrier:
        fail("qf-uf-bad-monoid-associativity carrier must match bad-nonassociative-table-rejected")
    qf_triple = data.get("failing_triple")
    if not isinstance(qf_triple, list) or len(qf_triple) != 3:
        fail("qf-uf-bad-monoid-associativity failing_triple must have three elements")
    for index, item in enumerate(qf_triple):
        require_string(f"qf-uf bad monoid failing_triple[{index}]", item)
    if qf_triple != failing_triple:
        fail("qf-uf-bad-monoid-associativity failing_triple must match bad-nonassociative-table-rejected")
    qf_left_associated = data.get("left_associated")
    qf_right_associated = data.get("right_associated")
    require_string("qf-uf bad monoid left_associated", qf_left_associated)
    require_string("qf-uf bad monoid right_associated", qf_right_associated)
    if qf_left_associated != left_associated:
        fail("qf-uf-bad-monoid-associativity left_associated must match replay")
    if qf_right_associated != right_associated:
        fail("qf-uf-bad-monoid-associativity right_associated must match replay")
    alethe_claim = data.get("alethe_associativity_claim")
    require_string("qf-uf bad monoid alethe_associativity_claim", alethe_claim)
    if alethe_claim != "(b*b)*b = b*(b*b)":
        fail("qf-uf-bad-monoid-associativity must document the Alethe associativity claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf bad monoid smt2_artifact", smt2_artifact)
    check_source("qf-uf bad monoid smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("qf-uf bad monoid proof_regression", proof_regression)
    if "finite_monoids_associativity_failure_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-monoid-associativity must link the Alethe regression")
    certificate = data.get("certificate")
    require_string("qf-uf bad monoid certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-monoid-associativity certificate must document zero-trust Alethe evidence")

    horizon = checks["general-monoid-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-monoid-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-monoid-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general monoid target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general monoid future_checker", data.get("future_checker"))


def require_permutation_group_values(
    context: str,
    values: dict[str, Any],
) -> tuple[
    list[str],
    list[str],
    str,
    dict[tuple[str, str], str],
    dict[str, dict[str, str]],
]:
    points = require_string_list(f"{context}.points", values.get("points"))
    carrier, identity, operation = require_group_structure(context, values)
    raw_permutations = values.get("permutations")
    if not isinstance(raw_permutations, dict) or set(raw_permutations) != set(carrier):
        fail(f"{context}.permutations must contain exactly one map per carrier element")
    point_set = set(points)
    permutations = {
        element: require_mapping_object(
            f"{context}.permutations.{element}",
            raw_permutations[element],
            points,
            points,
        )
        for element in carrier
    }
    for element, mapping in permutations.items():
        if set(mapping.values()) != point_set:
            fail(f"{context}.permutations.{element} must be bijective")
    identity_map = {point: point for point in points}
    if permutations[identity] != identity_map:
        fail(f"{context}.permutations identity element must be the identity map")
    return points, carrier, identity, operation, permutations


def permutation_cycle_lengths(points: list[str], mapping: dict[str, str]) -> list[int]:
    seen: set[str] = set()
    lengths: list[int] = []
    for point in points:
        if point in seen:
            continue
        cursor = point
        length = 0
        while cursor not in seen:
            seen.add(cursor)
            length += 1
            cursor = mapping[cursor]
        lengths.append(length)
    return sorted(lengths, reverse=True)


def permutation_sign(points: list[str], mapping: dict[str, str]) -> str:
    point_index = {point: index for index, point in enumerate(points)}
    image_indices = [point_index[mapping[point]] for point in points]
    inversions = 0
    for left in range(len(image_indices)):
        for right in range(left + 1, len(image_indices)):
            if image_indices[left] > image_indices[right]:
                inversions += 1
    return "even" if inversions % 2 == 0 else "odd"


def require_cycle_lengths(
    context: str,
    value: Any,
    carrier: list[str],
) -> dict[str, list[int]]:
    if not isinstance(value, dict) or set(value) != set(carrier):
        fail(f"{context} must contain exactly one row per carrier element")
    result: dict[str, list[int]] = {}
    for element in carrier:
        raw_lengths = value[element]
        if not isinstance(raw_lengths, list) or not raw_lengths:
            fail(f"{context}.{element} must be a non-empty list")
        lengths = [
            require_int(f"{context}.{element}[{index}]", item)
            for index, item in enumerate(raw_lengths)
        ]
        if any(length <= 0 for length in lengths):
            fail(f"{context}.{element} lengths must be positive")
        result[element] = lengths
    return result


def validate_finite_permutation_groups(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    laws = checks["s3-permutation-group-laws"]
    if laws["expected_result"] != "sat" or laws.get("proof_status") != "checked":
        fail("s3-permutation-group-laws must be a checked sat row")
    values = single_witness_values(laws, witnesses)
    points, carrier, identity, operation, permutations = require_permutation_group_values(
        "S3 permutation group",
        values,
    )
    if len(points) != 3 or len(carrier) != 6:
        fail("s3-permutation-group-laws must use a three-point S3 carrier with six elements")

    composition = checks["permutation-composition-table-replay"]
    if composition["expected_result"] != "sat" or composition.get("proof_status") != "checked":
        fail("permutation-composition-table-replay must be a checked sat row")
    values = single_witness_values(composition, witnesses)
    points, carrier, identity, operation, permutations = require_permutation_group_values(
        "S3 composition replay",
        values,
    )
    for left in carrier:
        for right in carrier:
            computed = compose_endomorphism(points, permutations[left], permutations[right])
            computed_label = matching_transformation_label(
                f"permutation-composition-table-replay {left} after {right}",
                permutations,
                computed,
            )
            if table_op(operation, left, right) != computed_label:
                fail("permutation-composition-table-replay table entry does not match composition")

    cycle_sign = checks["cycle-type-and-sign-replay"]
    if cycle_sign["expected_result"] != "sat" or cycle_sign.get("proof_status") != "checked":
        fail("cycle-type-and-sign-replay must be a checked sat row")
    values = single_witness_values(cycle_sign, witnesses)
    points, carrier, identity, operation, permutations = require_permutation_group_values(
        "S3 cycle/sign replay",
        values,
    )
    cycle_lengths = require_cycle_lengths("cycle lengths", values.get("cycle_lengths"), carrier)
    signs = require_mapping_object("signs", values.get("signs"), carrier, ["even", "odd"])
    sign_group_data = values.get("sign_group")
    if not isinstance(sign_group_data, dict):
        fail("cycle-type-and-sign-replay sign_group must be an object")
    sign_carrier, sign_identity, sign_op = require_group_structure("sign group", sign_group_data)
    if sign_carrier != ["even", "odd"] or sign_identity != "even":
        fail("cycle-type-and-sign-replay sign_group must be C2 under parity multiplication")
    for element in carrier:
        computed_lengths = permutation_cycle_lengths(points, permutations[element])
        if cycle_lengths[element] != computed_lengths:
            fail(f"cycle-type-and-sign-replay cycle lengths are incorrect for {element}")
        computed_sign = permutation_sign(points, permutations[element])
        if signs[element] != computed_sign:
            fail(f"cycle-type-and-sign-replay sign is incorrect for {element}")
    for left in carrier:
        for right in carrier:
            product_element = table_op(operation, left, right)
            product_sign = table_op(sign_op, signs[left], signs[right])
            if signs[product_element] != product_sign:
                fail("cycle-type-and-sign-replay sign map is not a homomorphism")

    action_check = checks["natural-action-orbit-stabilizer"]
    if action_check["expected_result"] != "sat" or action_check.get("proof_status") != "checked":
        fail("natural-action-orbit-stabilizer must be a checked sat row")
    values = single_witness_values(action_check, witnesses)
    points, carrier, identity, operation, permutations = require_permutation_group_values(
        "S3 natural action",
        values,
    )
    action = require_action_table("S3 natural action table", carrier, points, values.get("action"))
    for element in carrier:
        for point in points:
            if action[(element, point)] != permutations[element][point]:
                fail("natural-action-orbit-stabilizer action row must match the permutation map")
    failures = action_law_failures(carrier, identity, operation, points, action)
    if failures:
        fail(f"natural-action-orbit-stabilizer failed: {failures[0]}")
    sample_point = values.get("sample_point")
    require_string("S3 natural action sample_point", sample_point)
    if sample_point not in set(points):
        fail("natural-action-orbit-stabilizer sample_point is outside the acted-on set")
    listed_orbit = set(require_string_list("S3 natural action orbit", values.get("orbit")))
    listed_stabilizer = set(require_string_list("S3 natural action stabilizer", values.get("stabilizer")))
    orbit_size = require_int("S3 natural action orbit_size", values.get("orbit_size"))
    stabilizer_size = require_int("S3 natural action stabilizer_size", values.get("stabilizer_size"))
    group_size = require_int("S3 natural action group_size", values.get("group_size"))
    actual_orbit = orbit_of(carrier, action, sample_point)
    actual_stabilizer = stabilizer_of(carrier, action, sample_point)
    if listed_orbit != actual_orbit:
        fail("natural-action-orbit-stabilizer listed orbit is incorrect")
    if listed_stabilizer != actual_stabilizer:
        fail("natural-action-orbit-stabilizer listed stabilizer is incorrect")
    if orbit_size != len(actual_orbit):
        fail("natural-action-orbit-stabilizer orbit_size is incorrect")
    if stabilizer_size != len(actual_stabilizer):
        fail("natural-action-orbit-stabilizer stabilizer_size is incorrect")
    if group_size != len(carrier) or orbit_size * stabilizer_size != group_size:
        fail("natural-action-orbit-stabilizer orbit-stabilizer product is incorrect")

    bad = checks["bad-nonbijection-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-nonbijection-rejected must be a replay-only unsat row")
    data = bad.get("data", {})
    if not isinstance(data, dict):
        fail("bad-nonbijection-rejected data must be an object")
    points = require_string_list("bad nonbijection points", data.get("points"))
    mapping = require_mapping_object("bad nonbijection map", data.get("map"), points, points)
    duplicate_image = data.get("duplicate_image")
    missing_image = data.get("missing_image")
    require_string("bad nonbijection duplicate_image", duplicate_image)
    require_string("bad nonbijection missing_image", missing_image)
    if duplicate_image not in set(points) or missing_image not in set(points):
        fail("bad-nonbijection-rejected duplicate/missing images must be points")
    image_counts = {point: list(mapping.values()).count(point) for point in points}
    if image_counts[duplicate_image] < 2:
        fail("bad-nonbijection-rejected duplicate_image is not actually duplicated")
    if image_counts[missing_image] != 0:
        fail("bad-nonbijection-rejected missing_image is not actually missing")
    if set(mapping.values()) == set(points):
        fail("bad-nonbijection-rejected map unexpectedly is bijective")
    duplicate_preimages = data.get("duplicate_preimages")
    if not isinstance(duplicate_preimages, list) or len(duplicate_preimages) != 2:
        fail("bad-nonbijection-rejected duplicate_preimages must be a two-element list")
    left, right = duplicate_preimages
    require_string("bad nonbijection duplicate_preimages[0]", left)
    require_string("bad nonbijection duplicate_preimages[1]", right)
    if left == right:
        fail("bad-nonbijection-rejected duplicate_preimages must be distinct")
    if left not in points or right not in points:
        fail("bad-nonbijection-rejected duplicate_preimages must be points")
    if mapping[left] != duplicate_image or mapping[right] != duplicate_image:
        fail("bad-nonbijection-rejected duplicate_preimages must map to duplicate_image")

    bad_alethe = checks["qf-uf-bad-nonbijection-injectivity"]
    if bad_alethe["expected_result"] != "unsat" or bad_alethe.get("proof_status") != "checked":
        fail("qf-uf-bad-nonbijection-injectivity must be a checked unsat row")
    if bad_alethe["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-nonbijection-injectivity must use qf_uf_congruence_alethe validation")
    data = bad_alethe.get("data", {})
    qf_points = require_string_list("qf-uf bad nonbijection points", data.get("points"))
    if qf_points != points:
        fail("qf-uf-bad-nonbijection-injectivity points must match bad-nonbijection-rejected")
    qf_duplicate_preimages = data.get("duplicate_preimages")
    if not isinstance(qf_duplicate_preimages, list) or len(qf_duplicate_preimages) != 2:
        fail("qf-uf-bad-nonbijection-injectivity duplicate_preimages must be a two-element list")
    qf_left, qf_right = qf_duplicate_preimages
    require_string("qf-uf bad nonbijection duplicate_preimages[0]", qf_left)
    require_string("qf-uf bad nonbijection duplicate_preimages[1]", qf_right)
    if [qf_left, qf_right] != [left, right]:
        fail("qf-uf-bad-nonbijection-injectivity duplicate_preimages must match bad-nonbijection-rejected")
    if data.get("duplicate_image") != duplicate_image:
        fail("qf-uf-bad-nonbijection-injectivity duplicate_image must match bad-nonbijection-rejected")
    alethe_claim = data.get("alethe_injectivity_claim")
    require_string("qf-uf bad nonbijection alethe_injectivity_claim", alethe_claim)
    if alethe_claim != f"bad({left}) != bad({right})":
        fail("qf-uf-bad-nonbijection-injectivity must document the Alethe distinct-image claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf bad nonbijection smt2_artifact", smt2_artifact)
    check_source("qf-uf bad nonbijection smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("qf-uf bad nonbijection proof_regression", proof_regression)
    if "finite_permutation_groups_bad_nonbijection_emits_checked_alethe" not in proof_regression:
        fail("qf-uf-bad-nonbijection-injectivity must link the Alethe regression")
    certificate = data.get("certificate")
    require_string("qf-uf bad nonbijection certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-nonbijection-injectivity certificate must document zero-trust Alethe evidence")

    horizon = checks["general-permutation-group-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-permutation-group-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-permutation-group-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general permutation group target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general permutation group future_checker", data.get("future_checker"))


def require_action_table(
    context: str,
    group: list[str],
    points: list[str],
    value: Any,
) -> dict[tuple[str, str], str]:
    group_set = set(group)
    point_set = set(points)
    if not isinstance(value, dict):
        fail(f"{context} must be an object keyed by group element")
    if set(value) != group_set:
        fail(f"{context} must contain exactly one action row per group element")
    action: dict[tuple[str, str], str] = {}
    for group_element in group:
        row = value.get(group_element)
        if not isinstance(row, dict):
            fail(f"{context}.{group_element} must be an object keyed by point")
        if set(row) != point_set:
            fail(f"{context}.{group_element} must contain exactly one image per point")
        for point in points:
            image = row.get(point)
            require_string(f"{context}.{group_element}.{point}", image)
            if image not in point_set:
                fail(f"{context}.{group_element}.{point} is outside the acted-on set")
            action[(group_element, point)] = image
    return action


def action_law_failures(
    group: list[str],
    identity: str,
    operation: dict[tuple[str, str], str],
    points: list[str],
    action: dict[tuple[str, str], str],
) -> list[str]:
    failures: list[str] = []
    for point in points:
        if action[(identity, point)] != point:
            failures.append(f"identity action fails for {point}")
    for left in group:
        for right in group:
            product_element = table_op(operation, left, right)
            for point in points:
                lhs = action[(left, action[(right, point)])]
                rhs = action[(product_element, point)]
                if lhs != rhs:
                    failures.append(f"compatibility fails for {left},{right},{point}")
    return failures


def orbit_of(
    group: list[str],
    action: dict[tuple[str, str], str],
    point: str,
) -> set[str]:
    return {action[(group_element, point)] for group_element in group}


def stabilizer_of(
    group: list[str],
    action: dict[tuple[str, str], str],
    point: str,
) -> set[str]:
    return {
        group_element
        for group_element in group
        if action[(group_element, point)] == point
    }


def action_orbits(
    group: list[str],
    points: list[str],
    action: dict[tuple[str, str], str],
) -> set[frozenset[str]]:
    unseen = set(points)
    orbits: set[frozenset[str]] = set()
    while unseen:
        point = sorted(unseen)[0]
        orbit = orbit_of(group, action, point)
        orbits.add(frozenset(orbit))
        unseen -= orbit
    return orbits


def require_group_action_values(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], str, dict[tuple[str, str], str], list[str], dict[tuple[str, str], str]]:
    group_data = values.get("group")
    if not isinstance(group_data, dict):
        fail(f"{context}.group must be an object")
    group, identity, operation = require_cayley_table(f"{context}.group", group_data)
    failures = group_axiom_failures(group, identity, operation)
    if failures:
        fail(f"{context}.group is not a group: {failures[0]}")
    points = require_string_list(f"{context}.set", values.get("set"))
    action = require_action_table(f"{context}.action", group, points, values.get("action"))
    return group, identity, operation, points, action


def validate_finite_group_actions(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    laws = checks["c2-swap-action-laws"]
    if laws["expected_result"] != "sat" or laws.get("proof_status") != "checked":
        fail("c2-swap-action-laws must be a checked sat row")
    values = single_witness_values(laws, witnesses)
    group, identity, operation, points, action = require_group_action_values("C2 action", values)
    failures = action_law_failures(group, identity, operation, points, action)
    if failures:
        fail(f"c2-swap-action-laws failed: {failures[0]}")

    orbit_check = checks["orbit-stabilizer-replay"]
    if orbit_check["expected_result"] != "sat" or orbit_check.get("proof_status") != "checked":
        fail("orbit-stabilizer-replay must be a checked sat row")
    values = single_witness_values(orbit_check, witnesses)
    group, identity, operation, points, action = require_group_action_values("orbit stabilizer action", values)
    sample_point = values.get("sample_point")
    require_string("orbit sample_point", sample_point)
    if sample_point not in set(points):
        fail("orbit-stabilizer-replay sample_point is outside the acted-on set")
    listed_orbit = set(require_string_list("orbit-stabilizer orbit", values.get("orbit")))
    listed_stabilizer = set(require_string_list("orbit-stabilizer stabilizer", values.get("stabilizer")))
    orbit_size = require_int("orbit-stabilizer orbit_size", values.get("orbit_size"))
    stabilizer_size = require_int("orbit-stabilizer stabilizer_size", values.get("stabilizer_size"))
    group_size = require_int("orbit-stabilizer group_size", values.get("group_size"))
    actual_orbit = orbit_of(group, action, sample_point)
    actual_stabilizer = stabilizer_of(group, action, sample_point)
    if listed_orbit != actual_orbit:
        fail("orbit-stabilizer-replay listed orbit is incorrect")
    if listed_stabilizer != actual_stabilizer:
        fail("orbit-stabilizer-replay listed stabilizer is incorrect")
    if orbit_size != len(actual_orbit):
        fail("orbit-stabilizer-replay orbit_size is incorrect")
    if stabilizer_size != len(actual_stabilizer):
        fail("orbit-stabilizer-replay stabilizer_size is incorrect")
    if group_size != len(group):
        fail("orbit-stabilizer-replay group_size is incorrect")
    if orbit_size * stabilizer_size != group_size:
        fail("orbit-stabilizer-replay orbit-stabilizer product is incorrect")

    burnside = checks["burnside-orbit-count-replay"]
    if burnside["expected_result"] != "sat" or burnside.get("proof_status") != "checked":
        fail("burnside-orbit-count-replay must be a checked sat row")
    values = single_witness_values(burnside, witnesses)
    group, identity, operation, points, action = require_group_action_values("Burnside action", values)
    fixed_counts_raw = values.get("fixed_counts")
    if not isinstance(fixed_counts_raw, dict) or set(fixed_counts_raw) != set(group):
        fail("burnside fixed_counts must contain exactly one count per group element")
    fixed_counts = {
        group_element: require_int(f"burnside fixed_counts.{group_element}", fixed_counts_raw[group_element])
        for group_element in group
    }
    for group_element in group:
        actual_fixed = sum(1 for point in points if action[(group_element, point)] == point)
        if fixed_counts[group_element] != actual_fixed:
            fail(f"burnside fixed count is incorrect for {group_element}")
    orbit_count = require_int("burnside orbit count", values.get("burnside_orbit_count"))
    fixed_sum = sum(fixed_counts.values())
    if fixed_sum % len(group) != 0:
        fail("burnside fixed-count sum must be divisible by group size")
    if fixed_sum // len(group) != orbit_count:
        fail("burnside orbit count is not the fixed-point average")
    listed_orbits_raw = values.get("orbits")
    if not isinstance(listed_orbits_raw, list) or not listed_orbits_raw:
        fail("burnside orbits must be a non-empty list")
    listed_orbits = {
        frozenset(require_string_list(f"burnside orbits[{index}]", orbit))
        for index, orbit in enumerate(listed_orbits_raw)
    }
    actual_orbits = action_orbits(group, points, action)
    if listed_orbits != actual_orbits:
        fail("burnside listed orbits are incorrect")
    if len(actual_orbits) != orbit_count:
        fail("burnside direct orbit enumeration disagrees with orbit count")

    bad = checks["bad-action-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-action-rejected must be a replay-only unsat row")
    data = bad.get("data", {})
    if not isinstance(data, dict):
        fail("bad-action-rejected data must be an object")
    group, identity, operation, points, action = require_group_action_values("bad action", data)
    failing_law = data.get("failing_law")
    require_string("bad action failing_law", failing_law)
    failing_point = data.get("failing_point")
    require_string("bad action failing_point", failing_point)
    actual = data.get("actual")
    require_string("bad action actual", actual)
    if failing_law != "identity_action":
        fail("bad-action-rejected currently expects identity_action")
    if failing_point not in set(points):
        fail("bad-action-rejected failing_point is outside the acted-on set")
    if action[(identity, failing_point)] != actual:
        fail("bad-action-rejected actual value is incorrect")
    if action[(identity, failing_point)] == failing_point:
        fail("bad-action-rejected identity action unexpectedly holds")

    bad_identity_alethe = checks["qf-uf-bad-identity-action"]
    if bad_identity_alethe["expected_result"] != "unsat" or bad_identity_alethe.get("proof_status") != "checked":
        fail("qf-uf-bad-identity-action must be a checked unsat row")
    if bad_identity_alethe["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-identity-action must use qf_uf_congruence_alethe validation")
    data = bad_identity_alethe.get("data", {})
    if not isinstance(data, dict):
        fail("qf-uf-bad-identity-action data must be an object")
    qf_group = require_string_list("qf-uf bad identity group_carrier", data.get("group_carrier"))
    if qf_group != group:
        fail("qf-uf-bad-identity-action group_carrier must match bad-action-rejected")
    qf_points = require_string_list("qf-uf bad identity set", data.get("set"))
    if qf_points != points:
        fail("qf-uf-bad-identity-action set must match bad-action-rejected")
    qf_failing_law = data.get("failing_law")
    qf_identity = data.get("identity_element")
    qf_failing_point = data.get("failing_point")
    qf_expected = data.get("expected")
    qf_actual = data.get("actual")
    require_string("qf-uf bad identity failing_law", qf_failing_law)
    require_string("qf-uf bad identity identity_element", qf_identity)
    require_string("qf-uf bad identity failing_point", qf_failing_point)
    require_string("qf-uf bad identity expected", qf_expected)
    require_string("qf-uf bad identity actual", qf_actual)
    if qf_failing_law != failing_law:
        fail("qf-uf-bad-identity-action failing_law must match bad-action-rejected")
    if qf_identity != identity:
        fail("qf-uf-bad-identity-action identity_element must match bad-action-rejected")
    if qf_failing_point != failing_point:
        fail("qf-uf-bad-identity-action failing_point must match bad-action-rejected")
    if qf_expected != failing_point:
        fail("qf-uf-bad-identity-action expected value must be the failing point")
    if qf_actual != actual:
        fail("qf-uf-bad-identity-action actual must match bad-action-rejected")
    claim = data.get("alethe_identity_claim")
    require_string("qf-uf bad identity alethe_identity_claim", claim)
    if claim != "e.01 = 01":
        fail("qf-uf-bad-identity-action must document the Alethe identity claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf bad identity smt2_artifact", smt2_artifact)
    check_source("qf-uf bad identity smt2_artifact", smt2_artifact)
    regression = data.get("proof_regression")
    require_string("qf-uf bad identity proof_regression", regression)
    if "finite_group_actions_bad_identity_emits_checked_alethe" not in regression:
        fail("qf-uf-bad-identity-action must link the Alethe regression")
    certificate = data.get("certificate")
    require_string("qf-uf bad identity certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-identity-action certificate must document zero-trust Alethe evidence")

    bad_compatibility = checks["bad-compatibility-rejected"]
    if bad_compatibility["expected_result"] != "unsat" or bad_compatibility.get("proof_status") != "replay-only":
        fail("bad-compatibility-rejected must be a replay-only unsat row")
    if bad_compatibility["validation"] != "finite_group_action_compatibility_refutation":
        fail("bad-compatibility-rejected must use finite_group_action_compatibility_refutation validation")
    data = bad_compatibility.get("data", {})
    if not isinstance(data, dict):
        fail("bad-compatibility-rejected data must be an object")
    group, identity, operation, points, action = require_group_action_values("bad compatibility action", data)
    failing_law = data.get("failing_law")
    require_string("bad compatibility failing_law", failing_law)
    if failing_law != "compatibility":
        fail("bad-compatibility-rejected must document a compatibility failure")
    left_element = data.get("left_element")
    right_element = data.get("right_element")
    product_element = data.get("product_element")
    failing_point = data.get("failing_point")
    intermediate = data.get("intermediate")
    lhs = data.get("lhs")
    rhs = data.get("rhs")
    require_string("bad compatibility left_element", left_element)
    require_string("bad compatibility right_element", right_element)
    require_string("bad compatibility product_element", product_element)
    require_string("bad compatibility failing_point", failing_point)
    require_string("bad compatibility intermediate", intermediate)
    require_string("bad compatibility lhs", lhs)
    require_string("bad compatibility rhs", rhs)
    for group_element, label in ((left_element, "left_element"), (right_element, "right_element"), (product_element, "product_element")):
        if group_element not in set(group):
            fail(f"bad-compatibility-rejected {label} is outside the group")
    for point, label in ((failing_point, "failing_point"), (intermediate, "intermediate"), (lhs, "lhs"), (rhs, "rhs")):
        if point not in set(points):
            fail(f"bad-compatibility-rejected {label} is outside the acted-on set")
    if table_op(operation, left_element, right_element) != product_element:
        fail("bad-compatibility-rejected product_element is incorrect")
    if action[(right_element, failing_point)] != intermediate:
        fail("bad-compatibility-rejected intermediate is incorrect")
    if action[(left_element, intermediate)] != lhs:
        fail("bad-compatibility-rejected lhs is incorrect")
    if action[(product_element, failing_point)] != rhs:
        fail("bad-compatibility-rejected rhs is incorrect")
    if lhs == rhs:
        fail("bad-compatibility-rejected compatibility unexpectedly holds")
    if action_law_failures(group, identity, operation, points, action) == []:
        fail("bad-compatibility-rejected malformed table unexpectedly satisfies action laws")

    bad_compatibility_alethe = checks["qf-uf-bad-action-compatibility"]
    if (
        bad_compatibility_alethe["expected_result"] != "unsat"
        or bad_compatibility_alethe.get("proof_status") != "checked"
    ):
        fail("qf-uf-bad-action-compatibility must be a checked unsat row")
    if bad_compatibility_alethe["validation"] != "qf_uf_congruence_alethe":
        fail("qf-uf-bad-action-compatibility must use qf_uf_congruence_alethe validation")
    data = bad_compatibility_alethe.get("data", {})
    if not isinstance(data, dict):
        fail("qf-uf-bad-action-compatibility data must be an object")
    qf_group = require_string_list("qf-uf bad compatibility group_carrier", data.get("group_carrier"))
    if qf_group != group:
        fail("qf-uf-bad-action-compatibility group_carrier must match bad-compatibility-rejected")
    qf_points = require_string_list("qf-uf bad compatibility set", data.get("set"))
    if qf_points != points:
        fail("qf-uf-bad-action-compatibility set must match bad-compatibility-rejected")
    qf_failing_law = data.get("failing_law")
    qf_left_element = data.get("left_element")
    qf_right_element = data.get("right_element")
    qf_product_element = data.get("product_element")
    qf_failing_point = data.get("failing_point")
    qf_intermediate = data.get("intermediate")
    qf_lhs = data.get("lhs")
    qf_rhs = data.get("rhs")
    require_string("qf-uf bad compatibility failing_law", qf_failing_law)
    require_string("qf-uf bad compatibility left_element", qf_left_element)
    require_string("qf-uf bad compatibility right_element", qf_right_element)
    require_string("qf-uf bad compatibility product_element", qf_product_element)
    require_string("qf-uf bad compatibility failing_point", qf_failing_point)
    require_string("qf-uf bad compatibility intermediate", qf_intermediate)
    require_string("qf-uf bad compatibility lhs", qf_lhs)
    require_string("qf-uf bad compatibility rhs", qf_rhs)
    if qf_failing_law != failing_law:
        fail("qf-uf-bad-action-compatibility failing_law must match bad-compatibility-rejected")
    if qf_left_element != left_element:
        fail("qf-uf-bad-action-compatibility left_element must match bad-compatibility-rejected")
    if qf_right_element != right_element:
        fail("qf-uf-bad-action-compatibility right_element must match bad-compatibility-rejected")
    if qf_product_element != product_element:
        fail("qf-uf-bad-action-compatibility product_element must match bad-compatibility-rejected")
    if qf_failing_point != failing_point:
        fail("qf-uf-bad-action-compatibility failing_point must match bad-compatibility-rejected")
    if qf_intermediate != intermediate:
        fail("qf-uf-bad-action-compatibility intermediate must match bad-compatibility-rejected")
    if qf_lhs != lhs:
        fail("qf-uf-bad-action-compatibility lhs must match bad-compatibility-rejected")
    if qf_rhs != rhs:
        fail("qf-uf-bad-action-compatibility rhs must match bad-compatibility-rejected")
    claim = data.get("alethe_compatibility_claim")
    require_string("qf-uf bad compatibility alethe_compatibility_claim", claim)
    if claim != "s.(s.01) = (s*s).01":
        fail("qf-uf-bad-action-compatibility must document the Alethe compatibility claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-uf bad compatibility smt2_artifact", smt2_artifact)
    check_source("qf-uf bad compatibility smt2_artifact", smt2_artifact)
    regression = data.get("proof_regression")
    require_string("qf-uf bad compatibility proof_regression", regression)
    if "finite_group_actions_bad_compatibility_emits_checked_alethe" not in regression:
        fail("qf-uf-bad-action-compatibility must link the Alethe regression")
    certificate = data.get("certificate")
    require_string("qf-uf bad compatibility certificate", certificate)
    if "UnsatAletheProof" not in certificate or "no trusted reduction" not in certificate:
        fail("qf-uf-bad-action-compatibility certificate must document zero-trust Alethe evidence")

    horizon = checks["general-group-action-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-group-action-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-group-action-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general group action target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general group action future_checker", data.get("future_checker"))


def require_binary_table(
    context: str,
    carrier: list[str],
    value: Any,
) -> dict[tuple[str, str], str]:
    carrier_set = set(carrier)
    if not isinstance(value, list) or len(value) != len(carrier):
        fail(f"{context} must have one row per carrier element")
    operation: dict[tuple[str, str], str] = {}
    for row_index, row in enumerate(value):
        if not isinstance(row, list) or len(row) != len(carrier):
            fail(f"{context}[{row_index}] must have one entry per carrier element")
        left = carrier[row_index]
        for col_index, result in enumerate(row):
            require_string(f"{context}[{row_index}][{col_index}]", result)
            if result not in carrier_set:
                fail(f"{context}[{row_index}][{col_index}] is outside the carrier")
            operation[(left, carrier[col_index])] = result
    return operation


def require_ring_tables(
    context: str,
    values: dict[str, Any],
) -> tuple[list[str], str, str | None, dict[tuple[str, str], str], dict[tuple[str, str], str]]:
    carrier = require_string_list(f"{context}.carrier", values.get("carrier"))
    carrier_set = set(carrier)
    zero = values.get("zero")
    require_string(f"{context}.zero", zero)
    if zero not in carrier_set:
        fail(f"{context}.zero must be in the carrier")
    one = values.get("one")
    if one is not None:
        require_string(f"{context}.one", one)
        if one not in carrier_set:
            fail(f"{context}.one must be in the carrier")
    add_op = require_binary_table(f"{context}.add", carrier, values.get("add"))
    mul_op = require_binary_table(f"{context}.mul", carrier, values.get("mul"))
    return carrier, zero, one, add_op, mul_op


def is_commutative(carrier: list[str], operation: dict[tuple[str, str], str]) -> bool:
    return all(table_op(operation, left, right) == table_op(operation, right, left) for left in carrier for right in carrier)


def is_associative(carrier: list[str], operation: dict[tuple[str, str], str]) -> bool:
    for left in carrier:
        for middle in carrier:
            for right in carrier:
                lhs = table_op(operation, table_op(operation, left, middle), right)
                rhs = table_op(operation, left, table_op(operation, middle, right))
                if lhs != rhs:
                    return False
    return True


def distributivity_failures(
    carrier: list[str],
    add_op: dict[tuple[str, str], str],
    mul_op: dict[tuple[str, str], str],
) -> list[str]:
    failures: list[str] = []
    for left in carrier:
        for middle in carrier:
            for right in carrier:
                left_distrib = table_op(mul_op, left, table_op(add_op, middle, right))
                left_sum = table_op(add_op, table_op(mul_op, left, middle), table_op(mul_op, left, right))
                if left_distrib != left_sum:
                    failures.append(f"left distributivity fails for {(left, middle, right)}")
                    return failures
                right_distrib = table_op(mul_op, table_op(add_op, left, middle), right)
                right_sum = table_op(add_op, table_op(mul_op, left, right), table_op(mul_op, middle, right))
                if right_distrib != right_sum:
                    failures.append(f"right distributivity fails for {(left, middle, right)}")
                    return failures
    return failures


def ring_axiom_failures(
    carrier: list[str],
    zero: str,
    one: str | None,
    add_op: dict[tuple[str, str], str],
    mul_op: dict[tuple[str, str], str],
) -> list[str]:
    failures = group_axiom_failures(carrier, zero, add_op)
    if failures:
        return [f"addition {failures[0]}"]
    if not is_commutative(carrier, add_op):
        return ["addition is not commutative"]
    if not is_associative(carrier, mul_op):
        return ["multiplication is not associative"]
    if one is not None:
        for item in carrier:
            if table_op(mul_op, one, item) != item:
                return [f"left multiplicative identity fails for {item}"]
            if table_op(mul_op, item, one) != item:
                return [f"right multiplicative identity fails for {item}"]
    return distributivity_failures(carrier, add_op, mul_op)


def validate_finite_rings(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    ring_table = checks["z4-ring-table"]
    if ring_table["expected_result"] != "sat":
        fail("z4-ring-table must expect sat")
    values = single_witness_values(ring_table, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables("z4 ring", values)
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        fail(f"z4-ring-table failed ring axioms: {failures[0]}")

    zero_divisor = checks["z4-zero-divisor-witness"]
    if zero_divisor["expected_result"] != "sat":
        fail("z4-zero-divisor-witness must expect sat")
    values = single_witness_values(zero_divisor, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables("z4 zero divisor", values)
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if failures:
        fail(f"z4-zero-divisor-witness ring table failed axioms: {failures[0]}")
    witness = values.get("zero_divisor")
    if not isinstance(witness, dict):
        fail("z4-zero-divisor-witness zero_divisor must be an object")
    left = witness.get("left")
    right = witness.get("right")
    require_string("zero divisor left", left)
    require_string("zero divisor right", right)
    if left not in set(carrier) or right not in set(carrier):
        fail("zero divisor factors must be in the carrier")
    if left == zero or right == zero:
        fail("zero divisor factors must both be nonzero")
    if table_op(mul_op, left, right) != zero:
        fail("zero divisor factors do not multiply to zero")

    bad_table = checks["non-distributive-table-rejected"]
    if bad_table["expected_result"] != "unsat":
        fail("non-distributive-table-rejected must expect unsat")
    values = single_witness_values(bad_table, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables("non-distributive table", values)
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if not failures:
        fail("non-distributive-table-rejected unexpectedly satisfies the ring axioms")
    if not distributivity_failures(carrier, add_op, mul_op):
        fail("non-distributive-table-rejected must fail distributivity specifically")

    qf_bv = checks["non-distributive-table-qf-bv-drat"]
    if qf_bv["expected_result"] != "unsat":
        fail("non-distributive-table-qf-bv-drat must expect unsat")
    if qf_bv["proof_status"] != "checked":
        fail("non-distributive-table-qf-bv-drat must be checked")
    if qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("non-distributive-table-qf-bv-drat must use qf_bv_bitblast_drat validation")
    values = single_witness_values(qf_bv, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables(
        "non-distributive QF_BV table", values
    )
    data = qf_bv.get("data", {})
    counterexample = data.get("counterexample")
    if not isinstance(counterexample, dict):
        fail("non-distributive-table-qf-bv-drat counterexample must be an object")
    a = counterexample.get("a")
    b = counterexample.get("b")
    c = counterexample.get("c")
    lhs = counterexample.get("lhs")
    rhs = counterexample.get("rhs")
    for label, value in (("a", a), ("b", b), ("c", c), ("lhs", lhs), ("rhs", rhs)):
        require_string(f"non-distributive-table-qf-bv-drat counterexample {label}", value)
        if value not in set(carrier):
            fail(f"non-distributive-table-qf-bv-drat counterexample {label} not in carrier")
    computed_lhs = table_op(mul_op, a, table_op(add_op, b, c))
    computed_rhs = table_op(add_op, table_op(mul_op, a, b), table_op(mul_op, a, c))
    if computed_lhs != lhs or computed_rhs != rhs:
        fail("non-distributive-table-qf-bv-drat counterexample values do not match tables")
    if lhs == rhs:
        fail("non-distributive-table-qf-bv-drat counterexample must be a real conflict")
    smt2_artifact = data.get("smt2_artifact")
    require_string("non-distributive-table-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("non-distributive-table-qf-bv-drat smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("non-distributive-table-qf-bv-drat proof_regression", proof_regression)
    if "finite_rings_bad_distributivity_emits_checked_drat" not in proof_regression:
        fail("non-distributive-table-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("non-distributive-table-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("non-distributive-table-qf-bv-drat certificate must document DRAT and lowering trust")

    bad_identity = checks["bad-multiplicative-identity-rejected"]
    if bad_identity["expected_result"] != "unsat":
        fail("bad-multiplicative-identity-rejected must expect unsat")
    values = single_witness_values(bad_identity, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables("bad identity table", values)
    if one is None:
        fail("bad-multiplicative-identity-rejected must include a claimed one")
    failures = ring_axiom_failures(carrier, zero, one, add_op, mul_op)
    if not failures:
        fail("bad-multiplicative-identity-rejected unexpectedly satisfies the ring axioms")
    if "multiplicative identity fails" not in failures[0]:
        fail("bad-multiplicative-identity-rejected must fail multiplicative identity specifically")
    if group_axiom_failures(carrier, zero, add_op):
        fail("bad-multiplicative-identity-rejected addition should still be a group")
    if not is_commutative(carrier, add_op):
        fail("bad-multiplicative-identity-rejected addition should remain commutative")
    if not is_associative(carrier, mul_op):
        fail("bad-multiplicative-identity-rejected multiplication should remain associative")
    if distributivity_failures(carrier, add_op, mul_op):
        fail("bad-multiplicative-identity-rejected should isolate identity, not distributivity")
    if table_op(mul_op, one, one) == one:
        fail("bad-multiplicative-identity-rejected claimed one unexpectedly acts as identity")

    identity_qf_bv = checks["bad-multiplicative-identity-qf-bv-drat"]
    if identity_qf_bv["expected_result"] != "unsat":
        fail("bad-multiplicative-identity-qf-bv-drat must expect unsat")
    if identity_qf_bv["proof_status"] != "checked":
        fail("bad-multiplicative-identity-qf-bv-drat must be checked")
    if identity_qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("bad-multiplicative-identity-qf-bv-drat must use qf_bv_bitblast_drat validation")
    values = single_witness_values(identity_qf_bv, witnesses)
    carrier, zero, one, add_op, mul_op = require_ring_tables(
        "bad multiplicative identity QF_BV table", values
    )
    if one is None:
        fail("bad-multiplicative-identity-qf-bv-drat must include a claimed one")
    data = identity_qf_bv.get("data", {})
    counterexample = data.get("counterexample")
    if not isinstance(counterexample, dict):
        fail("bad-multiplicative-identity-qf-bv-drat counterexample must be an object")
    identity_value = counterexample.get("one")
    element = counterexample.get("element")
    product_value = counterexample.get("product")
    required_value = counterexample.get("required")
    for label, value in (
        ("one", identity_value),
        ("element", element),
        ("product", product_value),
        ("required", required_value),
    ):
        require_string(f"bad-multiplicative-identity-qf-bv-drat counterexample {label}", value)
        if value not in set(carrier):
            fail(f"bad-multiplicative-identity-qf-bv-drat counterexample {label} not in carrier")
    if identity_value != one:
        fail("bad-multiplicative-identity-qf-bv-drat counterexample one does not match table one")
    if required_value != element:
        fail("bad-multiplicative-identity-qf-bv-drat required value should be the element")
    computed_product = table_op(mul_op, identity_value, element)
    if computed_product != product_value:
        fail("bad-multiplicative-identity-qf-bv-drat product does not match table")
    if product_value == required_value:
        fail("bad-multiplicative-identity-qf-bv-drat counterexample must be a real conflict")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad-multiplicative-identity-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("bad-multiplicative-identity-qf-bv-drat smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("bad-multiplicative-identity-qf-bv-drat proof_regression", proof_regression)
    if "finite_rings_bad_multiplicative_identity_emits_checked_drat" not in proof_regression:
        fail("bad-multiplicative-identity-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("bad-multiplicative-identity-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("bad-multiplicative-identity-qf-bv-drat certificate must document DRAT and lowering trust")


def require_counting_int(context: str, value: Any) -> int:
    item = require_int(context, value)
    if item < 0:
        fail(f"{context} must be nonnegative")
    return item


def factorial(value: int) -> int:
    result = 1
    for item in range(2, value + 1):
        result *= item
    return result


def permutation_count(n_value: int, k_value: int) -> int:
    if k_value > n_value:
        return 0
    return factorial(n_value) // factorial(n_value - k_value)


def combination_count(n_value: int, k_value: int) -> int:
    if k_value > n_value:
        return 0
    return factorial(n_value) // (factorial(k_value) * factorial(n_value - k_value))


def has_injective_placement(pigeons: int, holes: int) -> bool:
    for placement in product(range(holes), repeat=pigeons):
        if len(set(placement)) == pigeons:
            return True
    return False


def validate_counting(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    permutation = checks["permutation-count-fixed"]
    if permutation["expected_result"] != "sat":
        fail("permutation-count-fixed must expect sat")
    values = single_witness_values(permutation, witnesses)
    n_value = require_counting_int("permutation n", values.get("n"))
    k_value = require_counting_int("permutation k", values.get("k"))
    expected_count = require_counting_int("permutation expected", values.get("expected"))
    if permutation_count(n_value, k_value) != expected_count:
        fail("permutation-count-fixed expected count does not match P(n,k)")

    pascal = checks["pascal-identity-fixed"]
    if pascal["expected_result"] != "sat":
        fail("pascal-identity-fixed must expect sat")
    values = single_witness_values(pascal, witnesses)
    n_value = require_counting_int("pascal n", values.get("n"))
    k_value = require_counting_int("pascal k", values.get("k"))
    left = require_counting_int("pascal left", values.get("left"))
    lower_left = require_counting_int("pascal lower_left", values.get("lower_left"))
    lower_right = require_counting_int("pascal lower_right", values.get("lower_right"))
    if n_value <= 0 or k_value <= 0 or k_value > n_value:
        fail("pascal identity requires 0 < k <= n")
    if combination_count(n_value, k_value) != left:
        fail("pascal left does not match C(n,k)")
    if combination_count(n_value - 1, k_value - 1) != lower_left:
        fail("pascal lower_left does not match C(n-1,k-1)")
    if combination_count(n_value - 1, k_value) != lower_right:
        fail("pascal lower_right does not match C(n-1,k)")
    if left != lower_left + lower_right:
        fail("pascal identity row does not satisfy left = lower_left + lower_right")

    pigeonhole = checks["pigeonhole-3-2-unsat"]
    if pigeonhole["expected_result"] != "unsat":
        fail("pigeonhole-3-2-unsat must expect unsat")
    data = pigeonhole.get("data", {})
    pigeons = require_counting_int("pigeonhole pigeons", data.get("pigeons"))
    holes = require_counting_int("pigeonhole holes", data.get("holes"))
    if pigeons <= holes:
        fail("pigeonhole unsat row must use more pigeons than holes")
    if has_injective_placement(pigeons, holes):
        fail("pigeonhole check unexpectedly found an injective placement")


def is_injective_mapping(mapping: dict[str, str]) -> bool:
    return len(set(mapping.values())) == len(mapping)


def is_surjective_mapping(mapping: dict[str, str], codomain: list[str]) -> bool:
    return set(mapping.values()) == set(codomain)


def function_space_size(domain: list[str], codomain: list[str]) -> int:
    return len(codomain) ** len(domain)


def require_small_function_space(context: str, domain: list[str], codomain: list[str]) -> None:
    size = function_space_size(domain, codomain)
    if size > 100_000:
        fail(f"{context} function space is too large for deterministic example-pack enumeration")


def has_injective_function(domain: list[str], codomain: list[str]) -> bool:
    require_small_function_space("injective-function search", domain, codomain)
    for outputs in product(codomain, repeat=len(domain)):
        if len(set(outputs)) == len(outputs):
            return True
    return False


def has_surjective_function(domain: list[str], codomain: list[str]) -> bool:
    require_small_function_space("surjective-function search", domain, codomain)
    codomain_set = set(codomain)
    for outputs in product(codomain, repeat=len(domain)):
        if set(outputs) == codomain_set:
            return True
    return False


def require_cardinality_sets(context: str, data: dict[str, Any]) -> tuple[list[str], list[str]]:
    domain = require_string_list(f"{context}.domain", data.get("domain"))
    codomain = require_string_list(f"{context}.codomain", data.get("codomain"))
    require_small_function_space(context, domain, codomain)
    return domain, codomain


def validate_finite_cardinality(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    bijection = checks["finite-bijection-cardinality-witness"]
    if bijection["expected_result"] != "sat":
        fail("finite-bijection-cardinality-witness must expect sat")
    values = single_witness_values(bijection, witnesses)
    domain, codomain, pairs = require_function_graph_data("finite cardinality bijection", values)
    if len(domain) != len(codomain):
        fail("finite-bijection-cardinality-witness must use equal finite sizes")
    if not is_total_function(domain, pairs):
        fail("finite-bijection-cardinality-witness graph is not total")
    if not is_single_valued(domain, pairs):
        fail("finite-bijection-cardinality-witness graph is not single-valued")
    mapping = function_mapping(domain, pairs)
    if not is_injective_mapping(mapping):
        fail("finite-bijection-cardinality-witness graph is not injective")
    if not is_surjective_mapping(mapping, codomain):
        fail("finite-bijection-cardinality-witness graph is not surjective")

    proper_subset = checks["proper-subset-injection-witness"]
    if proper_subset["expected_result"] != "sat":
        fail("proper-subset-injection-witness must expect sat")
    values = single_witness_values(proper_subset, witnesses)
    domain, codomain, pairs = require_function_graph_data("proper subset injection", values)
    if not set(domain) < set(codomain):
        fail("proper-subset-injection-witness domain must be a proper subset of codomain")
    if not is_total_function(domain, pairs):
        fail("proper-subset-injection-witness graph is not total")
    if not is_single_valued(domain, pairs):
        fail("proper-subset-injection-witness graph is not single-valued")
    mapping = function_mapping(domain, pairs)
    if not is_injective_mapping(mapping):
        fail("proper-subset-injection-witness graph is not injective")
    if is_surjective_mapping(mapping, codomain):
        fail("proper-subset-injection-witness graph unexpectedly is surjective")

    no_injection = checks["no-injection-four-to-three"]
    if no_injection["expected_result"] != "unsat":
        fail("no-injection-four-to-three must expect unsat")
    domain, codomain = require_cardinality_sets("no-injection-four-to-three", no_injection.get("data", {}))
    if len(domain) <= len(codomain):
        fail("no-injection-four-to-three must use a larger domain than codomain")
    if has_injective_function(domain, codomain):
        fail("no-injection-four-to-three unexpectedly found an injective function")
    if len(domain) != 4 or len(codomain) != 3:
        fail("no-injection-four-to-three DIMACS artifact is fixed to a 4-into-3 instance")
    expected_dimacs: list[list[str]] = []
    for input_index in range(len(domain)):
        expected_dimacs.append(
            [str(input_index * len(codomain) + output_index + 1) for output_index in range(len(codomain))]
        )
    for input_index in range(len(domain)):
        for left, right in combinations(range(len(codomain)), 2):
            left_var = input_index * len(codomain) + left + 1
            right_var = input_index * len(codomain) + right + 1
            expected_dimacs.append([f"-{left_var}", f"-{right_var}"])
    for output_index in range(len(codomain)):
        for left, right in combinations(range(len(domain)), 2):
            left_var = left * len(codomain) + output_index + 1
            right_var = right * len(codomain) + output_index + 1
            expected_dimacs.append([f"-{left_var}", f"-{right_var}"])
    no_injection_data = no_injection.get("data", {})
    require_dimacs_artifact(
        "no-injection-four-to-three",
        no_injection_data.get("cnf_artifact"),
        "p cnf 12 34",
        expected_dimacs,
    )
    proof_regression = no_injection_data.get("proof_regression")
    require_string("no-injection-four-to-three proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::finite_cardinality_no_injection" not in proof_regression:
        fail("no-injection-four-to-three proof_regression must name the Boolean resource test")
    certificate = no_injection_data.get("certificate")
    require_string("no-injection-four-to-three certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("no-injection-four-to-three certificate must document DRAT/LRAT independent checking")

    no_surjection = checks["no-surjection-two-to-three"]
    if no_surjection["expected_result"] != "unsat":
        fail("no-surjection-two-to-three must expect unsat")
    domain, codomain = require_cardinality_sets("no-surjection-two-to-three", no_surjection.get("data", {}))
    if len(domain) >= len(codomain):
        fail("no-surjection-two-to-three must use a smaller domain than codomain")
    if has_surjective_function(domain, codomain):
        fail("no-surjection-two-to-three unexpectedly found a surjective function")

    cantor = checks["cantor-diagonal-lean-horizon"]
    if cantor["expected_result"] != "not-run":
        fail("cantor-diagonal-lean-horizon must be not-run")
    if cantor["proof_status"] != "lean-horizon":
        fail("cantor-diagonal-lean-horizon must remain lean-horizon")
    data = cantor.get("data", {})
    require_string("cantor target theorem", data.get("target_theorem"))
    require_string("cantor future checker", data.get("future_checker"))


def require_subset_from_universe(context: str, value: Any, universe: set[str]) -> set[str]:
    items = require_string_list(context, value, nonempty=False)
    item_set = set(items)
    extra = sorted(item_set - universe)
    if extra:
        fail(f"{context} contains elements outside the universe: {extra}")
    return item_set


def require_count_table(context: str, value: Any, keys: list[str]) -> dict[str, int]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    expected_keys = set(keys)
    actual_keys = set(value)
    if actual_keys != expected_keys:
        missing = sorted(expected_keys - actual_keys)
        extra = sorted(actual_keys - expected_keys)
        fail(f"{context} must cover exactly {keys}; missing={missing} extra={extra}")
    return {
        key: require_counting_int(f"{context}.{key}", value[key])
        for key in keys
    }


def finite_powerset(base: list[str]) -> set[frozenset[str]]:
    return {
        frozenset(subset)
        for subset_size in range(len(base) + 1)
        for subset in combinations(base, subset_size)
    }


def validate_cardinality_principles(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    inclusion = checks["inclusion-exclusion-two-sets"]
    if inclusion["expected_result"] != "sat" or inclusion.get("proof_status") != "checked":
        fail("inclusion-exclusion-two-sets must be a checked sat row")
    values = single_witness_values(inclusion, witnesses)
    universe = set(require_string_list("inclusion universe", values.get("universe")))
    a_set = require_subset_from_universe("inclusion A", values.get("A"), universe)
    b_set = require_subset_from_universe("inclusion B", values.get("B"), universe)
    union = require_subset_from_universe("inclusion union", values.get("union"), universe)
    intersection = require_subset_from_universe("inclusion intersection", values.get("intersection"), universe)
    counts = require_count_table("inclusion counts", values.get("counts"), ["A", "B", "union", "intersection"])
    if union != a_set | b_set:
        fail("inclusion-exclusion listed union is wrong")
    if intersection != a_set & b_set:
        fail("inclusion-exclusion listed intersection is wrong")
    if counts["A"] != len(a_set) or counts["B"] != len(b_set):
        fail("inclusion-exclusion listed set counts are wrong")
    if counts["union"] != len(union) or counts["intersection"] != len(intersection):
        fail("inclusion-exclusion listed union/intersection counts are wrong")
    if counts["union"] != counts["A"] + counts["B"] - counts["intersection"]:
        fail("inclusion-exclusion identity does not hold")

    disjoint = checks["disjoint-union-additivity"]
    if disjoint["expected_result"] != "sat" or disjoint.get("proof_status") != "checked":
        fail("disjoint-union-additivity must be a checked sat row")
    values = single_witness_values(disjoint, witnesses)
    left = set(require_string_list("disjoint left", values.get("left")))
    right = set(require_string_list("disjoint right", values.get("right")))
    union = set(require_string_list("disjoint union", values.get("union")))
    counts = require_count_table("disjoint counts", values.get("counts"), ["left", "right", "union"])
    if left & right:
        fail("disjoint-union-additivity parts must be disjoint")
    if union != left | right:
        fail("disjoint-union-additivity listed union is wrong")
    if counts["left"] != len(left) or counts["right"] != len(right) or counts["union"] != len(union):
        fail("disjoint-union-additivity listed counts are wrong")
    if counts["union"] != counts["left"] + counts["right"]:
        fail("disjoint-union-additivity identity does not hold")

    double = checks["double-counting-bipartite-edges"]
    if double["expected_result"] != "sat" or double.get("proof_status") != "checked":
        fail("double-counting-bipartite-edges must be a checked sat row")
    values = single_witness_values(double, witnesses)
    left_vertices = require_string_list("double-counting left", values.get("left"))
    right_vertices = require_string_list("double-counting right", values.get("right"))
    edges = require_pair_set(
        "double-counting edges",
        values.get("edges"),
        set(left_vertices),
        set(right_vertices),
    )
    left_degrees = require_count_table("double-counting left_degrees", values.get("left_degrees"), left_vertices)
    right_degrees = require_count_table("double-counting right_degrees", values.get("right_degrees"), right_vertices)
    edge_count = require_counting_int("double-counting edge_count", values.get("edge_count"))
    if edge_count != len(edges):
        fail("double-counting edge_count does not match the edge table")
    for vertex in left_vertices:
        if left_degrees[vertex] != sum(1 for left_vertex, _ in edges if left_vertex == vertex):
            fail("double-counting left degree table is wrong")
    for vertex in right_vertices:
        if right_degrees[vertex] != sum(1 for _, right_vertex in edges if right_vertex == vertex):
            fail("double-counting right degree table is wrong")
    if sum(left_degrees.values()) != edge_count or sum(right_degrees.values()) != edge_count:
        fail("double-counting degree sums do not equal the edge count")

    powerset = checks["finite-powerset-cardinality"]
    if powerset["expected_result"] != "sat" or powerset.get("proof_status") != "checked":
        fail("finite-powerset-cardinality must be a checked sat row")
    values = single_witness_values(powerset, witnesses)
    base = require_string_list("powerset base", values.get("base"))
    base_set = set(base)
    subsets_value = values.get("subsets")
    if not isinstance(subsets_value, list):
        fail("powerset subsets must be a list")
    listed_subsets: set[frozenset[str]] = set()
    for index, subset_value in enumerate(subsets_value):
        subset = require_subset_from_universe(f"powerset subsets[{index}]", subset_value, base_set)
        frozen = frozenset(subset)
        if frozen in listed_subsets:
            fail("powerset subsets contains a duplicate subset")
        listed_subsets.add(frozen)
    if listed_subsets != finite_powerset(base):
        fail("powerset subsets do not match the full finite powerset")
    subset_count = require_counting_int("powerset subset_count", values.get("subset_count"))
    expected_count = require_counting_int("powerset expected_count", values.get("expected_count"))
    if expected_count != 2 ** len(base):
        fail("powerset expected_count does not match 2^|base|")
    if subset_count != len(listed_subsets) or subset_count != expected_count:
        fail("powerset listed count is wrong")

    bad_additivity = checks["overlapping-disjoint-additivity-counterexample"]
    if bad_additivity["expected_result"] != "sat" or bad_additivity.get("proof_status") != "checked":
        fail("overlapping-disjoint-additivity-counterexample must be a checked sat row")
    values = single_witness_values(bad_additivity, witnesses)
    universe = set(require_string_list("bad additivity universe", values.get("universe")))
    a_set = require_subset_from_universe("bad additivity A", values.get("A"), universe)
    b_set = require_subset_from_universe("bad additivity B", values.get("B"), universe)
    union = require_subset_from_universe("bad additivity union", values.get("union"), universe)
    intersection = require_subset_from_universe("bad additivity intersection", values.get("intersection"), universe)
    false_sum = require_counting_int("bad additivity false_disjoint_sum", values.get("false_disjoint_sum"))
    true_union_count = require_counting_int("bad additivity true_union_count", values.get("true_union_count"))
    if union != a_set | b_set:
        fail("bad additivity listed union is wrong")
    if intersection != a_set & b_set:
        fail("bad additivity listed intersection is wrong")
    if not intersection:
        fail("bad additivity counterexample must use overlapping sets")
    if false_sum != len(a_set) + len(b_set):
        fail("bad additivity false_disjoint_sum is not |A| + |B|")
    if true_union_count != len(union):
        fail("bad additivity true_union_count does not match |A union B|")
    if false_sum == true_union_count:
        fail("bad additivity row does not falsify disjoint additivity for overlapping sets")

    conflict = checks["overlap-additivity-count-conflict"]
    if conflict["expected_result"] != "unsat" or conflict.get("proof_status") != "checked":
        fail("overlap-additivity-count-conflict must be a checked unsat row")
    data = conflict.get("data", {})
    conflict_union_count = require_counting_int(
        "overlap additivity conflict true_union_count",
        data.get("true_union_count"),
    )
    conflict_disjoint_sum = require_counting_int(
        "overlap additivity conflict claimed_disjoint_sum",
        data.get("claimed_disjoint_sum"),
    )
    if conflict_union_count != true_union_count:
        fail("overlap-additivity-count-conflict true_union_count does not match replay")
    if conflict_disjoint_sum != false_sum:
        fail("overlap-additivity-count-conflict claimed_disjoint_sum does not match replay")
    if conflict_union_count == conflict_disjoint_sum:
        fail("overlap-additivity-count-conflict must record different counts")
    smt2_artifact = data.get("smt2_artifact")
    require_string("overlap additivity smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/cardinality-principles-v0/smt2/overlap-additivity-diophantine-conflict.smt2"
    ):
        fail("overlap-additivity-count-conflict smt2_artifact must name the checked QF_LIA artifact")
    check_source("overlap additivity smt2_artifact", smt2_artifact)
    lia_regression = data.get("lia_regression")
    require_string("overlap additivity lia_regression", lia_regression)
    if "cardinality_principles_overlap_additivity_emits_checked_diophantine_evidence" not in lia_regression:
        fail("overlap-additivity-count-conflict must link the LIA route regression")

    horizon = checks["cantor-schroeder-bernstein-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("cantor-schroeder-bernstein-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("cantor-schroeder-bernstein-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("cardinality-principles target theorem", data.get("target_theorem"))
    require_string("cardinality-principles future checker", data.get("future_checker"))


def validate_modular_arithmetic(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    crt = checks["crt-coprime-witness"]
    if crt["expected_result"] != "sat":
        fail("crt-coprime-witness must expect sat")
    crt_values = single_witness_values(crt, witnesses)
    x = require_int("crt witness x", crt_values.get("x"))
    congruences = crt_values.get("congruences")
    if not isinstance(congruences, list) or len(congruences) < 2:
        fail("crt witness congruences must contain at least two congruences")
    moduli: list[int] = []
    for index, congruence in enumerate(congruences):
        if not isinstance(congruence, dict):
            fail(f"crt congruence {index} must be an object")
        remainder = require_int(f"crt congruence {index}.remainder", congruence.get("remainder"))
        modulus = require_int(f"crt congruence {index}.modulus", congruence.get("modulus"))
        if modulus <= 1:
            fail(f"crt congruence {index}.modulus must be > 1")
        if x % modulus != remainder % modulus:
            fail(f"crt witness does not satisfy x == {remainder} mod {modulus}")
        moduli.append(modulus)
    for left_index, left in enumerate(moduli):
        for right in moduli[left_index + 1 :]:
            if gcd(left, right) != 1:
                fail(f"CRT moduli must be coprime: {left}, {right}")

    inverse = checks["modular-inverse-witness"]
    if inverse["expected_result"] != "sat":
        fail("modular-inverse-witness must expect sat")
    inv_values = single_witness_values(inverse, witnesses)
    a = require_int("inverse witness a", inv_values.get("a"))
    modulus = require_int("inverse witness modulus", inv_values.get("modulus"))
    inv = require_int("inverse witness inverse", inv_values.get("inverse"))
    if modulus <= 1:
        fail("inverse modulus must be > 1")
    if gcd(a, modulus) != 1:
        fail("inverse witness a must be coprime to modulus")
    if (a * inv) % modulus != 1:
        fail("inverse witness does not multiply to 1 modulo modulus")

    nonunit = checks["composite-nonunit-no-inverse"]
    if nonunit["expected_result"] != "unsat":
        fail("composite-nonunit-no-inverse must expect unsat")
    data = nonunit.get("data", {})
    a = require_int("nonunit data a", data.get("a"))
    modulus = require_int("nonunit data modulus", data.get("modulus"))
    if modulus <= 1:
        fail("nonunit modulus must be > 1")
    if gcd(a, modulus) == 1:
        fail("nonunit data must use a non-coprime residue")
    if has_mod_inverse(a, modulus):
        fail("nonunit check found an inverse unexpectedly")

    qf_lia = checks["qf-lia-nonunit-diophantine"]
    if qf_lia["expected_result"] != "unsat":
        fail("qf-lia-nonunit-diophantine must expect unsat")
    if qf_lia["proof_status"] != "checked":
        fail("qf-lia-nonunit-diophantine must be checked")
    if qf_lia["validation"] != "qf_lia_diophantine_evidence":
        fail("qf-lia-nonunit-diophantine must use qf_lia_diophantine_evidence validation")
    data = qf_lia.get("data", {})
    a = require_int("qf-lia nonunit data a", data.get("a"))
    modulus = require_int("qf-lia nonunit data modulus", data.get("modulus"))
    rhs = require_int("qf-lia nonunit data rhs", data.get("rhs"))
    if modulus <= 1:
        fail("qf-lia nonunit modulus must be > 1")
    if gcd(a, modulus) == 1:
        fail("qf-lia nonunit data must use a non-coprime residue")
    if gcd(a, modulus) == 0 or rhs % gcd(a, modulus) == 0:
        fail("qf-lia nonunit data must record a gcd divisibility obstruction")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-lia nonunit smt2_artifact", smt2_artifact)
    check_source("qf-lia nonunit smt2_artifact", smt2_artifact)
    require_string("qf-lia nonunit proof_regression", data.get("proof_regression"))
    certificate = data.get("certificate")
    require_string("qf-lia nonunit certificate", certificate)
    if "UnsatDiophantine" not in certificate or "Evidence::check" not in certificate:
        fail("qf-lia nonunit certificate must document checked Diophantine evidence")

    nonunit_qf_bv = checks["composite-nonunit-no-inverse-qf-bv-drat"]
    if nonunit_qf_bv["expected_result"] != "unsat":
        fail("composite-nonunit-no-inverse-qf-bv-drat must expect unsat")
    if nonunit_qf_bv["proof_status"] != "checked":
        fail("composite-nonunit-no-inverse-qf-bv-drat must be checked")
    if nonunit_qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("composite-nonunit-no-inverse-qf-bv-drat must use qf_bv_bitblast_drat validation")
    data = nonunit_qf_bv.get("data", {})
    a = require_int("QF_BV nonunit data a", data.get("a"))
    modulus = require_modulus("QF_BV nonunit modulus", data.get("modulus"))
    if gcd(a, modulus) == 1:
        fail("composite-nonunit-no-inverse-qf-bv-drat must use a nonunit residue")
    if has_mod_inverse(a, modulus):
        fail("composite-nonunit-no-inverse-qf-bv-drat found an inverse unexpectedly")
    candidate_residues = require_int_list(
        "QF_BV nonunit candidate_residues",
        data.get("candidate_residues"),
    )
    if candidate_residues != list(range(modulus)):
        fail("composite-nonunit-no-inverse-qf-bv-drat must list every residue modulo m")
    if any((a * residue) % modulus == 1 for residue in candidate_residues):
        fail("composite-nonunit-no-inverse-qf-bv-drat lists an inverse residue unexpectedly")
    residue_width = require_int("QF_BV nonunit residue_width", data.get("residue_width"))
    product_width = require_int("QF_BV nonunit product_width", data.get("product_width"))
    if 2**residue_width <= modulus:
        fail("composite-nonunit-no-inverse-qf-bv-drat residue_width must encode every residue and the modulus")
    max_product = max(a * residue for residue in candidate_residues)
    if 2**product_width <= max_product:
        fail("composite-nonunit-no-inverse-qf-bv-drat product_width must encode every listed product exactly")
    if a != 2 or modulus != 6 or residue_width != 3 or product_width != 6:
        fail("composite-nonunit-no-inverse-qf-bv-drat is fixed to 2 modulo 6 with 3-bit residues and 6-bit products")
    smt2_artifact = data.get("smt2_artifact")
    require_string("QF_BV nonunit smt2_artifact", smt2_artifact)
    check_source("QF_BV nonunit smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/modular-arithmetic-v0/smt2/nonunit-inverse-mod6-bitblast-conflict.smt2":
        fail("composite-nonunit-no-inverse-qf-bv-drat smt2_artifact must name the checked QF_BV artifact")
    proof_regression = data.get("proof_regression")
    require_string("QF_BV nonunit proof_regression", proof_regression)
    if "modular_arithmetic_nonunit_inverse_mod6_emits_checked_bv_drat" not in proof_regression:
        fail("composite-nonunit-no-inverse-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("QF_BV nonunit certificate", certificate)
    if "DRAT" not in certificate or "bit-blast" not in certificate or "Tseitin" not in certificate:
        fail("composite-nonunit-no-inverse-qf-bv-drat certificate must document DRAT and lowering trust")

    crt_qf_lia = checks["qf-lia-incompatible-crt-diophantine"]
    if crt_qf_lia["expected_result"] != "unsat":
        fail("qf-lia-incompatible-crt-diophantine must expect unsat")
    if crt_qf_lia["proof_status"] != "checked":
        fail("qf-lia-incompatible-crt-diophantine must be checked")
    if crt_qf_lia["validation"] != "qf_lia_diophantine_evidence":
        fail("qf-lia-incompatible-crt-diophantine must use qf_lia_diophantine_evidence validation")
    data = crt_qf_lia.get("data", {})
    congruences = require_congruences("qf-lia incompatible CRT congruences", data.get("congruences"))
    if len(congruences) != 2:
        fail("qf-lia-incompatible-crt-diophantine must use exactly two congruences")
    left, right = congruences
    divisor = gcd(left["modulus"], right["modulus"])
    expected_gcd = require_int("qf-lia incompatible CRT gcd", data.get("gcd"))
    delta = require_int("qf-lia incompatible CRT delta", data.get("delta"))
    if expected_gcd != divisor:
        fail("qf-lia-incompatible-crt-diophantine records the wrong modulus gcd")
    if delta != right["remainder"] - left["remainder"]:
        fail("qf-lia-incompatible-crt-diophantine records the wrong remainder delta")
    if delta % divisor == 0:
        fail("qf-lia-incompatible-crt-diophantine data is compatible by the CRT gcd criterion")
    if left != {"remainder": 1, "modulus": 4} or right != {"remainder": 2, "modulus": 6}:
        fail("qf-lia-incompatible-crt-diophantine solver promotion is fixed to x == 1 mod 4 and x == 2 mod 6")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-lia incompatible CRT smt2_artifact", smt2_artifact)
    check_source("qf-lia incompatible CRT smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/modular-arithmetic-v0/smt2/incompatible-crt-diophantine-conflict.smt2":
        fail("qf-lia-incompatible-crt-diophantine smt2_artifact must name the checked QF_LIA artifact")
    proof_regression = data.get("proof_regression")
    require_string("qf-lia incompatible CRT proof_regression", proof_regression)
    if "modular_incompatible_crt_emits_checked_diophantine_evidence" not in proof_regression:
        fail("qf-lia-incompatible-crt-diophantine proof_regression must name the LIA resource test")
    certificate = data.get("certificate")
    require_string("qf-lia incompatible CRT certificate", certificate)
    if "UnsatDiophantine" not in certificate or "Evidence::check" not in certificate:
        fail("qf-lia-incompatible-crt-diophantine certificate must document checked Diophantine evidence")

    fermat = checks["fermat-units-mod-prime"]
    if fermat["expected_result"] != "unsat":
        fail("fermat-units-mod-prime must expect unsat")
    data = fermat.get("data", {})
    modulus = require_int("fermat data modulus", data.get("modulus"))
    exponent = require_int("fermat data exponent", data.get("exponent"))
    if modulus <= 1:
        fail("fermat modulus must be > 1")
    for a in range(1, modulus):
        if gcd(a, modulus) == 1 and pow(a, exponent, modulus) != 1:
            fail(f"fermat counterexample found: a={a}, modulus={modulus}, exponent={exponent}")

    fermat_qf_bv = checks["fermat-units-mod-prime-qf-bv-drat"]
    if fermat_qf_bv["expected_result"] != "unsat":
        fail("fermat-units-mod-prime-qf-bv-drat must expect unsat")
    if fermat_qf_bv["proof_status"] != "checked":
        fail("fermat-units-mod-prime-qf-bv-drat must be checked")
    if fermat_qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("fermat-units-mod-prime-qf-bv-drat must use qf_bv_bitblast_drat validation")
    data = fermat_qf_bv.get("data", {})
    modulus = require_modulus("Fermat QF_BV modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("fermat-units-mod-prime-qf-bv-drat must use a prime modulus")
    exponent = require_int("Fermat QF_BV exponent", data.get("exponent"))
    if exponent != modulus - 1:
        fail("fermat-units-mod-prime-qf-bv-drat exponent must be p - 1")
    unit_residues = require_int_list("Fermat QF_BV unit_residues", data.get("unit_residues"))
    expected_units = [residue for residue in range(1, modulus) if gcd(residue, modulus) == 1]
    if unit_residues != expected_units:
        fail("fermat-units-mod-prime-qf-bv-drat must list exactly the nonzero units modulo p")
    for residue in unit_residues:
        if pow(residue, exponent, modulus) != 1:
            fail(f"Fermat QF_BV row lists a counterexample residue unexpectedly: {residue}")
    residue_width = require_int("Fermat QF_BV residue_width", data.get("residue_width"))
    power_width = require_int("Fermat QF_BV power_width", data.get("power_width"))
    if 2**residue_width <= modulus:
        fail("fermat-units-mod-prime-qf-bv-drat residue_width must encode every residue and the modulus")
    max_power = max(residue**exponent for residue in unit_residues)
    if 2**power_width <= max_power:
        fail("fermat-units-mod-prime-qf-bv-drat power_width must encode the largest listed power exactly")
    if modulus != 5 or exponent != 4 or residue_width != 3 or power_width != 9:
        fail("fermat-units-mod-prime-qf-bv-drat is fixed to modulo 5 with a 3-bit residue and 9-bit power")
    smt2_artifact = data.get("smt2_artifact")
    require_string("fermat-units-mod-prime-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("fermat-units-mod-prime-qf-bv-drat smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/modular-arithmetic-v0/smt2/fermat-units-mod5-bitblast-conflict.smt2":
        fail("fermat-units-mod-prime-qf-bv-drat smt2_artifact must name the checked QF_BV artifact")
    proof_regression = data.get("proof_regression")
    require_string("fermat-units-mod-prime-qf-bv-drat proof_regression", proof_regression)
    if "modular_arithmetic_fermat_units_mod5_emits_checked_bv_drat" not in proof_regression:
        fail("fermat-units-mod-prime-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("fermat-units-mod-prime-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("fermat-units-mod-prime-qf-bv-drat certificate must document DRAT and lowering trust")


def positive_divisors(value: int) -> list[int]:
    value = abs(value)
    if value == 0:
        fail("positive divisors are undefined for zero")
    return [candidate for candidate in range(1, value + 1) if value % candidate == 0]


def require_int_list(context: str, value: Any) -> list[int]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty integer list")
    return [require_int(f"{context}[{index}]", item) for index, item in enumerate(value)]


def validate_gcd_bezout(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    gcd_check = checks["gcd-common-divisors-replay"]
    if gcd_check["expected_result"] != "sat":
        fail("gcd-common-divisors-replay must expect sat")
    values = single_witness_values(gcd_check, witnesses)
    a = require_int("gcd witness a", values.get("a"))
    b = require_int("gcd witness b", values.get("b"))
    expected_gcd = require_int("gcd witness gcd", values.get("gcd"))
    if expected_gcd <= 0:
        fail("gcd witness gcd must be positive")
    computed_gcd = gcd(abs(a), abs(b))
    if computed_gcd != expected_gcd:
        fail("gcd-common-divisors-replay gcd does not match")
    listed_common_divisors = sorted(
        require_int_list("gcd witness common_divisors", values.get("common_divisors"))
    )
    computed_common_divisors = [
        divisor
        for divisor in positive_divisors(computed_gcd)
        if a % divisor == 0 and b % divisor == 0
    ]
    if listed_common_divisors != computed_common_divisors:
        fail("gcd-common-divisors-replay common divisors do not match")

    bezout = checks["bezout-identity-replay"]
    if bezout["expected_result"] != "sat":
        fail("bezout-identity-replay must expect sat")
    values = single_witness_values(bezout, witnesses)
    a = require_int("bezout witness a", values.get("a"))
    b = require_int("bezout witness b", values.get("b"))
    expected_gcd = require_int("bezout witness gcd", values.get("gcd"))
    x = require_int("bezout witness x", values.get("x"))
    y = require_int("bezout witness y", values.get("y"))
    if expected_gcd <= 0:
        fail("bezout witness gcd must be positive")
    if gcd(abs(a), abs(b)) != expected_gcd:
        fail("bezout-identity-replay gcd does not match")
    if a * x + b * y != expected_gcd:
        fail("bezout-identity-replay coefficients do not produce the gcd")

    divisibility = checks["divisibility-quotient-replay"]
    if divisibility["expected_result"] != "sat":
        fail("divisibility-quotient-replay must expect sat")
    values = single_witness_values(divisibility, witnesses)
    divisor = require_int("divisibility witness divisor", values.get("divisor"))
    dividend = require_int("divisibility witness dividend", values.get("dividend"))
    quotient = require_int("divisibility witness quotient", values.get("quotient"))
    if divisor == 0:
        fail("divisibility witness divisor must be nonzero")
    if divisor * quotient != dividend:
        fail("divisibility-quotient-replay quotient does not match dividend")

    obstruction = checks["diophantine-gcd-obstruction"]
    if obstruction["expected_result"] != "unsat":
        fail("diophantine-gcd-obstruction must expect unsat")
    data = obstruction.get("data", {})
    a = require_int("diophantine data a", data.get("a"))
    b = require_int("diophantine data b", data.get("b"))
    target = require_int("diophantine data target", data.get("target"))
    coefficient_gcd = gcd(abs(a), abs(b))
    if coefficient_gcd == 0:
        fail("diophantine coefficients must not both be zero")
    if target % coefficient_gcd == 0:
        fail("diophantine-gcd-obstruction data is satisfiable by the gcd criterion")


def require_residue(context: str, value: Any, modulus: int) -> int:
    residue = require_int(context, value)
    if residue < 0 or residue >= modulus:
        fail(f"{context} must be a residue in [0, {modulus})")
    return residue


def require_congruences(context: str, value: Any) -> list[dict[str, int]]:
    if not isinstance(value, list) or len(value) < 2:
        fail(f"{context} must contain at least two congruences")
    congruences: list[dict[str, int]] = []
    for index, congruence in enumerate(value):
        if not isinstance(congruence, dict):
            fail(f"{context}[{index}] must be an object")
        modulus = require_modulus(
            f"{context}[{index}].modulus",
            congruence.get("modulus"),
        )
        remainder = require_int(f"{context}[{index}].remainder", congruence.get("remainder"))
        congruences.append({"remainder": remainder, "modulus": modulus})
    return congruences


def has_square_root_mod(residue: int, modulus: int) -> bool:
    return any(
        (candidate * candidate) % modulus == residue % modulus
        for candidate in range(modulus)
    )


def validate_number_theory(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    crt = checks["crt-compatible-noncoprime-witness"]
    if crt["expected_result"] != "sat":
        fail("crt-compatible-noncoprime-witness must expect sat")
    values = single_witness_values(crt, witnesses)
    x = require_int("number theory CRT x", values.get("x"))
    congruences = require_congruences("number theory CRT congruences", values.get("congruences"))
    has_noncoprime_pair = False
    for congruence in congruences:
        if x % congruence["modulus"] != congruence["remainder"] % congruence["modulus"]:
            fail("crt-compatible-noncoprime-witness does not satisfy all congruences")
    for left_index, left in enumerate(congruences):
        for right in congruences[left_index + 1 :]:
            divisor = gcd(left["modulus"], right["modulus"])
            if divisor > 1:
                has_noncoprime_pair = True
            if (left["remainder"] - right["remainder"]) % divisor != 0:
                fail("crt-compatible-noncoprime-witness has incompatible congruences")
    if not has_noncoprime_pair:
        fail("crt-compatible-noncoprime-witness must include a non-coprime modulus pair")

    residue = checks["quadratic-residue-witness"]
    if residue["expected_result"] != "sat":
        fail("quadratic-residue-witness must expect sat")
    values = single_witness_values(residue, witnesses)
    modulus = require_modulus("quadratic residue modulus", values.get("modulus"))
    if not is_prime(modulus):
        fail("quadratic residue modulus must be prime")
    target = require_residue("quadratic residue target", values.get("residue"), modulus)
    root = require_residue("quadratic residue root", values.get("root"), modulus)
    if (root * root) % modulus != target:
        fail("quadratic-residue-witness root does not square to the target")

    nonresidue = checks["quadratic-nonresidue-rejected"]
    if nonresidue["expected_result"] != "unsat":
        fail("quadratic-nonresidue-rejected must expect unsat")
    data = nonresidue.get("data", {})
    modulus = require_modulus("quadratic nonresidue modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("quadratic nonresidue modulus must be prime")
    target = require_residue("quadratic nonresidue target", data.get("residue"), modulus)
    if has_square_root_mod(target, modulus):
        fail("quadratic-nonresidue-rejected found a square root unexpectedly")

    qf_bv = checks["quadratic-nonresidue-qf-bv-drat"]
    if qf_bv["expected_result"] != "unsat":
        fail("quadratic-nonresidue-qf-bv-drat must expect unsat")
    if qf_bv["proof_status"] != "checked":
        fail("quadratic-nonresidue-qf-bv-drat must be checked")
    if qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("quadratic-nonresidue-qf-bv-drat must use qf_bv_bitblast_drat validation")
    data = qf_bv.get("data", {})
    modulus = require_modulus("quadratic nonresidue QF_BV modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("quadratic-nonresidue-qf-bv-drat must use a prime modulus")
    target = require_residue("quadratic nonresidue QF_BV target", data.get("residue"), modulus)
    if has_square_root_mod(target, modulus):
        fail("quadratic-nonresidue-qf-bv-drat found a square root unexpectedly")
    residue_width = require_int("quadratic nonresidue QF_BV residue_width", data.get("residue_width"))
    product_width = require_int("quadratic nonresidue QF_BV product_width", data.get("product_width"))
    if 2**residue_width <= modulus:
        fail("quadratic nonresidue QF_BV residue_width must encode every residue and the modulus guard")
    if 2**product_width <= (modulus - 1) * (modulus - 1):
        fail("quadratic nonresidue QF_BV product_width must encode the maximum square exactly")
    smt2_artifact = data.get("smt2_artifact")
    require_string("quadratic-nonresidue-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("quadratic-nonresidue-qf-bv-drat smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("quadratic-nonresidue-qf-bv-drat proof_regression", proof_regression)
    if "number_theory_quadratic_nonresidue_emits_checked_bv_drat" not in proof_regression:
        fail("quadratic-nonresidue-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("quadratic-nonresidue-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("quadratic-nonresidue-qf-bv-drat certificate must document DRAT and lowering trust")

    bad_square = checks["bad-square-witness-rejected"]
    if bad_square["expected_result"] != "unsat":
        fail("bad-square-witness-rejected must expect unsat")
    if bad_square["proof_status"] != "checked":
        fail("bad-square-witness-rejected must be checked")
    if bad_square["validation"] != "bad_quadratic_residue_witness_replay":
        fail("bad-square-witness-rejected must use bad_quadratic_residue_witness_replay validation")
    data = bad_square.get("data", {})
    modulus = require_modulus("bad square witness modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("bad-square-witness-rejected must use a prime modulus")
    target = require_residue("bad square witness target", data.get("residue"), modulus)
    candidate = require_residue("bad square witness candidate", data.get("candidate"), modulus)
    square = require_residue("bad square witness square", data.get("square"), modulus)
    computed_square = (candidate * candidate) % modulus
    if computed_square != square:
        fail("bad-square-witness-rejected records the wrong candidate square")
    if square == target:
        fail("bad-square-witness-rejected must record a genuinely false square-root witness")

    bad_square_qf_bv = checks["bad-square-witness-qf-bv-drat"]
    if bad_square_qf_bv["expected_result"] != "unsat":
        fail("bad-square-witness-qf-bv-drat must expect unsat")
    if bad_square_qf_bv["proof_status"] != "checked":
        fail("bad-square-witness-qf-bv-drat must be checked")
    if bad_square_qf_bv["validation"] != "qf_bv_bitblast_drat":
        fail("bad-square-witness-qf-bv-drat must use qf_bv_bitblast_drat validation")
    data = bad_square_qf_bv.get("data", {})
    modulus = require_modulus("bad square witness QF_BV modulus", data.get("modulus"))
    if not is_prime(modulus):
        fail("bad-square-witness-qf-bv-drat must use a prime modulus")
    target = require_residue("bad square witness QF_BV target", data.get("residue"), modulus)
    candidate = require_residue("bad square witness QF_BV candidate", data.get("candidate"), modulus)
    square = require_residue("bad square witness QF_BV square", data.get("square"), modulus)
    computed_square = (candidate * candidate) % modulus
    if computed_square != square:
        fail("bad-square-witness-qf-bv-drat records the wrong candidate square")
    if square == target:
        fail("bad-square-witness-qf-bv-drat must record a genuinely false square-root witness")
    residue_width = require_int("bad square witness QF_BV residue_width", data.get("residue_width"))
    product_width = require_int("bad square witness QF_BV product_width", data.get("product_width"))
    if 2**residue_width <= modulus:
        fail("bad square witness QF_BV residue_width must encode every residue and the modulus")
    if 2**product_width <= (modulus - 1) * (modulus - 1):
        fail("bad square witness QF_BV product_width must encode the maximum square exactly")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad-square-witness-qf-bv-drat smt2_artifact", smt2_artifact)
    check_source("bad-square-witness-qf-bv-drat smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("bad-square-witness-qf-bv-drat proof_regression", proof_regression)
    if "number_theory_bad_square_witness_emits_checked_bv_drat" not in proof_regression:
        fail("bad-square-witness-qf-bv-drat proof_regression must name the BV route test")
    certificate = data.get("certificate")
    require_string("bad-square-witness-qf-bv-drat certificate", certificate)
    if "DRAT" not in certificate or "bit-blast/Tseitin" not in certificate:
        fail("bad-square-witness-qf-bv-drat certificate must document DRAT and lowering trust")

    sum_squares = checks["sum-two-squares-witness"]
    if sum_squares["expected_result"] != "sat":
        fail("sum-two-squares-witness must expect sat")
    values = single_witness_values(sum_squares, witnesses)
    n_value = require_int("sum two squares n", values.get("n"))
    left = require_int("sum two squares a", values.get("a"))
    right = require_int("sum two squares b", values.get("b"))
    if n_value < 0:
        fail("sum-two-squares-witness n must be nonnegative")
    if left * left + right * right != n_value:
        fail("sum-two-squares-witness does not match a^2 + b^2")

    mod4 = checks["sum-two-squares-mod4-rejected"]
    if mod4["expected_result"] != "unsat":
        fail("sum-two-squares-mod4-rejected must expect unsat")
    data = mod4.get("data", {})
    n_value = require_int("sum two squares mod4 n", data.get("n"))
    if n_value < 0:
        fail("sum-two-squares-mod4-rejected n must be nonnegative")
    square_residues = {candidate * candidate % 4 for candidate in range(4)}
    possible_sums = {(left + right) % 4 for left, right in product(square_residues, repeat=2)}
    if n_value % 4 in possible_sums:
        fail("sum-two-squares-mod4-rejected data is not ruled out by mod-4 squares")

    diophantine = checks["bounded-diophantine-witness"]
    if diophantine["expected_result"] != "sat":
        fail("bounded-diophantine-witness must expect sat")
    values = single_witness_values(diophantine, witnesses)
    coefficients = require_int_list("bounded diophantine coefficients", values.get("coefficients"))
    solution = require_int_list("bounded diophantine solution", values.get("solution"))
    target = require_int("bounded diophantine target", values.get("target"))
    if len(coefficients) != len(solution):
        fail("bounded-diophantine-witness coefficients and solution must have the same length")
    total = sum(coefficient * value for coefficient, value in zip(coefficients, solution))
    if total != target:
        fail("bounded-diophantine-witness solution does not satisfy the equation")

    diophantine_obstruction = checks["diophantine-gcd-obstruction-qf-lia"]
    if diophantine_obstruction["expected_result"] != "unsat":
        fail("diophantine-gcd-obstruction-qf-lia must expect unsat")
    if diophantine_obstruction["proof_status"] != "checked":
        fail("diophantine-gcd-obstruction-qf-lia must be checked")
    if diophantine_obstruction["validation"] != "gcd_divisibility_refutation":
        fail("diophantine-gcd-obstruction-qf-lia must use gcd_divisibility_refutation validation")
    data = diophantine_obstruction.get("data", {})
    coefficients = require_int_list("number theory Diophantine obstruction coefficients", data.get("coefficients"))
    target = require_int("number theory Diophantine obstruction target", data.get("target"))
    expected_gcd = require_int("number theory Diophantine obstruction gcd", data.get("gcd"))
    coefficient_gcd = 0
    for coefficient in coefficients:
        coefficient_gcd = gcd(coefficient_gcd, abs(coefficient))
    if coefficient_gcd == 0:
        fail("diophantine-gcd-obstruction-qf-lia coefficients must not all be zero")
    if coefficient_gcd != expected_gcd:
        fail("diophantine-gcd-obstruction-qf-lia records the wrong gcd")
    if target % coefficient_gcd == 0:
        fail("diophantine-gcd-obstruction-qf-lia data is satisfiable by the gcd criterion")
    if coefficients != [14, 21] or target != 5 or coefficient_gcd != 7:
        fail("diophantine-gcd-obstruction-qf-lia solver promotion is fixed to 14*x + 21*y = 5")
    smt2_artifact = data.get("smt2_artifact")
    require_string("number theory Diophantine obstruction smt2_artifact", smt2_artifact)
    check_source("number theory Diophantine obstruction smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/number-theory-v0/smt2/diophantine-gcd-obstruction-conflict.smt2":
        fail("diophantine-gcd-obstruction-qf-lia smt2_artifact must name the checked QF_LIA artifact")
    proof_regression = data.get("proof_regression")
    require_string("number theory Diophantine obstruction proof_regression", proof_regression)
    if "number_theory_diophantine_gcd_obstruction_emits_checked_diophantine_evidence" not in proof_regression:
        fail("diophantine-gcd-obstruction-qf-lia proof_regression must name the LIA resource test")
    certificate = data.get("certificate")
    require_string("number theory Diophantine obstruction certificate", certificate)
    if "UnsatDiophantine" not in certificate or "Evidence::check" not in certificate:
        fail("diophantine-gcd-obstruction-qf-lia certificate must document checked Diophantine evidence")


def integer_relation(left: int, right: int) -> str:
    if left < right:
        return "lt"
    if left > right:
        return "gt"
    return "eq"


def require_linear_integer_witness(
    context: str,
    values: dict[str, Any],
) -> tuple[list[int], list[int], int]:
    coefficients = require_int_list(f"{context}.coefficients", values.get("coefficients"))
    solution = require_int_list(f"{context}.solution", values.get("solution"))
    target = require_int(f"{context}.target", values.get("target"))
    if len(coefficients) != len(solution):
        fail(f"{context} coefficients and solution must have the same length")
    return coefficients, solution, target


def dot_product(left: list[int], right: list[int]) -> int:
    return sum(left_value * right_value for left_value, right_value in zip(left, right))


def validate_integer_lia(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    trichotomy = checks["signed-trichotomy-fixed"]
    if trichotomy["expected_result"] != "sat":
        fail("signed-trichotomy-fixed must expect sat")
    values = single_witness_values(trichotomy, witnesses)
    left = require_int("trichotomy left", values.get("left"))
    right = require_int("trichotomy right", values.get("right"))
    relation = values.get("relation")
    require_string("trichotomy relation", relation)
    if relation not in {"lt", "eq", "gt"}:
        fail("trichotomy relation must be one of lt, eq, gt")
    truth_values = [left < right, left == right, left > right]
    if sum(1 for truth_value in truth_values if truth_value) != 1:
        fail("signed-trichotomy-fixed did not find exactly one true relation")
    if integer_relation(left, right) != relation:
        fail("signed-trichotomy-fixed listed relation is not the true relation")

    transitivity = checks["order-transitivity-fixed"]
    if transitivity["expected_result"] != "sat":
        fail("order-transitivity-fixed must expect sat")
    values = single_witness_values(transitivity, witnesses)
    a_value = require_int("transitivity a", values.get("a"))
    b_value = require_int("transitivity b", values.get("b"))
    c_value = require_int("transitivity c", values.get("c"))
    if not (a_value < b_value and b_value < c_value and a_value < c_value):
        fail("order-transitivity-fixed chain does not satisfy transitivity")

    identity = checks["integer-ring-identity-replay"]
    if identity["expected_result"] != "sat":
        fail("integer-ring-identity-replay must expect sat")
    values = single_witness_values(identity, witnesses)
    a_value = require_int("ring identity a", values.get("a"))
    b_value = require_int("ring identity b", values.get("b"))
    result = require_int("ring identity result", values.get("result"))
    if (a_value + b_value) - b_value != result:
        fail("integer-ring-identity-replay result does not match")
    if result != a_value:
        fail("integer-ring-identity-replay result must equal a")

    equation = checks["linear-equation-witness"]
    if equation["expected_result"] != "sat":
        fail("linear-equation-witness must expect sat")
    values = single_witness_values(equation, witnesses)
    coefficients, solution, target = require_linear_integer_witness("linear equation", values)
    if dot_product(coefficients, solution) != target:
        fail("linear-equation-witness solution does not satisfy the equation")

    interval = checks["integer-interval-infeasible"]
    if interval["expected_result"] != "unsat":
        fail("integer-interval-infeasible must expect unsat")
    data = interval.get("data", {})
    lower = require_int("integer interval lower", data.get("lower"))
    upper = require_int("integer interval upper", data.get("upper"))
    if lower <= upper:
        fail("integer-interval-infeasible data is satisfiable")

    obstruction = checks["diophantine-gcd-obstruction"]
    if obstruction["expected_result"] != "unsat":
        fail("diophantine-gcd-obstruction must expect unsat")
    data = obstruction.get("data", {})
    coefficients = require_int_list("integer diophantine coefficients", data.get("coefficients"))
    target = require_int("integer diophantine target", data.get("target"))
    coefficient_gcd = 0
    for coefficient in coefficients:
        coefficient_gcd = gcd(coefficient_gcd, abs(coefficient))
    if coefficient_gcd == 0:
        fail("diophantine-gcd-obstruction coefficients must not all be zero")
    if target % coefficient_gcd == 0:
        fail("diophantine-gcd-obstruction data is satisfiable by the gcd criterion")
    if coefficients != [2, 4] or target != 3 or coefficient_gcd != 2:
        fail("diophantine-gcd-obstruction solver promotion is fixed to 2*x + 4*y = 3")
    smt2_artifact = data.get("smt2_artifact")
    require_string("integer-lia gcd smt2_artifact", smt2_artifact)
    check_source("integer-lia gcd smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/integer-lia-v0/smt2/diophantine-gcd-obstruction-conflict.smt2":
        fail("diophantine-gcd-obstruction smt2_artifact must name the checked QF_LIA artifact")
    proof_regression = data.get("proof_regression")
    require_string("integer-lia gcd proof_regression", proof_regression)
    if "integer_lia_diophantine_gcd_obstruction_emits_checked_diophantine_evidence" not in proof_regression:
        fail("diophantine-gcd-obstruction proof_regression must name the LIA resource test")
    certificate = data.get("certificate")
    require_string("integer-lia gcd certificate", certificate)
    if "UnsatDiophantine" not in certificate or "Evidence::check" not in certificate:
        fail("diophantine-gcd-obstruction certificate must document checked Diophantine evidence")


def require_natural(context: str, value: Any) -> int:
    item = require_int(context, value)
    if item < 0:
        fail(f"{context} must be nonnegative")
    return item


def require_bounded_natural_max(context: str, data: dict[str, Any]) -> int:
    max_value = require_natural(f"{context}.max", data.get("max"))
    if max_value > 1024:
        fail(f"{context}.max is too large for deterministic example-pack enumeration")
    return max_value


def validate_natural_arithmetic(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    successor_addition = checks["successor-addition-replay"]
    if successor_addition["expected_result"] != "sat":
        fail("successor-addition-replay must expect sat")
    values = single_witness_values(successor_addition, witnesses)
    a_value = require_natural("successor addition a", values.get("a"))
    b_value = require_natural("successor addition b", values.get("b"))
    successor_b = require_natural("successor addition successor_b", values.get("successor_b"))
    left = require_natural("successor addition left", values.get("left"))
    right = require_natural("successor addition right", values.get("right"))
    if successor_b != b_value + 1:
        fail("successor-addition-replay successor_b does not equal b + 1")
    if a_value + successor_b != left:
        fail("successor-addition-replay left side does not match a + S(b)")
    if a_value + b_value + 1 != right:
        fail("successor-addition-replay right side does not match S(a + b)")
    if left != right:
        fail("successor-addition-replay sides are not equal")

    commutativity = checks["addition-commutativity-fixed"]
    if commutativity["expected_result"] != "sat":
        fail("addition-commutativity-fixed must expect sat")
    values = single_witness_values(commutativity, witnesses)
    a_value = require_natural("commutativity a", values.get("a"))
    b_value = require_natural("commutativity b", values.get("b"))
    sum_ab = require_natural("commutativity sum_ab", values.get("sum_ab"))
    sum_ba = require_natural("commutativity sum_ba", values.get("sum_ba"))
    if a_value + b_value != sum_ab:
        fail("addition-commutativity-fixed sum_ab does not match")
    if b_value + a_value != sum_ba:
        fail("addition-commutativity-fixed sum_ba does not match")
    if sum_ab != sum_ba:
        fail("addition-commutativity-fixed sums are not equal")

    distributivity = checks["multiplication-distributivity-fixed"]
    if distributivity["expected_result"] != "sat":
        fail("multiplication-distributivity-fixed must expect sat")
    values = single_witness_values(distributivity, witnesses)
    a_value = require_natural("distributivity a", values.get("a"))
    b_value = require_natural("distributivity b", values.get("b"))
    c_value = require_natural("distributivity c", values.get("c"))
    left = require_natural("distributivity left", values.get("left"))
    right = require_natural("distributivity right", values.get("right"))
    if a_value * (b_value + c_value) != left:
        fail("multiplication-distributivity-fixed left side does not match")
    if a_value * b_value + a_value * c_value != right:
        fail("multiplication-distributivity-fixed right side does not match")
    if left != right:
        fail("multiplication-distributivity-fixed sides are not equal")

    injective = checks["successor-injective-bounded"]
    if injective["expected_result"] != "unsat":
        fail("successor-injective-bounded must expect unsat")
    max_value = require_bounded_natural_max("successor-injective-bounded", injective.get("data", {}))
    for left_value in range(max_value + 1):
        for right_value in range(max_value + 1):
            if left_value != right_value and left_value + 1 == right_value + 1:
                fail("successor-injective-bounded found a counterexample")

    zero = checks["zero-not-successor-bounded"]
    if zero["expected_result"] != "unsat":
        fail("zero-not-successor-bounded must expect unsat")
    max_value = require_bounded_natural_max("zero-not-successor-bounded", zero.get("data", {}))
    for value in range(max_value + 1):
        if value + 1 == 0:
            fail("zero-not-successor-bounded found a predecessor of zero")

    nonnegative = checks["bounded-natural-negative-rejected"]
    if nonnegative["expected_result"] != "unsat":
        fail("bounded-natural-negative-rejected must expect unsat")
    max_value = require_bounded_natural_max(
        "bounded-natural-negative-rejected",
        nonnegative.get("data", {}),
    )
    for value in range(max_value + 1):
        if value < 0:
            fail("bounded-natural-negative-rejected found a negative natural")
    if max_value != 7:
        fail("bounded-natural-negative-rejected solver promotion is fixed to domain 0..7")
    data = nonnegative.get("data", {})
    smt2_artifact = data.get("smt2_artifact")
    require_string("bounded natural negative smt2_artifact", smt2_artifact)
    check_source("bounded natural negative smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/natural-arithmetic-v0/smt2/bounded-natural-negative-lia-conflict.smt2":
        fail("bounded-natural-negative-rejected smt2_artifact must name the checked QF_LIA artifact")
    proof_regression = data.get("proof_regression")
    require_string("bounded natural negative proof_regression", proof_regression)
    if "natural_arithmetic_bounded_negative_emits_checked_lia_evidence" not in proof_regression:
        fail("bounded-natural-negative-rejected proof_regression must name the LIA resource test")
    certificate = data.get("certificate")
    require_string("bounded natural negative certificate", certificate)
    if "QF_LIA arithmetic evidence" not in certificate or "Evidence::check" not in certificate:
        fail("bounded-natural-negative-rejected certificate must document checked QF_LIA arithmetic evidence")


def require_bool(context: str, value: Any) -> bool:
    if not isinstance(value, bool):
        fail(f"{context} must be a boolean")
    return value


def prefix_sum(n_value: int) -> int:
    return sum(range(n_value + 1))


def prefix_sum_formula(n_value: int) -> int:
    return n_value * (n_value + 1) // 2


def prefix_sum_property_holds(n_value: int) -> bool:
    return prefix_sum(n_value) == prefix_sum_formula(n_value)


def require_bounded_induction_limit(context: str, data: dict[str, Any], key: str) -> int:
    max_value = require_natural(f"{context}.{key}", data.get(key))
    if max_value > 1024:
        fail(f"{context}.{key} is too large for deterministic example-pack enumeration")
    return max_value


def validate_induction_obligations(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    base = checks["sum-formula-base-case"]
    if base["expected_result"] != "sat":
        fail("sum-formula-base-case must expect sat")
    values = single_witness_values(base, witnesses)
    n_value = require_natural("sum formula base n", values.get("n"))
    listed_sum = require_natural("sum formula base sum_0_to_n", values.get("sum_0_to_n"))
    listed_formula = require_natural("sum formula base formula", values.get("formula"))
    if n_value != 0:
        fail("sum-formula-base-case must use n = 0")
    if listed_sum != prefix_sum(n_value):
        fail("sum-formula-base-case listed sum does not match sum(0..n)")
    if listed_formula != prefix_sum_formula(n_value):
        fail("sum-formula-base-case listed formula does not match n*(n+1)/2")
    if listed_sum != listed_formula:
        fail("sum-formula-base-case does not satisfy the property")

    step = checks["sum-formula-step-bounded"]
    if step["expected_result"] != "unsat":
        fail("sum-formula-step-bounded must expect unsat")
    step_data = step.get("data", {})
    max_k = require_bounded_induction_limit("sum-formula-step-bounded", step_data, "max_k")
    bad_step_count = require_natural("sum-formula-step-bounded.bad_step_count", step_data.get("bad_step_count"))
    actual_bad_step_count = 0
    for k_value in range(max_k + 1):
        if prefix_sum_property_holds(k_value) and not prefix_sum_property_holds(k_value + 1):
            actual_bad_step_count += 1
    if bad_step_count != actual_bad_step_count:
        fail("sum-formula-step-bounded bad_step_count does not match replay")
    if bad_step_count != 0:
        fail("sum-formula-step-bounded must record zero bad steps")
    smt2_artifact = step_data.get("smt2_artifact")
    require_string("sum-formula-step-bounded smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/induction-obligations-v0/smt2/bounded-step-counterexample-count-lia-conflict.smt2"
    ):
        fail("sum-formula-step-bounded smt2_artifact must name the checked QF_LIA artifact")
    check_source("sum-formula-step-bounded smt2_artifact", smt2_artifact)
    lia_regression = step_data.get("lia_regression")
    require_string("sum-formula-step-bounded lia_regression", lia_regression)
    if "induction_obligations_bounded_step_count_emits_checked_lia_evidence" not in lia_regression:
        fail("sum-formula-step-bounded must link the LIA route regression")

    conclusion = checks["sum-formula-conclusion-bounded"]
    if conclusion["expected_result"] != "unsat":
        fail("sum-formula-conclusion-bounded must expect unsat")
    max_n = require_bounded_induction_limit("sum-formula-conclusion-bounded", conclusion.get("data", {}), "max_n")
    for n_value in range(max_n + 1):
        if not prefix_sum_property_holds(n_value):
            fail("sum-formula-conclusion-bounded found a formula counterexample")

    bad_step = checks["bad-step-counterexample-witness"]
    if bad_step["expected_result"] != "sat":
        fail("bad-step-counterexample-witness must expect sat")
    values = single_witness_values(bad_step, witnesses)
    property_name = values.get("property")
    require_string("bad step property", property_name)
    if property_name != "n_eq_0":
        fail("bad-step-counterexample-witness must use property n_eq_0")
    k_value = require_natural("bad step k", values.get("k"))
    p_k = require_bool("bad step p_k", values.get("p_k"))
    p_next = require_bool("bad step p_next", values.get("p_next"))
    if p_k != (k_value == 0):
        fail("bad-step-counterexample-witness p_k does not match n_eq_0")
    if p_next != (k_value + 1 == 0):
        fail("bad-step-counterexample-witness p_next does not match n_eq_0 at k+1")
    if not p_k or p_next:
        fail("bad-step-counterexample-witness does not witness a step failure")

    schema = checks["induction-schema-lean-horizon"]
    if schema["expected_result"] != "not-run":
        fail("induction-schema-lean-horizon must be not-run")
    if schema["proof_status"] != "lean-horizon":
        fail("induction-schema-lean-horizon must remain lean-horizon")
    data = schema.get("data", {})
    require_string("induction target theorem", data.get("target_theorem"))
    require_string("induction future checker", data.get("future_checker"))


def require_bool_list(context: str, value: Any) -> list[bool]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty boolean list")
    return [require_bool(f"{context}[{index}]", item) for index, item in enumerate(value)]


def validate_induction_patterns(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    weak = checks["weak-induction-even-sum-prefix"]
    if weak["expected_result"] != "unsat" or weak.get("proof_status") != "checked":
        fail("weak-induction-even-sum-prefix must be a checked unsat row")
    values = single_witness_values(weak, witnesses)
    n_max = require_natural("weak induction n_max", values.get("n_max"))
    if n_max > 1024:
        fail("weak induction prefix is too large for deterministic replay")
    table = require_int_list("weak induction values", values.get("values"))
    differences = require_int_list("weak induction step_differences", values.get("step_differences"))
    if len(table) != n_max + 1:
        fail("weak induction values length must equal n_max + 1")
    if len(differences) != n_max:
        fail("weak induction step_differences length must equal n_max")
    for n_value, listed in enumerate(table):
        expected_value = n_value * (n_value + 1)
        if listed != expected_value:
            fail("weak induction value table does not match n * (n + 1)")
        if listed % 2 != 0:
            fail("weak induction value table contains an odd value")
    if table[0] != 0:
        fail("weak induction base value must be zero")
    for k_value, listed_difference in enumerate(differences):
        expected_difference = 2 * (k_value + 1)
        if listed_difference != expected_difference:
            fail("weak induction listed step difference is wrong")
        if table[k_value + 1] - table[k_value] != listed_difference:
            fail("weak induction values do not match listed step difference")

    qf_lia = checks["qf-lia-even-product-odd-obstruction"]
    if qf_lia["expected_result"] != "unsat":
        fail("qf-lia-even-product-odd-obstruction must expect unsat")
    if qf_lia["proof_status"] != "checked":
        fail("qf-lia-even-product-odd-obstruction must be checked")
    if qf_lia["validation"] != "qf_lia_diophantine_evidence":
        fail("qf-lia-even-product-odd-obstruction must use qf_lia_diophantine_evidence validation")
    data = qf_lia.get("data", {})
    n_value = require_natural("qf-lia even product n", data.get("n"))
    if n_value > n_max:
        fail("qf-lia-even-product-odd-obstruction n must be inside the weak-induction prefix")
    product = require_natural("qf-lia even product product", data.get("product"))
    if product != table[n_value] or product != n_value * (n_value + 1):
        fail("qf-lia-even-product-odd-obstruction product is incorrect")
    if product % 2 != 0:
        fail("qf-lia-even-product-odd-obstruction product must be even")
    claimed_half = require_natural("qf-lia even product claimed_half", data.get("claimed_half"))
    rhs = require_natural("qf-lia even product odd_equation_rhs", data.get("odd_equation_rhs"))
    if rhs != 2 * claimed_half + 1:
        fail("qf-lia-even-product-odd-obstruction odd_equation_rhs must equal 2*claimed_half + 1")
    if rhs != product - 1:
        fail("qf-lia-even-product-odd-obstruction odd_equation_rhs must be the adjacent odd claim below product")
    if rhs % 2 == 0:
        fail("qf-lia-even-product-odd-obstruction rhs must be odd")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-lia even product smt2_artifact", smt2_artifact)
    check_source("qf-lia even product smt2_artifact", smt2_artifact)
    require_string("qf-lia even product proof_regression", data.get("proof_regression"))
    certificate = data.get("certificate")
    require_string("qf-lia even product certificate", certificate)
    if "UnsatDiophantine" not in certificate or "Evidence::check" not in certificate:
        fail("qf-lia even product certificate must document checked Diophantine evidence")

    strong = checks["strong-induction-fibonacci-bound-prefix"]
    if strong["expected_result"] != "unsat" or strong.get("proof_status") != "checked":
        fail("strong-induction-fibonacci-bound-prefix must be a checked unsat row")
    values = single_witness_values(strong, witnesses)
    n_max = require_natural("strong induction n_max", values.get("n_max"))
    if n_max < 2:
        fail("strong induction prefix must include at least the two Fibonacci base cases and one step")
    if n_max > 64:
        fail("strong induction prefix is too large for deterministic replay")
    fib = require_int_list("strong induction fib", values.get("fib"))
    powers = require_int_list("strong induction powers_of_two", values.get("powers_of_two"))
    if len(fib) != n_max + 1:
        fail("strong induction fib length must equal n_max + 1")
    if len(powers) != n_max + 1:
        fail("strong induction powers_of_two length must equal n_max + 1")
    if fib[0] != 0 or fib[1] != 1:
        fail("strong induction Fibonacci base cases must be fib(0)=0 and fib(1)=1")
    for n_value in range(n_max + 1):
        if powers[n_value] != 2**n_value:
            fail("strong induction powers_of_two table is wrong")
        if fib[n_value] > powers[n_value]:
            fail("strong induction Fibonacci bound is violated")
    for n_value in range(2, n_max + 1):
        if fib[n_value] != fib[n_value - 1] + fib[n_value - 2]:
            fail("strong induction Fibonacci recurrence is wrong")
        if fib[n_value - 1] + fib[n_value - 2] > powers[n_value]:
            fail("strong induction finite step bound is violated")

    invariant = checks["loop-invariant-prefix-sum-trace"]
    if invariant["expected_result"] != "sat" or invariant.get("proof_status") != "checked":
        fail("loop-invariant-prefix-sum-trace must be a checked sat row")
    values = single_witness_values(invariant, witnesses)
    n_limit = require_natural("loop invariant n", values.get("n"))
    trace_value = values.get("trace")
    if not isinstance(trace_value, list) or not trace_value:
        fail("loop invariant trace must be a non-empty list")
    if len(trace_value) != n_limit + 1:
        fail("loop invariant trace length must equal n + 1")
    previous_i: int | None = None
    previous_acc: int | None = None
    for index, row in enumerate(trace_value):
        if not isinstance(row, dict):
            fail(f"loop invariant trace[{index}] must be an object")
        i_value = require_natural(f"loop invariant trace[{index}].i", row.get("i"))
        acc_value = require_natural(f"loop invariant trace[{index}].acc", row.get("acc"))
        if i_value != index:
            fail("loop invariant trace indices must increase by one from zero")
        if acc_value != i_value * (i_value + 1) // 2:
            fail("loop invariant trace row violates acc = i * (i + 1) / 2")
        if previous_i is not None and previous_acc is not None:
            if i_value != previous_i + 1:
                fail("loop invariant transition does not increment i by one")
            if acc_value != previous_acc + i_value:
                fail("loop invariant transition does not add the new i to acc")
        previous_i = i_value
        previous_acc = acc_value

    bad_step = checks["bad-induction-step-rejected"]
    if bad_step["expected_result"] != "sat" or bad_step.get("proof_status") != "checked":
        fail("bad-induction-step-rejected must be a checked sat row")
    values = single_witness_values(bad_step, witnesses)
    property_name = values.get("property")
    require_string("bad induction property", property_name)
    if property_name != "n_lt_3":
        fail("bad-induction-step-rejected must use property n_lt_3")
    threshold = require_natural("bad induction threshold", values.get("threshold"))
    if threshold != 3:
        fail("bad-induction-step-rejected must use threshold 3")
    n_max = require_natural("bad induction n_max", values.get("n_max"))
    table = require_bool_list("bad induction values", values.get("values"))
    if len(table) != n_max + 1:
        fail("bad induction values length must equal n_max + 1")
    for n_value, listed in enumerate(table):
        if listed != (n_value < threshold):
            fail("bad induction predicate table does not match n < 3")
    failing_k = require_natural("bad induction failing_k", values.get("failing_k"))
    if failing_k + 1 > n_max:
        fail("bad induction failing_k must have a successor in the listed table")
    if not table[failing_k] or table[failing_k + 1]:
        fail("bad induction row does not witness P(k) true and P(k + 1) false")

    schema = checks["general-induction-schema-lean-horizon"]
    if schema["expected_result"] != "not-run":
        fail("general-induction-schema-lean-horizon must be not-run")
    if schema["proof_status"] != "lean-horizon":
        fail("general-induction-schema-lean-horizon must remain lean-horizon")
    data = schema.get("data", {})
    require_string("general induction target theorem", data.get("target_theorem"))
    require_string("general induction future checker", data.get("future_checker"))


def require_bool_assignment(
    context: str,
    value: Any,
    variables: list[str],
) -> dict[str, bool]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    variable_set = set(variables)
    if set(value) != variable_set:
        missing = sorted(variable_set - set(value))
        extra = sorted(set(value) - variable_set)
        fail(f"{context} must cover exactly variables; missing={missing} extra={extra}")
    return {
        variable: require_bool(f"{context}.{variable}", value[variable])
        for variable in variables
    }


def boolean_assignments(variables: list[str]) -> list[dict[str, bool]]:
    return [
        dict(zip(variables, values))
        for values in product([False, True], repeat=len(variables))
    ]


def require_boolean_variables(context: str, data: dict[str, Any], expected: list[str]) -> list[str]:
    variables = require_string_list(f"{context}.variables", data.get("variables"))
    if variables != expected:
        fail(f"{context}.variables must be exactly {expected}")
    if len(variables) > 16:
        fail(f"{context}.variables is too large for deterministic truth-table enumeration")
    return variables


def eval_boolean_literal(literal: str, assignment: dict[str, bool]) -> bool:
    if literal.startswith("!"):
        variable = literal[1:]
        if variable not in assignment:
            fail(f"literal {literal!r} references unknown variable")
        return not assignment[variable]
    if literal not in assignment:
        fail(f"literal {literal!r} references unknown variable")
    return assignment[literal]


def boolean_implies(left: bool, right: bool) -> bool:
    return (not left) or right


def require_cnf_clauses(context: str, value: Any) -> list[list[str]]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty list")
    clauses: list[list[str]] = []
    for clause_index, clause in enumerate(value):
        literals = require_string_list(f"{context}[{clause_index}]", clause)
        clauses.append(literals)
    return clauses


def require_dimacs_artifact(
    context: str,
    artifact: Any,
    expected_header: str,
    expected_clauses: list[list[str]],
) -> None:
    require_string(f"{context} cnf_artifact", artifact)
    check_source(f"{context} cnf_artifact", artifact)
    dimacs_path = ROOT / artifact
    dimacs_header = None
    dimacs_clauses: list[list[str]] = []
    for raw_line in dimacs_path.read_text(encoding="utf-8").splitlines():
        line = raw_line.strip()
        if not line or line.startswith("c"):
            continue
        if line.startswith("p "):
            dimacs_header = line
            continue
        parts = line.split()
        if not parts or parts[-1] != "0":
            fail(f"{context} DIMACS clauses must end with 0")
        dimacs_clauses.append(parts[:-1])
    if dimacs_header != expected_header:
        fail(f"{context} DIMACS header must be {expected_header}")
    if dimacs_clauses != expected_clauses:
        fail(f"{context} DIMACS clauses do not match the documented CNF")


def cnf_satisfied(clauses: list[list[str]], assignment: dict[str, bool]) -> bool:
    return all(any(eval_boolean_literal(literal, assignment) for literal in clause) for clause in clauses)


def php_variable(pigeon: int, hole: int) -> str:
    return f"x_p{pigeon}_h{hole}"


def php_variables(pigeons: int, holes: int) -> list[str]:
    return [
        php_variable(pigeon, hole)
        for pigeon in range(pigeons)
        for hole in range(holes)
    ]


def php_cnf(pigeons: int, holes: int) -> list[list[str]]:
    clauses: list[list[str]] = []

    for pigeon in range(pigeons):
        clauses.append([php_variable(pigeon, hole) for hole in range(holes)])
        for left_hole in range(holes):
            for right_hole in range(left_hole + 1, holes):
                clauses.append(
                    [
                        f"!{php_variable(pigeon, left_hole)}",
                        f"!{php_variable(pigeon, right_hole)}",
                    ]
                )

    for hole in range(holes):
        for left_pigeon in range(pigeons):
            for right_pigeon in range(left_pigeon + 1, pigeons):
                clauses.append(
                    [
                        f"!{php_variable(left_pigeon, hole)}",
                        f"!{php_variable(right_pigeon, hole)}",
                    ]
                )

    return clauses


def validate_php_assignment(
    context: str,
    pigeons: int,
    holes: int,
    assignment: dict[str, bool],
) -> None:
    for pigeon in range(pigeons):
        chosen = [
            hole
            for hole in range(holes)
            if assignment[php_variable(pigeon, hole)]
        ]
        if len(chosen) != 1:
            fail(f"{context}: pigeon {pigeon} must choose exactly one hole")

    for hole in range(holes):
        occupants = [
            pigeon
            for pigeon in range(pigeons)
            if assignment[php_variable(pigeon, hole)]
        ]
        if len(occupants) > 1:
            fail(f"{context}: hole {hole} receives multiple pigeons")


def validate_proof_methods_refutation(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    sat_control = checks["php-2-2-sat"]
    if sat_control["expected_result"] != "sat":
        fail("php-2-2-sat must expect sat")
    if sat_control.get("proof_status") != "checked":
        fail("php-2-2-sat proof_status must be checked")
    values = single_witness_values(sat_control, witnesses)
    pigeons = require_counting_int("php-2-2-sat pigeons", values.get("pigeons"))
    holes = require_counting_int("php-2-2-sat holes", values.get("holes"))
    if (pigeons, holes) != (2, 2):
        fail("php-2-2-sat must use PHP(2,2)")
    assignment = require_bool_assignment(
        "php-2-2-sat assignment",
        values.get("assignment"),
        php_variables(pigeons, holes),
    )
    validate_php_assignment("php-2-2-sat", pigeons, holes, assignment)

    unsat_row = checks["php-3-2-unsat"]
    if unsat_row["expected_result"] != "unsat":
        fail("php-3-2-unsat must expect unsat")
    if unsat_row.get("proof_status") != "checked":
        fail("php-3-2-unsat proof_status must be checked")
    data = unsat_row.get("data", {})
    if not isinstance(data, dict):
        fail("php-3-2-unsat data must be an object")
    pigeons = require_counting_int("php-3-2-unsat pigeons", data.get("pigeons"))
    holes = require_counting_int("php-3-2-unsat holes", data.get("holes"))
    if (pigeons, holes) != (3, 2):
        fail("php-3-2-unsat must use PHP(3,2)")
    if pigeons <= holes:
        fail("php-3-2-unsat must use more pigeons than holes")

    variables = require_boolean_variables(
        "php-3-2-unsat",
        data,
        php_variables(pigeons, holes),
    )
    clauses = require_cnf_clauses("php-3-2-unsat.clauses", data.get("clauses"))
    if clauses != php_cnf(pigeons, holes):
        fail("php-3-2-unsat clauses are not the deterministic PHP CNF")
    if has_injective_placement(pigeons, holes):
        fail("php-3-2-unsat unexpectedly has an injective placement")
    for assignment in boolean_assignments(variables):
        if cnf_satisfied(clauses, assignment):
            fail("php-3-2-unsat CNF is satisfied by an assignment")


def validate_proof_methods_patterns(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    direct = checks["direct-proof-modus-ponens-witness"]
    if direct["expected_result"] != "sat" or direct.get("proof_status") != "checked":
        fail("direct-proof-modus-ponens-witness must be a checked sat row")
    values = single_witness_values(direct, witnesses)
    assignment = require_bool_assignment(
        "direct proof assignment",
        values.get("assignment"),
        ["p", "q"],
    )
    if not assignment["p"]:
        fail("direct-proof-modus-ponens-witness premise p is false")
    if not boolean_implies(assignment["p"], assignment["q"]):
        fail("direct-proof-modus-ponens-witness implication p -> q is false")
    if not assignment["q"]:
        fail("direct-proof-modus-ponens-witness conclusion q is false")

    contrapositive = checks["contrapositive-equivalence-no-counterexample"]
    if contrapositive["expected_result"] != "unsat" or contrapositive.get("proof_status") != "checked":
        fail("contrapositive-equivalence-no-counterexample must be a checked unsat row")
    variables = require_boolean_variables(
        "contrapositive-equivalence-no-counterexample",
        contrapositive.get("data", {}),
        ["p", "q"],
    )
    for assignment in boolean_assignments(variables):
        left = boolean_implies(assignment["p"], assignment["q"])
        right = boolean_implies(not assignment["q"], not assignment["p"])
        if left != right:
            fail("contrapositive-equivalence-no-counterexample found a counterexample")

    cases = checks["proof-by-cases-no-counterexample"]
    if cases["expected_result"] != "unsat" or cases.get("proof_status") != "checked":
        fail("proof-by-cases-no-counterexample must be a checked unsat row")
    variables = require_boolean_variables(
        "proof-by-cases-no-counterexample",
        cases.get("data", {}),
        ["p", "r"],
    )
    for assignment in boolean_assignments(variables):
        premise_left = boolean_implies(assignment["p"], assignment["r"])
        premise_right = boolean_implies(not assignment["p"], assignment["r"])
        if premise_left and premise_right and not assignment["r"]:
            fail("proof-by-cases-no-counterexample found a counterexample")

    contradiction = checks["contradiction-refutation-unsat"]
    if contradiction["expected_result"] != "unsat" or contradiction.get("proof_status") != "checked":
        fail("contradiction-refutation-unsat must be a checked unsat row")
    variables = require_boolean_variables(
        "contradiction-refutation-unsat",
        contradiction.get("data", {}),
        ["p", "q"],
    )
    for assignment in boolean_assignments(variables):
        if assignment["p"] and boolean_implies(assignment["p"], assignment["q"]) and not assignment["q"]:
            fail("contradiction-refutation-unsat found a satisfying assignment")

    converse = checks["invalid-converse-counterexample"]
    if converse["expected_result"] != "sat" or converse.get("proof_status") != "checked":
        fail("invalid-converse-counterexample must be a checked sat row")
    values = single_witness_values(converse, witnesses)
    assignment = require_bool_assignment(
        "invalid converse assignment",
        values.get("assignment"),
        ["p", "q"],
    )
    if not boolean_implies(assignment["p"], assignment["q"]):
        fail("invalid-converse-counterexample requires p -> q to hold")
    if boolean_implies(assignment["q"], assignment["p"]):
        fail("invalid-converse-counterexample does not falsify q -> p")

    horizon = checks["general-natural-deduction-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-natural-deduction-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-natural-deduction-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general natural deduction target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general natural deduction future_checker", data.get("future_checker"))


def require_predicate_table(context: str, universe: list[str], value: Any) -> dict[str, bool]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    universe_set = set(universe)
    keys = set(value)
    missing = sorted(universe_set - keys)
    extra = sorted(keys - universe_set)
    if missing or extra:
        fail(f"{context} must cover exactly the universe; missing={missing} extra={extra}")
    return {
        element: require_bool(f"{context}.{element}", value[element])
        for element in universe
    }


def predicate_valuations(universe: list[str]) -> list[dict[str, bool]]:
    if len(universe) > 16:
        fail("finite predicate valuation universe is too large for deterministic enumeration")
    return [
        dict(zip(universe, values))
        for values in product([False, True], repeat=len(universe))
    ]


def validate_finite_predicate(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    forall = checks["forall-predicate-finite-replay"]
    if forall["expected_result"] != "sat":
        fail("forall-predicate-finite-replay must expect sat")
    values = single_witness_values(forall, witnesses)
    universe = require_string_list("forall predicate universe", values.get("universe"))
    predicate = require_predicate_table("forall predicate table", universe, values.get("predicate"))
    if not all(predicate[element] for element in universe):
        fail("forall-predicate-finite-replay predicate table does not satisfy forall x. P(x)")

    exists = checks["exists-predicate-finite-replay"]
    if exists["expected_result"] != "sat":
        fail("exists-predicate-finite-replay must expect sat")
    values = single_witness_values(exists, witnesses)
    universe = require_string_list("exists predicate universe", values.get("universe"))
    predicate = require_predicate_table("exists predicate table", universe, values.get("predicate"))
    witness = values.get("witness_element")
    require_string("exists predicate witness_element", witness)
    if witness not in universe:
        fail("exists-predicate-finite-replay witness_element is outside the universe")
    if not predicate[witness]:
        fail("exists-predicate-finite-replay witness_element does not satisfy P")
    if not any(predicate[element] for element in universe):
        fail("exists-predicate-finite-replay predicate table does not satisfy exists x. P(x)")

    implication = checks["forall-implies-exists-finite"]
    if implication["expected_result"] != "unsat" or implication.get("proof_status") != "checked":
        fail("forall-implies-exists-finite must be a checked unsat row")
    implication_data = implication.get("data", {})
    universe = require_string_list("forall-implies-exists-finite.universe", implication_data.get("universe"))
    if not universe:
        fail("forall-implies-exists-finite universe must be non-empty")
    for valuation in predicate_valuations(universe):
        if all(valuation[element] for element in universe) and not any(valuation[element] for element in universe):
            fail("forall-implies-exists-finite found a finite counterexample")
    if universe != ["a", "b"]:
        fail("forall-implies-exists-finite DIMACS artifact is fixed to universe [a, b]")
    require_dimacs_artifact(
        "forall-implies-exists-finite",
        implication_data.get("cnf_artifact"),
        "p cnf 2 4",
        [["1"], ["2"], ["-1"], ["-2"]],
    )
    proof_regression = implication_data.get("proof_regression")
    require_string("forall-implies-exists-finite proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::finite_predicate_forall_implies_exists" not in proof_regression:
        fail("forall-implies-exists-finite proof_regression must name the Boolean resource test")
    certificate = implication_data.get("certificate")
    require_string("forall-implies-exists-finite certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("forall-implies-exists-finite certificate must document DRAT/LRAT independent checking")

    not_forall = checks["exists-not-forall-counterexample"]
    if not_forall["expected_result"] != "sat":
        fail("exists-not-forall-counterexample must expect sat")
    values = single_witness_values(not_forall, witnesses)
    universe = require_string_list("exists-not-forall universe", values.get("universe"))
    predicate = require_predicate_table("exists-not-forall predicate table", universe, values.get("predicate"))
    witness = values.get("witness_element")
    counterexample = values.get("counterexample_element")
    require_string("exists-not-forall witness_element", witness)
    require_string("exists-not-forall counterexample_element", counterexample)
    if witness not in universe or counterexample not in universe:
        fail("exists-not-forall witness/counterexample element is outside the universe")
    if not predicate[witness]:
        fail("exists-not-forall witness_element does not satisfy P")
    if predicate[counterexample]:
        fail("exists-not-forall counterexample_element unexpectedly satisfies P")
    if not any(predicate[element] for element in universe):
        fail("exists-not-forall predicate table does not satisfy exists x. P(x)")
    if all(predicate[element] for element in universe):
        fail("exists-not-forall predicate table unexpectedly satisfies forall x. P(x)")

    asymmetry = checks["binary-relation-symmetry-counterexample"]
    if asymmetry["expected_result"] != "sat":
        fail("binary-relation-symmetry-counterexample must expect sat")
    values = single_witness_values(asymmetry, witnesses)
    universe = require_string_list("binary relation universe", values.get("universe"))
    pairs = require_pair_set("binary relation pairs", values.get("pairs"), set(universe), set(universe))
    pair_value = values.get("counterexample_pair")
    if not isinstance(pair_value, list) or len(pair_value) != 2:
        fail("binary relation counterexample_pair must be a two-element list")
    left, right = pair_value
    require_string("binary relation counterexample_pair[0]", left)
    require_string("binary relation counterexample_pair[1]", right)
    if left not in universe or right not in universe:
        fail("binary relation counterexample_pair references an element outside the universe")
    if (left, right) not in pairs:
        fail("binary-relation-symmetry-counterexample pair is not present")
    if (right, left) in pairs:
        fail("binary-relation-symmetry-counterexample reverse pair is present")

    horizon = checks["general-first-order-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-first-order-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-first-order-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general-first-order target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general-first-order future_checker", data.get("future_checker"))


def validate_logic_basics(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    and_witness = checks["and-formula-sat-witness"]
    if and_witness["expected_result"] != "sat":
        fail("and-formula-sat-witness must expect sat")
    values = single_witness_values(and_witness, witnesses)
    assignment = require_bool_assignment("and witness assignment", values.get("assignment"), ["p", "q"])
    if not (assignment["p"] and assignment["q"]):
        fail("and-formula-sat-witness assignment does not satisfy p and q")

    excluded_middle = checks["excluded-middle-no-counterexample"]
    if excluded_middle["expected_result"] != "unsat":
        fail("excluded-middle-no-counterexample must expect unsat")
    variables = require_boolean_variables("excluded-middle-no-counterexample", excluded_middle.get("data", {}), ["p"])
    for assignment in boolean_assignments(variables):
        if not (assignment["p"] or not assignment["p"]):
            fail("excluded-middle-no-counterexample found a counterexample")

    contradiction = checks["contradiction-unsat"]
    if contradiction["expected_result"] != "unsat":
        fail("contradiction-unsat must expect unsat")
    variables = require_boolean_variables("contradiction-unsat", contradiction.get("data", {}), ["p"])
    for assignment in boolean_assignments(variables):
        if assignment["p"] and not assignment["p"]:
            fail("contradiction-unsat found a satisfying assignment")

    demorgan = checks["demorgan-equivalence-no-counterexample"]
    if demorgan["expected_result"] != "unsat":
        fail("demorgan-equivalence-no-counterexample must expect unsat")
    variables = require_boolean_variables("demorgan-equivalence-no-counterexample", demorgan.get("data", {}), ["p", "q"])
    for assignment in boolean_assignments(variables):
        left = not (assignment["p"] and assignment["q"])
        right = (not assignment["p"]) or (not assignment["q"])
        if left != right:
            fail("demorgan-equivalence-no-counterexample found a counterexample")

    cnf = checks["tiny-cnf-refutation"]
    if cnf["expected_result"] != "unsat":
        fail("tiny-cnf-refutation must expect unsat")
    data = cnf.get("data", {})
    variables = require_boolean_variables("tiny-cnf-refutation", data, ["p", "q"])
    clauses = require_cnf_clauses("tiny-cnf-refutation.clauses", data.get("clauses"))
    expected_clauses = [["p"], ["!p", "q"], ["!q"]]
    if clauses != expected_clauses:
        fail("tiny-cnf-refutation clauses must match the documented CNF")
    require_dimacs_artifact(
        "tiny-cnf-refutation",
        data.get("cnf_artifact"),
        "p cnf 2 3",
        [["1"], ["-1", "2"], ["-2"]],
    )
    proof_regression = data.get("proof_regression")
    require_string("tiny-cnf-refutation proof_regression", proof_regression)
    if "math_resource_boolean_routes.rs::logic_basics_tiny_cnf_refutation" not in proof_regression:
        fail("tiny-cnf-refutation proof_regression must name the Boolean resource test")
    certificate = data.get("certificate")
    require_string("tiny-cnf-refutation certificate", certificate)
    if "DRAT" not in certificate or "LRAT" not in certificate or "independently" not in certificate:
        fail("tiny-cnf-refutation certificate must document DRAT/LRAT independent checking")
    for assignment in boolean_assignments(variables):
        if cnf_satisfied(clauses, assignment):
            fail("tiny-cnf-refutation found a satisfying assignment")


def require_fraction(context: str, value: Any) -> Fraction:
    if not isinstance(value, str) or not value:
        fail(f"{context} must be a non-empty fraction string")
    try:
        return Fraction(value)
    except ValueError as error:
        fail(f"{context} is not a valid exact fraction: {error}")


def require_fraction_vector(context: str, value: Any) -> list[Fraction]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty vector")
    return [require_fraction(f"{context}[{index}]", item) for index, item in enumerate(value)]


def normalize_polynomial(polynomial: list[Fraction]) -> list[Fraction]:
    normalized = list(polynomial)
    while len(normalized) > 1 and normalized[-1] == 0:
        normalized.pop()
    return normalized


def require_polynomial(context: str, value: Any) -> list[Fraction]:
    return normalize_polynomial(require_fraction_vector(context, value))


def polynomial_mul(left: list[Fraction], right: list[Fraction]) -> list[Fraction]:
    result = [Fraction(0) for _ in range(len(left) + len(right) - 1)]
    for left_index, left_coeff in enumerate(left):
        for right_index, right_coeff in enumerate(right):
            result[left_index + right_index] += left_coeff * right_coeff
    return normalize_polynomial(result)


def polynomial_add(left: list[Fraction], right: list[Fraction]) -> list[Fraction]:
    width = max(len(left), len(right))
    result = [Fraction(0) for _ in range(width)]
    for index, coefficient in enumerate(left):
        result[index] += coefficient
    for index, coefficient in enumerate(right):
        result[index] += coefficient
    return normalize_polynomial(result)


def polynomial_sub(left: list[Fraction], right: list[Fraction]) -> list[Fraction]:
    width = max(len(left), len(right))
    result = [Fraction(0) for _ in range(width)]
    for index, coefficient in enumerate(left):
        result[index] += coefficient
    for index, coefficient in enumerate(right):
        result[index] -= coefficient
    return normalize_polynomial(result)


def polynomial_is_zero(polynomial: list[Fraction]) -> bool:
    normalized = normalize_polynomial(polynomial)
    return len(normalized) == 1 and normalized[0] == 0


def polynomial_degree(polynomial: list[Fraction]) -> int:
    normalized = normalize_polynomial(polynomial)
    if polynomial_is_zero(normalized):
        return -1
    return len(normalized) - 1


def polynomial_divmod(
    dividend: list[Fraction],
    divisor: list[Fraction],
) -> tuple[list[Fraction], list[Fraction]]:
    dividend = normalize_polynomial(dividend)
    divisor = normalize_polynomial(divisor)
    if polynomial_is_zero(divisor):
        fail("polynomial division by zero divisor")
    if polynomial_degree(dividend) < polynomial_degree(divisor):
        return [Fraction(0)], dividend

    quotient = [
        Fraction(0)
        for _ in range(polynomial_degree(dividend) - polynomial_degree(divisor) + 1)
    ]
    remainder = list(dividend)
    divisor_degree = polynomial_degree(divisor)
    divisor_leading = divisor[-1]
    while not polynomial_is_zero(remainder) and polynomial_degree(remainder) >= divisor_degree:
        shift = polynomial_degree(remainder) - divisor_degree
        coefficient = remainder[-1] / divisor_leading
        quotient[shift] += coefficient
        subtraction = [Fraction(0) for _ in range(shift)] + [
            coefficient * item for item in divisor
        ]
        remainder = polynomial_sub(remainder, subtraction)
    return normalize_polynomial(quotient), normalize_polynomial(remainder)


def polynomial_monic(polynomial: list[Fraction]) -> list[Fraction]:
    polynomial = normalize_polynomial(polynomial)
    if polynomial_is_zero(polynomial):
        return [Fraction(0)]
    leading = polynomial[-1]
    return normalize_polynomial([coefficient / leading for coefficient in polynomial])


def polynomial_gcd(left: list[Fraction], right: list[Fraction]) -> list[Fraction]:
    left = normalize_polynomial(left)
    right = normalize_polynomial(right)
    while not polynomial_is_zero(right):
        _, remainder = polynomial_divmod(left, right)
        left, right = right, remainder
    return polynomial_monic(left)


def require_polynomial_list(context: str, value: Any) -> list[list[Fraction]]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty list of polynomials")
    return [
        require_polynomial(f"{context}[{index}]", polynomial)
        for index, polynomial in enumerate(value)
    ]


def polynomial_derivative(polynomial: list[Fraction]) -> list[Fraction]:
    if len(polynomial) == 1:
        return [Fraction(0)]
    return normalize_polynomial([
        coefficient * index
        for index, coefficient in enumerate(polynomial[1:], start=1)
    ])


def polynomial_eval(polynomial: list[Fraction], point: Fraction) -> Fraction:
    value = Fraction(0)
    for coefficient in reversed(polynomial):
        value = value * point + coefficient
    return value


BivariatePolynomial = list[tuple[Fraction, int, int]]


def require_nonnegative_int(context: str, value: Any) -> int:
    integer = require_int(context, value)
    if integer < 0:
        fail(f"{context} must be non-negative")
    return integer


def require_bivariate_polynomial(context: str, value: Any) -> BivariatePolynomial:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty list of monomials")
    polynomial: BivariatePolynomial = []
    seen_terms: set[tuple[int, int]] = set()
    for index, term in enumerate(value):
        if not isinstance(term, dict):
            fail(f"{context}[{index}] must be a monomial object")
        require_keys(f"{context}[{index}]", term, {"coeff", "x_power", "y_power"})
        coefficient = require_fraction(f"{context}[{index}].coeff", term.get("coeff"))
        x_power = require_nonnegative_int(f"{context}[{index}].x_power", term.get("x_power"))
        y_power = require_nonnegative_int(f"{context}[{index}].y_power", term.get("y_power"))
        power_pair = (x_power, y_power)
        if power_pair in seen_terms:
            fail(f"{context} repeats monomial powers {power_pair}")
        seen_terms.add(power_pair)
        if coefficient != 0:
            polynomial.append((coefficient, x_power, y_power))
    if not polynomial:
        fail(f"{context} must contain a non-zero monomial")
    return polynomial


def require_bivariate_point(context: str, value: Any) -> tuple[Fraction, Fraction]:
    point = require_fraction_vector(context, value)
    if len(point) != 2:
        fail(f"{context} must contain exactly two coordinates")
    return point[0], point[1]


def bivariate_eval(polynomial: BivariatePolynomial, point: tuple[Fraction, Fraction]) -> Fraction:
    x_value, y_value = point
    return sum(
        coefficient * (x_value ** x_power) * (y_value ** y_power)
        for coefficient, x_power, y_power in polynomial
    )


def bivariate_partial(polynomial: BivariatePolynomial, variable: str) -> BivariatePolynomial:
    derivative: BivariatePolynomial = []
    for coefficient, x_power, y_power in polynomial:
        if variable == "x" and x_power > 0:
            derivative.append((coefficient * x_power, x_power - 1, y_power))
        elif variable == "y" and y_power > 0:
            derivative.append((coefficient * y_power, x_power, y_power - 1))
    return derivative


def bivariate_gradient(polynomial: BivariatePolynomial, point: tuple[Fraction, Fraction]) -> list[Fraction]:
    return [
        bivariate_eval(bivariate_partial(polynomial, "x"), point),
        bivariate_eval(bivariate_partial(polynomial, "y"), point),
    ]


def bivariate_hessian(polynomial: BivariatePolynomial, point: tuple[Fraction, Fraction]) -> list[list[Fraction]]:
    partial_x = bivariate_partial(polynomial, "x")
    partial_y = bivariate_partial(polynomial, "y")
    return [
        [
            bivariate_eval(bivariate_partial(partial_x, "x"), point),
            bivariate_eval(bivariate_partial(partial_x, "y"), point),
        ],
        [
            bivariate_eval(bivariate_partial(partial_y, "x"), point),
            bivariate_eval(bivariate_partial(partial_y, "y"), point),
        ],
    ]


def require_bivariate_map(context: str, value: Any) -> list[BivariatePolynomial]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty list of component polynomials")
    return [
        require_bivariate_polynomial(f"{context}[{index}]", component)
        for index, component in enumerate(value)
    ]


def bivariate_map_eval(polynomials: list[BivariatePolynomial], point: tuple[Fraction, Fraction]) -> list[Fraction]:
    return [bivariate_eval(polynomial, point) for polynomial in polynomials]


def bivariate_jacobian(polynomials: list[BivariatePolynomial], point: tuple[Fraction, Fraction]) -> list[list[Fraction]]:
    return [bivariate_gradient(polynomial, point) for polynomial in polynomials]


def require_vector_length(context: str, vector: list[Fraction], length: int) -> None:
    if len(vector) != length:
        fail(f"{context} must have length {length}")


def require_matrix_shape(context: str, matrix: list[list[Fraction]], height: int, width: int) -> None:
    if len(matrix) != height or any(len(row) != width for row in matrix):
        fail(f"{context} must have shape {height}x{width}")


def matrix_det_2(matrix: list[list[Fraction]]) -> Fraction:
    require_matrix_shape("2x2 determinant matrix", matrix, 2, 2)
    return matrix[0][0] * matrix[1][1] - matrix[0][1] * matrix[1][0]


def validate_multivariable_calculus_rational(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    gradient = checks["gradient-at-point-replay"]
    if gradient["expected_result"] != "sat":
        fail("gradient-at-point-replay must expect sat")
    values = single_witness_values(gradient, witnesses)
    polynomial = require_bivariate_polynomial("multivariable gradient polynomial", values.get("polynomial"))
    point = require_bivariate_point("multivariable gradient point", values.get("point"))
    value = require_fraction("multivariable gradient value", values.get("value"))
    listed_gradient = require_fraction_vector("multivariable gradient", values.get("gradient"))
    require_vector_length("multivariable gradient", listed_gradient, 2)
    if bivariate_eval(polynomial, point) != value:
        fail("gradient-at-point-replay value is incorrect")
    actual_gradient = bivariate_gradient(polynomial, point)
    if listed_gradient != actual_gradient:
        fail("gradient-at-point-replay gradient is incorrect")

    directional = checks["directional-derivative-dot-product"]
    if directional["expected_result"] != "sat" or directional.get("proof_status") != "checked":
        fail("directional-derivative-dot-product must be a checked sat row")
    values = single_witness_values(directional, witnesses)
    polynomial = require_bivariate_polynomial("directional polynomial", values.get("polynomial"))
    point = require_bivariate_point("directional point", values.get("point"))
    direction = require_fraction_vector("directional direction", values.get("direction"))
    require_vector_length("directional direction", direction, 2)
    listed_gradient = require_fraction_vector("directional gradient", values.get("gradient"))
    require_vector_length("directional gradient", listed_gradient, 2)
    directional_derivative = require_fraction(
        "directional directional_derivative",
        values.get("directional_derivative"),
    )
    actual_gradient = bivariate_gradient(polynomial, point)
    if listed_gradient != actual_gradient:
        fail("directional-derivative-dot-product gradient is incorrect")
    actual_directional = sum((left * right for left, right in zip(actual_gradient, direction)), Fraction(0))
    if directional_derivative != actual_directional:
        fail("directional-derivative-dot-product value is incorrect")

    chain = checks["jacobian-chain-rule-replay"]
    if chain["expected_result"] != "sat" or chain.get("proof_status") != "checked":
        fail("jacobian-chain-rule-replay must be a checked sat row")
    values = single_witness_values(chain, witnesses)
    point = require_bivariate_point("chain point", values.get("point"))
    inner_map = require_bivariate_map("chain inner_map", values.get("inner_map"))
    outer_map = require_bivariate_map("chain outer_map", values.get("outer_map"))
    if len(inner_map) != 2 or len(outer_map) != 2:
        fail("jacobian-chain-rule-replay currently expects 2D maps")
    inner_value = require_fraction_vector("chain inner_value", values.get("inner_value"))
    require_vector_length("chain inner_value", inner_value, 2)
    listed_jacobian_inner = require_fraction_matrix("chain jacobian_inner", values.get("jacobian_inner"))
    listed_jacobian_outer = require_fraction_matrix(
        "chain jacobian_outer_at_inner",
        values.get("jacobian_outer_at_inner"),
    )
    listed_jacobian_composite = require_fraction_matrix(
        "chain jacobian_composite",
        values.get("jacobian_composite"),
    )
    require_matrix_shape("chain jacobian_inner", listed_jacobian_inner, 2, 2)
    require_matrix_shape("chain jacobian_outer_at_inner", listed_jacobian_outer, 2, 2)
    require_matrix_shape("chain jacobian_composite", listed_jacobian_composite, 2, 2)
    actual_inner_value = bivariate_map_eval(inner_map, point)
    if inner_value != actual_inner_value:
        fail("jacobian-chain-rule-replay inner_value is incorrect")
    actual_inner_jacobian = bivariate_jacobian(inner_map, point)
    actual_outer_jacobian = bivariate_jacobian(outer_map, (inner_value[0], inner_value[1]))
    if listed_jacobian_inner != actual_inner_jacobian:
        fail("jacobian-chain-rule-replay inner Jacobian is incorrect")
    if listed_jacobian_outer != actual_outer_jacobian:
        fail("jacobian-chain-rule-replay outer Jacobian is incorrect")
    actual_composite = mat_mul(actual_outer_jacobian, actual_inner_jacobian)
    if listed_jacobian_composite != actual_composite:
        fail("jacobian-chain-rule-replay composite Jacobian is incorrect")

    hessian = checks["hessian-positive-definite-replay"]
    if hessian["expected_result"] != "sat" or hessian.get("proof_status") != "checked":
        fail("hessian-positive-definite-replay must be a checked sat row")
    values = single_witness_values(hessian, witnesses)
    polynomial = require_bivariate_polynomial("hessian polynomial", values.get("polynomial"))
    point = require_bivariate_point("hessian point", values.get("point"))
    listed_hessian = require_fraction_matrix("hessian matrix", values.get("hessian"))
    require_matrix_shape("hessian matrix", listed_hessian, 2, 2)
    leading_minor = require_fraction("hessian leading_minor", values.get("leading_minor"))
    determinant = require_fraction("hessian determinant", values.get("determinant"))
    actual_hessian = bivariate_hessian(polynomial, point)
    if listed_hessian != actual_hessian:
        fail("hessian-positive-definite-replay Hessian is incorrect")
    if leading_minor != listed_hessian[0][0]:
        fail("hessian-positive-definite-replay leading minor is incorrect")
    if determinant != matrix_det_2(listed_hessian):
        fail("hessian-positive-definite-replay determinant is incorrect")
    if leading_minor <= 0 or determinant <= 0:
        fail("hessian-positive-definite-replay minors must be positive")

    bad = checks["bad-gradient-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "checked":
        fail("bad-gradient-rejected must be a checked unsat row")
    data = bad.get("data", {})
    polynomial = require_bivariate_polynomial("bad gradient polynomial", data.get("polynomial"))
    point = require_bivariate_point("bad gradient point", data.get("point"))
    claimed = require_fraction_vector("bad gradient claimed_gradient", data.get("claimed_gradient"))
    actual = require_fraction_vector("bad gradient actual_gradient", data.get("actual_gradient"))
    require_vector_length("bad gradient claimed_gradient", claimed, 2)
    require_vector_length("bad gradient actual_gradient", actual, 2)
    recomputed = bivariate_gradient(polynomial, point)
    if actual != recomputed:
        fail("bad-gradient-rejected actual_gradient is incorrect")
    if claimed == recomputed:
        fail("bad-gradient-rejected claimed gradient unexpectedly matches")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad gradient smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/multivariable-calculus-rational-v0/smt2/bad-gradient-farkas-conflict.smt2"
    ):
        fail("bad-gradient-rejected smt2_artifact must name the checked QF_LRA artifact")
    check_source("bad gradient smt2_artifact", smt2_artifact)
    farkas_regression = data.get("farkas_regression")
    require_string("bad gradient farkas_regression", farkas_regression)
    if "multivariable_calculus_bad_gradient_artifact_emits_checked_farkas" not in farkas_regression:
        fail("bad-gradient-rejected must link the Farkas regression")

    horizon = checks["general-multivariable-calculus-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-multivariable-calculus-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-multivariable-calculus-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general multivariable target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general multivariable future_checker", data.get("future_checker"))


def validate_finite_newton_step(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    gradient = checks["quadratic-gradient-hessian-replay"]
    if gradient["expected_result"] != "sat":
        fail("quadratic-gradient-hessian-replay must expect sat")
    values = single_witness_values(gradient, witnesses)
    polynomial = require_bivariate_polynomial("Newton polynomial", values.get("polynomial"))
    start_point = require_bivariate_point("Newton start_point", values.get("start_point"))
    start_vector = [start_point[0], start_point[1]]
    start_value = require_fraction("Newton start_value", values.get("start_value"))
    listed_gradient = require_fraction_vector("Newton gradient", values.get("gradient"))
    require_vector_length("Newton gradient", listed_gradient, 2)
    listed_hessian = require_fraction_matrix("Newton hessian", values.get("hessian"))
    require_matrix_shape("Newton hessian", listed_hessian, 2, 2)
    leading_minor = require_fraction("Newton leading_minor", values.get("leading_minor"))
    determinant = require_fraction("Newton determinant", values.get("determinant"))
    if bivariate_eval(polynomial, start_point) != start_value:
        fail("quadratic-gradient-hessian-replay start_value is incorrect")
    if bivariate_gradient(polynomial, start_point) != listed_gradient:
        fail("quadratic-gradient-hessian-replay gradient is incorrect")
    if bivariate_hessian(polynomial, start_point) != listed_hessian:
        fail("quadratic-gradient-hessian-replay Hessian is incorrect")
    if leading_minor != listed_hessian[0][0]:
        fail("quadratic-gradient-hessian-replay leading minor is incorrect")
    if determinant != matrix_det_2(listed_hessian):
        fail("quadratic-gradient-hessian-replay determinant is incorrect")
    if leading_minor <= 0 or determinant <= 0:
        fail("quadratic-gradient-hessian-replay minors must be positive")

    solve = checks["newton-linear-solve-replay"]
    if solve["expected_result"] != "sat":
        fail("newton-linear-solve-replay must expect sat")
    values = single_witness_values(solve, witnesses)
    rhs = require_fraction_vector("Newton rhs", values.get("newton_rhs"))
    require_vector_length("Newton rhs", rhs, 2)
    hessian_inverse = require_fraction_matrix("Newton hessian_inverse", values.get("hessian_inverse"))
    require_matrix_shape("Newton hessian_inverse", hessian_inverse, 2, 2)
    direction = require_fraction_vector("Newton direction", values.get("direction"))
    require_vector_length("Newton direction", direction, 2)
    if rhs != scalar_vec(Fraction(-1), listed_gradient):
        fail("newton-linear-solve-replay rhs must be -gradient")
    if mat_vec(listed_hessian, direction) != rhs:
        fail("newton-linear-solve-replay direction does not solve Hessian * direction = rhs")
    identity = [[Fraction(1), Fraction(0)], [Fraction(0), Fraction(1)]]
    if mat_mul(hessian_inverse, listed_hessian) != identity:
        fail("newton-linear-solve-replay hessian_inverse is incorrect")
    if mat_vec(hessian_inverse, rhs) != direction:
        fail("newton-linear-solve-replay inverse * rhs is not the listed direction")

    step = checks["newton-step-stationarity-replay"]
    if step["expected_result"] != "sat":
        fail("newton-step-stationarity-replay must expect sat")
    values = single_witness_values(step, witnesses)
    next_point = require_fraction_vector("Newton next_point", values.get("next_point"))
    require_vector_length("Newton next_point", next_point, 2)
    next_gradient = require_fraction_vector("Newton next_gradient", values.get("next_gradient"))
    require_vector_length("Newton next_gradient", next_gradient, 2)
    if vector_add_fraction(start_vector, direction) != next_point:
        fail("newton-step-stationarity-replay next_point must equal start + direction")
    if bivariate_gradient(polynomial, (next_point[0], next_point[1])) != next_gradient:
        fail("newton-step-stationarity-replay next_gradient is incorrect")
    if any(component != 0 for component in next_gradient):
        fail("newton-step-stationarity-replay expected zero gradient at the Newton point")

    decrease = checks["newton-objective-decrease-replay"]
    if decrease["expected_result"] != "sat":
        fail("newton-objective-decrease-replay must expect sat")
    values = single_witness_values(decrease, witnesses)
    next_value = require_fraction("Newton next_value", values.get("next_value"))
    listed_decrease = require_fraction("Newton decrease", values.get("decrease"))
    if bivariate_eval(polynomial, (next_point[0], next_point[1])) != next_value:
        fail("newton-objective-decrease-replay next_value is incorrect")
    if start_value - next_value != listed_decrease:
        fail("newton-objective-decrease-replay decrease is incorrect")
    if listed_decrease <= 0:
        fail("newton-objective-decrease-replay expected positive decrease")

    bad = checks["bad-newton-coordinate-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-newton-coordinate-rejected must be a replay-only unsat row")
    data = bad.get("data", {})
    if data.get("source_witness") != "two-variable-quadratic-newton-step":
        fail("bad-newton-coordinate-rejected must cite the Newton witness")
    computed_next = require_fraction_vector("bad Newton computed_next_point", data.get("computed_next_point"))
    require_vector_length("bad Newton computed_next_point", computed_next, 2)
    claimed_next_x = require_fraction("bad Newton claimed_next_x", data.get("claimed_next_x"))
    if computed_next != next_point:
        fail("bad-newton-coordinate-rejected computed_next_point does not match replay")
    if claimed_next_x == next_point[0]:
        fail("bad-newton-coordinate-rejected malformed x-coordinate unexpectedly matches")

    checked = checks["qf-lra-bad-newton-coordinate"]
    if checked["expected_result"] != "unsat" or checked.get("proof_status") != "checked":
        fail("qf-lra-bad-newton-coordinate must be a checked unsat row")
    data = checked.get("data", {})
    if data.get("source_replay_row") != "bad-newton-coordinate-rejected":
        fail("qf-lra-bad-newton-coordinate must point back to the replay rejection row")
    computed_next_x = require_fraction("checked Newton computed_next_x", data.get("computed_next_x"))
    checked_claimed_next_x = require_fraction("checked Newton claimed_next_x", data.get("claimed_next_x"))
    if computed_next_x != next_point[0] or checked_claimed_next_x != claimed_next_x:
        fail("qf-lra-bad-newton-coordinate must reuse the replayed and claimed coordinates")
    smt2_artifact = data.get("smt2_artifact")
    require_string("checked Newton smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/finite-newton-step-v0/smt2/bad-newton-coordinate-farkas-conflict.smt2":
        fail("qf-lra-bad-newton-coordinate smt2_artifact must name the checked QF_LRA artifact")
    check_source("checked Newton smt2_artifact", smt2_artifact)
    regression = data.get("farkas_regression")
    require_string("checked Newton farkas_regression", regression)
    if "finite_newton_step_bad_coordinate_artifact_emits_checked_farkas" not in regression:
        fail("qf-lra-bad-newton-coordinate must link the Farkas regression")
    certificate = data.get("certificate")
    require_string("checked Newton certificate", certificate)
    if "UnsatFarkas" not in certificate:
        fail("qf-lra-bad-newton-coordinate certificate must document checked Farkas evidence")

    horizon = checks["general-newton-method-lean-horizon"]
    if horizon["expected_result"] != "not-run" or horizon["proof_status"] != "lean-horizon":
        fail("general-newton-method-lean-horizon must remain a not-run Lean horizon")
    data = horizon.get("data", {})
    require_string("Newton horizon target_theorem_shape", data.get("target_theorem_shape"))
    require_string("Newton horizon future_checker", data.get("future_checker"))


def validate_polynomial_identities(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    binomial = checks["binomial-square-identity"]
    if binomial["expected_result"] != "sat":
        fail("binomial-square-identity must expect sat")
    values = single_witness_values(binomial, witnesses)
    factor = require_polynomial("binomial factor", values.get("factor"))
    expanded = require_polynomial("binomial expanded", values.get("expanded"))
    if polynomial_mul(factor, factor) != expanded:
        fail("binomial-square-identity expansion does not match factor * factor")

    factor_theorem = checks["factor-theorem-root-witness"]
    if factor_theorem["expected_result"] != "sat":
        fail("factor-theorem-root-witness must expect sat")
    values = single_witness_values(factor_theorem, witnesses)
    polynomial = require_polynomial("factor theorem polynomial", values.get("polynomial"))
    root = require_fraction("factor theorem root", values.get("root"))
    factor = require_polynomial("factor theorem factor", values.get("factor"))
    quotient = require_polynomial("factor theorem quotient", values.get("quotient"))
    if polynomial_eval(polynomial, root) != 0:
        fail("factor-theorem-root-witness root does not evaluate to zero")
    expected_linear_factor = normalize_polynomial([-root, Fraction(1)])
    if factor != expected_linear_factor:
        fail("factor-theorem-root-witness factor must be x - root")
    if polynomial_mul(factor, quotient) != polynomial:
        fail("factor-theorem-root-witness factor * quotient does not reconstruct polynomial")

    false_root = checks["false-rational-root-rejected"]
    if false_root["expected_result"] != "unsat" or false_root.get("proof_status") != "checked":
        fail("false-rational-root-rejected must be a checked unsat row")
    if false_root["validation"] != "qf_lia_diophantine_evidence":
        fail("false-rational-root-rejected must use qf_lia_diophantine_evidence validation")
    values = single_witness_values(false_root, witnesses)
    polynomial = require_polynomial("false root polynomial", values.get("polynomial"))
    candidate = require_fraction("false root candidate", values.get("candidate_root"))
    evaluated = polynomial_eval(polynomial, candidate)
    if evaluated == 0:
        fail("false-rational-root-rejected candidate unexpectedly is a root")
    data = false_root.get("data", {})
    data_polynomial = require_polynomial("false root data polynomial", data.get("polynomial"))
    data_candidate = require_fraction("false root data candidate_root", data.get("candidate_root"))
    actual_value = require_fraction("false root actual_value", data.get("actual_value"))
    claimed_value = require_fraction("false root claimed_value", data.get("claimed_value"))
    if data_polynomial != polynomial:
        fail("false-rational-root-rejected data polynomial must match the witness polynomial")
    if data_candidate != candidate:
        fail("false-rational-root-rejected data candidate_root must match the witness candidate")
    if actual_value != evaluated:
        fail("false-rational-root-rejected actual_value must match exact polynomial evaluation")
    if claimed_value != 0:
        fail("false-rational-root-rejected claimed_value must be the claimed root value 0")
    smt2_artifact = data.get("smt2_artifact")
    require_string("false root smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/polynomial-identities-v0/smt2/false-rational-root-diophantine-conflict.smt2":
        fail("false-rational-root-rejected smt2_artifact must name the checked QF_LIA artifact")
    check_source("false root smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("false root proof_regression", proof_regression)
    if "polynomial_identities_false_rational_root_emits_checked_diophantine_evidence" not in proof_regression:
        fail("false-rational-root-rejected proof_regression must name the LIA resource test")
    certificate = data.get("certificate")
    require_string("false root certificate", certificate)
    if "UnsatDiophantine" not in certificate or "Evidence::check" not in certificate:
        fail("false-rational-root-rejected certificate must document checked Diophantine evidence")


def validate_polynomial_factorization_rational(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    product = checks["factorization-product-replay"]
    if product["expected_result"] != "sat":
        fail("factorization-product-replay must expect sat")
    values = single_witness_values(product, witnesses)
    polynomial = require_polynomial("factorization polynomial", values.get("polynomial"))
    factors = require_polynomial_list("factorization factors", values.get("factors"))
    computed_product = [Fraction(1)]
    for factor in factors:
        computed_product = polynomial_mul(computed_product, factor)
    if computed_product != polynomial:
        fail("factorization-product-replay factor product does not reconstruct polynomial")

    division = checks["polynomial-division-replay"]
    if division["expected_result"] != "sat" or division.get("proof_status") != "checked":
        fail("polynomial-division-replay must be a checked sat row")
    values = single_witness_values(division, witnesses)
    polynomial = require_polynomial("division polynomial", values.get("polynomial"))
    divisor = require_polynomial("division divisor", values.get("divisor"))
    quotient = require_polynomial("division quotient", values.get("quotient"))
    remainder = require_polynomial("division remainder", values.get("remainder"))
    computed_quotient, computed_remainder = polynomial_divmod(polynomial, divisor)
    if computed_quotient != quotient:
        fail("polynomial-division-replay quotient is incorrect")
    if computed_remainder != remainder:
        fail("polynomial-division-replay remainder is incorrect")
    reconstructed = polynomial_add(polynomial_mul(divisor, quotient), remainder)
    if reconstructed != polynomial:
        fail("polynomial-division-replay reconstruction is incorrect")

    gcd = checks["euclidean-gcd-replay"]
    if gcd["expected_result"] != "sat" or gcd.get("proof_status") != "checked":
        fail("euclidean-gcd-replay must be a checked sat row")
    values = single_witness_values(gcd, witnesses)
    left = require_polynomial("GCD left", values.get("left"))
    right = require_polynomial("GCD right", values.get("right"))
    listed_gcd = require_polynomial("GCD gcd", values.get("gcd"))
    left_quotient = require_polynomial("GCD left_quotient", values.get("left_quotient"))
    right_quotient = require_polynomial("GCD right_quotient", values.get("right_quotient"))
    if polynomial_gcd(left, right) != listed_gcd:
        fail("euclidean-gcd-replay listed GCD is incorrect")
    if polynomial_mul(listed_gcd, left_quotient) != left:
        fail("euclidean-gcd-replay left quotient is incorrect")
    if polynomial_mul(listed_gcd, right_quotient) != right:
        fail("euclidean-gcd-replay right quotient is incorrect")

    square_free = checks["square-free-decomposition-replay"]
    if square_free["expected_result"] != "sat" or square_free.get("proof_status") != "checked":
        fail("square-free-decomposition-replay must be a checked sat row")
    values = single_witness_values(square_free, witnesses)
    polynomial = require_polynomial("square-free polynomial", values.get("polynomial"))
    derivative = require_polynomial("square-free derivative", values.get("derivative"))
    repeated_factor = require_polynomial("square-free repeated_factor", values.get("repeated_factor"))
    square_free_part = require_polynomial("square-free square_free_part", values.get("square_free_part"))
    if polynomial_derivative(polynomial) != derivative:
        fail("square-free-decomposition-replay derivative is incorrect")
    if polynomial_gcd(polynomial, derivative) != repeated_factor:
        fail("square-free-decomposition-replay repeated factor is not gcd(p,p')")
    quotient, remainder = polynomial_divmod(polynomial, repeated_factor)
    if remainder != [Fraction(0)]:
        fail("square-free-decomposition-replay repeated factor does not divide polynomial")
    if quotient != square_free_part:
        fail("square-free-decomposition-replay square-free part is incorrect")
    if polynomial_mul(repeated_factor, square_free_part) != polynomial:
        fail("square-free-decomposition-replay reconstruction is incorrect")

    irreducible = checks["irreducible-quadratic-rational-rejected"]
    if irreducible["expected_result"] != "unsat" or irreducible.get("proof_status") != "checked":
        fail("irreducible-quadratic-rational-rejected must be a checked unsat row")
    data = irreducible.get("data", {})
    polynomial = require_quadratic("irreducible quadratic polynomial", data.get("polynomial"))
    discriminant = require_fraction("irreducible quadratic discriminant", data.get("discriminant"))
    reason = data.get("reason")
    require_string("irreducible quadratic reason", reason)
    if quadratic_discriminant(polynomial) != discriminant:
        fail("irreducible-quadratic-rational-rejected discriminant is incorrect")
    if reason != "negative_discriminant":
        fail("irreducible-quadratic-rational-rejected must use negative_discriminant reason")
    if discriminant >= 0:
        fail("irreducible-quadratic-rational-rejected discriminant must be negative")

    conflict = checks["irreducible-quadratic-discriminant-conflict"]
    if conflict["expected_result"] != "unsat" or conflict.get("proof_status") != "checked":
        fail("irreducible-quadratic-discriminant-conflict must be a checked unsat row")
    data = conflict.get("data", {})
    conflict_polynomial = require_quadratic(
        "irreducible discriminant conflict polynomial",
        data.get("polynomial"),
    )
    conflict_discriminant = require_fraction(
        "irreducible discriminant conflict discriminant",
        data.get("discriminant"),
    )
    if conflict_polynomial != polynomial:
        fail("irreducible-quadratic-discriminant-conflict polynomial does not match replay row")
    if conflict_discriminant != discriminant:
        fail("irreducible-quadratic-discriminant-conflict discriminant does not match replay row")
    if quadratic_discriminant(conflict_polynomial) != conflict_discriminant:
        fail("irreducible-quadratic-discriminant-conflict discriminant is incorrect")
    if conflict_discriminant >= 0:
        fail("irreducible-quadratic-discriminant-conflict must record a negative discriminant")
    if data.get("required_nonnegative_discriminant") is not True:
        fail("irreducible-quadratic-discriminant-conflict must require a nonnegative discriminant")
    smt2_artifact = data.get("smt2_artifact")
    require_string("irreducible discriminant conflict smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/polynomial-factorization-rational-v0/smt2/irreducible-quadratic-discriminant-farkas-conflict.smt2"
    ):
        fail("irreducible-quadratic-discriminant-conflict smt2_artifact must name the checked QF_LRA artifact")
    check_source("irreducible discriminant conflict smt2_artifact", smt2_artifact)
    lra_regression = data.get("lra_regression")
    require_string("irreducible discriminant conflict lra_regression", lra_regression)
    if "polynomial_factorization_irreducible_quadratic_discriminant_artifact_emits_checked_farkas" not in lra_regression:
        fail("irreducible-quadratic-discriminant-conflict must link the LRA route regression")

    horizon = checks["general-factorization-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-factorization-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-factorization-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general factorization target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general factorization future_checker", data.get("future_checker"))


def polynomial_prefix(polynomial: list[Fraction], length: int) -> list[Fraction]:
    return [
        polynomial[index] if index < len(polynomial) else Fraction(0)
        for index in range(length)
    ]


def validate_generating_functions(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    coefficients = checks["coefficient-extraction-witness"]
    if coefficients["expected_result"] != "sat":
        fail("coefficient-extraction-witness must expect sat")
    values = single_witness_values(coefficients, witnesses)
    sequence = require_fraction_vector("generating coefficients sequence", values.get("sequence"))
    polynomial = require_fraction_vector("generating coefficients polynomial", values.get("polynomial"))
    indices = require_nonnegative_int_list("generating coefficients indices", values.get("indices"))
    extracted = require_fraction_vector("generating coefficients extracted", values.get("extracted"))
    if sequence != polynomial:
        fail("coefficient-extraction-witness polynomial must equal the sequence prefix")
    if len(indices) != len(extracted):
        fail("coefficient-extraction-witness indices and extracted values must have the same length")
    for index, extracted_value in zip(indices, extracted):
        if index >= len(polynomial):
            fail("coefficient-extraction-witness index is outside the polynomial prefix")
        if polynomial[index] != extracted_value:
            fail("coefficient-extraction-witness extracted value is incorrect")

    cauchy = checks["cauchy-product-convolution"]
    if cauchy["expected_result"] != "sat":
        fail("cauchy-product-convolution must expect sat")
    values = single_witness_values(cauchy, witnesses)
    left = require_polynomial("Cauchy product left", values.get("left"))
    right = require_polynomial("Cauchy product right", values.get("right"))
    product_value = require_polynomial("Cauchy product product", values.get("product"))
    if polynomial_mul(left, right) != product_value:
        fail("cauchy-product-convolution product does not equal the exact Cauchy product")

    fibonacci = checks["fibonacci-generating-prefix"]
    if fibonacci["expected_result"] != "sat":
        fail("fibonacci-generating-prefix must expect sat")
    values = single_witness_values(fibonacci, witnesses)
    fib_coefficients = require_fraction_vector("Fibonacci coefficients", values.get("coefficients"))
    multiplier = require_polynomial("Fibonacci multiplier", values.get("multiplier"))
    truncation_degree = require_nonnegative_int("Fibonacci truncation_degree", values.get("truncation_degree"))
    identity_prefix = require_fraction_vector("Fibonacci identity_prefix", values.get("identity_prefix"))
    if truncation_degree + 1 != len(identity_prefix):
        fail("fibonacci-generating-prefix identity_prefix must have truncation_degree + 1 entries")
    if truncation_degree >= len(fib_coefficients):
        fail("fibonacci-generating-prefix truncation_degree must fit inside the coefficient prefix")
    if len(fib_coefficients) < 3:
        fail("fibonacci-generating-prefix requires at least three coefficients")
    if fib_coefficients[0] != 0 or fib_coefficients[1] != 1:
        fail("fibonacci-generating-prefix must use F_0 = 0 and F_1 = 1")
    for index in range(2, truncation_degree + 1):
        if fib_coefficients[index] != fib_coefficients[index - 1] + fib_coefficients[index - 2]:
            fail(f"fibonacci-generating-prefix coefficient {index} violates the recurrence")
    computed_prefix = polynomial_prefix(polynomial_mul(fib_coefficients, multiplier), truncation_degree + 1)
    if computed_prefix != identity_prefix:
        fail("fibonacci-generating-prefix truncated identity prefix is incorrect")

    bad_product = checks["bad-cauchy-product-rejected"]
    if bad_product["expected_result"] != "unsat" or bad_product.get("proof_status") != "checked":
        fail("bad-cauchy-product-rejected must be a checked unsat row")
    if bad_product["validation"] != "qf_lia_diophantine_evidence":
        fail("bad-cauchy-product-rejected must use qf_lia_diophantine_evidence validation")
    data = bad_product.get("data", {})
    left = require_polynomial("bad Cauchy left", data.get("left"))
    right = require_polynomial("bad Cauchy right", data.get("right"))
    claimed_product = require_polynomial("bad Cauchy claimed_product", data.get("claimed_product"))
    actual_product = require_polynomial("bad Cauchy actual_product", data.get("actual_product"))
    first_bad_index = require_nonnegative_int("bad Cauchy first_bad_index", data.get("first_bad_index"))
    if polynomial_mul(left, right) != actual_product:
        fail("bad-cauchy-product-rejected actual_product is incorrect")
    if claimed_product == actual_product:
        fail("bad-cauchy-product-rejected claimed product unexpectedly matches")
    if first_bad_index >= max(len(claimed_product), len(actual_product)):
        fail("bad-cauchy-product-rejected first_bad_index is outside the product range")
    claimed_at_index = claimed_product[first_bad_index] if first_bad_index < len(claimed_product) else Fraction(0)
    actual_at_index = actual_product[first_bad_index] if first_bad_index < len(actual_product) else Fraction(0)
    if claimed_at_index == actual_at_index:
        fail("bad-cauchy-product-rejected first_bad_index does not identify a mismatch")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad Cauchy smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/generating-functions-v0/smt2/bad-cauchy-product-diophantine-conflict.smt2":
        fail("bad-cauchy-product-rejected smt2_artifact must name the checked QF_LIA artifact")
    check_source("bad Cauchy smt2_artifact", smt2_artifact)
    proof_regression = data.get("proof_regression")
    require_string("bad Cauchy proof_regression", proof_regression)
    if "generating_functions_bad_cauchy_product_emits_checked_diophantine_evidence" not in proof_regression:
        fail("bad-cauchy-product-rejected proof_regression must name the LIA resource test")
    certificate = data.get("certificate")
    require_string("bad Cauchy certificate", certificate)
    if "UnsatDiophantine" not in certificate or "Evidence::check" not in certificate:
        fail("bad-cauchy-product-rejected certificate must document checked Diophantine evidence")

    horizon = checks["general-generating-functions-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-generating-functions-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-generating-functions-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general generating functions target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general generating functions future_checker", data.get("future_checker"))


def require_fraction_matrix(context: str, value: Any) -> list[list[Fraction]]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty matrix")
    matrix = [
        require_fraction_vector(f"{context}[{row_index}]", row)
        for row_index, row in enumerate(value)
    ]
    width = len(matrix[0])
    for row_index, row in enumerate(matrix):
        if len(row) != width:
            fail(f"{context}[{row_index}] must have width {width}")
    return matrix


def require_mat_vec_shape(context: str, matrix: list[list[Fraction]], vector: list[Fraction]) -> None:
    if len(matrix[0]) != len(vector):
        fail(f"{context} matrix width must match vector length")


def require_mat_mul_shape(
    context: str,
    left: list[list[Fraction]],
    right: list[list[Fraction]],
) -> None:
    if len(left[0]) != len(right):
        fail(f"{context} left width must match right height")


def mat_vec(matrix: list[list[Fraction]], vector: list[Fraction]) -> list[Fraction]:
    return [
        sum((coefficient * vector[index] for index, coefficient in enumerate(row)), Fraction(0))
        for row in matrix
    ]


def mat_mul(left: list[list[Fraction]], right: list[list[Fraction]]) -> list[list[Fraction]]:
    columns = list(zip(*right))
    return [
        [sum((a * b for a, b in zip(row, column)), Fraction(0)) for column in columns]
        for row in left
    ]


def require_square_matrix(context: str, matrix: list[list[Fraction]]) -> None:
    if len(matrix) != len(matrix[0]):
        fail(f"{context} must be square")


def validate_lu_shape(l_matrix: list[list[Fraction]], u_matrix: list[list[Fraction]]) -> None:
    require_square_matrix("L matrix", l_matrix)
    require_square_matrix("U matrix", u_matrix)
    if len(l_matrix) != len(u_matrix):
        fail("L and U matrices must have the same dimension")
    dimension = len(l_matrix)
    for row_index in range(dimension):
        if l_matrix[row_index][row_index] != 1:
            fail("L matrix must have unit diagonal")
        for col_index in range(row_index + 1, dimension):
            if l_matrix[row_index][col_index] != 0:
                fail("L matrix must be lower triangular")
        for col_index in range(row_index):
            if u_matrix[row_index][col_index] != 0:
                fail("U matrix must be upper triangular")


def validate_rationals_lra(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    density = checks["density-between-witness"]
    if density["expected_result"] != "sat":
        fail("density-between-witness must expect sat")
    values = single_witness_values(density, witnesses)
    a = require_fraction("density a", values.get("a"))
    b = require_fraction("density b", values.get("b"))
    midpoint = require_fraction("density midpoint", values.get("midpoint"))
    if not a < midpoint < b:
        fail("density witness must satisfy a < midpoint < b")
    if midpoint != (a + b) / 2:
        fail("density midpoint must be exactly (a + b) / 2")

    inverse = checks["additive-inverse-witness"]
    if inverse["expected_result"] != "sat":
        fail("additive-inverse-witness must expect sat")
    values = single_witness_values(inverse, witnesses)
    x = require_fraction("inverse x", values.get("x"))
    neg_x = require_fraction("inverse inverse", values.get("inverse"))
    total = require_fraction("inverse sum", values.get("sum"))
    if x + neg_x != total or total != 0:
        fail("additive inverse witness must sum to exactly zero")

    trichotomy = checks["trichotomy-fixed-unsat"]
    if trichotomy["expected_result"] != "unsat":
        fail("trichotomy-fixed-unsat must expect unsat")
    data = trichotomy.get("data", {})
    left = require_fraction("trichotomy left", data.get("left"))
    right = require_fraction("trichotomy right", data.get("right"))
    relations = [left < right, left == right, left > right]
    if sum(1 for relation in relations if relation) != 1:
        fail("trichotomy fixed pair must satisfy exactly one relation")

    transitivity = checks["order-transitivity-fixed-unsat"]
    if transitivity["expected_result"] != "unsat":
        fail("order-transitivity-fixed-unsat must expect unsat")
    data = transitivity.get("data", {})
    lower = require_fraction("transitivity a", data.get("a"))
    middle = require_fraction("transitivity b", data.get("b"))
    upper = require_fraction("transitivity c", data.get("c"))
    if not (lower < middle and middle < upper):
        fail("transitivity fixed data must satisfy a < b < c")
    if not lower < upper:
        fail("transitivity fixed data unexpectedly violates a < c")


def require_quadratic(context: str, value: Any) -> list[Fraction]:
    polynomial = require_polynomial(context, value)
    if len(polynomial) != 3:
        fail(f"{context} must be a quadratic polynomial with three coefficients")
    if polynomial[2] == 0:
        fail(f"{context} quadratic coefficient must be nonzero")
    return polynomial


def quadratic_discriminant(polynomial: list[Fraction]) -> Fraction:
    constant, linear, quadratic = polynomial
    return linear * linear - 4 * quadratic * constant


def validate_reals_rcf_shadow(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    midpoint_check = checks["ordered-field-midpoint-witness"]
    if midpoint_check["expected_result"] != "sat":
        fail("ordered-field-midpoint-witness must expect sat")
    values = single_witness_values(midpoint_check, witnesses)
    left = require_fraction("real midpoint left", values.get("left"))
    right = require_fraction("real midpoint right", values.get("right"))
    midpoint = require_fraction("real midpoint midpoint", values.get("midpoint"))
    if not left < midpoint < right:
        fail("ordered-field-midpoint-witness must satisfy left < midpoint < right")
    if midpoint != (left + right) / 2:
        fail("ordered-field-midpoint-witness midpoint must equal (left + right) / 2")

    product_check = checks["nra-product-threshold-witness"]
    if product_check["expected_result"] != "sat":
        fail("nra-product-threshold-witness must expect sat")
    values = single_witness_values(product_check, witnesses)
    x_value = require_fraction("product witness x", values.get("x"))
    y_value = require_fraction("product witness y", values.get("y"))
    lower_bound = require_fraction("product witness lower_bound", values.get("lower_bound"))
    product_value = require_fraction("product witness product", values.get("product"))
    if product_value != x_value * y_value:
        fail("nra-product-threshold-witness product does not equal x * y")
    if x_value < lower_bound or y_value < lower_bound:
        fail("nra-product-threshold-witness violates the lower-bound assumptions")
    if lower_bound != 1:
        fail("nra-product-threshold-witness currently documents the fixed lower bound 1")
    if product_value < lower_bound:
        fail("nra-product-threshold-witness product violates the threshold")

    root_check = checks["quadratic-root-real-witness"]
    if root_check["expected_result"] != "sat":
        fail("quadratic-root-real-witness must expect sat")
    values = single_witness_values(root_check, witnesses)
    polynomial = require_quadratic("real quadratic root polynomial", values.get("polynomial"))
    root = require_fraction("real quadratic root", values.get("root"))
    if polynomial_eval(polynomial, root) != 0:
        fail("quadratic-root-real-witness root does not evaluate to zero")

    square_check = checks["square-nonnegative-unsat"]
    if square_check["expected_result"] != "unsat":
        fail("square-nonnegative-unsat must expect unsat")
    data = square_check.get("data", {})
    polynomial = require_quadratic("square-nonnegative polynomial", data.get("polynomial"))
    relation = data.get("relation")
    certificate = data.get("certificate")
    require_string("square-nonnegative relation", relation)
    require_string("square-nonnegative certificate", certificate)
    bound = require_fraction("square-nonnegative bound", data.get("bound"))
    if polynomial != [Fraction(0), Fraction(0), Fraction(1)]:
        fail("square-nonnegative-unsat must use the fixed polynomial x^2")
    if relation != "lt" or bound != 0 or certificate != "square_nonnegative":
        fail("square-nonnegative-unsat must document the fixed x^2 < 0 certificate")

    discriminant_check = checks["negative-discriminant-no-real-root"]
    if discriminant_check["expected_result"] != "unsat":
        fail("negative-discriminant-no-real-root must expect unsat")
    data = discriminant_check.get("data", {})
    polynomial = require_quadratic("negative-discriminant polynomial", data.get("polynomial"))
    relation = data.get("relation")
    require_string("negative-discriminant relation", relation)
    bound = require_fraction("negative-discriminant bound", data.get("bound"))
    expected_discriminant = require_fraction(
        "negative-discriminant expected_discriminant",
        data.get("expected_discriminant"),
    )
    actual_discriminant = quadratic_discriminant(polynomial)
    if relation != "eq" or bound != 0:
        fail("negative-discriminant-no-real-root must document a polynomial = 0 row")
    if actual_discriminant != expected_discriminant:
        fail("negative-discriminant-no-real-root discriminant does not match expected value")
    if actual_discriminant >= 0:
        fail("negative-discriminant-no-real-root requires a negative discriminant")

    conflict = checks["negative-discriminant-farkas-conflict"]
    if conflict["expected_result"] != "unsat" or conflict.get("proof_status") != "checked":
        fail("negative-discriminant-farkas-conflict must be a checked unsat row")
    data = conflict.get("data", {})
    conflict_polynomial = require_quadratic(
        "negative-discriminant conflict polynomial",
        data.get("polynomial"),
    )
    conflict_discriminant = require_fraction(
        "negative-discriminant conflict discriminant",
        data.get("discriminant"),
    )
    if conflict_polynomial != polynomial:
        fail("negative-discriminant-farkas-conflict polynomial does not match replay row")
    if conflict_discriminant != actual_discriminant:
        fail("negative-discriminant-farkas-conflict discriminant does not match replay row")
    if conflict_discriminant >= 0:
        fail("negative-discriminant-farkas-conflict must record a negative discriminant")
    if data.get("required_nonnegative_discriminant") is not True:
        fail("negative-discriminant-farkas-conflict must require a nonnegative discriminant")
    smt2_artifact = data.get("smt2_artifact")
    require_string("negative-discriminant conflict smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/reals-rcf-shadow-v0/smt2/negative-discriminant-farkas-conflict.smt2":
        fail("negative-discriminant-farkas-conflict smt2_artifact must name the checked QF_LRA artifact")
    check_source("negative-discriminant conflict smt2_artifact", smt2_artifact)
    lra_regression = data.get("lra_regression")
    require_string("negative-discriminant conflict lra_regression", lra_regression)
    if "reals_rcf_shadow_negative_discriminant_artifact_emits_checked_farkas" not in lra_regression:
        fail("negative-discriminant-farkas-conflict must link the LRA route regression")

    horizon = checks["real-completeness-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("real-completeness-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("real-completeness-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("real completeness target_theorem_shape", data.get("target_theorem_shape"))
    require_string("real completeness future_checker", data.get("future_checker"))


def require_fraction_interval(context: str, value: Any) -> tuple[Fraction, Fraction, bool]:
    if not isinstance(value, dict):
        fail(f"{context} must be an object")
    lower = require_fraction(f"{context}.lower", value.get("lower"))
    upper = require_fraction(f"{context}.upper", value.get("upper"))
    closed = require_bool(f"{context}.closed", value.get("closed"))
    if lower > upper:
        fail(f"{context} lower must be <= upper")
    return lower, upper, closed


def linear_fraction_value(slope: Fraction, intercept: Fraction, point: Fraction) -> Fraction:
    return slope * point + intercept


def validate_real_analysis_rational(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    interval = checks["nested-rational-neighborhood-witness"]
    if interval["expected_result"] != "sat":
        fail("nested-rational-neighborhood-witness must expect sat")
    values = single_witness_values(interval, witnesses)
    lower, upper, closed = require_fraction_interval("nested rational inner_interval", values.get("inner_interval"))
    if not closed:
        fail("nested-rational-neighborhood-witness currently documents a closed inner interval")
    outer_ball = values.get("outer_ball")
    if not isinstance(outer_ball, dict):
        fail("nested rational outer_ball must be an object")
    center = require_fraction("nested rational outer_ball.center", outer_ball.get("center"))
    radius = require_fraction("nested rational outer_ball.radius", outer_ball.get("radius"))
    strict = require_bool("nested rational outer_ball.strict", outer_ball.get("strict"))
    if radius <= 0:
        fail("nested-rational-neighborhood-witness radius must be positive")
    samples = require_fraction_vector("nested rational sample_points", values.get("sample_points"))
    if not samples:
        fail("nested-rational-neighborhood-witness sample_points must be non-empty")
    for point in samples:
        if not lower <= point <= upper:
            fail("nested-rational-neighborhood-witness sample point is outside the inner interval")
        distance = abs(point - center)
        if strict and not distance < radius:
            fail("nested-rational-neighborhood-witness sample point is outside the open ball")
        if not strict and not distance <= radius:
            fail("nested-rational-neighborhood-witness sample point is outside the closed ball")
    endpoint_distance = max(abs(lower - center), abs(upper - center))
    listed_endpoint_distance = require_fraction(
        "nested rational max_endpoint_distance",
        values.get("max_endpoint_distance"),
    )
    if endpoint_distance != listed_endpoint_distance:
        fail("nested-rational-neighborhood-witness max endpoint distance is incorrect")
    if strict and not endpoint_distance < radius:
        fail("nested-rational-neighborhood-witness inner interval is not inside the open ball")
    if not strict and not endpoint_distance <= radius:
        fail("nested-rational-neighborhood-witness inner interval is not inside the closed ball")

    linear = checks["linear-epsilon-delta-rational-witness"]
    if linear["expected_result"] != "sat":
        fail("linear-epsilon-delta-rational-witness must expect sat")
    values = single_witness_values(linear, witnesses)
    slope = require_fraction("linear epsilon-delta slope", values.get("slope"))
    intercept = require_fraction("linear epsilon-delta intercept", values.get("intercept"))
    center = require_fraction("linear epsilon-delta center", values.get("center"))
    center_value = require_fraction("linear epsilon-delta center_value", values.get("center_value"))
    epsilon = require_fraction("linear epsilon-delta epsilon", values.get("epsilon"))
    delta = require_fraction("linear epsilon-delta delta", values.get("delta"))
    samples = require_fraction_vector("linear epsilon-delta sample_points", values.get("sample_points"))
    listed_domain = set(require_fraction_vector("linear epsilon-delta domain_points", values.get("domain_points")))
    if epsilon <= 0 or delta <= 0:
        fail("linear-epsilon-delta-rational-witness epsilon and delta must be positive")
    if linear_fraction_value(slope, intercept, center) != center_value:
        fail("linear-epsilon-delta-rational-witness center_value is incorrect")
    if abs(slope) * delta > epsilon:
        fail("linear-epsilon-delta-rational-witness delta does not satisfy the linear side condition")
    actual_domain = {point for point in samples if abs(point - center) < delta}
    if actual_domain != listed_domain:
        fail("linear-epsilon-delta-rational-witness domain_points are incorrect")
    for point in actual_domain:
        output_distance = abs(linear_fraction_value(slope, intercept, point) - center_value)
        if output_distance >= epsilon:
            fail("linear-epsilon-delta-rational-witness found a finite epsilon violation")

    squeeze = checks["squeeze-polynomial-bound-witness"]
    if squeeze["expected_result"] != "sat":
        fail("squeeze-polynomial-bound-witness must expect sat")
    values = single_witness_values(squeeze, witnesses)
    radius = require_fraction("squeeze radius", values.get("radius"))
    square_bound = require_fraction("squeeze square_bound", values.get("square_bound"))
    cube_bound = require_fraction("squeeze cube_bound", values.get("cube_bound"))
    samples = require_fraction_vector("squeeze sample_points", values.get("sample_points"))
    if radius <= 0:
        fail("squeeze-polynomial-bound-witness radius must be positive")
    if square_bound != radius * radius:
        fail("squeeze-polynomial-bound-witness square_bound must equal radius^2")
    if cube_bound != radius * radius * radius:
        fail("squeeze-polynomial-bound-witness cube_bound must equal radius^3")
    for point in samples:
        if abs(point) > radius:
            fail("squeeze-polynomial-bound-witness sample point is outside the radius")
        if point * point > square_bound:
            fail("squeeze-polynomial-bound-witness square bound fails")
        if abs(point * point * point) > cube_bound:
            fail("squeeze-polynomial-bound-witness cube bound fails")

    bad_delta = checks["bad-linear-delta-rejected"]
    if bad_delta["expected_result"] != "unsat" or bad_delta.get("proof_status") != "checked":
        fail("bad-linear-delta-rejected must be a checked unsat row")
    data = bad_delta.get("data", {})
    slope = require_fraction("bad linear delta slope", data.get("slope"))
    intercept = require_fraction("bad linear delta intercept", data.get("intercept"))
    center = require_fraction("bad linear delta center", data.get("center"))
    epsilon = require_fraction("bad linear delta epsilon", data.get("epsilon"))
    claimed_delta = require_fraction("bad linear delta claimed_delta", data.get("claimed_delta"))
    counterexample = require_fraction("bad linear delta counterexample", data.get("counterexample"))
    domain_distance = require_fraction("bad linear delta domain_distance", data.get("domain_distance"))
    output_distance = require_fraction("bad linear delta output_distance", data.get("output_distance"))
    if epsilon <= 0 or claimed_delta <= 0:
        fail("bad-linear-delta-rejected epsilon and claimed_delta must be positive")
    if abs(counterexample - center) != domain_distance:
        fail("bad-linear-delta-rejected domain_distance is incorrect")
    center_value = linear_fraction_value(slope, intercept, center)
    counterexample_value = linear_fraction_value(slope, intercept, counterexample)
    if abs(counterexample_value - center_value) != output_distance:
        fail("bad-linear-delta-rejected output_distance is incorrect")
    if not domain_distance < claimed_delta:
        fail("bad-linear-delta-rejected counterexample is not inside the claimed delta ball")
    if output_distance < epsilon:
        fail("bad-linear-delta-rejected counterexample unexpectedly satisfies epsilon")
    output_claim = data.get("farkas_output_claim")
    require_string("bad linear delta farkas_output_claim", output_claim)
    if output_claim != "output_distance < epsilon":
        fail("bad-linear-delta-rejected must document the Farkas output claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad linear delta smt2_artifact", smt2_artifact)
    if not (ROOT / smt2_artifact).is_file():
        fail("bad-linear-delta-rejected smt2_artifact is missing")
    regression = data.get("farkas_regression")
    require_string("bad linear delta farkas_regression", regression)
    if "real_analysis_bad_linear_delta_emits_checked_farkas" not in regression:
        fail("bad-linear-delta-rejected must link the Farkas regression")

    horizon = checks["general-real-analysis-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-real-analysis-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-real-analysis-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general real-analysis target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general real-analysis future_checker", data.get("future_checker"))


def require_fraction_sequence(context: str, value: Any) -> list[Fraction]:
    return require_fraction_vector(context, value)


def require_nonnegative_int(context: str, value: Any) -> int:
    number = require_int(context, value)
    if number < 0:
        fail(f"{context} must be nonnegative")
    return number


def validate_sequence_limit_shadow(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    reciprocal = checks["reciprocal-tail-bounded-epsilon"]
    if reciprocal["expected_result"] != "sat":
        fail("reciprocal-tail-bounded-epsilon must expect sat")
    values = single_witness_values(reciprocal, witnesses)
    limit = require_fraction("reciprocal tail limit", values.get("limit"))
    epsilon = require_fraction("reciprocal tail epsilon", values.get("epsilon"))
    start_index = require_nonnegative_int("reciprocal tail start_index", values.get("start_index"))
    horizon = require_nonnegative_int("reciprocal tail horizon", values.get("horizon"))
    sequence = require_fraction_sequence("reciprocal tail values", values.get("values"))
    if epsilon <= 0:
        fail("reciprocal-tail-bounded-epsilon epsilon must be positive")
    if start_index > horizon:
        fail("reciprocal-tail-bounded-epsilon start_index must be <= horizon")
    if len(sequence) != horizon + 1:
        fail("reciprocal-tail-bounded-epsilon values must cover indices 0..horizon")
    for index, value in enumerate(sequence):
        expected_value = Fraction(1, index + 1)
        if value != expected_value:
            fail(f"reciprocal-tail-bounded-epsilon value {index} does not equal 1/(n+1)")
    for value in sequence[start_index : horizon + 1]:
        if abs(value - limit) >= epsilon:
            fail("reciprocal-tail-bounded-epsilon found a finite tail counterexample")
    reciprocal_limit = limit
    reciprocal_sequence = sequence

    counterexample = checks["constant-one-limit-counterexample"]
    if counterexample["expected_result"] != "sat":
        fail("constant-one-limit-counterexample must expect sat")
    values = single_witness_values(counterexample, witnesses)
    limit = require_fraction("constant counterexample limit", values.get("limit"))
    epsilon = require_fraction("constant counterexample epsilon", values.get("epsilon"))
    index = require_nonnegative_int("constant counterexample index", values.get("index"))
    value = require_fraction("constant counterexample value", values.get("value"))
    if epsilon <= 0:
        fail("constant-one-limit-counterexample epsilon must be positive")
    if value != 1:
        fail("constant-one-limit-counterexample documents the fixed constant-one sequence")
    if abs(value - limit) < epsilon:
        fail("constant-one-limit-counterexample is unexpectedly within epsilon")

    monotone = checks["monotone-bounded-prefix"]
    if monotone["expected_result"] != "sat":
        fail("monotone-bounded-prefix must expect sat")
    values = single_witness_values(monotone, witnesses)
    upper_bound = require_fraction("monotone prefix upper_bound", values.get("upper_bound"))
    sequence = require_fraction_sequence("monotone prefix values", values.get("values"))
    if len(sequence) < 2:
        fail("monotone-bounded-prefix requires at least two values")
    for index, value in enumerate(sequence):
        expected_value = Fraction(index, index + 1)
        if value != expected_value:
            fail(f"monotone-bounded-prefix value {index} does not equal n/(n+1)")
        if value >= upper_bound:
            fail("monotone-bounded-prefix value violates the upper bound")
    for left, right in zip(sequence, sequence[1:]):
        if not left < right:
            fail("monotone-bounded-prefix is not strictly increasing")

    geometric = checks["geometric-partial-sum-identity"]
    if geometric["expected_result"] != "sat":
        fail("geometric-partial-sum-identity must expect sat")
    values = single_witness_values(geometric, witnesses)
    ratio = require_fraction("geometric ratio", values.get("ratio"))
    n_value = require_nonnegative_int("geometric n", values.get("n"))
    partial_sum = require_fraction("geometric partial_sum", values.get("partial_sum"))
    closed_form = require_fraction("geometric closed_form", values.get("closed_form"))
    if ratio == 1:
        fail("geometric-partial-sum-identity requires ratio != 1")
    computed_sum = sum((ratio**index for index in range(n_value + 1)), Fraction(0))
    computed_closed = (1 - ratio ** (n_value + 1)) / (1 - ratio)
    if partial_sum != computed_sum:
        fail("geometric-partial-sum-identity partial_sum is incorrect")
    if closed_form != computed_closed:
        fail("geometric-partial-sum-identity closed_form is incorrect")
    if partial_sum != closed_form:
        fail("geometric-partial-sum-identity partial_sum and closed_form differ")

    cauchy = checks["bounded-cauchy-tail-no-counterexample"]
    if cauchy["expected_result"] != "unsat":
        fail("bounded-cauchy-tail-no-counterexample must expect unsat")
    data = cauchy.get("data", {})
    epsilon = require_fraction("bounded cauchy epsilon", data.get("epsilon"))
    sequence = require_fraction_sequence("bounded cauchy values", data.get("values"))
    if epsilon <= 0:
        fail("bounded-cauchy-tail-no-counterexample epsilon must be positive")
    if not sequence:
        fail("bounded-cauchy-tail-no-counterexample values must be nonempty")
    max_pair_distance = Fraction(0)
    for left in sequence:
        for right in sequence:
            distance = abs(left - right)
            if distance > max_pair_distance:
                max_pair_distance = distance
            if distance >= epsilon:
                fail("bounded-cauchy-tail-no-counterexample found a finite pairwise counterexample")
    documented_max = require_fraction(
        "bounded cauchy max_pair_distance",
        data.get("max_pair_distance"),
    )
    if documented_max != max_pair_distance:
        fail("bounded-cauchy-tail-no-counterexample max_pair_distance is wrong")
    documented_pair = require_fraction_vector(
        "bounded cauchy farthest_pair",
        data.get("farthest_pair"),
    )
    if len(documented_pair) != 2:
        fail("bounded-cauchy-tail-no-counterexample farthest_pair must have length 2")
    if abs(documented_pair[0] - documented_pair[1]) != max_pair_distance:
        fail("bounded-cauchy-tail-no-counterexample farthest_pair does not realize max_pair_distance")
    if documented_pair[0] not in sequence or documented_pair[1] not in sequence:
        fail("bounded-cauchy-tail-no-counterexample farthest_pair values must come from the finite tail")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bounded cauchy smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/sequence-limit-shadow-v0/smt2/bounded-cauchy-tail-farkas-conflict.smt2"
    ):
        fail("bounded-cauchy-tail-no-counterexample smt2_artifact must name the checked QF_LRA artifact")
    check_source("bounded cauchy smt2_artifact", smt2_artifact)
    farkas_regression = data.get("farkas_regression")
    require_string("bounded cauchy farkas_regression", farkas_regression)
    if "sequence_limit_bounded_cauchy_tail_artifact_emits_checked_farkas" not in farkas_regression:
        fail("bounded-cauchy-tail-no-counterexample must link the Farkas regression")

    bad_tail = checks["bad-reciprocal-tail-bound-rejected"]
    if bad_tail["expected_result"] != "unsat" or bad_tail.get("proof_status") != "checked":
        fail("bad-reciprocal-tail-bound-rejected must be a checked unsat row")
    data = bad_tail.get("data", {})
    if data.get("source_witness") != "reciprocal-tail":
        fail("bad-reciprocal-tail-bound-rejected must cite the reciprocal-tail source witness")
    claimed_start_index = require_nonnegative_int(
        "bad reciprocal tail claimed_start_index",
        data.get("claimed_start_index"),
    )
    witness_index = require_nonnegative_int(
        "bad reciprocal tail witness_index",
        data.get("witness_index"),
    )
    bad_limit = require_fraction("bad reciprocal tail limit", data.get("limit"))
    bad_epsilon = require_fraction("bad reciprocal tail epsilon", data.get("epsilon"))
    witness_value = require_fraction("bad reciprocal tail witness_value", data.get("witness_value"))
    tail_distance = require_fraction("bad reciprocal tail tail_distance", data.get("tail_distance"))
    tail_excess = require_fraction("bad reciprocal tail tail_excess", data.get("tail_excess"))
    if bad_epsilon <= 0:
        fail("bad-reciprocal-tail-bound-rejected epsilon must be positive")
    if bad_limit != reciprocal_limit:
        fail("bad-reciprocal-tail-bound-rejected limit must match the reciprocal-tail witness")
    if claimed_start_index > witness_index:
        fail("bad-reciprocal-tail-bound-rejected witness_index must be inside the claimed tail")
    if witness_index >= len(reciprocal_sequence):
        fail("bad-reciprocal-tail-bound-rejected witness_index is outside the source sequence")
    if reciprocal_sequence[witness_index] != witness_value:
        fail("bad-reciprocal-tail-bound-rejected witness_value does not match replay")
    if abs(witness_value - bad_limit) != tail_distance:
        fail("bad-reciprocal-tail-bound-rejected tail_distance does not match replay")
    if tail_distance - bad_epsilon != tail_excess:
        fail("bad-reciprocal-tail-bound-rejected tail_excess is incorrect")
    if tail_excess <= 0:
        fail("bad-reciprocal-tail-bound-rejected must document a positive epsilon violation")
    tail_claim = data.get("farkas_tail_claim")
    require_string("bad reciprocal tail farkas_tail_claim", tail_claim)
    if tail_claim != "tail_distance < epsilon":
        fail("bad-reciprocal-tail-bound-rejected must document the Farkas tail claim")
    smt2_artifact = data.get("smt2_artifact")
    require_string("bad reciprocal tail smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/sequence-limit-shadow-v0/smt2/bad-reciprocal-tail-bound-farkas-conflict.smt2"
    ):
        fail("bad-reciprocal-tail-bound-rejected smt2_artifact must name the checked QF_LRA artifact")
    check_source("bad reciprocal tail smt2_artifact", smt2_artifact)
    farkas_regression = data.get("farkas_regression")
    require_string("bad reciprocal tail farkas_regression", farkas_regression)
    if "sequence_limit_bad_reciprocal_tail_bound_artifact_emits_checked_farkas" not in farkas_regression:
        fail("bad-reciprocal-tail-bound-rejected must link the Farkas regression")
    certificate = data.get("certificate")
    require_string("bad reciprocal tail certificate", certificate)
    if "UnsatFarkas" not in certificate or "Evidence::check" not in certificate:
        fail("bad-reciprocal-tail-bound-rejected certificate must document checked Farkas evidence")

    horizon = checks["general-limit-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-limit-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-limit-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general limit target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general limit future_checker", data.get("future_checker"))


def validate_bounded_monotone_sequence(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    monotone = checks["monotone-upper-bound-prefix"]
    if monotone["expected_result"] != "sat":
        fail("monotone-upper-bound-prefix must expect sat")
    values = single_witness_values(monotone, witnesses)
    upper_bound = require_fraction("bounded monotone upper_bound", values.get("upper_bound"))
    sequence = require_fraction_sequence("bounded monotone values", values.get("values"))
    if len(sequence) < 2:
        fail("monotone-upper-bound-prefix requires at least two values")
    for index, value in enumerate(sequence):
        expected_value = Fraction(index, index + 1)
        if value != expected_value:
            fail(f"monotone-upper-bound-prefix value {index} does not equal n/(n+1)")
        if value >= upper_bound:
            fail("monotone-upper-bound-prefix value violates the upper bound")
    for left, right in zip(sequence, sequence[1:]):
        if not left < right:
            fail("monotone-upper-bound-prefix is not strictly increasing")

    supremum = checks["finite-prefix-supremum"]
    if supremum["expected_result"] != "sat":
        fail("finite-prefix-supremum must expect sat")
    values = single_witness_values(supremum, witnesses)
    prefix = require_fraction_sequence("finite prefix supremum values", values.get("values"))
    documented_supremum = require_fraction(
        "finite prefix supremum prefix_supremum",
        values.get("prefix_supremum"),
    )
    argmax_index = require_nonnegative_int("finite prefix supremum argmax_index", values.get("argmax_index"))
    if argmax_index >= len(prefix):
        fail("finite-prefix-supremum argmax_index is outside the prefix")
    actual_supremum = max(prefix)
    if documented_supremum != actual_supremum:
        fail("finite-prefix-supremum prefix_supremum does not match the finite maximum")
    if prefix[argmax_index] != actual_supremum:
        fail("finite-prefix-supremum argmax_index does not realize the maximum")

    tail = checks["tail-gap-below-epsilon"]
    if tail["expected_result"] != "sat":
        fail("tail-gap-below-epsilon must expect sat")
    values = single_witness_values(tail, witnesses)
    limit = require_fraction("tail gap limit", values.get("limit"))
    epsilon = require_fraction("tail gap epsilon", values.get("epsilon"))
    start_index = require_nonnegative_int("tail gap start_index", values.get("start_index"))
    horizon = require_nonnegative_int("tail gap horizon", values.get("horizon"))
    tail_sequence = require_fraction_sequence("tail gap values", values.get("values"))
    documented_max_gap = require_fraction("tail gap max_tail_gap", values.get("max_tail_gap"))
    if epsilon <= 0:
        fail("tail-gap-below-epsilon epsilon must be positive")
    if start_index > horizon:
        fail("tail-gap-below-epsilon start_index must be <= horizon")
    if len(tail_sequence) != horizon + 1:
        fail("tail-gap-below-epsilon values must cover indices 0..horizon")
    for index, value in enumerate(tail_sequence):
        expected_value = Fraction(index, index + 1)
        if value != expected_value:
            fail(f"tail-gap-below-epsilon value {index} does not equal n/(n+1)")
    max_gap = max((abs(limit - value) for value in tail_sequence[start_index : horizon + 1]), default=Fraction(0))
    if documented_max_gap != max_gap:
        fail("tail-gap-below-epsilon max_tail_gap does not match replay")
    if max_gap >= epsilon:
        fail("tail-gap-below-epsilon found a finite tail gap outside epsilon")

    bad = checks["bad-upper-bound-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-upper-bound-rejected must be a replay-only unsat row")
    if bad.get("validation") != "finite_bad_monotone_upper_bound_refutation":
        fail("bad-upper-bound-rejected must use finite_bad_monotone_upper_bound_refutation")
    data = bad.get("data", {})
    if data.get("source_witness") != "rational-monotone-prefix":
        fail("bad-upper-bound-rejected must cite the rational-monotone-prefix source witness")
    for checked_key in ("smt2_artifact", "farkas_regression", "certificate"):
        if checked_key in data:
            fail("bad-upper-bound-rejected must leave checked evidence to qf-lra-bad-upper-bound")
    claimed_upper_bound = require_fraction(
        "bad upper bound claimed_upper_bound",
        data.get("claimed_upper_bound"),
    )
    witness_index = require_nonnegative_int("bad upper bound witness_index", data.get("witness_index"))
    witness_value = require_fraction("bad upper bound witness_value", data.get("witness_value"))
    if witness_index >= len(sequence):
        fail("bad-upper-bound-rejected witness_index is outside the source prefix")
    if sequence[witness_index] != witness_value:
        fail("bad-upper-bound-rejected witness_value does not match replay")
    if witness_value <= claimed_upper_bound:
        fail("bad-upper-bound-rejected witness must violate the claimed upper bound")
    notes = bad.get("notes")
    require_string("bad upper bound notes", notes)
    if "qf-lra-bad-upper-bound" not in notes:
        fail("bad-upper-bound-rejected notes must point to the checked qf-lra row")

    qf_bad = checks["qf-lra-bad-upper-bound"]
    if qf_bad["expected_result"] != "unsat" or qf_bad.get("proof_status") != "checked":
        fail("qf-lra-bad-upper-bound must be a checked unsat row")
    if qf_bad.get("validation") != "qf_lra_bounded_monotone_sequence_bad_upper_bound_refutation":
        fail("qf-lra-bad-upper-bound must use its qf_lra validation")
    qf_data = qf_bad.get("data", {})
    if qf_data.get("source_replay_row") != "bad-upper-bound-rejected":
        fail("qf-lra-bad-upper-bound must cite the source replay row")
    qf_claimed_upper_bound = require_fraction(
        "qf bad upper bound claimed_upper_bound",
        qf_data.get("claimed_upper_bound"),
    )
    qf_witness_value = require_fraction(
        "qf bad upper bound witness_value",
        qf_data.get("witness_value"),
    )
    if qf_claimed_upper_bound != claimed_upper_bound:
        fail("qf-lra-bad-upper-bound claimed_upper_bound must match the replay row")
    if qf_witness_value != witness_value:
        fail("qf-lra-bad-upper-bound witness_value must match the replay row")
    if (
        qf_data.get("farkas_conflict")
        != "witness_value = 6/7 and claimed_upper_bound = 5/6 and witness_value <= claimed_upper_bound"
    ):
        fail("qf-lra-bad-upper-bound must document the expected Farkas conflict")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("bad upper bound smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/bounded-monotone-sequence-v0/smt2/bad-upper-bound-farkas-conflict.smt2"
    ):
        fail("qf-lra-bad-upper-bound smt2_artifact must name the checked QF_LRA artifact")
    check_source("bad upper bound smt2_artifact", smt2_artifact)
    farkas_regression = qf_data.get("farkas_regression")
    require_string("bad upper bound farkas_regression", farkas_regression)
    if "bounded_monotone_sequence_bad_upper_bound_artifact_emits_checked_farkas" not in farkas_regression:
        fail("qf-lra-bad-upper-bound must link the LRA route regression")
    certificate = qf_data.get("certificate")
    require_string("bad upper bound certificate", certificate)
    if "UnsatFarkas" not in certificate or "independently checks" not in certificate:
        fail("qf-lra-bad-upper-bound certificate must document checked Farkas evidence")

    bad_tail = checks["bad-tail-gap-rejected"]
    if bad_tail["expected_result"] != "unsat" or bad_tail.get("proof_status") != "replay-only":
        fail("bad-tail-gap-rejected must be a replay-only unsat row")
    if bad_tail.get("validation") != "finite_bad_tail_gap_refutation":
        fail("bad-tail-gap-rejected must use finite_bad_tail_gap_refutation")
    data = bad_tail.get("data", {})
    if data.get("source_witness") != "bounded-tail-gap":
        fail("bad-tail-gap-rejected must cite the bounded-tail-gap source witness")
    for checked_key in ("smt2_artifact", "farkas_regression", "certificate"):
        if checked_key in data:
            fail("bad-tail-gap-rejected must leave checked evidence to qf-lra-bad-tail-gap")
    claimed_start_index = require_nonnegative_int(
        "bad tail gap claimed_start_index",
        data.get("claimed_start_index"),
    )
    tail_witness_index = require_nonnegative_int(
        "bad tail gap witness_index",
        data.get("witness_index"),
    )
    tail_witness_value = require_fraction("bad tail gap witness_value", data.get("witness_value"))
    bad_limit = require_fraction("bad tail gap limit", data.get("limit"))
    bad_epsilon = require_fraction("bad tail gap epsilon", data.get("epsilon"))
    tail_gap = require_fraction("bad tail gap tail_gap", data.get("tail_gap"))
    tail_excess = require_fraction("bad tail gap tail_excess", data.get("tail_excess"))
    if bad_limit != limit:
        fail("bad-tail-gap-rejected limit must match the tail-gap witness")
    if bad_epsilon != epsilon:
        fail("bad-tail-gap-rejected epsilon must match the tail-gap witness")
    if claimed_start_index >= start_index:
        fail("bad-tail-gap-rejected must document a stricter earlier tail claim")
    if tail_witness_index < claimed_start_index:
        fail("bad-tail-gap-rejected witness_index must be inside the claimed tail")
    if tail_witness_index >= len(tail_sequence):
        fail("bad-tail-gap-rejected witness_index is outside the source sequence")
    if tail_sequence[tail_witness_index] != tail_witness_value:
        fail("bad-tail-gap-rejected witness_value does not match replay")
    if abs(bad_limit - tail_witness_value) != tail_gap:
        fail("bad-tail-gap-rejected tail_gap does not match replay")
    if tail_gap - bad_epsilon != tail_excess:
        fail("bad-tail-gap-rejected tail_excess is incorrect")
    if tail_excess <= 0:
        fail("bad-tail-gap-rejected must document a positive epsilon violation")
    notes = bad_tail.get("notes")
    require_string("bad tail gap notes", notes)
    if "qf-lra-bad-tail-gap" not in notes:
        fail("bad-tail-gap-rejected notes must point to the checked qf-lra row")

    qf_bad_tail = checks["qf-lra-bad-tail-gap"]
    if qf_bad_tail["expected_result"] != "unsat" or qf_bad_tail.get("proof_status") != "checked":
        fail("qf-lra-bad-tail-gap must be a checked unsat row")
    if qf_bad_tail.get("validation") != "qf_lra_bounded_monotone_sequence_bad_tail_gap_refutation":
        fail("qf-lra-bad-tail-gap must use its qf_lra validation")
    qf_data = qf_bad_tail.get("data", {})
    if qf_data.get("source_replay_row") != "bad-tail-gap-rejected":
        fail("qf-lra-bad-tail-gap must cite the source replay row")
    qf_tail_gap = require_fraction("qf bad tail gap tail_gap", qf_data.get("tail_gap"))
    qf_epsilon = require_fraction("qf bad tail gap epsilon", qf_data.get("epsilon"))
    qf_tail_excess = require_fraction(
        "qf bad tail gap tail_excess",
        qf_data.get("tail_excess"),
    )
    if qf_tail_gap != tail_gap:
        fail("qf-lra-bad-tail-gap tail_gap must match the replay row")
    if qf_epsilon != bad_epsilon:
        fail("qf-lra-bad-tail-gap epsilon must match the replay row")
    if qf_tail_excess != tail_excess:
        fail("qf-lra-bad-tail-gap tail_excess must match the replay row")
    if qf_data.get("farkas_conflict") != "tail_excess = 1/12 and tail_excess <= 0":
        fail("qf-lra-bad-tail-gap must document the expected Farkas conflict")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("bad tail gap smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/bounded-monotone-sequence-v0/smt2/bad-tail-gap-farkas-conflict.smt2"
    ):
        fail("qf-lra-bad-tail-gap smt2_artifact must name the checked QF_LRA artifact")
    check_source("bad tail gap smt2_artifact", smt2_artifact)
    farkas_regression = qf_data.get("farkas_regression")
    require_string("bad tail gap farkas_regression", farkas_regression)
    if "bounded_monotone_sequence_bad_tail_gap_artifact_emits_checked_farkas" not in farkas_regression:
        fail("qf-lra-bad-tail-gap must link the LRA route regression")
    certificate = qf_data.get("certificate")
    require_string("bad tail gap certificate", certificate)
    if "UnsatFarkas" not in certificate or "independently checks" not in certificate:
        fail("qf-lra-bad-tail-gap certificate must document checked Farkas evidence")

    horizon = checks["monotone-convergence-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("monotone-convergence-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("monotone-convergence-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("monotone convergence target_theorem_shape", data.get("target_theorem_shape"))
    require_string("monotone convergence future_checker", data.get("future_checker"))


def validate_finite_recurrence_prefix(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    fibonacci = checks["fibonacci-prefix-replay"]
    if fibonacci["expected_result"] != "sat":
        fail("fibonacci-prefix-replay must expect sat")
    values = single_witness_values(fibonacci, witnesses)
    initial = require_fraction_vector("Fibonacci initial", values.get("initial"))
    fibonacci_sequence = require_fraction_sequence("Fibonacci values", values.get("values"))
    if initial != [Fraction(0), Fraction(1)]:
        fail("fibonacci-prefix-replay must use F_0 = 0 and F_1 = 1")
    if len(fibonacci_sequence) < 3:
        fail("fibonacci-prefix-replay requires at least three values")
    if fibonacci_sequence[:2] != initial:
        fail("fibonacci-prefix-replay values must start with the initial pair")
    for index in range(2, len(fibonacci_sequence)):
        expected_value = fibonacci_sequence[index - 1] + fibonacci_sequence[index - 2]
        if fibonacci_sequence[index] != expected_value:
            fail(f"fibonacci-prefix-replay value {index} violates the recurrence")

    affine = checks["affine-recurrence-prefix-replay"]
    if affine["expected_result"] != "sat":
        fail("affine-recurrence-prefix-replay must expect sat")
    values = single_witness_values(affine, witnesses)
    affine_initial = require_fraction("affine recurrence initial", values.get("initial"))
    multiplier = require_fraction("affine recurrence multiplier", values.get("multiplier"))
    increment = require_fraction("affine recurrence increment", values.get("increment"))
    steps = require_nonnegative_int("affine recurrence steps", values.get("steps"))
    affine_values = require_fraction_sequence("affine recurrence values", values.get("values"))
    if len(affine_values) != steps + 1:
        fail("affine-recurrence-prefix-replay values must contain steps + 1 entries")
    if affine_values[0] != affine_initial:
        fail("affine-recurrence-prefix-replay values must start at the initial value")
    for index in range(steps):
        expected_value = multiplier * affine_values[index] + increment
        if affine_values[index + 1] != expected_value:
            fail(f"affine-recurrence-prefix-replay transition {index}->{index + 1} is incorrect")

    companion = checks["companion-matrix-prefix-replay"]
    if companion["expected_result"] != "sat":
        fail("companion-matrix-prefix-replay must expect sat")
    values = single_witness_values(companion, witnesses)
    matrix = require_fraction_matrix("companion matrix", values.get("matrix"))
    states = require_fraction_matrix("companion states", values.get("states"))
    steps = require_nonnegative_int("companion steps", values.get("steps"))
    if len(matrix) != 2 or any(len(row) != 2 for row in matrix):
        fail("companion-matrix-prefix-replay requires a 2x2 matrix")
    if len(states) != steps + 1:
        fail("companion-matrix-prefix-replay states must contain steps + 1 entries")
    for index, state in enumerate(states):
        if len(state) != 2:
            fail(f"companion-matrix-prefix-replay state {index} must have length 2")
    for index in range(steps):
        require_mat_vec_shape("companion matrix step", matrix, states[index])
        if mat_vec(matrix, states[index]) != states[index + 1]:
            fail(f"companion-matrix-prefix-replay transition {index}->{index + 1} is incorrect")

    bad = checks["bad-fibonacci-value-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-fibonacci-value-rejected must be a replay-only unsat row")
    if bad.get("validation") != "finite_bad_recurrence_value_refutation":
        fail("bad-fibonacci-value-rejected must use finite_bad_recurrence_value_refutation")
    data = bad.get("data", {})
    if data.get("source_witness") != "fibonacci-prefix":
        fail("bad-fibonacci-value-rejected must cite the fibonacci-prefix source witness")
    for checked_key in ("smt2_artifact", "farkas_regression", "certificate"):
        if checked_key in data:
            fail("bad-fibonacci-value-rejected must leave checked evidence to qf-lra-bad-fibonacci-value")
    witness_index = require_nonnegative_int("bad Fibonacci witness_index", data.get("witness_index"))
    computed_value = require_fraction("bad Fibonacci computed_value", data.get("computed_value"))
    claimed_value = require_fraction("bad Fibonacci claimed_value", data.get("claimed_value"))
    if witness_index >= len(fibonacci_sequence):
        fail("bad-fibonacci-value-rejected witness_index is outside the source prefix")
    if fibonacci_sequence[witness_index] != computed_value:
        fail("bad-fibonacci-value-rejected computed_value does not match replay")
    if claimed_value == computed_value:
        fail("bad-fibonacci-value-rejected claimed value unexpectedly matches replay")
    notes = bad.get("notes")
    require_string("bad Fibonacci notes", notes)
    if "qf-lra-bad-fibonacci-value" not in notes:
        fail("bad-fibonacci-value-rejected notes must point to the checked qf-lra row")

    qf_bad = checks["qf-lra-bad-fibonacci-value"]
    if qf_bad["expected_result"] != "unsat" or qf_bad.get("proof_status") != "checked":
        fail("qf-lra-bad-fibonacci-value must be a checked unsat row")
    if qf_bad.get("validation") != "qf_lra_finite_recurrence_prefix_bad_value_refutation":
        fail("qf-lra-bad-fibonacci-value must use its qf_lra validation")
    qf_data = qf_bad.get("data", {})
    if qf_data.get("source_replay_row") != "bad-fibonacci-value-rejected":
        fail("qf-lra-bad-fibonacci-value must cite the source replay row")
    qf_computed_value = require_fraction("qf bad Fibonacci computed_value", qf_data.get("computed_value"))
    qf_claimed_value = require_fraction("qf bad Fibonacci claimed_value", qf_data.get("claimed_value"))
    if qf_computed_value != computed_value:
        fail("qf-lra-bad-fibonacci-value computed_value must match the replay row")
    if qf_claimed_value != claimed_value:
        fail("qf-lra-bad-fibonacci-value claimed_value must match the replay row")
    if qf_data.get("farkas_conflict") != "f6 = 8 and f6 = 9":
        fail("qf-lra-bad-fibonacci-value must document the expected Farkas conflict")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("bad Fibonacci smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/finite-recurrence-prefix-v0/smt2/bad-fibonacci-value-farkas-conflict.smt2"
    ):
        fail("qf-lra-bad-fibonacci-value smt2_artifact must name the checked QF_LRA artifact")
    check_source("bad Fibonacci smt2_artifact", smt2_artifact)
    farkas_regression = qf_data.get("farkas_regression")
    require_string("bad Fibonacci farkas_regression", farkas_regression)
    if "finite_recurrence_prefix_bad_value_artifact_emits_checked_farkas" not in farkas_regression:
        fail("qf-lra-bad-fibonacci-value must link the LRA route regression")
    certificate = qf_data.get("certificate")
    require_string("bad Fibonacci certificate", certificate)
    if "UnsatFarkas" not in certificate or "independently checks" not in certificate:
        fail("qf-lra-bad-fibonacci-value certificate must document checked Farkas evidence")

    bad_affine = checks["bad-affine-step-rejected"]
    if bad_affine["expected_result"] != "unsat" or bad_affine.get("proof_status") != "replay-only":
        fail("bad-affine-step-rejected must be a replay-only unsat row")
    if bad_affine.get("validation") != "finite_bad_affine_step_refutation":
        fail("bad-affine-step-rejected must use finite_bad_affine_step_refutation")
    data = bad_affine.get("data", {})
    if data.get("source_witness") != "affine-plus-one-prefix":
        fail("bad-affine-step-rejected must cite the affine-plus-one-prefix source witness")
    for checked_key in ("smt2_artifact", "farkas_regression", "certificate"):
        if checked_key in data:
            fail("bad-affine-step-rejected must leave checked evidence to qf-lra-bad-affine-step")
    step_index = require_nonnegative_int("bad affine step_index", data.get("step_index"))
    previous_value = require_fraction("bad affine previous_value", data.get("previous_value"))
    bad_multiplier = require_fraction("bad affine multiplier", data.get("multiplier"))
    bad_increment = require_fraction("bad affine increment", data.get("increment"))
    computed_next = require_fraction("bad affine computed_next", data.get("computed_next"))
    claimed_next = require_fraction("bad affine claimed_next", data.get("claimed_next"))
    transition_residual = require_fraction(
        "bad affine transition_residual",
        data.get("transition_residual"),
    )
    if bad_multiplier != multiplier:
        fail("bad-affine-step-rejected multiplier must match the affine witness")
    if bad_increment != increment:
        fail("bad-affine-step-rejected increment must match the affine witness")
    if step_index >= steps:
        fail("bad-affine-step-rejected step_index is outside the affine prefix")
    if affine_values[step_index] != previous_value:
        fail("bad-affine-step-rejected previous_value does not match replay")
    if affine_values[step_index + 1] != computed_next:
        fail("bad-affine-step-rejected computed_next does not match replay")
    if multiplier * previous_value + increment != computed_next:
        fail("bad-affine-step-rejected computed_next does not match the affine transition")
    if computed_next - claimed_next != transition_residual:
        fail("bad-affine-step-rejected transition_residual is incorrect")
    if transition_residual <= 0:
        fail("bad-affine-step-rejected must document a positive transition residual")
    notes = bad_affine.get("notes")
    require_string("bad affine step notes", notes)
    if "qf-lra-bad-affine-step" not in notes:
        fail("bad-affine-step-rejected notes must point to the checked qf-lra row")

    qf_bad_affine = checks["qf-lra-bad-affine-step"]
    if qf_bad_affine["expected_result"] != "unsat" or qf_bad_affine.get("proof_status") != "checked":
        fail("qf-lra-bad-affine-step must be a checked unsat row")
    if qf_bad_affine.get("validation") != "qf_lra_finite_recurrence_prefix_bad_affine_step_refutation":
        fail("qf-lra-bad-affine-step must use its qf_lra validation")
    qf_data = qf_bad_affine.get("data", {})
    if qf_data.get("source_replay_row") != "bad-affine-step-rejected":
        fail("qf-lra-bad-affine-step must cite the source replay row")
    qf_computed_next = require_fraction("qf bad affine computed_next", qf_data.get("computed_next"))
    qf_claimed_next = require_fraction("qf bad affine claimed_next", qf_data.get("claimed_next"))
    qf_transition_residual = require_fraction(
        "qf bad affine transition_residual",
        qf_data.get("transition_residual"),
    )
    if qf_computed_next != computed_next:
        fail("qf-lra-bad-affine-step computed_next must match the replay row")
    if qf_claimed_next != claimed_next:
        fail("qf-lra-bad-affine-step claimed_next must match the replay row")
    if qf_transition_residual != transition_residual:
        fail("qf-lra-bad-affine-step transition_residual must match the replay row")
    if qf_data.get("farkas_conflict") != "transition_residual = 1 and transition_residual <= 0":
        fail("qf-lra-bad-affine-step must document the expected Farkas conflict")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("bad affine step smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/finite-recurrence-prefix-v0/smt2/bad-affine-step-farkas-conflict.smt2"
    ):
        fail("qf-lra-bad-affine-step smt2_artifact must name the checked QF_LRA artifact")
    check_source("bad affine step smt2_artifact", smt2_artifact)
    farkas_regression = qf_data.get("farkas_regression")
    require_string("bad affine step farkas_regression", farkas_regression)
    if "finite_recurrence_prefix_bad_affine_step_artifact_emits_checked_farkas" not in farkas_regression:
        fail("qf-lra-bad-affine-step must link the LRA route regression")
    certificate = qf_data.get("certificate")
    require_string("bad affine step certificate", certificate)
    if "UnsatFarkas" not in certificate or "independently checks" not in certificate:
        fail("qf-lra-bad-affine-step certificate must document checked Farkas evidence")

    horizon = checks["general-recurrence-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-recurrence-theory-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-recurrence-theory-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general recurrence target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general recurrence future_checker", data.get("future_checker"))


def validate_finite_root_finding(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    bisection = checks["bisection-bracket-replay"]
    if bisection["expected_result"] != "sat":
        fail("bisection-bracket-replay must expect sat")
    values = single_witness_values(bisection, witnesses)
    polynomial = require_polynomial("bisection polynomial", values.get("polynomial"))
    left = require_fraction("bisection left", values.get("left"))
    right = require_fraction("bisection right", values.get("right"))
    midpoint = require_fraction("bisection midpoint", values.get("midpoint"))
    f_left = require_fraction("bisection f_left", values.get("f_left"))
    f_midpoint = require_fraction("bisection f_midpoint", values.get("f_midpoint"))
    f_right = require_fraction("bisection f_right", values.get("f_right"))
    selected_interval = require_fraction_vector(
        "bisection selected_interval",
        values.get("selected_interval"),
    )
    initial_width = require_fraction("bisection initial_width", values.get("initial_width"))
    selected_width = require_fraction("bisection selected_width", values.get("selected_width"))
    if not left < right:
        fail("bisection-bracket-replay requires left < right")
    if midpoint != (left + right) / 2:
        fail("bisection-bracket-replay midpoint is incorrect")
    if f_left != polynomial_eval(polynomial, left):
        fail("bisection-bracket-replay f_left is incorrect")
    if f_midpoint != polynomial_eval(polynomial, midpoint):
        fail("bisection-bracket-replay f_midpoint is incorrect")
    if f_right != polynomial_eval(polynomial, right):
        fail("bisection-bracket-replay f_right is incorrect")
    if f_left * f_right >= 0:
        fail("bisection-bracket-replay initial interval must have a strict sign change")
    if len(selected_interval) != 2:
        fail("bisection-bracket-replay selected_interval must have two endpoints")
    if f_left * f_midpoint < 0:
        expected_interval = [left, midpoint]
    elif f_midpoint * f_right < 0:
        expected_interval = [midpoint, right]
    else:
        fail("bisection-bracket-replay midpoint does not choose a strict sign-changing subinterval")
    if selected_interval != expected_interval:
        fail("bisection-bracket-replay selected_interval does not match the sign-changing half")
    if initial_width != right - left:
        fail("bisection-bracket-replay initial_width is incorrect")
    if selected_width != selected_interval[1] - selected_interval[0]:
        fail("bisection-bracket-replay selected_width is incorrect")
    if selected_width * 2 != initial_width:
        fail("bisection-bracket-replay selected interval must halve the width")

    newton = checks["newton-step-replay"]
    if newton["expected_result"] != "sat":
        fail("newton-step-replay must expect sat")
    values = single_witness_values(newton, witnesses)
    newton_polynomial = require_polynomial("Newton polynomial", values.get("polynomial"))
    derivative = require_polynomial("Newton derivative", values.get("derivative"))
    current = require_fraction("Newton current", values.get("current"))
    f_current = require_fraction("Newton f_current", values.get("f_current"))
    derivative_value = require_fraction("Newton derivative_value", values.get("derivative_value"))
    next_value = require_fraction("Newton next", values.get("next"))
    f_next = require_fraction("Newton f_next", values.get("f_next"))
    if newton_polynomial != polynomial:
        fail("newton-step-replay must use the same polynomial as the bisection row")
    if polynomial_derivative(newton_polynomial) != derivative:
        fail("newton-step-replay derivative polynomial is incorrect")
    if f_current != polynomial_eval(newton_polynomial, current):
        fail("newton-step-replay f_current is incorrect")
    if derivative_value != polynomial_eval(derivative, current):
        fail("newton-step-replay derivative_value is incorrect")
    if derivative_value == 0:
        fail("newton-step-replay derivative_value must be nonzero")
    computed_next = current - f_current / derivative_value
    if next_value != computed_next:
        fail("newton-step-replay next iterate is incorrect")
    if f_next != polynomial_eval(newton_polynomial, next_value):
        fail("newton-step-replay f_next is incorrect")

    residual = checks["residual-decrease-witness"]
    if residual["expected_result"] != "sat":
        fail("residual-decrease-witness must expect sat")
    values = single_witness_values(residual, witnesses)
    residual_before = require_fraction("Newton residual_before", values.get("residual_before"))
    residual_after = require_fraction("Newton residual_after", values.get("residual_after"))
    if residual_before != abs(f_current):
        fail("residual-decrease-witness residual_before is incorrect")
    if residual_after != abs(f_next):
        fail("residual-decrease-witness residual_after is incorrect")
    if not residual_after < residual_before:
        fail("residual-decrease-witness must strictly decrease the residual")

    bad = checks["bad-newton-step-rejected"]
    if bad["expected_result"] != "unsat" or bad.get("proof_status") != "replay-only":
        fail("bad-newton-step-rejected must be a replay-only unsat row")
    if bad.get("validation") != "finite_bad_newton_step_refutation":
        fail("bad-newton-step-rejected validation is incorrect")
    data = bad.get("data", {})
    if data.get("source_witness") != "sqrt-two-newton-step":
        fail("bad-newton-step-rejected must cite the sqrt-two-newton-step source witness")
    computed = require_fraction("bad Newton computed_next", data.get("computed_next"))
    claimed = require_fraction("bad Newton claimed_next", data.get("claimed_next"))
    if computed != next_value:
        fail("bad-newton-step-rejected computed_next does not match replay")
    if claimed == computed:
        fail("bad-newton-step-rejected claimed next unexpectedly matches replay")
    for forbidden in ("smt2_artifact", "farkas_regression", "certificate"):
        if forbidden in data:
            fail("bad-newton-step-rejected must leave checked evidence to qf-lra-bad-newton-step")
    notes = bad.get("notes")
    require_string("bad Newton notes", notes)
    if "qf-lra-bad-newton-step" not in notes:
        fail("bad-newton-step-rejected notes must point to the checked qf-lra row")

    bad_qf = checks["qf-lra-bad-newton-step"]
    if bad_qf["expected_result"] != "unsat" or bad_qf.get("proof_status") != "checked":
        fail("qf-lra-bad-newton-step must be a checked unsat row")
    if bad_qf.get("validation") != "qf_lra_finite_root_finding_bad_newton_step_refutation":
        fail("qf-lra-bad-newton-step validation is incorrect")
    data = bad_qf.get("data", {})
    if data.get("source_replay_row") != "bad-newton-step-rejected":
        fail("qf-lra-bad-newton-step must cite bad-newton-step-rejected as source_replay_row")
    qf_computed = require_fraction("qf-lra bad Newton computed_next", data.get("computed_next"))
    qf_claimed = require_fraction("qf-lra bad Newton claimed_next", data.get("claimed_next"))
    if qf_computed != computed:
        fail("qf-lra-bad-newton-step computed_next must match replay")
    if qf_claimed != claimed:
        fail("qf-lra-bad-newton-step claimed_next must match replay")
    if qf_computed == qf_claimed:
        fail("qf-lra-bad-newton-step must be linearly contradictory")
    farkas_conflict = data.get("farkas_conflict")
    require_string("qf-lra bad Newton farkas_conflict", farkas_conflict)
    if farkas_conflict != "newton_next = 17/12 and newton_next = 4/3":
        fail("qf-lra-bad-newton-step must document the fixed equality conflict")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-lra bad Newton smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/finite-root-finding-v0/smt2/bad-newton-step-farkas-conflict.smt2":
        fail("qf-lra-bad-newton-step smt2_artifact must name the checked QF_LRA artifact")
    check_source("qf-lra bad Newton smt2_artifact", smt2_artifact)
    regression = data.get("farkas_regression")
    require_string("qf-lra bad Newton farkas_regression", regression)
    if "finite_root_finding_bad_newton_step_artifact_emits_checked_farkas" not in regression:
        fail("qf-lra-bad-newton-step must link the LRA route regression")
    certificate = data.get("certificate")
    require_string("qf-lra bad Newton certificate", certificate)
    if "UnsatFarkas" not in certificate or "independently checks" not in certificate:
        fail("qf-lra-bad-newton-step certificate must document checked Farkas evidence")

    bad_width = checks["bad-bisection-width-rejected"]
    if bad_width["expected_result"] != "unsat" or bad_width.get("proof_status") != "replay-only":
        fail("bad-bisection-width-rejected must be a replay-only unsat row")
    if bad_width.get("validation") != "finite_bad_bisection_width_refutation":
        fail("bad-bisection-width-rejected validation is incorrect")
    data = bad_width.get("data", {})
    if data.get("source_witness") != "sqrt-two-bisection-step":
        fail("bad-bisection-width-rejected must cite the sqrt-two-bisection-step source witness")
    bad_selected_interval = require_fraction_vector(
        "bad bisection selected_interval",
        data.get("selected_interval"),
    )
    computed_width = require_fraction("bad bisection computed_width", data.get("computed_width"))
    claimed_width = require_fraction("bad bisection claimed_width", data.get("claimed_width"))
    width_excess = require_fraction("bad bisection width_excess", data.get("width_excess"))
    if bad_selected_interval != selected_interval:
        fail("bad-bisection-width-rejected selected_interval must match replay")
    if computed_width != selected_width:
        fail("bad-bisection-width-rejected computed_width must match replay")
    if computed_width - claimed_width != width_excess:
        fail("bad-bisection-width-rejected width_excess is incorrect")
    if width_excess <= 0:
        fail("bad-bisection-width-rejected must document a positive width excess")
    for forbidden in ("smt2_artifact", "farkas_regression", "certificate"):
        if forbidden in data:
            fail("bad-bisection-width-rejected must leave checked evidence to qf-lra-bad-bisection-width")
    notes = bad_width.get("notes")
    require_string("bad bisection width notes", notes)
    if "qf-lra-bad-bisection-width" not in notes:
        fail("bad-bisection-width-rejected notes must point to the checked qf-lra row")

    bad_width_qf = checks["qf-lra-bad-bisection-width"]
    if bad_width_qf["expected_result"] != "unsat" or bad_width_qf.get("proof_status") != "checked":
        fail("qf-lra-bad-bisection-width must be a checked unsat row")
    if bad_width_qf.get("validation") != "qf_lra_finite_root_finding_bad_bisection_width_refutation":
        fail("qf-lra-bad-bisection-width validation is incorrect")
    data = bad_width_qf.get("data", {})
    if data.get("source_replay_row") != "bad-bisection-width-rejected":
        fail("qf-lra-bad-bisection-width must cite bad-bisection-width-rejected as source_replay_row")
    qf_computed_width = require_fraction(
        "qf-lra bad bisection computed_width",
        data.get("computed_width"),
    )
    qf_claimed_width = require_fraction(
        "qf-lra bad bisection claimed_width",
        data.get("claimed_width"),
    )
    qf_width_excess = require_fraction(
        "qf-lra bad bisection width_excess",
        data.get("width_excess"),
    )
    if qf_computed_width != computed_width:
        fail("qf-lra-bad-bisection-width computed_width must match replay")
    if qf_claimed_width != claimed_width:
        fail("qf-lra-bad-bisection-width claimed_width must match replay")
    if qf_width_excess != width_excess:
        fail("qf-lra-bad-bisection-width width_excess must match replay")
    farkas_conflict = data.get("farkas_conflict")
    require_string("qf-lra bad bisection width farkas_conflict", farkas_conflict)
    if farkas_conflict != "width_excess = 1/6 and width_excess <= 0":
        fail("qf-lra-bad-bisection-width must document the fixed width-excess conflict")
    smt2_artifact = data.get("smt2_artifact")
    require_string("qf-lra bad bisection width smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/finite-root-finding-v0/smt2/bad-bisection-width-farkas-conflict.smt2":
        fail("qf-lra-bad-bisection-width smt2_artifact must name the checked QF_LRA artifact")
    check_source("qf-lra bad bisection width smt2_artifact", smt2_artifact)
    regression = data.get("farkas_regression")
    require_string("qf-lra bad bisection width farkas_regression", regression)
    if "finite_root_finding_bad_bisection_width_artifact_emits_checked_farkas" not in regression:
        fail("qf-lra-bad-bisection-width must link the LRA route regression")
    certificate = data.get("certificate")
    require_string("qf-lra bad bisection width certificate", certificate)
    if "UnsatFarkas" not in certificate or "independently checks" not in certificate:
        fail("qf-lra-bad-bisection-width certificate must document checked Farkas evidence")

    horizon = checks["general-root-finding-convergence-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-root-finding-convergence-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-root-finding-convergence-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("root finding target_theorem_shape", data.get("target_theorem_shape"))
    require_string("root finding future_checker", data.get("future_checker"))


def validate_calculus_algebraic_shadow(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    derivative_check = checks["polynomial-derivative-coefficients"]
    if derivative_check["expected_result"] != "sat":
        fail("polynomial-derivative-coefficients must expect sat")
    values = single_witness_values(derivative_check, witnesses)
    polynomial = require_polynomial("calculus derivative polynomial", values.get("polynomial"))
    derivative = require_polynomial("calculus derivative coefficients", values.get("derivative"))
    if polynomial_derivative(polynomial) != derivative:
        fail("polynomial-derivative-coefficients derivative list is incorrect")

    product_rule = checks["product-rule-polynomial-identity"]
    if product_rule["expected_result"] != "sat":
        fail("product-rule-polynomial-identity must expect sat")
    values = single_witness_values(product_rule, witnesses)
    f_poly = require_polynomial("product rule f", values.get("f"))
    g_poly = require_polynomial("product rule g", values.get("g"))
    product_derivative = require_polynomial(
        "product rule product_derivative",
        values.get("product_derivative"),
    )
    product_rule_rhs = require_polynomial(
        "product rule product_rule_rhs",
        values.get("product_rule_rhs"),
    )
    actual_product_derivative = polynomial_derivative(polynomial_mul(f_poly, g_poly))
    actual_rhs = polynomial_add(
        polynomial_mul(polynomial_derivative(f_poly), g_poly),
        polynomial_mul(f_poly, polynomial_derivative(g_poly)),
    )
    if product_derivative != actual_product_derivative:
        fail("product-rule-polynomial-identity product_derivative is incorrect")
    if product_rule_rhs != actual_rhs:
        fail("product-rule-polynomial-identity product_rule_rhs is incorrect")
    if product_derivative != product_rule_rhs:
        fail("product-rule-polynomial-identity sides differ")

    tangent = checks["tangent-line-value-witness"]
    if tangent["expected_result"] != "sat":
        fail("tangent-line-value-witness must expect sat")
    values = single_witness_values(tangent, witnesses)
    polynomial = require_polynomial("tangent polynomial", values.get("polynomial"))
    point = require_fraction("tangent point", values.get("point"))
    target_x = require_fraction("tangent target_x", values.get("target_x"))
    derivative_at_point = require_fraction("tangent derivative_at_point", values.get("derivative_at_point"))
    tangent_value = require_fraction("tangent tangent_value", values.get("tangent_value"))
    actual_derivative_at_point = polynomial_eval(polynomial_derivative(polynomial), point)
    if derivative_at_point != actual_derivative_at_point:
        fail("tangent-line-value-witness derivative_at_point is incorrect")
    expected_tangent = polynomial_eval(polynomial, point) + derivative_at_point * (target_x - point)
    if tangent_value != expected_tangent:
        fail("tangent-line-value-witness tangent_value is incorrect")

    critical = checks["convex-quadratic-critical-point"]
    if critical["expected_result"] != "sat":
        fail("convex-quadratic-critical-point must expect sat")
    values = single_witness_values(critical, witnesses)
    polynomial = require_quadratic("convex critical polynomial", values.get("polynomial"))
    critical_point = require_fraction("convex critical_point", values.get("critical_point"))
    value = require_fraction("convex value", values.get("value"))
    second_derivative = require_fraction("convex second_derivative", values.get("second_derivative"))
    derivative = polynomial_derivative(polynomial)
    actual_second = polynomial_derivative(derivative)
    if polynomial_eval(derivative, critical_point) != 0:
        fail("convex-quadratic-critical-point derivative is not zero at critical_point")
    if polynomial_eval(polynomial, critical_point) != value:
        fail("convex-quadratic-critical-point value is incorrect")
    if polynomial_eval(actual_second, critical_point) != second_derivative:
        fail("convex-quadratic-critical-point second_derivative is incorrect")
    if second_derivative <= 0:
        fail("convex-quadratic-critical-point must have positive second derivative")

    false_derivative = checks["false-derivative-value-rejected"]
    if false_derivative["expected_result"] != "unsat":
        fail("false-derivative-value-rejected must expect unsat")
    data = false_derivative.get("data", {})
    polynomial = require_polynomial("false derivative polynomial", data.get("polynomial"))
    point = require_fraction("false derivative point", data.get("point"))
    claimed = require_fraction("false derivative claimed_derivative", data.get("claimed_derivative"))
    actual = polynomial_eval(polynomial_derivative(polynomial), point)
    documented_actual = require_fraction("false derivative actual_derivative", data.get("actual_derivative"))
    if documented_actual != actual:
        fail("false-derivative-value-rejected actual_derivative is incorrect")
    if actual == claimed:
        fail("false-derivative-value-rejected claimed derivative unexpectedly matches")
    smt2_artifact = data.get("smt2_artifact")
    require_string("false derivative smt2_artifact", smt2_artifact)
    if (
        smt2_artifact
        != "artifacts/examples/math/calculus-algebraic-shadow-v0/smt2/false-derivative-farkas-conflict.smt2"
    ):
        fail("false-derivative-value-rejected smt2_artifact must name the checked QF_LRA artifact")
    check_source("false derivative smt2_artifact", smt2_artifact)
    farkas_regression = data.get("farkas_regression")
    require_string("false derivative farkas_regression", farkas_regression)
    if "calculus_algebraic_false_derivative_artifact_emits_checked_farkas" not in farkas_regression:
        fail("false-derivative-value-rejected must link the Farkas regression")

    horizon = checks["general-calculus-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-calculus-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("general-calculus-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("general calculus target_theorem_shape", data.get("target_theorem_shape"))
    require_string("general calculus future_checker", data.get("future_checker"))


def polynomial_antiderivative(polynomial: list[Fraction]) -> list[Fraction]:
    return normalize_polynomial([
        Fraction(0),
        *[
            coefficient / Fraction(index + 1)
            for index, coefficient in enumerate(polynomial)
        ],
    ])


def polynomial_integral(polynomial: list[Fraction], left: Fraction, right: Fraction) -> Fraction:
    antiderivative = polynomial_antiderivative(polynomial)
    return polynomial_eval(antiderivative, right) - polynomial_eval(antiderivative, left)


def require_interval_endpoints(context: str, values: dict[str, Any]) -> tuple[Fraction, Fraction]:
    left = require_fraction(f"{context}.a", values.get("a"))
    right = require_fraction(f"{context}.b", values.get("b"))
    if not left < right:
        fail(f"{context} requires a < b")
    return left, right


def require_partition(context: str, value: Any, left: Fraction, right: Fraction) -> list[Fraction]:
    partition = require_fraction_vector(context, value)
    if len(partition) < 2:
        fail(f"{context} must have at least two endpoints")
    if partition[0] != left or partition[-1] != right:
        fail(f"{context} endpoints must match the listed interval")
    for previous, current in zip(partition, partition[1:]):
        if not previous < current:
            fail(f"{context} must be strictly increasing")
    return partition


def riemann_left_sum(polynomial: list[Fraction], partition: list[Fraction]) -> Fraction:
    return sum(
        polynomial_eval(polynomial, partition[index]) * (partition[index + 1] - partition[index])
        for index in range(len(partition) - 1)
    )


def riemann_right_sum(polynomial: list[Fraction], partition: list[Fraction]) -> Fraction:
    return sum(
        polynomial_eval(polynomial, partition[index + 1]) * (partition[index + 1] - partition[index])
        for index in range(len(partition) - 1)
    )


def riemann_midpoints(partition: list[Fraction]) -> list[Fraction]:
    return [
        (partition[index] + partition[index + 1]) / 2
        for index in range(len(partition) - 1)
    ]


def riemann_midpoint_sum(polynomial: list[Fraction], partition: list[Fraction]) -> Fraction:
    return sum(
        polynomial_eval(polynomial, midpoint) * (partition[index + 1] - partition[index])
        for index, midpoint in enumerate(riemann_midpoints(partition))
    )


def riemann_trapezoid_sum(polynomial: list[Fraction], partition: list[Fraction]) -> Fraction:
    return sum(
        (
            polynomial_eval(polynomial, partition[index])
            + polynomial_eval(polynomial, partition[index + 1])
        )
        / 2
        * (partition[index + 1] - partition[index])
        for index in range(len(partition) - 1)
    )


def validate_simpson_panel(context: str, values: dict[str, Any]) -> dict[str, Any]:
    method = values.get("method")
    require_string(f"{context}.method", method)
    if method != "single_panel_simpson_rule":
        fail(f"{context}.method must be single_panel_simpson_rule")
    polynomial = require_polynomial(f"{context}.polynomial", values.get("polynomial"))
    left, right = require_interval_endpoints(f"{context}.interval", values)
    nodes = require_fraction_vector(f"{context}.nodes", values.get("nodes"))
    weights = require_fraction_vector(f"{context}.weights", values.get("weights"))
    sample_values = require_fraction_vector(f"{context}.sample_values", values.get("sample_values"))
    scale = require_fraction(f"{context}.scale", values.get("scale"))
    weighted_sum = require_fraction(f"{context}.weighted_sum", values.get("weighted_sum"))
    simpson_value = require_fraction(f"{context}.simpson_value", values.get("simpson_value"))
    exact_integral = require_fraction(f"{context}.exact_integral", values.get("exact_integral"))
    midpoint = (left + right) / 2
    if right <= left:
        fail(f"{context}.interval must have a < b")
    if nodes != [left, midpoint, right]:
        fail(f"{context}.nodes must be [a, (a+b)/2, b]")
    if weights != [Fraction(1), Fraction(4), Fraction(1)]:
        fail(f"{context}.weights must be [1, 4, 1]")
    expected_values = [polynomial_eval(polynomial, node) for node in nodes]
    if sample_values != expected_values:
        fail(f"{context}.sample_values do not match the polynomial")
    expected_scale = (right - left) / 6
    if scale != expected_scale:
        fail(f"{context}.scale must be (b-a)/6")
    expected_weighted_sum = sum(weight * value for weight, value in zip(weights, sample_values))
    if weighted_sum != expected_weighted_sum:
        fail(f"{context}.weighted_sum is incorrect")
    if simpson_value != scale * weighted_sum:
        fail(f"{context}.simpson_value is incorrect")
    if exact_integral != polynomial_integral(polynomial, left, right):
        fail(f"{context}.exact_integral is incorrect")
    return {
        "polynomial": polynomial,
        "left": left,
        "right": right,
        "nodes": nodes,
        "weights": weights,
        "sample_values": sample_values,
        "scale": scale,
        "weighted_sum": weighted_sum,
        "simpson_value": simpson_value,
        "exact_integral": exact_integral,
    }


def require_fraction_vector_table(context: str, value: Any) -> list[list[Fraction]]:
    if not isinstance(value, list) or not value:
        fail(f"{context} must be a non-empty list")
    return [
        require_fraction_vector(f"{context}[{index}]", row)
        for index, row in enumerate(value)
    ]


def divided_difference_rows(nodes: list[Fraction], sample_values: list[Fraction]) -> list[list[Fraction]]:
    rows = [sample_values]
    for order in range(1, len(nodes)):
        previous = rows[-1]
        current: list[Fraction] = []
        for index in range(len(previous) - 1):
            denominator = nodes[index + order] - nodes[index]
            if denominator == 0:
                fail("divided differences require distinct nodes")
            current.append((previous[index + 1] - previous[index]) / denominator)
        rows.append(current)
    return rows


def newton_basis_values(nodes: list[Fraction], point: Fraction) -> list[Fraction]:
    basis = [Fraction(1)]
    product_value = Fraction(1)
    for node in nodes[:-1]:
        product_value *= point - node
        basis.append(product_value)
    return basis


def validate_divided_difference_trace(context: str, values: dict[str, Any]) -> dict[str, Any]:
    method = values.get("method")
    require_string(f"{context}.method", method)
    if method != "newton_divided_differences":
        fail(f"{context}.method must be newton_divided_differences")
    polynomial = require_polynomial(f"{context}.polynomial", values.get("polynomial"))
    nodes = require_fraction_vector(f"{context}.nodes", values.get("nodes"))
    if len(nodes) < 2:
        fail(f"{context}.nodes must contain at least two nodes")
    for previous, current in zip(nodes, nodes[1:]):
        if not previous < current:
            fail(f"{context}.nodes must be strictly increasing")
    if len(normalize_polynomial(polynomial)) > len(nodes):
        fail(f"{context}.polynomial degree must be less than the number of nodes")
    sample_values = require_fraction_vector(f"{context}.sample_values", values.get("sample_values"))
    if len(sample_values) != len(nodes):
        fail(f"{context}.sample_values length must match nodes")
    expected_samples = [polynomial_eval(polynomial, node) for node in nodes]
    if sample_values != expected_samples:
        fail(f"{context}.sample_values do not match the polynomial")
    table = require_fraction_vector_table(
        f"{context}.divided_difference_table",
        values.get("divided_difference_table"),
    )
    if len(table) != len(nodes):
        fail(f"{context}.divided_difference_table must have one row per divided-difference order")
    for order, row in enumerate(table):
        expected_length = len(nodes) - order
        if len(row) != expected_length:
            fail(f"{context}.divided_difference_table[{order}] must have length {expected_length}")
    expected_table = divided_difference_rows(nodes, sample_values)
    if table != expected_table:
        fail(f"{context}.divided_difference_table is incorrect")
    coefficients = require_fraction_vector(
        f"{context}.newton_coefficients",
        values.get("newton_coefficients"),
    )
    expected_coefficients = [row[0] for row in expected_table]
    if coefficients != expected_coefficients:
        fail(f"{context}.newton_coefficients must be the first entry of each divided-difference row")
    point = require_fraction(f"{context}.evaluation_point", values.get("evaluation_point"))
    basis = require_fraction_vector(f"{context}.newton_basis_values", values.get("newton_basis_values"))
    expected_basis = newton_basis_values(nodes, point)
    if basis != expected_basis:
        fail(f"{context}.newton_basis_values are incorrect")
    terms = require_fraction_vector(f"{context}.newton_terms", values.get("newton_terms"))
    expected_terms = [coefficient * basis_value for coefficient, basis_value in zip(coefficients, basis)]
    if terms != expected_terms:
        fail(f"{context}.newton_terms are incorrect")
    interpolated_value = require_fraction(
        f"{context}.interpolated_value",
        values.get("interpolated_value"),
    )
    if interpolated_value != sum(terms):
        fail(f"{context}.interpolated_value is incorrect")
    polynomial_value = require_fraction(f"{context}.polynomial_value", values.get("polynomial_value"))
    if polynomial_value != polynomial_eval(polynomial, point):
        fail(f"{context}.polynomial_value is incorrect")
    if interpolated_value != polynomial_value:
        fail(f"{context}.interpolated_value must match the polynomial value")
    return {
        "polynomial": polynomial,
        "nodes": nodes,
        "sample_values": sample_values,
        "table": table,
        "coefficients": coefficients,
        "evaluation_point": point,
        "basis": basis,
        "terms": terms,
        "interpolated_value": interpolated_value,
        "polynomial_value": polynomial_value,
    }


def barycentric_weights(nodes: list[Fraction]) -> list[Fraction]:
    weights: list[Fraction] = []
    for index, node in enumerate(nodes):
        denominator = Fraction(1)
        for other_index, other_node in enumerate(nodes):
            if index == other_index:
                continue
            difference = node - other_node
            if difference == 0:
                fail("barycentric interpolation requires distinct nodes")
            denominator *= difference
        weights.append(Fraction(1, denominator))
    return weights


def validate_barycentric_trace(context: str, values: dict[str, Any]) -> dict[str, Any]:
    method = values.get("method")
    require_string(f"{context}.method", method)
    if method != "barycentric_interpolation":
        fail(f"{context}.method must be barycentric_interpolation")
    polynomial = require_polynomial(f"{context}.polynomial", values.get("polynomial"))
    nodes = require_fraction_vector(f"{context}.nodes", values.get("nodes"))
    if len(nodes) < 2:
        fail(f"{context}.nodes must contain at least two nodes")
    for previous, current in zip(nodes, nodes[1:]):
        if not previous < current:
            fail(f"{context}.nodes must be strictly increasing")
    if len(normalize_polynomial(polynomial)) > len(nodes):
        fail(f"{context}.polynomial degree must be less than the number of nodes")
    sample_values = require_fraction_vector(f"{context}.sample_values", values.get("sample_values"))
    if len(sample_values) != len(nodes):
        fail(f"{context}.sample_values length must match nodes")
    expected_samples = [polynomial_eval(polynomial, node) for node in nodes]
    if sample_values != expected_samples:
        fail(f"{context}.sample_values do not match the polynomial")
    weights = require_fraction_vector(
        f"{context}.barycentric_weights",
        values.get("barycentric_weights"),
    )
    expected_weights = barycentric_weights(nodes)
    if weights != expected_weights:
        fail(f"{context}.barycentric_weights are incorrect")
    point = require_fraction(f"{context}.evaluation_point", values.get("evaluation_point"))
    mode = values.get("evaluation_mode")
    require_string(f"{context}.evaluation_mode", mode)
    polynomial_value = require_fraction(f"{context}.polynomial_value", values.get("polynomial_value"))
    if polynomial_value != polynomial_eval(polynomial, point):
        fail(f"{context}.polynomial_value is incorrect")
    interpolated_value = require_fraction(
        f"{context}.interpolated_value",
        values.get("interpolated_value"),
    )

    if mode == "regular":
        if point in nodes:
            fail(f"{context}.evaluation_point must not be a node in regular mode")
        denominator_terms = require_fraction_vector(
            f"{context}.denominator_terms",
            values.get("denominator_terms"),
        )
        numerator_terms = require_fraction_vector(
            f"{context}.numerator_terms",
            values.get("numerator_terms"),
        )
        if len(denominator_terms) != len(nodes):
            fail(f"{context}.denominator_terms length must match nodes")
        if len(numerator_terms) != len(nodes):
            fail(f"{context}.numerator_terms length must match nodes")
        expected_denominator_terms = [
            weight / (point - node) for weight, node in zip(weights, nodes)
        ]
        expected_numerator_terms = [
            weight * sample / (point - node)
            for weight, sample, node in zip(weights, sample_values, nodes)
        ]
        if denominator_terms != expected_denominator_terms:
            fail(f"{context}.denominator_terms are incorrect")
        if numerator_terms != expected_numerator_terms:
            fail(f"{context}.numerator_terms are incorrect")
        denominator_sum = require_fraction(
            f"{context}.denominator_sum",
            values.get("denominator_sum"),
        )
        numerator_sum = require_fraction(f"{context}.numerator_sum", values.get("numerator_sum"))
        if denominator_sum != sum(denominator_terms):
            fail(f"{context}.denominator_sum is incorrect")
        if numerator_sum != sum(numerator_terms):
            fail(f"{context}.numerator_sum is incorrect")
        if denominator_sum == 0:
            fail(f"{context}.denominator_sum must be nonzero")
        if interpolated_value != numerator_sum / denominator_sum:
            fail(f"{context}.interpolated_value is incorrect")
    elif mode == "node_hit":
        node_hit_index = require_int(f"{context}.node_hit_index", values.get("node_hit_index"))
        if not 0 <= node_hit_index < len(nodes):
            fail(f"{context}.node_hit_index out of range")
        if point != nodes[node_hit_index]:
            fail(f"{context}.evaluation_point must equal the node-hit node")
        if interpolated_value != sample_values[node_hit_index]:
            fail(f"{context}.interpolated_value must equal the node-hit sample value")
    else:
        fail(f"{context}.evaluation_mode must be regular or node_hit")

    if interpolated_value != polynomial_value:
        fail(f"{context}.interpolated_value must match the polynomial value")
    return {
        "polynomial": polynomial,
        "nodes": nodes,
        "sample_values": sample_values,
        "weights": weights,
        "evaluation_point": point,
        "mode": mode,
        "interpolated_value": interpolated_value,
        "polynomial_value": polynomial_value,
    }


def nth_polynomial_derivative(polynomial: list[Fraction], order: int) -> list[Fraction]:
    derivative = polynomial
    for _ in range(order):
        derivative = polynomial_derivative(derivative)
    return derivative


def validate_finite_difference_trace(context: str, values: dict[str, Any]) -> dict[str, Any]:
    method = values.get("method")
    require_string(f"{context}.method", method)
    if method != "finite_difference_derivative":
        fail(f"{context}.method must be finite_difference_derivative")
    polynomial = require_polynomial(f"{context}.polynomial", values.get("polynomial"))
    point = require_fraction(f"{context}.point", values.get("point"))
    step = require_fraction(f"{context}.step", values.get("step"))
    if step == 0:
        fail(f"{context}.step must be nonzero")
    derivative_order = require_int(f"{context}.derivative_order", values.get("derivative_order"))
    if derivative_order <= 0:
        fail(f"{context}.derivative_order must be positive")
    stencil = values.get("stencil")
    require_string(f"{context}.stencil", stencil)
    offsets = require_fraction_vector(
        f"{context}.stencil_offsets",
        values.get("stencil_offsets"),
    )
    weights = require_fraction_vector(
        f"{context}.stencil_weights",
        values.get("stencil_weights"),
    )
    if len(offsets) != len(weights):
        fail(f"{context}.stencil_offsets length must match stencil_weights")
    sample_points = require_fraction_vector(
        f"{context}.stencil_points",
        values.get("stencil_points"),
    )
    if len(sample_points) != len(offsets):
        fail(f"{context}.stencil_points length must match stencil_offsets")
    expected_points = [point + offset * step for offset in offsets]
    if sample_points != expected_points:
        fail(f"{context}.stencil_points are incorrect")
    sample_values = require_fraction_vector(
        f"{context}.sample_values",
        values.get("sample_values"),
    )
    if len(sample_values) != len(sample_points):
        fail(f"{context}.sample_values length must match stencil_points")
    expected_samples = [polynomial_eval(polynomial, sample_point) for sample_point in sample_points]
    if sample_values != expected_samples:
        fail(f"{context}.sample_values do not match the polynomial")
    weighted_terms = require_fraction_vector(
        f"{context}.weighted_terms",
        values.get("weighted_terms"),
    )
    if len(weighted_terms) != len(weights):
        fail(f"{context}.weighted_terms length must match stencil_weights")
    expected_terms = [weight * sample for weight, sample in zip(weights, sample_values)]
    if weighted_terms != expected_terms:
        fail(f"{context}.weighted_terms are incorrect")
    weighted_sum = require_fraction(f"{context}.weighted_sum", values.get("weighted_sum"))
    if weighted_sum != sum(weighted_terms):
        fail(f"{context}.weighted_sum is incorrect")
    scale = require_fraction(f"{context}.scale", values.get("scale"))
    finite_difference_value = require_fraction(
        f"{context}.finite_difference_value",
        values.get("finite_difference_value"),
    )
    if finite_difference_value != scale * weighted_sum:
        fail(f"{context}.finite_difference_value is incorrect")
    derivative_polynomial = nth_polynomial_derivative(polynomial, derivative_order)
    exact_derivative_value = require_fraction(
        f"{context}.exact_derivative_value",
        values.get("exact_derivative_value"),
    )
    if exact_derivative_value != polynomial_eval(derivative_polynomial, point):
        fail(f"{context}.exact_derivative_value is incorrect")
    if finite_difference_value != exact_derivative_value:
        fail(f"{context}.finite_difference_value must match the exact derivative value")
    return {
        "polynomial": polynomial,
        "point": point,
        "step": step,
        "derivative_order": derivative_order,
        "stencil": stencil,
        "offsets": offsets,
        "weights": weights,
        "sample_points": sample_points,
        "sample_values": sample_values,
        "weighted_terms": weighted_terms,
        "weighted_sum": weighted_sum,
        "scale": scale,
        "finite_difference_value": finite_difference_value,
        "exact_derivative_value": exact_derivative_value,
    }


def validate_calculus_riemann_sum(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    linear = checks["riemann-sums-linear-partition"]
    if linear["expected_result"] != "sat" or linear.get("proof_status") != "checked":
        fail("riemann-sums-linear-partition must be a checked sat row")
    values = single_witness_values(linear, witnesses)
    polynomial = require_polynomial("linear Riemann polynomial", values.get("polynomial"))
    left, right = require_interval_endpoints("linear Riemann interval", values)
    partition = require_partition("linear Riemann partition", values.get("partition"), left, right)
    left_sum = require_fraction("linear Riemann left_sum", values.get("left_sum"))
    right_sum = require_fraction("linear Riemann right_sum", values.get("right_sum"))
    trapezoid_sum = require_fraction("linear Riemann trapezoid_sum", values.get("trapezoid_sum"))
    exact_integral = require_fraction("linear Riemann exact_integral", values.get("exact_integral"))
    if left_sum != riemann_left_sum(polynomial, partition):
        fail("riemann-sums-linear-partition left_sum is wrong")
    if right_sum != riemann_right_sum(polynomial, partition):
        fail("riemann-sums-linear-partition right_sum is wrong")
    if trapezoid_sum != riemann_trapezoid_sum(polynomial, partition):
        fail("riemann-sums-linear-partition trapezoid_sum is wrong")
    if exact_integral != polynomial_integral(polynomial, left, right):
        fail("riemann-sums-linear-partition exact_integral is wrong")

    midpoint = checks["midpoint-rule-affine-exact"]
    if midpoint["expected_result"] != "sat" or midpoint.get("proof_status") != "checked":
        fail("midpoint-rule-affine-exact must be a checked sat row")
    values = single_witness_values(midpoint, witnesses)
    polynomial = require_polynomial("midpoint polynomial", values.get("polynomial"))
    left, right = require_interval_endpoints("midpoint interval", values)
    partition = require_partition("midpoint partition", values.get("partition"), left, right)
    listed_midpoints = require_fraction_vector("midpoint midpoints", values.get("midpoints"))
    midpoint_sum = require_fraction("midpoint midpoint_sum", values.get("midpoint_sum"))
    exact_integral = require_fraction("midpoint exact_integral", values.get("exact_integral"))
    if listed_midpoints != riemann_midpoints(partition):
        fail("midpoint-rule-affine-exact listed midpoints are wrong")
    if midpoint_sum != riemann_midpoint_sum(polynomial, partition):
        fail("midpoint-rule-affine-exact midpoint_sum is wrong")
    if exact_integral != polynomial_integral(polynomial, left, right):
        fail("midpoint-rule-affine-exact exact_integral is wrong")
    if midpoint_sum != exact_integral:
        fail("midpoint-rule-affine-exact should be exact for this affine row")

    endpoint = checks["antiderivative-endpoint-replay"]
    if endpoint["expected_result"] != "sat" or endpoint.get("proof_status") != "checked":
        fail("antiderivative-endpoint-replay must be a checked sat row")
    values = single_witness_values(endpoint, witnesses)
    integrand = require_polynomial("endpoint integrand", values.get("integrand"))
    antiderivative = require_polynomial("endpoint antiderivative", values.get("antiderivative"))
    left, right = require_interval_endpoints("endpoint interval", values)
    endpoint_difference = require_fraction("endpoint endpoint_difference", values.get("endpoint_difference"))
    if polynomial_derivative(antiderivative) != integrand:
        fail("antiderivative-endpoint-replay derivative does not match integrand")
    if endpoint_difference != polynomial_eval(antiderivative, right) - polynomial_eval(antiderivative, left):
        fail("antiderivative-endpoint-replay endpoint difference is wrong")

    bounds = checks["monotone-quadratic-lower-upper-bounds"]
    if bounds["expected_result"] != "sat" or bounds.get("proof_status") != "checked":
        fail("monotone-quadratic-lower-upper-bounds must be a checked sat row")
    values = single_witness_values(bounds, witnesses)
    polynomial = require_polynomial("monotone bounds polynomial", values.get("polynomial"))
    left, right = require_interval_endpoints("monotone bounds interval", values)
    partition = require_partition("monotone bounds partition", values.get("partition"), left, right)
    direction = values.get("monotone_direction")
    require_string("monotone bounds monotone_direction", direction)
    if direction != "increasing":
        fail("monotone-quadratic-lower-upper-bounds currently documents an increasing row")
    lower_sum = require_fraction("monotone bounds lower_sum", values.get("lower_sum"))
    upper_sum = require_fraction("monotone bounds upper_sum", values.get("upper_sum"))
    exact_integral = require_fraction("monotone bounds exact_integral", values.get("exact_integral"))
    endpoint_values = [polynomial_eval(polynomial, point) for point in partition]
    for previous, current in zip(endpoint_values, endpoint_values[1:]):
        if previous > current:
            fail("monotone-quadratic-lower-upper-bounds endpoint values are not increasing")
    if lower_sum != riemann_left_sum(polynomial, partition):
        fail("monotone-quadratic-lower-upper-bounds lower_sum is wrong")
    if upper_sum != riemann_right_sum(polynomial, partition):
        fail("monotone-quadratic-lower-upper-bounds upper_sum is wrong")
    if exact_integral != polynomial_integral(polynomial, left, right):
        fail("monotone-quadratic-lower-upper-bounds exact_integral is wrong")
    if not lower_sum <= exact_integral <= upper_sum:
        fail("monotone-quadratic-lower-upper-bounds exact integral is not bracketed")

    false_claim = checks["false-integral-claim-rejected"]
    if false_claim["expected_result"] != "unsat" or false_claim.get("proof_status") != "checked":
        fail("false-integral-claim-rejected must be a checked unsat row")
    data = false_claim.get("data", {})
    polynomial = require_polynomial("false integral polynomial", data.get("polynomial"))
    left, right = require_interval_endpoints("false integral interval", data)
    claimed = require_fraction("false integral claimed_integral", data.get("claimed_integral"))
    actual = require_fraction("false integral actual_integral", data.get("actual_integral"))
    if actual != polynomial_integral(polynomial, left, right):
        fail("false-integral-claim-rejected actual_integral is wrong")
    if claimed == actual:
        fail("false-integral-claim-rejected claim unexpectedly matches the exact integral")
    smt2_artifact = data.get("smt2_artifact")
    require_string("false integral smt2_artifact", smt2_artifact)
    if smt2_artifact != "artifacts/examples/math/calculus-riemann-sum-v0/smt2/false-integral-farkas-conflict.smt2":
        fail("false-integral-claim-rejected smt2_artifact must name the checked QF_LRA artifact")
    check_source("false integral smt2_artifact", smt2_artifact)
    farkas_regression = data.get("farkas_regression")
    require_string("false integral farkas_regression", farkas_regression)
    if "calculus_riemann_sum_false_integral_artifact_emits_checked_farkas" not in farkas_regression:
        fail("false-integral-claim-rejected must link the Farkas regression")

    horizon = checks["fundamental-theorem-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("fundamental-theorem-lean-horizon must be not-run")
    if horizon["proof_status"] != "lean-horizon":
        fail("fundamental-theorem-lean-horizon must remain lean-horizon")
    data = horizon.get("data", {})
    require_string("fundamental theorem target_theorem_shape", data.get("target_theorem_shape"))
    require_string("fundamental theorem future_checker", data.get("future_checker"))


def validate_finite_simpson_rule(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    cubic = checks["simpson-cubic-exact-witness"]
    if cubic["expected_result"] != "sat":
        fail("simpson-cubic-exact-witness must expect sat")
    if cubic.get("proof_status") != "replay-only":
        fail("simpson-cubic-exact-witness must be replay-only")
    if cubic.get("validation") != "exact_rational_simpson_rule_replay":
        fail("simpson-cubic-exact-witness validation is incorrect")
    cubic_values = single_witness_values(cubic, witnesses)
    cubic_replay = validate_simpson_panel("cubic Simpson panel", cubic_values)
    if cubic_replay["simpson_value"] != cubic_replay["exact_integral"]:
        fail("simpson-cubic-exact-witness should be exact for this cubic row")
    if cubic_replay["simpson_value"] != Fraction(4):
        fail("simpson-cubic-exact-witness must compute value 4")

    quadratic = checks["simpson-quadratic-exact-witness"]
    if quadratic["expected_result"] != "sat":
        fail("simpson-quadratic-exact-witness must expect sat")
    if quadratic.get("proof_status") != "replay-only":
        fail("simpson-quadratic-exact-witness must be replay-only")
    if quadratic.get("validation") != "exact_rational_simpson_rule_replay":
        fail("simpson-quadratic-exact-witness validation is incorrect")
    quadratic_values = single_witness_values(quadratic, witnesses)
    quadratic_replay = validate_simpson_panel("quadratic Simpson panel", quadratic_values)
    if quadratic_replay["simpson_value"] != quadratic_replay["exact_integral"]:
        fail("simpson-quadratic-exact-witness should be exact for this quadratic row")

    bad = checks["bad-simpson-value-rejected"]
    if bad["expected_result"] != "unsat":
        fail("bad-simpson-value-rejected must expect unsat")
    if bad.get("proof_status") != "replay-only":
        fail("bad-simpson-value-rejected must be replay-only")
    if bad.get("validation") != "exact_rational_bad_simpson_value_replay":
        fail("bad-simpson-value-rejected validation is incorrect")
    data = bad.get("data", {})
    if data.get("source_witness") != "cubic-single-panel-simpson":
        fail("bad-simpson-value-rejected must cite the cubic Simpson witness")
    computed = require_fraction("bad Simpson computed_simpson_value", data.get("computed_simpson_value"))
    claimed = require_fraction("bad Simpson claimed_simpson_value", data.get("claimed_simpson_value"))
    gap = require_fraction("bad Simpson simpson_value_gap", data.get("simpson_value_gap"))
    if computed != cubic_replay["simpson_value"]:
        fail("bad-simpson-value-rejected computed value must match the cubic replay")
    if computed == claimed:
        fail("bad-simpson-value-rejected malformed claim must disagree with replay")
    if computed - claimed != gap:
        fail("bad-simpson-value-rejected simpson_value_gap is incorrect")
    if gap <= 0:
        fail("bad-simpson-value-rejected simpson_value_gap must be positive")
    if "separate qf-lra-bad-simpson-value" not in bad.get("notes", ""):
        fail("bad-simpson-value-rejected notes must name the checked qf-lra row")

    qf_bad = checks["qf-lra-bad-simpson-value"]
    if qf_bad["expected_result"] != "unsat":
        fail("qf-lra-bad-simpson-value must expect unsat")
    if qf_bad.get("proof_status") != "checked":
        fail("qf-lra-bad-simpson-value must be checked")
    if qf_bad.get("validation") != "exact_rational_farkas_evidence":
        fail("qf-lra-bad-simpson-value must use exact_rational_farkas_evidence")
    qf_data = qf_bad.get("data", {})
    if qf_data.get("source_witness") != "cubic-single-panel-simpson":
        fail("qf-lra-bad-simpson-value must cite the cubic Simpson witness")
    if qf_data.get("source_replay_row") != "bad-simpson-value-rejected":
        fail("qf-lra-bad-simpson-value must cite the replay row")
    qf_computed = require_fraction(
        "qf Simpson computed_simpson_value",
        qf_data.get("computed_simpson_value"),
    )
    qf_claimed = require_fraction(
        "qf Simpson claimed_simpson_value",
        qf_data.get("claimed_simpson_value"),
    )
    if qf_computed != computed or qf_claimed != claimed:
        fail("qf-lra-bad-simpson-value data must match the replay row")
    conflict = qf_data.get("farkas_conflict")
    require_string("qf Simpson farkas_conflict", conflict)
    if conflict != "simpson_value = 4 and simpson_value = 7/2":
        fail("qf-lra-bad-simpson-value must document the Farkas conflict")
    smt2_artifact = qf_data.get("smt2_artifact")
    require_string("qf Simpson smt2_artifact", smt2_artifact)
    expected_smt2 = (
        "artifacts/examples/math/finite-simpson-rule-v0/smt2/"
        "bad-simpson-value-farkas-conflict.smt2"
    )
    if smt2_artifact != expected_smt2:
        fail("qf-lra-bad-simpson-value smt2_artifact must name the checked source artifact")
    check_source("qf Simpson smt2_artifact", smt2_artifact)
    regression = qf_data.get("farkas_regression")
    require_string("qf Simpson farkas_regression", regression)
    if "finite_simpson_rule_bad_value_artifact_emits_checked_farkas" not in regression:
        fail("qf-lra-bad-simpson-value must link the Farkas regression")
    certificate = qf_data.get("certificate")
    require_string("qf Simpson certificate", certificate)
    if "UnsatFarkas" not in certificate or "independently checks" not in certificate:
        fail("qf-lra-bad-simpson-value certificate must document checked Farkas evidence")

    horizon = checks["general-simpson-rule-theory-lean-horizon"]
    if horizon["expected_result"] != "not-run":
        fail("general-simpson-rule-theory-lean-horizon must be not-run")
    if horizon.get("proof_status") != "lean-horizon":
        fail("general-simpson-rule-theory-lean-horizon must remain lean-horizon")
    horizon_data = horizon.get("data", {})
    require_string("Simpson horizon target_theorem_shape", horizon_data.get("target_theorem_shape"))
    require_string("Simpson horizon future_checker", horizon_data.get("future_checker"))


def validate_finite_divided_differences(expected: dict[str, Any]) -> None:
    witnesses = witness_by_id(expected)
    checks = {check["id"]: check for check in expected["checks"]}

    quadratic = checks["quadratic-divided-difference-table"]
    if quadratic["expected_result"] != "sat":
        fail("quadratic-divided-difference-table must expect sat")
